window.HADITH_CACHE["bukhari_10"] = {"5001":{"ar":"حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا سُلَيْمَانُ عَنْ يَحْيَى بْنِ سَعِيدٍ قَالَ سَمِعْتُ أَبَا سَلَمَةَ قَالَ سَمِعْتُ أَبَا قَتَادَةَ يَقُولُسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الرُّؤْيَا مِنْ اللَّهِ وَالْحُلْمُ مِنْ الشَّيْطَانِ فَإِذَا رَأَى أَحَدُكُمْ شَيْئًا يَكْرَهُهُ فَلْيَنْفِثْ حِينَ يَسْتَيْقِظُ ثَلَاثَ مَرَّاتٍ وَيَتَعَوَّذْ مِنْ شَرِّهَا فَإِنَّهَا لَا تَضُرُّهُوَقَالَ أَبُو سَلَمَةَ وَإِنْ كُنْتُ لَأَرَى الرُّؤْيَا أَثْقَلَ عَلَيَّ مِنْ الْجَبَلِ فَمَا هُوَ إِلَّا أَنْ سَمِعْتُ هَذَا الْحَدِيثَ فَمَا أُبَالِيهَا","id":"Telah menceritakan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Sulaiman] dari [Yahya bin Sa'id] dia berkata; saya mendengar [Abu Salamah] berkata; saya mendengar [Abu Qatadah] berkata; saya mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Mimpi baik dari Allah sedangkan ihtilam (mimpi buruk) datangnya dari syetan, maka apabila salah seorang dari kalian mimpi sesuatu yang dibencinya, hendaknya ia menidupkan tiga kali tiaupan ketika bangun, lalu meminta perlindungan dari kejahatannya, sebab kejahatan tersebut tidak akan membahayakan dirinya.\" Abu Salamah berkata; \"Apabila aku bermimpi sesuatu yang aku merasa lebih berat dari gunung, maka aku tidak akan memperdulikannya setelah aku mendengar hadits ini.\""},"5002":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ الْأُوَيْسِيُّ حَدَّثَنَا سُلَيْمَانُ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَوَى إِلَى فِرَاشِهِ نَفَثَ فِي كَفَّيْهِ بِقُلْ هُوَ اللَّهُ أَحَدٌ وَبِالْمُعَوِّذَتَيْنِ جَمِيعًا ثُمَّ يَمْسَحُ بِهِمَا وَجْهَهُ وَمَا بَلَغَتْ يَدَاهُ مِنْ جَسَدِهِ قَالَتْ عَائِشَةُ فَلَمَّا اشْتَكَى كَانَ يَأْمُرُنِي أَنْ أَفْعَلَ ذَلِكَ بِهِقَالَ يُونُسُ كُنْتُ أَرَى ابْنَ شِهَابٍ يَصْنَعُ ذَلِكَ إِذَا أَتَى إِلَى فِرَاشِهِ","id":"Telah menceritakan kepada kami [Abdul Aziz bin Abdullah Al Uwaisi] telah menceritakan kepada kami [Sulaiman] dari [Yunus] dari [Ibnu Syihab] dari ['Urwah bin Az Zubair] dari ['Aisyah] radliallahu 'anha dia berkata; \"Apabila Rasulullah shallallahu 'alaihi wasallam hendak tidur, maka beliau akan meniupkan ke telapak tangannya sambil membaca QUL HUWALLAHU AHAD (QS Al Ikhlas 1-4) dan Mu'awidzatain (An Nas dan Al Falaq), kemudian beliau mengusapkan ke wajahnya dan seluruh tubuhnya. Aisyah berkata; Ketika beliau sakit, beliau menyuruhku melakukan hal itu.\" Yunus berkata; aku melihat Ibnu Syihab apabila hendak tidur, ia melakukan hal itu juga.\""},"5003":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ أَبِي الْمُتَوَكِّلِ عَنْ أَبِي سَعِيدٍأَنَّ رَهْطًا مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْطَلَقُوا فِي سَفْرَةٍ سَافَرُوهَا حَتَّى نَزَلُوا بِحَيٍّ مِنْ أَحْيَاءِ الْعَرَبِ فَاسْتَضَافُوهُمْ فَأَبَوْا أَنْ يُضَيِّفُوهُمْ فَلُدِغَ سَيِّدُ ذَلِكَ الْحَيِّ فَسَعَوْا لَهُ بِكُلِّ شَيْءٍ لَا يَنْفَعُهُ شَيْءٌ فَقَالَ بَعْضُهُمْ لَوْ أَتَيْتُمْ هَؤُلَاءِ الرَّهْطَ الَّذِينَ قَدْ نَزَلُوا بِكُمْ لَعَلَّهُ أَنْ يَكُونَ عِنْدَ بَعْضِهِمْ شَيْءٌ فَأَتَوْهُمْ فَقَالُوا يَا أَيُّهَا الرَّهْطُ إِنَّ سَيِّدَنَا لُدِغَ فَسَعَيْنَا لَهُ بِكُلِّ شَيْءٍ لَا يَنْفَعُهُ شَيْءٌ فَهَلْ عِنْدَ أَحَدٍ مِنْكُمْ شَيْءٌ فَقَالَ بَعْضُهُمْ نَعَمْ وَاللَّهِ إِنِّي لَرَاقٍ وَلَكِنْ وَاللَّهِ لَقَدْ اسْتَضَفْنَاكُمْ فَلَمْ تُضَيِّفُونَا فَمَا أَنَا بِرَاقٍ لَكُمْ حَتَّى تَجْعَلُوا لَنَا جُعْلًا فَصَالَحُوهُمْ عَلَى قَطِيعٍ مِنْ الْغَنَمِ فَانْطَلَقَ فَجَعَلَ يَتْفُلُ وَيَقْرَأُ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ حَتَّى لَكَأَنَّمَا نُشِطَ مِنْ عِقَالٍ فَانْطَلَقَ يَمْشِي مَا بِهِ قَلَبَةٌ قَالَ فَأَوْفَوْهُمْ جُعْلَهُمْ الَّذِي صَالَحُوهُمْ عَلَيْهِ فَقَالَ بَعْضُهُمْ اقْسِمُوا فَقَالَ الَّذِي رَقَى لَا تَفْعَلُوا حَتَّى نَأْتِيَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَذْكُرَ لَهُ الَّذِي كَانَ فَنَنْظُرَ مَا يَأْمُرُنَا فَقَدِمُوا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرُوا لَهُ فَقَالَ وَمَا يُدْرِيكَ أَنَّهَا رُقْيَةٌ أَصَبْتُمْ اقْسِمُوا وَاضْرِبُوا لِي مَعَكُمْ بِسَهْمٍ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Abu Al Mutawakkil] dari [Abu Sa'id] bahwa beberapa orang dari sahabat Rasulullah shallallahu 'alaihi wasallam pergi dalam suatu perjalanan, ketika mereka singgah di suatu perkampungan dari perkampungan Arab, mereka meminta supaya diberi jamuan, namun penduduk perkampungan itu enggan untuk menjamu mereka, ternyata salah seorang dari tokoh mereka tersengat binatang berbisa, mereka sudah berusaha menerapinya namun tidak juga memberi manfa'at sama sekali, maka sebagian mereka mengatakan; \"Sekiranya kalian mendatangi sekelompok laki-laki (sahabat Nabi) yang singgah di tempat kalian, semoga saja salah seorang dari mereka ada yang memiliki sesuatu, lantas mereka mendatangi para sahabat Nabi sambil berkata; \"Wahai orang-orang, sesungguhnya pemimpin kami tersengat binatang berbisa, dan kami telah berusaha menerapinya dengan segala sesuatu namun tidak juga membuahkan hasil, apakah salah seorang dari kalian memiliki sesuatu (sebagai obat)?\" Salah seorang sahabat Nabi menjawab; \"Ya, demi Allah aku akan meruqyahnya (menjampinya), akan tetapi demi Allah, sungguh kami tadi meminta kalian supaya menjamu kami, namun kalian enggan menjamu kami, dan aku tidak akan meruqyah (menjampinya) sehingga kalian memberikan imbalan kepada kami.\" Lantas penduduk kampung itu menjamu mereka dengan menyediakan beberapa ekor kambing, lalu salah satu sahabat Nabi itu pergi dan membaca al hamdulillahi rabbil 'alamin (al fatihah) dan meludahkan kepadanya hingga seakan-akan pemimpin mereka terlepas dari tali yang membelenggunya dan terbebas dari penyakit yang dapat membinasakannya. Abu Sa'id berkata; \"Lantas penduduk kampung tersebut memberikan imbalan yang telah mereka persiapkan kepada sahabat Nabi, dan sahabat Nabi yang lain pun berkata; \"Bagilah.\" Namun sahabat yang meruqyah berkata; \"Jangan dulu sebelum kita menemui Rasulullah shallallahu 'alaihi wasallam dan memberitahukan apa yang terjadi dan kita akan melihat apa yang beliau perintahkan kepada kita.\" Setelah itu mereka menemui Rasulullah shallallahu 'alaihi wasallam dan memberitahukannya kepada beliau, beliau bersabda: \"Apakah kamu tidak tahu bahwa itu adalah ruqyah? Dan kalian telah mendapatkan imbalan darinya, maka bagilah dan berilah bagian untukku.\""},"5004":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ عَنْ الْأَعْمَشِ عَنْ مُسْلِمٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَوِّذُ بَعْضَهُمْ يَمْسَحُهُ بِيَمِينِهِ أَذْهِبْ الْبَاسَ رَبَّ النَّاسِ وَاشْفِ أَنْتَ الشَّافِي لَا شِفَاءَ إِلَّا شِفَاؤُكَ شِفَاءً لَا يُغَادِرُ سَقَمًافَذَكَرْتُهُ لِمَنْصُورٍ فَحَدَّثَنِي عَنْ إِبْرَاهِيمَ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ بِنَحْوِهِ","id":"Telah menceritakan kepada kami [Abdullah bin Abu Syaibah] telah menceritakan kepada kami [Yahya] dari [Sufyan] dari [Al A'masy] dari [Muslim] dari [Masruq] dari ['Aisyah] radliallahu 'anha dia berkata; bahwa Nabi shallallahu 'alaihi wasallam memintakan perlindungan untuk sebagian keluarga beliau, lalu beliau mengusapkan kepadanya dengan tangan kanannya sambil berdo'a: \"ADZHIBIL BA`SA ALLAHUMMA RABBAN NAASI WASYFII ANTA SYAAFI LAA SYIFAA`A ILLA SYIFAA`UKA SYIFAA`AN LAA YUGHAADIRU SAQAMA (Hilangkanlah rasa sakit Ya Allah Rabb manusia, sembuhkanlah sesungguhnya Engkau Dzat yang Maha menyembuhkan, tidak ada kesembuhan melainkan dari kesembuhan-Mu, yaitu kesembuhan yang tidak menyisakan rasa sakit).\" Lalu aku menceritakan hal ini kepada [Manshur], maka dia menceritakan kepadaku dari [Ibrahim] dari [Masruq] dari [Aisyah] seperti hadits di atas."},"5005":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ الْجُعْفِيُّ حَدَّثَنَا هِشَامٌ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَنْفِثُ عَلَى نَفْسِهِ فِي مَرَضِهِ الَّذِي قُبِضَ فِيهِ بِالْمُعَوِّذَاتِ فَلَمَّا ثَقُلَ كُنْتُ أَنَا أَنْفِثُ عَلَيْهِ بِهِنَّ فَأَمْسَحُ بِيَدِ نَفْسِهِ لِبَرَكَتِهَا فَسَأَلْتُ ابْنَ شِهَابٍ كَيْفَ كَانَ يَنْفِثُ قَالَ يَنْفِثُ عَلَى يَدَيْهِ ثُمَّ يَمْسَحُ بِهِمَا وَجْهَهُ","id":"Telah menceritakan kepadaku [Abdullah bin Muhammad Al Ju'fi] telah menceritakan kepada kami [Hisyam] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah] radliallahu 'anha bahwa Nabi shallallahu 'alaihi wasallam biasa meniupkan pada diri beliau sendiri dengan mu'awwidzat (surat An nas dan Al falaq) ketika sakit menjelang kematiannya, ketika sakit beliau semakin parah, maka akulah yang meniupkan (dengan membacakan mu'awidzat) kepadanya, aku mengusapkan dengan tangan beliau sendiri karena berharap keberkahan darinya.\" Aku bertanya kepada Ibnu Syihab; \"Bagaimana cara beliau meniup (dengan membaca mu'awidzat)?\" dia menjawab; \"Yaitu beliau meniupkan (dengan membaca mu'awidzat) pada tangannya kemudian beliau mengusapkannya ke wajah beliau.\""},"5006":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حُصَيْنُ بْنُ نُمَيْرٍ عَنْ حُصَيْنِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَخَرَجَ عَلَيْنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا فَقَالَ عُرِضَتْ عَلَيَّ الْأُمَمُ فَجَعَلَ يَمُرُّ النَّبِيُّ مَعَهُ الرَّجُلُ وَالنَّبِيُّ مَعَهُ الرَّجُلَانِ وَالنَّبِيُّ مَعَهُ الرَّهْطُ وَالنَّبِيُّ لَيْسَ مَعَهُ أَحَدٌ وَرَأَيْتُ سَوَادًا كَثِيرًا سَدَّ الْأُفُقَ فَرَجَوْتُ أَنْ تَكُونَ أُمَّتِي فَقِيلَ هَذَا مُوسَى وَقَوْمُهُ ثُمَّ قِيلَ لِي انْظُرْ فَرَأَيْتُ سَوَادًا كَثِيرًا سَدَّ الْأُفُقَ فَقِيلَ لِي انْظُرْ هَكَذَا وَهَكَذَا فَرَأَيْتُ سَوَادًا كَثِيرًا سَدَّ الْأُفُقَ فَقِيلَ هَؤُلَاءِ أُمَّتُكَ وَمَعَ هَؤُلَاءِ سَبْعُونَ أَلْفًا يَدْخُلُونَ الْجَنَّةَ بِغَيْرِ حِسَابٍ فَتَفَرَّقَ النَّاسُ وَلَمْ يُبَيَّنْ لَهُمْ فَتَذَاكَرَ أَصْحَابُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا أَمَّا نَحْنُ فَوُلِدْنَا فِي الشِّرْكِ وَلَكِنَّا آمَنَّا بِاللَّهِ وَرَسُولِهِ وَلَكِنْ هَؤُلَاءِ هُمْ أَبْنَاؤُنَا فَبَلَغَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هُمْ الَّذِينَ لَا يَتَطَيَّرُونَ وَلَا يَسْتَرْقُونَ وَلَا يَكْتَوُونَ وَعَلَى رَبِّهِمْ يَتَوَكَّلُونَ فَقَامَ عُكَّاشَةُ بْنُ مِحْصَنٍ فَقَالَ أَمِنْهُمْ أَنَا يَا رَسُولَ اللَّهِ قَالَ نَعَمْ فَقَامَ آخَرُ فَقَالَ أَمِنْهُمْ أَنَا فَقَالَ سَبَقَكَ بِهَا عُكَاشَةُ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Hushain bin Numair] dari [Hushain bin Abdurrahman] dari [Sa'id bin Jubair] dari [Ibnu Abbas] radliallahu 'anhuma dia berkata; Nabi shallallahu 'alaihi wasallam keluar menemui kami lalu beliau bersabda: \"Telah ditampakkan kepadaku umat-umat, maka aku melihat seorang Nabi lewat bersama satu orang, seorang Nabi bersama dua orang saja, seorang Nabi bersama sekelompok orang dan seorang Nabi tanpa seorang pun bersamanya. Lalu tiba-tiba ditampakkan kepadaku kumpulan manusia yang banyak memenuhi ufuk, aku berharap mereka adalah ummatku, namun dikatakan padaku; 'Ini adalah Musa dan kaumnya, lalu di katakana pula kepadaku; \"Tapi lihatlah di ujung sebelah sana.' Ternyata aku melihat ada sekumpulan orang yang sangat banyak, kemudian dikatakan lagi padaku; 'Lihat juga yang sebelah sana.' Ternyata aku juga melihat ada sekumpulan orang yang sangat banyak lagi, lalu dikatakan padaku; 'Ini adalah umatmu, dan bersama mereka ada tujuh puluh ribu orang yang akan masuk surga tanpa hisab.\" Setelah itu orang-orang bubar dan belum sempat ada penjelasan kepada mereka, sehingga para sahabat Nabi shallallahu 'alaihi wasallam saling membicarakan hal itu, mereka berkata; \"Adapun kita dilahirkan dalam kesyirikan akan tetapi kita beriman kepada Allah dan Rasul-Nya, mungkin mereka adalah para anak cucu kita.\" Lantas peristiwa tersebut sampai kepada Nabi shallallahu 'alaihi wasallam, lalu beliau bersabda: \"Mereka itu adalah orang-orang yang tidak pernah bertathayur (menganggap sial sesuatu hingga tidak jadi beramal), tidak pernah meminta untuk diruqyah dan tidak mau menggunakan Kay (pengobatan dengan besi panas), dan kepada Tuhan merekalah mereka bertawakkal.\" Lalu Ukasyah bin Mihshan berdiri dan berkata; \"Apakah aku termasuk di antara mereka, wahai Rasulullah?\" Beliau menjawab: \"Ya.\" Kemudian yang lainnya berdiri lalu bertanya; \"Apakah aku juga termasuk di antara mereka?\" Beliau menjawab: \"Ukasyah telah mendahuluimu dalam hal ini.\""},"5007":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا يُونُسُ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا عَدْوَى وَلَا طِيَرَةَ وَالشُّؤْمُ فِي ثَلَاثٍ فِي الْمَرْأَةِ وَالدَّارِ وَالدَّابَّةِ","id":"Telah menceritakan kepadaku [Abdullah bin Muhammad] telah menceritakan kepada kami [Utsman bin Umar] telah menceritakan kepada kami [Yunus] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar] radliallahu 'anhuma bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada 'adwa (keyakinan adanya penularan penyakit) tidak ada thiyarah (menganggap sial sesuatu hingga tidak jadi beramal), dan adakalanya kesialan itu terdapat pada tiga hal, yaitu; isteri, tempat tinggal dan kendaraan.\""},"5008":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّ أَبَا هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا طِيَرَةَ وَخَيْرُهَا الْفَأْلُ قَالُوا وَمَا الْفَأْلُ قَالَ الْكَلِمَةُ الصَّالِحَةُ يَسْمَعُهَا أَحَدُكُمْ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku ['Ubaidullah bin Abdullah bin 'Utbah] bahwa [Abu Hurairah] berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada thiyarah (menganggap sial pada sesuatu sehingga tidak jadi beramal) dan yang baik adalah Alfa`lu.\" Para sahabat bertanya; \"wahai Rasulullah apakah Al fa`lu itu?\" beliau menjawab: \"Yaitu kalimat baik yang di dengar oleh salah satu dari kalian.\""},"5009":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ أَخْبَرَنَا هِشَامٌ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا طِيَرَةَ وَخَيْرُهَا الْفَأْلُ قَالَ وَمَا الْفَأْلُ يَا رَسُولَ اللَّهِ قَالَ الْكَلِمَةُ الصَّالِحَةُ يَسْمَعُهَا أَحَدُكُمْ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] telah mengabarkan kepada kami [Hisyam] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Abu Hurairah] radliallahu 'anhu dia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak ada thiyarah (menganggap sial pada sesuatu sehingga tidak jadi beramal) dan yang baik adalah al fa'lu.\" Abu Hurairah bertanya; \"Apakah al fa'lu itu wahai Rasulullah?\" beliau menjawab: \"Kalimat yang baik yang di dengar oleh salah seorang dari kalian.\""},"5010":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا عَدْوَى وَلَا طِيَرَةَ وَيُعْجِبُنِي الْفَأْلُ الصَّالِحُ الْكَلِمَةُ الْحَسَنَةُ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hisyam] telah menceritakan kepada kami [Qatadah] dari [Anas] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Tidak ada 'adwa (keyakinan adanya penularan penyakit), tidak ada thiyarah (menganggap sial sesuatu hingga tidak jadi beramal), dan yang menakjubkanku adalah al fa'lu yang baik yaitu kalimat yang baik.\""},"5011":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْحَكَمِ حَدَّثَنَا النَّضْرُ أَخْبَرَنَا إِسْرَائِيلُ أَخْبَرَنَا أَبُو حَصِينٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا عَدْوَى وَلَا طِيَرَةَ وَلَا هَامَةَ وَلَا صَفَرَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Hakam] telah menceritakan kepada kami [An Nadlr] telah mengabarkan kepada kami [Isra`il] telah mengabarkan kepada kami [Abu Hashin] dari [Abu Shalih] dari [Abu Hurairah] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Tidak ada 'adwa (keyakinan adanya penularan penyakit), tidak ada thiyarah (menganggap sial sesuatu hingga tidak jadi beramal), tidak ada hammah (keyakinan jahiliyah tentang rengkarnasi) dan tidak pula shafar (menganggap bulan shafar sebagai bulan haram atau keramat).\""},"5012":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ حَدَّثَنَا اللَّيْثُ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ خَالِدٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى فِي امْرَأَتَيْنِ مِنْ هُذَيْلٍ اقْتَتَلَتَا فَرَمَتْ إِحْدَاهُمَا الْأُخْرَى بِحَجَرٍ فَأَصَابَ بَطْنَهَا وَهِيَ حَامِلٌ فَقَتَلَتْ وَلَدَهَا الَّذِي فِي بَطْنِهَا فَاخْتَصَمُوا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَضَى أَنَّ دِيَةَ مَا فِي بَطْنِهَا غُرَّةٌ عَبْدٌ أَوْ أَمَةٌ فَقَالَ وَلِيُّ الْمَرْأَةِ الَّتِي غَرِمَتْ كَيْفَ أَغْرَمُ يَا رَسُولَ اللَّهِ مَنْ لَا شَرِبَ وَلَا أَكَلَ وَلَا نَطَقَ وَلَا اسْتَهَلَّ فَمِثْلُ ذَلِكَ يُطَلُّ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا هَذَا مِنْ إِخْوَانِ الْكُهَّانِ","id":"Telah menceritakan kepada kami [Sa'id bin 'Ufair] telah menceritakan kepada kami [Al Laits] dia berkata; telah menceritakan kepadaku [Abdurrahman bin Khalid] dari [Ibnu Syihab] dari [Abu Salamah] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam pernah memutuskan perkara antara dua wanita dari Bani Hudzail yang sedang berkelahi, salah seorang melempar lawannya dengan batu dan mengenai perutnya padahal ia sedang hamil, hingga menyebabkan kematian anak yang dikandungnya. Lalu mereka mengadukan peristiwa itu kepada Nabi shallallahu 'alaihi wasallam. Beliau memutuskan hukuman (bagi wanita pembunuh) untuk membayar diyat janin dengan seorang hamba sahaya laki-laki atau perempuan, lantas wali wanita yang menanggung (diyat) berkata; \"Ya Rasulullah, bagaimana saya harus menanggung orang yang belum bisa makan dan minum, bahkan belum bisa berbicara ataupun menjerit sama sekali?, tidakkah hal itu dapat dikatagorikan sebagai kecelakaan yang tidak dapat dihindari?\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya perkara itu seperti perkara paranormal yang membacakan mantera-mantera.\""},"5013":{"ar":"حَدَّثَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ امْرَأَتَيْنِ رَمَتْ إِحْدَاهُمَا الْأُخْرَى بِحَجَرٍ فَطَرَحَتْ جَنِينَهَا فَقَضَى فِيهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِغُرَّةٍ عَبْدٍ أَوْ وَلِيدَةٍ وَعَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى فِي الْجَنِينِ يُقْتَلُ فِي بَطْنِ أُمِّهِ بِغُرَّةٍ عَبْدٍ أَوْ وَلِيدَةٍ فَقَالَ الَّذِي قُضِيَ عَلَيْهِ كَيْفَ أَغْرَمُ مَا لَا أَكَلَ وَلَا شَرِبَ وَلَا نَطَقَ وَلَا اسْتَهَلَّ وَمِثْلُ ذَلِكَ يُطَلُّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا هَذَا مِنْ إِخْوَانِ الْكُهَّانِ","id":"Telah menceritakan kepada kami [Qutaibah] dari [Malik] dari [Ibnu Syihab] dari [Abu Salamah] dari [Abu Hurairah] radliallahu 'anhu bahwa salah seorang dari dua orang wanita melempar lawannya dengan batu hingga menyebabkan janinnya gugur, lalu Nabi shallallahu 'alaihi wasallam memutuskan untuk membayar diyat janin dengan seorang budak baik laki-laki maupun perempuan.\" Dan dari [Ibnu Syihab] dari [Sa'id bin Musayyab] bahwa Rasulullah shallallahu 'alaihi wasallam pernah memutuskan mengenai janin yang terbunuh di perut ibunya dengan (membayar diyat) seorang hamba sahaya baik laki-laki maupun perempuan. Lantas orang yang diputusi hukuman berkata; \"Bagaimana saya harus menanggung orang yang belum bisa makan dan minum, bahkan belum bisa berbicara ataupun menjerit sama sekali?, tidakkah hal itu dapat dikatagorikan sebagai kecelakaan yang tidak dapat di hindari?\" maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya perkara itu seperti perkara paranormal (yang membacakan mantera-mantera).\""},"5014":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ عَنْ أَبِي مَسْعُودٍ قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ث��مَنِ الْكَلْبِ وَمَهْرِ الْبَغِيِّ وَحُلْوَانِ الْكَاهِنِ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Az Zuhri] dari [Abu Bakar bin Abdurrahman bin Al Harits] dari [Abu Mas'ud] dia berkata; Nabi shallallahu 'alaihi wasallam melarang dari upah hasil penjualan anjing, upah pelacuran dan upah dari perdukunan.\""},"5015":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا هِشَامُ بْنُ يُوسُفَ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ يَحْيَى بْنِ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْسَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَاسٌ عَنْ الْكُهَّانِ فَقَالَ لَيْسَ بِشَيْءٍ فَقَالُوا يَا رَسُولَ اللَّهِ إِنَّهُمْ يُحَدِّثُونَا أَحْيَانًا بِشَيْءٍ فَيَكُونُ حَقًّا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تِلْكَ الْكَلِمَةُ مِنْ الْحَقِّ يَخْطَفُهَا مِنْ الْجِنِّيِّ فَيَقُرُّهَا فِي أُذُنِ وَلِيِّهِ فَيَخْلِطُونَ مَعَهَا مِائَةَ كَذْبَةٍقَالَ عَلِيٌّ قَالَ عَبْدُ الرَّزَّاقِ مُرْسَلٌ الْكَلِمَةُ مِنْ الْحَقِّ ثُمَّ بَلَغَنِي أَنَّهُ أَسْنَدَهُ بَعْدَهُ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Hisyam bin Yusuf] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Yahya bin 'Urwah bin Az Zubair] dari [Urwah bin Az Zubair] dari ['Aisyah] radliallahu 'anha dia berkata; beberapa orang bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai paranormal, lalu beliau menjawab: \"\"Mereka (para dukun) bukanlah apa-apa.\" Mereka berkata; \"Wahai Rasulullah! Terkadang apa yang mereka ceritakan adalah benar.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perkataan yang nyata (benar) itu adalah perkataan yang dicuri oleh jin, kemudian ia menempatkannya di telinga walinya lalu mereka mencampur adukkan bersama kebenaran itu dengan seratus kedustaan.\" Ali berkata; Abdurrazaq berkata; lafazh \"Perkataan yang nyata (benar) …\" adalah mursal, setelah itu sampai kepadaku bahwa lafazh tersebut telah di musnadkan.\""},"5016":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا عِيسَى بْنُ يُونُسَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْسَحَرَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ مِنْ بَنِي زُرَيْقٍ يُقَالُ لَهُ لَبِيدُ بْنُ الْأَعْصَمِ حَتَّى كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُخَيَّلُ إِلَيْهِ أَنَّهُ كَانَ يَفْعَلُ الشَّيْءَ وَمَا فَعَلَهُ حَتَّى إِذَا كَانَ ذَاتَ يَوْمٍ أَوْ ذَاتَ لَيْلَةٍ وَ��ُوَ عِنْدِي لَكِنَّهُ دَعَا وَدَعَا ثُمَّ قَالَ يَا عَائِشَةُ أَشَعَرْتِ أَنَّ اللَّهَ أَفْتَانِي فِيمَا اسْتَفْتَيْتُهُ فِيهِ أَتَانِي رَجُلَانِ فَقَعَدَ أَحَدُهُمَا عِنْدَ رَأْسِي وَالْآخَرُ عِنْدَ رِجْلَيَّ فَقَالَ أَحَدُهُمَا لِصَاحِبِهِ مَا وَجَعُ الرَّجُلِ فَقَالَ مَطْبُوبٌ قَالَ مَنْ طَبَّهُ قَالَ لَبِيدُ بْنُ الْأَعْصَمِ قَالَ فِي أَيِّ شَيْءٍ قَالَ فِي مُشْطٍ وَمُشَاطَةٍ وَجُفِّ طَلْعِ نَخْلَةٍ ذَكَرٍ قَالَ وَأَيْنَ هُوَ قَالَ فِي بِئْرِ ذَرْوَانَ فَأَتَاهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نَاسٍ مِنْ أَصْحَابِهِ فَجَاءَ فَقَالَ يَا عَائِشَةُ كَأَنَّ مَاءَهَا نُقَاعَةُ الْحِنَّاءِ أَوْ كَأَنَّ رُءُوسَ نَخْلِهَا رُءُوسُ الشَّيَاطِينِ قُلْتُ يَا رَسُولَ اللَّهِ أَفَلَا اسْتَخْرَجْتَهُ قَالَ قَدْ عَافَانِي اللَّهُ فَكَرِهْتُ أَنْ أُثَوِّرَ عَلَى النَّاسِ فِيهِ شَرًّا فَأَمَرَ بِهَا فَدُفِنَتْتَابَعَهُ أَبُو أُسَامَةَ وَأَبُو ضَمْرَةَ وَابْنُ أَبِي الزِّنَادِ عَنْ هِشَامٍ وَقَالَ اللَّيْثُ وَابْنُ عُيَيْنَةَ عَنْ هِشَامٍ فِي مُشْطٍ وَمُشَاقَةٍ يُقَالُ الْمُشَاطَةُ مَا يَخْرُجُ مِنْ الشَّعَرِ إِذَا مُشِطَ وَالْمُشَاقَةُ مِنْ مُشَاقَةِ الْكَتَّانِ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] telah mengabarkan kepada kami [Isa bin Yunus] dari [Hisyam] dari [ayahnya] dari ['Aisyah] radliallahu 'anha dia berkata; \"Seorang Yahudi dari Bani Zuraiq yang bernama Labid bin Al A'sham telah menyihir Rasulullah shallallahu 'alaihi wasallam, sehingga Rasulullah shallallahu 'alaihi wasallam pun dibuat seakan-akan telah melakukan sesuatu pekerjaan yang beliau tidak kerjakan. Sampai disuatu hari -atau suatu malam- beliau berada di sampingku namun beliau tetap berdo'a dan berdo'a, kemudian beliau bersabda: \"Wahai Aisyah, apakah kamu telah merasakan bahwa Allah telah memberikan fatwa (menghukumi) dengan apa yang telah aku fatwakan (hukumi)? Dua orang laki-laki telah datang kepadaku, lalu salah seorang dari keduanya duduk di atas kepalaku dan satunya lagi di kakiku. Kemudian salah seorang berkata kepada yang satunya; \"Menderita sakit apakah laki-laki ini?\" temannya menjawab; \"Terkena sihir.' salah satu mala'ikat tersebut bertanya; \"Siapakah yang menyihirnya?\" temannya menjawab; \"Labid bin Al A'sham.\" Malaikat yang satu bertanya; \"Dengan benda apakah dia menyihir?\" temannya menjawab; \"Dengan rambut yang terjatuh ketika disisir dan seludang mayang kurma.\" Salah satu malaikat bertanya; \"Di manakah benda itu diletakkan?\" temannya menjawab; \"Di dalam sumur Dzarwan.\" Kemudian Rasulullah shallallahu 'alaihi wasallam mendatanginya bersama beberapa orang sahabatnya, lalu bersabda: \"Wahai Aisyah! seakan-akan airnya berubah bagaikan rendaman pohon inai atau seakan-akan pohon kurmanya bagaikan kepala syetan.\" Aku bertanya; \"Wahai Rasulullah, tidakkah anda mengeluarkannya?\" beliau menjawab: \"Tidak, sesungguhnya Allah telah menyembuhkanku dan aku hanya tidak suka memberikan kesan buruk kepada orang lain dari peristiwa itu.\" Kemudian beliau memerintahkan seseorang membawanya (barang yang dipakai untuk menyihir) lalu menguburnya.\" Hadits ini juga diperkuat oleh riwayat [Abu Usamah] dan [Abu Dlamrah] serta [Ibnu Abu Az Zinad] dari [Hisyam]. [Al Laits] dan [Ibnu 'Uyainah] mengatakan dari [Hisyam] mengenai lafazh \"Musth (sisir) \" dan \"Musyaqah (helai rambut yang jatuh karena disisir) dikatakana pula \"Al Musyathah yaitu helai rambut yang jatuh apabila disisir.\" Sedangkan Musyaqqah ialah rambut yang melekat pada sisir tatkala menyisir.\""},"5017":{"ar":"حَدَّثَنِي عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي سُلَيْمَانُ عَنْ ثَوْرِ بْنِ زَيْدٍ عَنْ أَبِي الْغَيْثِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اجْتَنِبُوا الْمُوبِقَاتِ الشِّرْكُ بِاللَّهِ وَالسِّحْرُ","id":"Telah menceritakan kepadaku [Abdul Aziz bin Abdullah] dia berkata; telah menceritakan kepadaku [Sulaiman] dari [Tsaur bin Zaid] dari [Abu Al Ghaits] dari [Abu Hurairah] radliallahu 'anhu bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jauhilah hal-hal yang membinasakan yaitu menyekutukan Allah dan sihr.\""},"5018":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ قَالَ سَمِعْتُ ابْنَ عُيَيْنَةَ يَقُولُ أَوَّلُ مَنْ حَدَّثَنَا بِهِ ابْنُ جُرَيْجٍ يَقُولُ حَدَّثَنِي آلُ عُرْوَةَ عَنْ عُرْوَةَ فَسَأَلْتُ هِشَامًا عَنْهُ فَحَدَّثَنَا عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُحِرَ حَتَّى كَانَ يَرَى أَنَّهُ يَأْتِي النِّسَاءَ وَلَا يَأْتِيهِنَّ قَالَ سُفْيَانُ وَهَذَا أَشَدُّ مَا يَكُونُ مِنْ السِّحْرِ إِذَا كَانَ كَذَا فَقَالَ يَا عَائِشَةُ أَعَلِمْتِ أَنَّ اللَّهَ قَدْ أَفْتَانِي فِيمَا اسْتَفْتَيْتُهُ فِيهِ أَتَانِي رَجُلَانِ فَقَعَدَ أَحَدُهُمَا عِنْدَ رَأْسِي وَالْآخَرُ عِنْدَ رِجْلَيَّ فَقَالَ الَّذِي عِنْدَ رَأْسِي لِلْآخَرِ مَا بَالُ الرَّجُلِ قَالَ مَطْبُوبٌ قَالَ وَمَنْ طَبَّهُ قَالَ لَبِيدُ بْنُ أَعْصَمَ رَجُلٌ مِنْ بَنِي زُرَيْقٍ حَلِيفٌ لِيَهُودَ كَانَ مُنَافِقًا قَالَ وَفِيمَ قَالَ فِي مُشْطٍ وَمُشَاقَةٍ قَالَ وَأَيْنَ قَالَ فِي جُفِّ طَلْعَةٍ ذَكَرٍ تَحْتَ رَاعُوفَةٍ فِي بِئْرِ ذَرْوَانَ قَالَتْ فَأَتَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبِئْرَ حَتَّى اسْتَخْرَجَهُ فَقَالَ هَذِهِ الْبِئْرُ الَّتِي أُرِيتُهَا وَكَأَنَّ مَاءَهَا نُقَاعَةُ الْحِنَّاءِ وَكَأَنَّ نَخْلَهَا رُءُوسُ الشَّيَاطِينِ قَالَ فَاسْتُخْرِجَ قَالَتْ فَقُلْتُ أَفَلَا أَيْ تَنَشَّرْتَ فَقَالَ أَمَّا اللَّهُ فَقَدْ شَفَانِي وَأَكْرَهُ أَنْ أُثِيرَ عَلَى أَحَدٍ مِنْ النَّاسِ شَرًّا","id":"Telah menceritakan kepadaku [Abdullah bin Muhammad] dia berkata; saya mendengar [Ibnu 'Uyainah] berkata; orang yang pertama kali menceritakan kepada kami adalah [Ibnu Juraij], dia berkata; telah menceritakan kepadaku [keluarga 'Urwah] dari ['Urwah], lalu aku bertanya kepada [Hisyam] tentang haditsnya, maka dia menceritakannya kepada kami dari [Ayahnya] dari ['Aisyah] radliallahu 'anha dia berkata; bahwa Rasulullah shallallahu 'alaihi wasallam pernah disihir hingga seakan-akan beliau telah mendatangi para isterinya, padahal beliau tidak mendatanginya, -Sufyan mengatakan; \"Bahwa keadaan seperti ini termasuk sihir yang paling berat- kemudian beliau bersabda: \"Wahai Aisyah, apakah kamu mengetahui bahwa Allah telah memberikan fatwa (menghukumi) dengan apa yang telah aku fatwakan (hukumi)? Dua orang laki-laki telah datang kepadaku, lalu salah seorang dari keduanya duduk di atas kepalaku dan satunya lagi di kakiku. Kemudian seorang yang berada di kepalaku berkata kepada yang satunya; \"Kenapa laki-laki ini?\" temannya menjawab; \"Terkena sihir.' salah seorang darinya bertanya; \"Siapakah yang menyihirnya?\" temannya menjawab; \"Lubid bin Al A'sham, laki-laki dari Bani Zuraiq, seorang munafik dan menjadi sekutu orang-orang Yahudi.\" Salah seorang darinya bertanya; \"Dengan benda apakah dia menyihir?\" temannya menjawab; \"Dengan rambut yang terjatuh ketika disisir.\" Salah seorang darinya bertanya; \"Di manakah benda itu diletakkan?\" temannya menjawab; \"Di mayang kurma yang diletakkan di bawah batu dalam sumur Dzarwan.\" Aisyah berkata; \"Kemudian Rasulullah shallallahu 'alaihi wasallam mendatangi sumur tersebut hingga beliau dapat mengeluarkan barang tersebut, lalu beliau bersabda: \"Ini adalah sumur yang diperlihatkan padaku, seakan-akan airnya berubah bagaikan rendaman pohon inai dan seakan-akan pohon kurmanya bagaikan kepala syetan.\" Abu Hisyam berkata; \"apakah beliau meminta barangnya dikeluarkan?\" Aisyah berkata; Lalu aku bertanya; \"Apakah anda tidak meruqyahnya?\" beliau bersabda: \"Tidak, sesungguhnya Allah telah menyembuhkanku dan aku hanya tidak suka memberikan kesan buruk kepada orang lain dari peristiwa itu.\""},"5019":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْسُحِرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِنَّهُ لَيُخَيَّلُ إِلَيْهِ أَنَّهُ يَفْعَلُ الشَّيْءَ وَمَا فَعَلَهُ حَتَّى إِذَا كَانَ ذَاتَ يَوْمٍ وَهُوَ عِنْدِي دَعَا اللَّهَ وَدَعَاهُ ثُمَّ قَالَ أَشَعَرْتِ يَا عَائِشَةُ أَنَّ اللَّهَ قَدْ أَفْتَانِي فِيمَا اسْتَفْتَيْتُهُ فِيهِ قُلْتُ وَمَا ذَاكَ يَا رَسُولَ اللَّهِ قَالَ جَاءَنِي رَجُلَانِ فَجَلَسَ أَحَدُهُمَا عِنْدَ رَأْسِي وَالْآخَرُ عِنْدَ رِجْلَيَّ ثُمَّ قَالَ أَحَدُهُمَا لِصَاحِبِهِ مَا وَجَعُ الرَّجُلِ قَالَ مَطْبُوبٌ قَالَ وَمَنْ طَبَّهُ قَالَ لَبِيدُ بْنُ الْأَعْصَمِ الْيَهُودِيُّ مِنْ بَنِي زُرَيْقٍ قَالَ فِيمَا ذَا قَالَ فِي مُشْطٍ وَمُشَاطَةٍ وَجُفِّ طَلْعَةٍ ذَكَرٍ قَالَ فَأَيْنَ هُوَ قَالَ فِي بِئْرِ ذِي أَرْوَانَ قَالَ فَذَهَبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أُنَاسٍ مِنْ أَصْحَابِهِ إِلَى الْبِئْرِ فَنَظَرَ إِلَيْهَا وَعَلَيْهَا نَخْلٌ ثُمَّ رَجَعَ إِلَى عَائِشَةَ فَقَالَ وَاللَّهِ لَكَأَنَّ مَاءَهَا نُقَاعَةُ الْحِنَّاءِ وَلَكَأَنَّ نَخْلَهَا رُءُوسُ الشَّيَاطِينِ قُلْتُ يَا رَسُولَ اللَّهِ أَفَأَخْرَجْتَهُ قَالَ لَا أَمَّا أَنَا فَقَدْ عَافَانِيَ اللَّهُ وَشَفَانِي وَخَشِيتُ أَنْ أُثَوِّرَ عَلَى النَّاسِ مِنْهُ شَرًّا وَأَمَرَ بِهَا فَدُفِنَتْ","id":"Telah menceritakan kepada kami ['Ubaid bin Isma'il] telah menceritakan kepada kami [Abu Usamah] dari [Hisyam] dari [Ayahnya] dari [Aisyah] dia berkata; Nabi shallallahu 'alaihi wasallam disihir hingga seakan-akan beliau mengangan-angan telah berbuat sesuatu, padahal beliau tidak melakukannya, hingga ketika beliau berada di sampingku, beliau berdo'a kepada Allah dan selalu berdo'a, kemudian beliau bersabda: \"Wahai Aisyah, apakah kamu telah merasakan bahwa Allah telah memberikan fatwa (menghukumi) dengan apa yang telah aku fatwakan (hukumi)? Jawabku; \"Apa itu wahai Rasulullah?\" Beliau bersabda: \"Dua orang laki-laki telah datang kepadaku, lalu salah seorang dari keduanya duduk di atas kepalaku dan satunya lagi di kakiku. Kemudian salah seorang berkata kepada yang satunya; \"Menderita sakit apakah laki-laki ini?\" temannya menjawab; \"Terkena sihir.' salah seorang darinya bertanya; \"Siapakah yang menyihirnya?\" temannya menjawab; \"Lubid bin Al A'sham seorang Yahudi dari Bani Zuraiq.\" Salah satunya bertanya; \"Dengan benda apakah dia menyihir?\" temannya menjawab; \"Dengan rambut yang terjatuh ketika disisir dan seludang mayang kurma.\" Salah seorang darinya bertanya; \"Di manakah benda itu di letakkan?\" temannya menjawab; \"Di dalam sumur Dzi Arwan.\" Kemudian Rasulullah shallallahu 'alaihi wasallam mendatangi sumur tersebut bersama beberapa orang sahabatnya, beliau pun melihat ke dalam ternyata di dalamnya terdapat pohon kurma, lalu beliau kembali menemui 'Aisyah bersabda: \"Wahai Aisyah! seakan-akan airnya berubah bagaikan rendaman pohon inai atau seakan-akan pohon kurmanya bagaikan kepala syetan.\" Aku bertanya; \"Wahai Rasulullah, tidakkah anda mengeluarkannya?\" beliau menjawab: \"Tidak, sesungguhnya Allah telah menyembuhkanku dan aku hanya tidak suka memberikan kesan buruk kepada orang lain dari peristiwa itu.\" Kemudian beliau memerintahkan seseorang membawanya (barang yang dipakai untuk menyihir) lalu menguburnya.\""},"5020":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّهُ قَدِمَ رَجُلَانِ مِنْ الْمَشْرِقِ فَخَطَبَا فَعَجِبَ النَّاسُ لِبَيَانِهِمَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ الْبَيَانِ لَسِحْرًا أَوْ إِنَّ بَعْضَ الْبَيَانِ لَسِحْرٌ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Zaid bin Aslam] dari [Abdullah bin Umar] radliallahu 'anhuma bahwa dua orang dari penduduk Masyriq datang kepadanya, lalu keduanya berkhutbah hingga orang-orang heran dengan penjelasannya, lantas Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya dalam penjelasan (bayan) itu mengandung sihir, atau sesungguhnya sebagian bayan (penjelasan) itu mengandung sihir.\""},"5021":{"ar":"حَدَّثَنَا عَلِيٌّ حَدَّثَنَا مَرْوَانُ أَخْبَرَنَا هَاشِمٌ أَخْبَرَنَا عَامِرُ بْنُ سَعْدٍ عَنْ أَبِيهِ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اصْطَبَحَ كُلَّ يَوْمٍ تَمَرَاتٍ عَجْوَةً لَمْ يَضُرَّهُ سُمٌّ وَلَا سِحْرٌ ذَلِكَ الْيَوْمَ إِلَى اللَّيْلِ وَقَالَ غَيْرُهُ سَبْعَ تَمَرَاتٍ","id":"Telah menceritakan kepada kami [Ali] telah menceritakan kepada kami [Marwan] telah mengabarkan kepada kami [Hasyim] telah mengabarkan kepada kami ['Amir bin Sa'd] dari [Ayahnya] radliallahu 'anhu dia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa di pagi hari makan beberapa biji kurma 'ajwah setiap harinya, maka tidak akan membahayakan terhadap dirinya baik itu racun maupun sihir pada hari itu hingga malam hari.\" Dan yang lain mengatakan tujuh biji kurma.\""},"5022":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ مَنْصُورٍ أَخْبَرَنَا أَبُو أُسَامَةَ حَدَّثَنَا هَاشِمُ بْنُ هَاشِمٍ قَالَ سَمِعْتُ عَامِرَ بْنَ سَعْدٍ سَمِعْتُ سَعْدًا رَضِيَ اللَّهُ عَنْهُ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ تَصَبَّحَ سَبْعَ تَمَرَاتٍ عَجْوَةً لَمْ يَضُرَّهُ ذَلِكَ الْيَوْمَ سُمٌّ وَلَا سِحْرٌ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] telah mengabarkan kepada kami [Abu Usamah] telah menceritakan kepada kami [Hasyim bin Hasyim] dia berkata; saya mendengar ['Amir bin Sa'd] saya mendengar [Sa'd] radliallahu 'anhu berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa di pagi hari makan tujuh biji kurma 'ajwah setiap harinya, maka tidak akan membahayakan terhadap dirinya baik itu racun dan juga sihir pada hari itu.\""},"5023":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا هِشَامُ بْنُ يُوسُفَ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا عَدْوَى وَلَا صَفَرَ وَلَا هَامَةَ فَقَالَ أَعْرَابِيٌّ يَا رَسُولَ اللَّهِ فَمَا بَالُ الْإِبِلِ تَكُونُ فِي الرَّمْلِ كَأَنَّهَا الظِّبَاءُ فَيُخَالِطُهَا الْبَعِيرُ الْأَجْرَبُ فَيُجْرِبُهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَنْ أَعْدَى الْأَوَّلَوَعَنْ أَبِي سَلَمَةَ سَمِعَ أَبَا هُرَيْرَةَ بَعْدُ يَقُولُ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُورِدَنَّ مُمْرِضٌ عَلَى مُصِحٍّ وَأَنْكَرَ أَبُو هُرَيْرَةَ حَدِيثَ الْأَوَّلِ قُلْنَا أَلَمْ تُحَدِّثْ أَنَّهُ لَا عَدْوَى فَرَطَنَ بِالْحَبَشِيَّةِ قَالَ أَبُو سَلَمَةَ فَمَا رَأَيْتُهُ نَسِيَ حَدِيثًا غَيْرَهُ","id":"Telah menceritakan kepadaku [Abdullah bin Muhammad] telah menceritakan kepada kami [Hisyam bin Yusuf] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] radliallahu 'anhu dia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak ada 'adwa (keyakinan adanya penularan penyakit) tidak ada shafar (menganggap bulan shafar sebagai bulan haram atau keramat) dan tidak pula hammah (keyakinan jahiliyah tentang rengkarnasi).\" Lalu seorang Arab badui berkata; \"Wahai Rasulullah, lalu bagimana dengan unta yang ada di padang pasir, seakan-akan (bersih) bagaikan gerombolan kijang lalu datang padanya unta berkudis dan bercampur baur dengannya sehingga ia menularinya?\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Lalu siapakah yang menulari yang pertama?\" Setelah itu Abu Salamah mendengar Abu Hurairah mengatakan; Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah (unta) yang sakit dicampurbaurkan dengan yang sehat.\" -sepertinya Abu Hurairah mengingkari hadits yang pertama- maka kami bertanya; \"Tidakkah anda pernah menceritakan bahwa tidak ada 'adwa (keyakinan adanya penularan penyakit).\" Lalu dia bicara dengan bahasa Habasyah, maka aku tidak pernah melihatnya lupa terhadap hadits selain hadits di atas.\""},"5024":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ قَالَ حَدَّثَنِي ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ وَحَمْزَةُ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا عَدْوَى وَلَا طِيَرَةَ إِنَّمَا الشُّؤْمُ فِي ثَلَاثٍ فِي الْفَرَسِ وَالْمَرْأَةِ وَالدَّارِ","id":"Telah menceritaka kepada kami [Sa'id bin 'Ufair] dia berkata; telah menceritaka kepadaku [Ibnu Wahb] dari [Yunus] dari [Ibnu Syihab] dia berkata; telah mengabarkan kepadaku [Salim bin Abdullah] dan [Hamzah] bahwa [Abdullah bin Umar] radliallahu 'anhuma berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada 'adwa (keyakinan adanya penularan penyakit) tidak ada thiyarah (menganggap sial sesuatu hingga tidak jadi beramal), dan adakalanya kesialan itu terdapat pada tiga hal, yaitu; kendaraan, isteri dan tempat tinggal.\""},"5025":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا عَدْوَى قَالَ أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ سَمِعْتُ أَبَا هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُورِدُوا الْمُمْرِضَ عَلَى الْمُصِحِّ وَعَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سِنَانُ بْنُ أَبِي سِنَانٍ الدُّؤَلِيُّ أَنَّ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا عَدْوَى فَقَامَ أَعْرَابِيٌّ فَقَالَ أَرَأَيْتَ الْإِبِلَ تَكُونُ فِي الرِّمَالِ أَمْثَالَ الظِّبَاءِ فَيَأْتِيهَا الْبَعِيرُ الْأَجْرَبُ فَتَجْرَبُ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَنْ أَعْدَى الْأَوَّلَ","id":"Telah menceritaka kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; telah menceritaka kepadaku [Abu Salamah bin Abdurrahman] bahwa [Abu Hurairah] berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada 'adwa (keyakinan adanya penularan penyakit).\" Abu Salamah bin Abdurrahman berkata; saya mendengar Abu Hurairah dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Janganlah kalian mencampurkan antara yang sakit dengan yang sehat.\" Dan dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku [Sinan bin Abu Sinan Ad Du`ali] bahwa [Abu Hurairah] radliallahu 'anhu berkata; sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada 'adwa (keyakinan adanya penularan penyakit) \" maka seorang Arab badui berdiri dan berkata; \"Lalu bagimana dengan unta yang ada di padang pasir, seakan-akan (bersih) bagaikan gerombolan kijang lalu datang padanya unta berkudis dan bercampur baur dengannya sehingga ia menularinya?\" Nabi shallallahu 'alaihi wasallam bersabda: \"Lalu siapakah yang menulari yang pertama.\""},"5026":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا عَدْوَى وَلَا طِيَرَةَ وَيُعْجِبُنِي الْفَأْلُ قَالُوا وَمَا الْفَأْلُ قَالَ كَلِمَةٌ طَيِّبَةٌ","id":"Telah menceritaka kepadaku [Muhammad bin Basyar] telah menceritaka kepada kami [Muhammad bin Ja'far] telah menceritaka kepada kami [Syu'bah] dia berkata; saya mendengar [Qatadah] dari [Anas bin Malik] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Tidak ada 'adwa (keyakinan adanya penularan penyakit) dan tidak pula thiyarah (menganggap sial pada sesuatu sehingga tidak jadi beramal) dan yang menakjubkanku adalah al fa'lu.\" Mereka bertanya; \"Apakah al fa'lu itu?\" beliau menjawab: \"Kalimat yang baik.\""},"5027":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ أَنَّهُ قَالَلَمَّا فُتِحَتْ خَيْبَرُ أُهْدِيَتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَاةٌ فِيهَا سَمٌّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اجْمَعُوا لِي مَنْ كَانَ هَا هُنَا مِنْ الْيَهُودِ فَجُمِعُوا لَهُ فَقَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي سَائِلُكُمْ عَنْ شَيْءٍ فَهَلْ أَنْتُمْ صَادِقِيَّ عَنْهُ فَقَالُوا نَعَمْ يَا أَبَا الْقَاسِمِ فَقَالَ لَهُمْ رَسُولُ الل��َهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَبُوكُمْ قَالُوا أَبُونَا فُلَانٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَذَبْتُمْ بَلْ أَبُوكُمْ فُلَانٌ فَقَالُوا صَدَقْتَ وَبَرِرْتَ فَقَالَ هَلْ أَنْتُمْ صَادِقِيَّ عَنْ شَيْءٍ إِنْ سَأَلْتُكُمْ عَنْهُ فَقَالُوا نَعَمْ يَا أَبَا الْقَاسِمِ وَإِنْ كَذَبْنَاكَ عَرَفْتَ كَذِبَنَا كَمَا عَرَفْتَهُ فِي أَبِينَا قَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَهْلُ النَّارِ فَقَالُوا نَكُونُ فِيهَا يَسِيرًا ثُمَّ تَخْلُفُونَنَا فِيهَا فَقَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اخْسَئُوا فِيهَا وَاللَّهِ لَا نَخْلُفُكُمْ فِيهَا أَبَدًا ثُمَّ قَالَ لَهُمْ فَهَلْ أَنْتُمْ صَادِقِيَّ عَنْ شَيْءٍ إِنْ سَأَلْتُكُمْ عَنْهُ قَالُوا نَعَمْ فَقَالَ هَلْ جَعَلْتُمْ فِي هَذِهِ الشَّاةِ سَمًّا فَقَالُوا نَعَمْ فَقَالَ مَا حَمَلَكُمْ عَلَى ذَلِكَ فَقَالُوا أَرَدْنَا إِنْ كُنْتَ كَذَّابًا نَسْتَرِيحُ مِنْكَ وَإِنْ كُنْتَ نَبِيًّا لَمْ يَضُرَّكَ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Sa'id bin Abu Sa'id] dari [Abu Haurairah] Bahwa ketika Khaibar ditaklukkan, Rasulullah shallallahu 'alaihi wasallam diberi hadiah seekor kambing beracun. Rasulullah shallallahu 'alaihi wasallam langsung bersabda: 'Tolong kumpulkanlah orang-orang Yahudi yang ada di sini.' Maka mereka dikumpulkanlah di hadapan beliau. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: 'Saya akan bertanya kepada kalian tentang sesuatu, apakah kalian akan menjawab dengan jujur? ', mereka menjawab; 'Ya, wahai Abu Qasim (Nabi Muhammad Shallallahu'alaihi wasallam).' Lalu Rasulullah shallallahu 'alaihi wasallam bertanya: 'Siapakah ayah kalian? ' Mereka menjawab; 'Ayah kami si fulan.' Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: 'Kalian bohong!, tetapi ayah kalian adalah si fulan.' Mereka menjawab; 'Baginda benar.' Lalu beliau bersabda kepada mereka: 'Apakah kalian akan jujur jika saya tanya tentang sesuatu? ' Mereka menjawab; 'Ya, dan jika kami berbohong niscaya baginda mengetahuinya, sebagaimana baginda mengetahui ayah-ayah kami.' Rasulullah shallallahu 'alaihi wasallam bertanya kepada mereka: 'Siapakah penghuni neraka? ' Mereka menjawab; 'Kami berada di dalamnya sebentar dan kemudian baginda menggantikan kami di dalamnya.' Maka Rasulullah shallallahu 'alaihi wasallam berkata kepada mereka: Terhinalah kalian di dalamnya, demi Allah subhanahu wata'ala kami tidak akan menggantikan kalian di dalamnya selamanya.\" Lalu Rasulullah shallallahu 'alaihi wasallam bertanya kepada mereka: \"Apakah kalian akan berkata jujur terhadap pertanyaan yang akan kutanyakan kepada kalian?\", mereka menjawab; Ya. Beliau bersabda: \"Apakah kalian membubuhi racun pada (daging) kambing tersebut?\" Mereka menjawab; \"Ya, \" beliau bertanya: \"Apa yang menyebabkan kalian berbuat demikian?\" Mereka menjawab; \"Kami ingin terbebas jika baginda seorang pembohong dan jika baginda benar seorang Nabi maka (racun itu) tidak bakalan mencelakai baginda.\""},"5028":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الْوَهَّابِ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ قَالَ سَمِعْتُ ذَكْوَانَ يُحَدِّثُ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ تَرَدَّى مِنْ جَبَلٍ فَقَتَلَ نَفْسَهُ فَهُوَ فِي نَارِ جَهَنَّمَ يَتَرَدَّى فِيهِ خَالِدًا مُخَلَّدًا فِيهَا أَبَدًا وَمَنْ تَحَسَّى سُمًّا فَقَتَلَ نَفْسَهُ فَسُمُّهُ فِي يَدِهِ يَتَحَسَّاهُ فِي نَارِ جَهَنَّمَ خَالِدًا مُخَلَّدًا فِيهَا أَبَدًا وَمَنْ قَتَلَ نَفْسَهُ بِحَدِيدَةٍ فَحَدِيدَتُهُ فِي يَدِهِ يَجَأُ بِهَا فِي بَطْنِهِ فِي نَارِ جَهَنَّمَ خَالِدًا مُخَلَّدًا فِيهَا أَبَدًا","id":"Telah menceritakan kepada kami [Abdullah bin Abdul Wahhab] telah menceritakan kepada kami [Khalid bin Al Harits] telah menceritakan kepada kami [Syu'bah] dari [Sulaiman] dia berkata; saya mendengar [Dzakwan] menceritakan dari [Abu Hurairah] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Barangsiapa menjatuhkan diri dari gunung, hingga membunuh jiwanya (bunuh diri), maka ia akan jatuh ke neraka jahannam, ia kekal serta abadi di dalamnya selama-lamanya. Barangsiapa menegak racun, hingga meninggal dunia, maka racun tersebut akan berada di tangannya, dan ia akan menegaknya di neraka jahannam, ia kekal serta abadi di dalamnya selama-lamanya. Dan barang siapa bunuh diri dengan (menusuk dirinya dengan) besi, maka besi itu akan ada di tangannya, dengannya ia akan menghujamkan ke perutnya di neraka jahannam, ia kekal dan abadi di dalamnya selama-lamanya.\""},"5029":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَامٍ حَدَّثَنَا أَحْمَدُ بْنُ بَشِيرٍ أَبُو بَكْرٍ أَخْبَرَنَا هَاشِمُ بْنُ هَاشِمٍ قَالَ أَخْبَرَنِي عَامِرُ بْنُ سَعْدٍ قَالَ سَمِعْتُ أَبِي يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ اصْطَبَحَ بِسَبْعِ تَمَرَاتِ عَجْوَةٍ لَمْ يَضُرَّهُ ذَلِكَ الْيَوْمَ سَمٌّ وَلَا سِحْرٌ","id":"Telah menceritakan kepada kami [Muhammad bin Salam] telah menceritakan kepada kami [Ahmad bin Basyir Abu Bakar] telah mengabarkan kepada kami [Hasyim bin Hasyim] dia berkata; telah mengabarkan kepadaku ['Amir bin Sa'd] dia berkata; saya mendengar [Ayahku] berkata; saya mendengar Rasulullah Shallallahu 'alai wasallam bersabda: \"Barangsiapa di pagi hari makan tujuh buah kurma 'ajwah, maka pada hari itu racun dan sihir tidak akan membahayakan dirinya.\""},"5030":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ أَبِي إِدْرِيسَ الْخَوْلَانِيِّ عَنْ أَبِي ثَعْلَبَةَ الْخُشَنِيِّ رَضِيَ اللَّهُ عَنْهُ قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَكْلِ كُلِّ ذِي نَابٍ مِنْ السَّبُعِقَالَ الزُّهْرِيُّ وَلَمْ أَسْمَعْهُ حَتَّى أَتَيْتُ الشَّأْمَ وَزَادَ اللَّيْثُ قَالَ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ وَسَأَلْتُهُ هَلْ نَتَوَضَّأُ أَوْ نَشْرَبُ أَلْبَانَ الْأُتُنِ أَوْ مَرَارَةَ السَّبُعِ أَوْ أَبْوَالَ الْإِبِلِ قَالَ قَدْ كَانَ الْمُسْلِمُونَ يَتَدَاوَوْنَ بِهَا فَلَا يَرَوْنَ بِذَلِكَ بَأْسًا فَأَمَّا أَلْبَانُ الْأُتُنِ فَقَدْ بَلَغَنَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ لُحُومِهَا وَلَمْ يَبْلُغْنَا عَنْ أَلْبَانِهَا أَمْرٌ وَلَا نَهْيٌ وَأَمَّا مَرَارَةُ السَّبُعِ قَالَ ابْنُ شِهَابٍ أَخْبَرَنِي أَبُو إِدْرِيسَ الْخَوْلَانِيُّ أَنَّ أَبَا ثَعْلَبَةَ الْخُشَنِيَّ أَخْبَرَهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ أَكْلِ كُلِّ ذِي نَابٍ مِنْ السَّبُعِ","id":"Telah menceritakan kepadaku [Abdullah bin Muhammad] telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Abu Idris Al Khaulani] dari [Abu Tsa'labah Al Khusyani] radliallahu 'anhu dia berkata; Nabi Shallallahu 'alai wasallam melarang makan setiap binatang buas yang bertaring.\" Az Zuhri mengatakan; \"Aku belum mendengar hadits tersebut hingga aku tiba di Syam, [Al Laits] menambahkan, katanya; telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab] perawi berkata; lalu aku bertanya kepada Ibnu Syihab; \"Apakah kita harus berwudlu' atau bolehkah kita meminum susu keledai betina atau memakan empedu binatang buas atau meminum kencing unta?\" dia menjawab; \"Orang-orang muslim banyak yang menjadikannya obat, dan mereka menganggap hal itu tidak mengapa, adapun susu keledai, maka telah sampai kepada kami bahwa Rasulullah shallallahu 'alaihi wasallam melarang memakan dagingnya sementara belum sampai kepada kami tentang larangan dan perintah meminum susunya, sedangkan empedu binatang buas. Ibnu Syihab mengatakan; telah mengabarkan kepadaku [Abu Idris Al Khaulani] bahwa [Abu Tsa'labah Al Khusani] telah mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam melarang makan setiap binatang buas yang bertaring.\""},"5031":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ عَنْ عُتْبَةَ بْنِ مُسْلِمٍ مَوْلَى بَنِي تَيْمٍ عَنْ عُبَيْدِ بْنِ حُنَيْنٍ مَوْلَى بَنِي زُرَيْقٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا وَقَعَ الذُّبَابُ فِي إِنَاءِ أَحَدِكُمْ فَلْيَغْمِسْهُ كُلَّهُ ثُمَّ لِيَطْرَحْهُ فَإِنَّ فِي أَحَدِ جَنَاحَيْهِ شِفَاءً وَفِي الْآخَرِ دَاءً","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Isma'il bin Ja'far] dari ['Utbah bin Muslim] mantan budak Bani Taim dari ['Ubaid bin Hunain] mantan budak Bani Zuraiq dari [Abu Hurairah] radliallahu 'anhu bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila seekor lalat hinggap di tempat minum salah seorang dari kalian, hendaknya ia mencelupkan ke dalam minuman tersebut, kemudian membuangnya, karena pada salah satu sayapnya terdapat penyakit dan pada sayap lainnya terdapat penawarnya.\""},"5032":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ نَافِعٍ وَعَبْدِ اللَّهِ بْنِ دِينَارٍ وَزَيْدِ بْنِ أَسْلَمَ يُخْبِرُونَهُ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَنْظُرُ اللَّهُ إِلَى مَنْ جَرَّ ثَوْبَهُ خُيَلَاءَ","id":"Telah menceritakan kepadaku [Isma'il] dia berkata; telah menceritakan kepadaku [Malik] dari [Nafi'] dan [Abdullah bin Dinar] serta [Zaid bin Aslam] mereka telah mengabarkan kepadanya dari [Ibnu Umar] radliallahu 'anhuma bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah tidak akan melihat orang yang menjulurkan pakaiannya dengan sombong.\""},"5033":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ جَرَّ ثَوْبَهُ خُيَلَاءَ لَمْ يَنْظُرْ اللَّهُ إِلَيْهِ يَوْمَ الْقِيَامَةِ قَالَ أَبُو بَكْرٍ يَا رَسُولَ اللَّهِ إِنَّ أَحَدَ شِقَّيْ إِزَارِي يَسْتَرْخِي إِلَّا أَنْ أَتَعَاهَدَ ذَلِكَ مِنْهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَسْتَ مِمَّنْ يَصْنَعُهُ خُيَلَاءَ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Musa bin 'Uqbah] dari [Salim bin Abdullah] dari [Ayahnya] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Siapa yang menjulurkan pakaiannya (hingga ke bawah mata kaki) dengan sombong, maka Allah tidak akan melihatnya pada hari Kiamat kelak.\" Lalu Abu Bakar berkata; \"Wahai Rasulullah, sesungguhnya salah satu dari sarungku terkadang turun sendiri, kecuali jika aku selalu menjaganya?\" lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Engkau bukan termasuk orang yang melakukan hal itu karena sombong.\""},"5034":{"ar":"حَدَّثَنِي مُحَمَّدٌ أَخْبَرَنَا عَبْدُ الْأَعْلَى عَنْ يُونُسَ عَنْ الْحَسَنِ عَنْ أَبِي بَكْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَخَسَفَتْ الشَّمْسُ وَنَحْنُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ يَجُرُّ ثَوْبَهُ مُسْتَعْجِلًا حَتَّى أَتَى الْمَسْجِدَ وَثَابَ النَّاسُ فَصَلَّى رَكْعَتَيْنِ فَجُلِّيَ عَنْهَا ثُمَّ أَقْبَلَ عَلَيْنَا وَقَالَ إِنَّ الشَّمْسَ وَالْقَمَرَ آيَتَانِ مِنْ آيَاتِ اللَّهِ فَإِذَا رَأَيْتُمْ مِنْهَا شَيْئًا فَصَلُّوا وَادْعُوا اللَّهَ حَتَّى يَكْشِفَهَا","id":"Telah menceritakan kepadaku [Muhammad] telah mengabarkan kepada kami [Abdul A'la] dari [Yunus] dari [Al Hasan] dari [Abu Bakrah] radliallahu 'anhu dia berkata; \"Ketika kami berada di samping Nabi shallallahu 'alaihi wasallam, tiba-tiba terjadi gerhana Matahari, maka beliau segera berdiri menuju masjid, dan menarik pakainnya karena tergesa-gesa hingga tiba dimasjid. Lalu orang-orang pun segera berdiri di sisinya dan beliau mengerjakan shalat dua rakaat. Setelah matahari terang, beliau berkhutbah di hadapan kami seraya bersabda: \"Matahari dan bulan tidak mengalami gerhana karena kematian atau kelahiran seseorang, tetapi keduanya merupakan tanda diantara tanda-tanda kebesaran Allah. Jika kalian melihat kedua gerhana tersebut, maka shalatlah dan berdoalah hingga gerhana tersingkap dari kalian (nampak kembali).\""},"5035":{"ar":"حَدَّثَنِي إِسْحَاقُ أَخْبَرَنَا ابْنُ شُمَيْلٍ أَخْبَرَنَا عُمَرُ بْنُ أَبِي زَائِدَةَ أَخْبَرَنَا عَوْنُ بْنُ أَبِي جُحَيْفَةَ عَنْ أَبِيهِ أَبِي جُحَيْفَةَ قَالَفَرَأَيْتُ بِلَالًا جَاءَ بِعَنَزَةٍ فَرَكَزَهَا ثُمَّ أَقَامَ الصَّلَاةَ فَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ فِي حُلَّةٍ مُشَمِّرًا فَصَلَّى رَكْعَتَيْنِ إِلَى الْعَنَزَةِ وَرَأَيْتُ النَّاسَ وَالدَّوَابَّ يَمُرُّونَ بَيْنَ يَدَيْهِ مِنْ وَرَاءِ الْعَنَزَةِ","id":"Telah menceritakan kepadaku [Ishaq] telah mengabarkan kepada kami [Ibnu Syumail] telah mengabarkan kepada kami [Umar bin Abu Za`idah] telah mengabarkan kepada kami ['Aun bin Abu Juhaifah] dari ayahnya [Abu Juhaifah] dia berkata; \"Lalu aku melihat Bilal datang dengan membawa tongkat (berujung runcing) dan menancapkan tongkat tersebut, kemudian dia mengumandangkan iqamah, setelah itu saya melihat Rasulullah shallallahu 'alaihi wasallam keluar (rumah) dengan menyingsingkan pakaiannya, lalu beliau shalat dua raka'at di hadapan tongkat tersebut, dan saya melihat orang-orang dan binatang pun lewat di hadapan beliau di belakang tongkat tersebut.\""},"5036":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا سَعِيدُ بْنُ أَبِي سَعِيدٍ الْمَقْبُرِيُّ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا أَسْفَلَ مِنْ الْكَعْبَيْنِ مِنْ الْإِزَارِ فَفِي النَّارِ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Sa'id bin Abu Sa'id Al Maqburi] dari [Abu Hurairah] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Barangsiapa menjulurkan kain sarungnya hingga dibawah mata kaki, maka tempatnya adalah neraka.\""},"5037":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَنْظُرُ اللَّهُ يَوْمَ الْقِيَامَةِ إِلَى مَنْ جَرَّ إِزَارَهُ بَطَرًا","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Abu Az Zinnad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada hari kiamat kelak, Allah tidak akan melihat orang yang menjulurkan kain sarungnya karena sombong.\""},"5038":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا مُحَمَّدُ بْنُ زِيَادٍ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ قَالَ أَبُو الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَمَا رَجُلٌ يَمْشِي فِي حُلَّةٍ تُعْجِبُهُ نَفْسُهُ مُرَجِّلٌ جُمَّتَهُ إِذْ خَسَفَ اللَّهُ بِهِ فَهُوَ يَتَجَلْجَلُ إِلَى يَوْمِ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Muhammad bin Ziyad] dia berkata; saya mendengar [Abu Hurairah] berkata; Nabi shallallahu 'alaihi wasallam bersabda atau Abu Qasim shallallahu 'alaihi wasallam bersabda: \"Ketika seorang lelaki berjalan dengan menggunakan jubah yang ia kenakan, dan berjalan dengan rasa ta'ajub, lalu ia ditelan (oleh bumi), dan ia akan tetap berguncang-guncang (di dalam perut bumi) hingga datang hari kiamat.\""},"5039":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ قَالَ حَدَّثَنِي اللَّيْثُ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ خَالِدٍ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ أَنَّ أَبَاهُ حَدَّثَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَا رَجُلٌ يَجُرُّ إِزَارَهُ إِذْ خُسِفَ بِهِ فَهُوَ يَتَجَلَّلُ فِي الْأَرْضِ إِلَى يَوْمِ الْقِيَامَةِتَابَعَهُ يُونُسُ عَنْ الزُّهْرِيِّ وَلَمْ يَرْفَعْهُ شُعَيْبٌ عَنْ الزُّهْرِيِّ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ أَخْبَرَنَا أَبِي عَنْ عَمِّهِ جَرِيرِ بْنِ زَيْدٍ قَالَ كُنْتُ مَعَ سَالِمِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَلَى بَابِ دَارِهِ فَقَالَ سَمِعْتُ أَبَا هُرَيْرَةَ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Sa'id bin 'Ufair] dia berkata; telah menceritakan kepadaku [Al Laits] dia berkata; telah menceritakan kepadaku [Abdurrahman bin Khalid] dari [Ibnu Syihab] dari [Salim bin Abdullah] bahwa [Ayahnya] telah menceritakan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Katika ada seseorang yang menjulurkan kain sarungnya maka dia akan berguncang-guncang (diadzab) di perut bumi hingga datangnya hari Kiamat.\" Hadits ini juga diperkuat oleh riwayat [Yunus] dari [Az Zuhri] namun dia tidak merafa'kannya (sanadnya tersambung sampai kepada Nabi shallallahu 'alaihi wasallam) yaitu dari [Syu'aib] dari [Az Zuhri]. Telah menceritakan kepadaku [Abdullah bin Muhammad] telah menceritakan kepada kami [Wahb bin Jarir] telah mengabarkan kepada kami [Ayahku] dari pamannya [Jarir bin Zaid] dia berkata; saya pernah bersama [Salim bin Abdullah bin Umar] berada di depan pintunya, lalu dia berkata; saya mendengar bahwa [Abu Hurairah] mendengar Nabi shallallahu 'alaihi wasallam bersabda seperti hadits di atas.\""},"5040":{"ar":"حَدَّثَنَا مَطَرُ بْنُ الْفَضْلِ حَدَّثَنَا شَبَابَةُ حَدَّثَنَا شُعْبَةُ قَالَ لَقِيتُ مُحَارِبَ بْنَ دِثَارٍ عَلَى فَرَسٍ وَهُوَ يَأْتِي مَكَانَهُ الَّذِي يَقْضِي فِيهِ فَسَأَلْتُهُ عَنْ هَذَا الْحَدِيثِ فَحَدَّثَنِي فَقَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ جَرَّ ثَوْبَهُ مَخِيلَةً لَمْ يَنْظُرْ اللَّهُ إِلَيْهِ يَوْمَ الْقِيَامَةِ فَقُلْتُ لِمُحَارِبٍ أَذَكَرَ إِزَارَهُ قَالَ مَا خَصَّ إِزَارًا وَلَا قَمِيصًاتَابَعَهُ جَبَلَةُ بْنُ سُحَيْمٍ وَزَيْدُ بْنُ أَسْلَمَ وَزَيْدُ بْنُ عَبْدِ اللَّهِ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ مِثْلَهُ وَتَابَعَهُ مُوسَى بْنُ عُقْبَةَ وَعُمَرُ بْنُ مُحَمَّدٍ وَقُدَامَةُ بْنُ مُوسَى عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ جَرَّ ثَوْبَهُ","id":"Telah menceritakan kepada kami [Mathar bin Al Fadl] telah menceritakan kepada kami [Syababah] telah menceritakan kepada kami [Syu'bah] dia berkata; saya berjumpa [Muharib bin Ditsar] di atas kudanya, ketika ia datang di tempat untuk memutuskan suatu perkara, lalu aku bertanya tentang suatu hadits, maka dia menceritakan kepadaku, katanya; saya mendengar [Abdullah bin Umar] radliallahu 'anhuma berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menjulurkan kainnya karena sombong, maka Allah tidak akan melihatnya pada hari Kiamat kelak.\" Lalu tanyaku kepada Muharib; \"Apakah beliau menyebutkan kain sarung?\" dia menjawab; \"Beliau tidak mengkhususkan kain sarung ataukah jubah.\" Hadits ini juga diperkuat oleh riwayat [Jabalah bin Suhaim] dan [Zaid bin Aslam] serta [Zaid bin Abdullah] dari [Ibnu Umar] dari Nabi Shallallahu 'alaihi. [Al Laits] mengatakan; dari [Nafi'] dari [Ibnu Umar] seperti itu. Dan diperkuat pula oleh riwayat [Musa bin 'Uqbah], [Umar bin Muhammad] dan [Qudamah bin Musa] dari [Salim] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam yaitu dengan redaksi: \"Barangsiapa menjulurkan pakainnya....\""},"5041":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْجَاءَتْ امْرَأَةُ رِفَاعَةَ الْقُرَظِيِّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا جَالِسَةٌ وَعِنْدَهُ أَبُو بَكْرٍ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي كُنْتُ تَحْتَ رِفَاعَةَ فَطَلَّقَنِي فَبَتَّ طَلَاقِي فَتَزَوَّجْتُ بَعْدَهُ عَبْدَ الرَّحْمَنِ بْنَ الزُّبَيْرِ وَإِنَّهُ وَاللَّهِ مَا مَعَهُ يَا رَسُولَ اللَّهِ إِلَّا مِثْلُ هَذِهِ الْهُدْبَةِ وَأَخَذَتْ هُدْبَةً مِنْ جِلْبَابِهَا فَسَمِعَ خَالِدُ بْنُ سَعِيدٍ قَوْلَهَا وَهُوَ بِالْبَابِ لَمْ يُؤْذَنْ لَهُ قَالَتْ فَقَالَ خَالِدٌ يَا أَبَا بَكْرٍ أَلَا تَنْهَى هَذِهِ عَمَّا تَجْهَرُ بِهِ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَا وَاللَّهِ مَا يَزِيدُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى التَّبَسُّمِ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَلَّكِ تُرِيدِينَ أَنْ تَرْجِعِي إِلَى رِفَاعَةَ لَا حَتَّى يَذُوقَ عُسَيْلَتَكِ وَتَذُوقِي عُسَيْلَتَهُفَصَارَ سُنَّةً بَعْدُ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] telah mengabarkan kepadaku ['Urwah bin Az Zubair] bahwa [Aisyah] radliallahu 'anha isteri Nabi shallallahu 'alaihi wasallam berkata; \"Telah datang isteri Rifa'ah Al Qurazhi kepada Nabi shallallahu 'alaihi wasallam, sementara diriku sedang duduk dan Abu Bakr ada di sisi beliau. Isteri Rifa'ah berkata; \"Wahai Rasulullah, sesungguhnya saya dahulu dibawah naungan Rifa'ah Al Qurazhi, kemudian ia menceraiku sama sekali (talak tiga). Kemudian saya menikah dengan Abdur Rahman bin Az Zubair, dan demi Allah wahai Rasulullah, tidaklah aku bersamanya melainkan ia tidak memiliki kemampuan kecuali seperti ujung pakaian ini.\" -seraya mengambil ujung jilbabnya, - sementara Khalid bin Sa'id ada di depan pintu, belum di izinkan masuk oleh beliau, Aisyah melanjutkan; \"Lantas Khalid berkata; \"Wahai Abu Bakr, tidakkah engkau menahan wanita ini berkata keji dengan apa yang ia katakan di sisi Rasulullah shallallahu 'alaihi wasallam?\" dan Rasulullah shallallahu 'alaihi wasallam hanya tersenyum mendengarnya, kemudian beliau bersabda: \"Sepertinya dirimu ingin kembali kepada Rifa'ah, Tidak, hingga kamu merasakan kenikmatannya dan ia merasakan kenikmatanmu.\" Maka hal itu menjadi ajaran beliau.\""},"5042":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ أَخْبَرَنِي عَلِيُّ بْنُ حُسَيْنٍ أَنَّ حُسَيْنَ بْنَ عَلِيٍّ أَخْبَرَهُ أَنَّ عَلِيًّا رَضِيَ اللَّهُ عَنْهُ قَالَفَدَعَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِرِدَائِهِ ثُمَّ انْطَلَقَ يَمْشِي وَاتَّبَعْتُهُ أَنَا وَزَيْدُ بْنُ حَارِثَةَ حَتَّى جَاءَ الْبَيْتَ الَّذِي فِيهِ حَمْزَةُ فَاسْتَأْذَنَ فَأَذِنُوا لَهُمْ","id":"Telah menceritakan kepada kami ['Abdan] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Yunus] dari [Az Zuhri] telah mengabarkan kepadaku [Ali bin Husain] bahwa [Husain bin Ali] telah mengabarkan kepadanya, bahwa [Ali] radliallahu 'anhu berkata; \"...lalu Nabi shallallahu 'alaihi wasallam meminta jubahnya kemudian beliau pergi berjalan, aku dan Zaid bin Haritsah pun turut mengikuti beliau hingga beliau tiba di Ka'bah yang di dalamnya ada Hamzah, kemudian beliau meminta izin, dan dia pun mengizinkan masuk.\""},"5043":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ مَا يَلْبَسُ الْمُحْرِمُ مِنْ الثِّيَابِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَلْبَسُ الْمُحْرِمُ الْقَمِيصَ وَلَا السَّرَاوِيلَ وَلَا الْبُرْنُسَ وَلَا الْخُفَّيْنِ إِلَّا أَنْ لَا يَجِدَ النَّعْلَيْنِ فَلْيَلْبَسْ مَا هُوَ أَسْفَلُ مِنْ الْكَعْبَيْنِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhuma bahwa seorang laki-laki bertanya; \"Wahai Rasulullah, pakaian yang bagaimanakah yang tidak boleh dikenakan oleh orang yang berihram?\" Nabi shallallahu 'alaihi wasallam menjawab: \"Ia tidak boleh memakai jubah, celana panjang, baju panjang yang bertutup kepala, dan tidak memakai sepatu kecuali bagi orang yang tidak mendapatkan dua sandal, hendaknya ia memotongnya hingga dibawah kedua mata kaki.\""},"5044":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُثْمَانَ أَخْبَرَنَا ابْنُ عُيَيْنَةَ عَنْ عَمْرٍو سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَأَتَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَبْدَ اللَّهِ بْنَ أُبَيٍّ بَعْدَ مَا أُدْخِلَ قَبْرَهُ فَأَمَرَ بِهِ فَأُخْرِجَ وَوُضِعَ عَلَى رُكْبَتَيْهِ وَنَفَثَ عَلَيْهِ مِنْ رِيقِهِ وَأَلْبَسَهُ قَمِيصَهُ فَاللَّهُ أَعْلَمُ","id":"Telah menceritakan kepada kami [Abdullah bin Utsman] telah mengabarkan kepada kami [Ibnu 'Uyainah] dari ['Amru] dia mendengar [Jabir bin Abdullah] radliallahu 'anhuma berkata; \"Nabi shallallahu 'alaihi wasallam pernah mendatangi kuburan Abdullah bin Ubay setelah ia dikuburkan, beliau kemudian menyuruh untuk mengeluarkannya, lalu diletakkan di atas lututnya, beliau kemudian meniup sedikit air liurnya dan memakaikan bajunya.\" Wallahhu Ta'ala A'lam."},"5045":{"ar":"حَدَّثَنَا صَدَقَةُ أَخْبَرَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ قَالَ أَخْبَرَنِي نَافِعٌ عَنْ عَبْدِ اللَّهِ قَالَلَمَّا تُوُفِّيَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ جَاءَ ابْنُهُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَعْطِنِي قَمِيصَكَ أُكَفِّنْهُ فِيهِ وَصَلِّ عَلَيْهِ وَاسْتَغْفِرْ لَهُ فَأَعْطَاهُ قَمِيصَهُ وَقَالَ إِذَا فَرَغْتَ مِنْهُ فَآذِنَّا فَلَمَّا فَرَغَ آذَنَهُ بِهِ فَجَاءَ لِيُصَلِّيَ عَلَيْهِ فَجَذَبَهُ عُمَرُ فَقَالَ أَلَيْسَ قَدْ نَهَاكَ اللَّهُ أَنْ تُصَلِّيَ عَلَى الْمُنَافِقِينَ فَقَالَ{ اسْتَغْفِرْ لَهُمْ أَوْ لَا تَسْتَغْفِرْ لَهُمْ إِنْ تَسْتَغْفِرْ لَهُمْ سَبْعِينَ مَرَّةً فَلَنْ يَغْفِرَ اللَّهُ لَهُمْ }فَنَزَلَتْ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا وَلَا تَقُمْ عَلَى قَبْرِهِ }فَتَرَكَ الصَّلَاةَ عَلَيْهِمْ","id":"Telah menceritakan kepada kami [Shadaqah] telah mengabarkan kepada kami [Yahya bin Sa'id] dari ['Ubaidullah] dia berkata; telah mengabarkan kepadaku [Nafi'] dari ['Abdullah] dia berkata; Setelah Abdullah bin Ubay meninggal dunia, anaknya datang menemui Nabi shallallahu 'alaihi wasallam, dan berkata; 'Wahai Rasulullah, berikanlah baju engkau kepadaku hingga aku mengkafaninya dengan baju itu, shalatkanlah ia dan mintalah ampunan untuknya!\" lalu beliau memberikan baju beliau kepadanya. Kemudian beliau bersabda: \"Jika kalian telah selesai, beritahulah aku.\" Ketika telah selesai, maka anaknya Abdullah bin Ubay memberitahukan kepada beliau, lalu beliau datang untuk menshalatinya. Maka Umar menariknya seraya berkata; 'Tidakkah Allah telah melarang engkau untuk menshalatkan orang-orang munafik'. Namun beliau membaca ayat: \"Mintakanlah ampun untuk mereka atau kamu tidak memintakan ampun untuk mereka, sama saja jika kamu memintakan ampun untuk mereka sebanyak tujuh puluh kali maka Allah tidak akan mengampuni mereka.\" Lalu turunlah ayat, Dan janganlah kamu sekali-kali menshalatkan (jenazah) seorang yang mati diantara mereka, dan janganlah kamu berdiri (mendoakan) di kuburnya'. Akhirnya beliaupun tidak lagi menshalatkan mereka.\""},"5046":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ نَافِعٍ عَنْ الْحَسَنِ عَنْ طَاوُسٍ عَنْ أَبِي هُرَيْرَةَ قَالَضَرَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثَلَ الْبَخِيلِ وَالْمُتَصَدِّقِ كَمَثَلِ رَجُلَيْنِ عَلَيْهِمَا جُبَّتَانِ مِنْ حَدِيدٍ قَدْ اضْطُرَّتْ أَيْدِيهِمَا إِلَى ثُدِيِّهِمَا وَتَرَاقِيهِمَا فَجَعَلَ الْمُتَصَدِّقُ كُلَّمَا تَصَدَّقَ بِصَدَقَةٍ انْبَسَطَتْ عَنْهُ حَتَّى تَغْشَى أَنَامِلَهُ وَتَعْفُوَ أَثَرَهُ وَجَعَلَ الْبَخِيلُ كُلَّمَا هَمَّ بِصَدَقَةٍ قَلَصَتْ وَأَخَذَتْ كُلُّ حَلْقَةٍ بِمَكَانِهَا قَالَ أَبُو هُرَيْرَةَ فَأَنَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بِإِصْبَعِهِ هَكَذَا فِي جَيْبِهِ فَلَوْ رَأَيْتَهُ يُوَسِّعُهَا وَلَا تَتَوَسَّعُتَابَعَهُ ابْنُ طَاوُسٍ عَنْ أَبِيهِ وَأَبُو الزِّنَادِ عَنْ الْأَعْرَجِ فِي الْجُبَّتَيْنِ وَقَالَ حَنْظَلَةُ سَمِعْتُ طَاوُسًا سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُ جُبَّتَانِ وَقَالَ جَعْفَرُ بْنُ حَيَّانَ عَنْ الْأَعْرَجِ جُبَّتَانِ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] telah menceritakan kepada kami [Abu 'Amir] telah menceritakan kepada kami [Ibrahim bin Nafi'] dari [Al Hasan] dari [Thawus] dari [Abu Hurairah] dia berkata; Rasulullah Shalallahu 'Alaihi Wa Sallam membuat perumpamaan orang yang bakhil dan orang yang suka bersedekah seperti dua orang yang memakai dua jubah dari besi, mulai dari payudara (dada) sampai tulang selangka mereka berdua. Jika orang tersebut ingin berinfak, maka baju besinya melebar atau bergerak hingga menutupi ujung jarinya dan menghilangkan bekas jalannya. Jika orang yang bakhil ingin berinfak, baju besinya mengerut, dan setiap baju besi tetap di tempatnya (tidak melebar) hingga mengambilnya dengan tulang selangkanya atau dengan lehernya.\" Abu Hurairah berkata; 'Aku menyaksikan bahwa ia melihat Rasulullah Shalallahu 'Alaihi Wa Sallam memberi isyarat dengan jari-jarinya dengan melebarkan tameng besi, namun aku melihat baju tersebut tidak melebar.' Hadits ini juga diperkuat oleh [Ibnu Thawus] dari [Ayahnya] dan [Abu Az Zinnad] dari [Al A'raj] mengenai dua jubah, sedangkan [Hanzhalah] mengatakan; aku mendengar [Thawus] saya mendengar [Abu Hurairah] mengatakan dua jubah, [Ja'far bin Hayyan] mengatakan dari [Al A'raj] yaitu dua jubah.\""},"5047":{"ar":"حَدَّثَنَا قَيْسُ بْنُ حَفْصٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا الْأَعْمَشُ قَالَ حَدَّثَنِي أَبُو الضُّحَى قَالَ حَدَّثَنِي مَسْرُوقٌ قَالَ حَدَّثَنِي الْمُغِيرَةُ بْنُ شُعْبَةَ قَالَانْطَلَقَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِحَاجَتِهِ ثُمَّ أَقْبَلَ فَتَلَقَّيْتُهُ بِمَاءٍ فَتَوَضَّأَ وَعَلَيْهِ جُبَّةٌ شَأْمِيَّةٌ فَمَضْمَضَ وَاسْتَنْشَقَ وَغَسَلَ وَجْهَهُ فَذَهَبَ يُخْرِجُ يَدَيْهِ مِنْ كُمَّيْهِ فَكَانَا ضَيِّقَيْنِ فَأَخْرَجَ يَدَيْهِ مِنْ تَحْتِ الْجُبَّةِ فَغَسَلَهُمَا وَمَسَحَ بِرَأْسِهِ وَعَلَى خُفَّيْهِ","id":"Telah menceritakan kepada kami [Qais bin Hafsh] telah menceritakan kepada kami [Abdul Wahid] telah menceritakan kepada kami [Al A'masy] dia berkata; telah menceritakan kepadaku [Abu Adl Dluha] dia berkata; telah menceritakan kepadaku [Masruq] dia berkata; telah menceritakan kepadaku [Al Mughirah bin Syu'bah] dia berkata; \"Nabi shallallahu 'alaihi wasallam pergi untuk suatu kebutuhan, lalu beliau datang dan akupun langsung menemui beliau dengan membawa air, kemudian beliau berwudlu', waktu itu beliau sedang mengenakan jubah dari Syam, lalu beliau berkumur-kumur dan beristinsyaq (memasukkan air ke dalam hidung) serta membasuh wajahnya, beliau berusaha mengeluarkan kedua tangannya dari kedua lengan bajunya, karena sempit maka beliau mengeluarkan kedua tangan beliau melalui bawah jubahnya, lalu beliau membasuh kedua tangan beliau dan mengusap kepala beliau serta kedua sepatu beliau.\""},"5048":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زَكَرِيَّاءُ عَنْ عَامِرٍ عَنْ عُرْوَةَ بْنِ الْمُغِيرَةِ عَنْ أَبِيهِ رَضِيَ اللَّهُ عَنْهُ قَالَكُنْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ فِي سَفَرٍ فَقَالَ أَمَعَكَ مَاءٌ قُلْتُ نَعَمْ فَنَزَلَ عَنْ رَاحِلَتِهِ فَمَشَى حَتَّى تَوَارَى عَنِّي فِي سَوَادِ اللَّيْلِ ثُمَّ جَاءَ فَأَفْرَغْتُ عَلَيْهِ الْإِدَاوَةَ فَغَسَلَ وَجْهَهُ وَيَدَيْهِ وَعَلَيْهِ جُبَّةٌ مِنْ صُوفٍ فَلَمْ يَسْتَطِعْ أَنْ يُخْرِجَ ذِرَاعَيْهِ مِنْهَا حَتَّى أَخْرَجَهُمَا مِنْ أَسْفَلِ الْجُبَّةِ فَغَسَلَ ذِرَاعَيْهِ ثُمَّ مَسَحَ بِرَأْسِهِ ثُمَّ أَهْوَيْتُ لِأَنْزِعَ خُفَّيْهِ فَقَالَ دَعْهُمَا فَإِنِّي أَدْخَلْتُهُمَا طَاهِرَتَيْنِ فَمَسَحَ عَلَيْهِمَا","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Zakariya] dari ['Amir] dari ['Urwah bin Al Mughirah] dari [Ayahnya] radliallahu 'anhu dia berkata; \"Pada suatu malam saya bersama Nabi shallallahu 'alaihi wasallam mengadakan suatu perjalanan, lalu beliau bersabda: \"Apakah kamu membawa air?\" jawabku; \"Ya.\" Kemudian beliau turun dari kendaraannya dan berjalan hingga menjauh dariku di gelapnya malam, setelah itu beliau kembali dan akupun menuangkan air dari wadah, kemudian beliau membasuh wajahnya dan tangannya, karena beliau mengenakan jubah dari shuf (bulu domba) beliau tidak dapat mengeluarkan kedua tangan beliau, akhirnya beliau mengeluarkannya dari bawah jubahnya, kemudian beliau membasuh kedua lengannya dan mengusap kepalanya, lalu aku jongkok hendak melepas sepatunya, namun beliau bersabda: \"Biarkanlah, karena aku mengenakan sepatu tersebut dalam kedaan suci.\" Lalu beliau sekedar mengusapnya.\""},"5049":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ الْمِسْوَرِ بْنِ مَخْرَمَةَ قَالَقَسَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْبِيَةً وَلَمْ يُعْطِ مَخْرَمَةَ شَيْئًا فَقَالَ مَخْرَمَةُ يَا بُنَيِّ انْطَلِقْ بِنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَانْطَلَقْتُ مَعَهُ فَقَالَ ادْخُلْ فَادْعُهُ لِي قَالَ فَدَعَوْتُهُ لَهُ فَخَرَجَ إِلَيْهِ وَعَلَيْهِ قَبَاءٌ مِنْهَا فَقَالَ خَبَأْتُ هَذَا لَكَ قَالَ فَنَظَرَ إِلَيْهِ فَقَالَ رَضِيَ مَخْرَمَةُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Laits] dari [Ibnu Abu Mulaikah] dari [Al Miswar bin Makhramah] dia berkata; Rasulullah shallallahu 'alaihi wasallam pernah membagi-bagikan aqbiah (sejenis jubah), namun beliau tidak memberi Makhramah sesuatu pun. Makhramah lalu berkata, \"Wahai anakku, mari ikut kami pergi menemui Rasulullah shallallahu 'alaihi wasallam.\" Maka aku pun pergi bersamanya. Makhramah berkata, \"Masuk dan mintakanlah untukku.\" Miswar berkata, \"Aku lalu memintakannya, hingga beliau keluar menemuinya (Makhramah) dengan membawa Quba (sejenis jubah). Beliau bersabda: \"Aku sembunyikan ini khusus untukmu.\" Makhramah pun melihat jubah tersebut dan berkata; \"Makhramah telah ridla.\""},"5050":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ عُقْبَةَ بْنِ عَامِرٍ رَضِيَ اللَّهُ عَنْهُ أَنَّهُ قَالَأُهْدِيَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرُّوجُ حَرِيرٍ فَلَبِسَهُ ثُمَّ صَلَّى فِيهِ ثُمَّ انْصَرَفَ فَنَزَعَهُ نَزْعًا شَدِيدًا كَالْكَارِهِ لَهُ ثُمَّ قَالَ لَا يَنْبَغِي هَذَا لِلْمُتَّقِينَتَابَعَهُ عَبْدُ اللَّهِ بْنُ يُوسُفَ عَنْ اللَّ��ْثِ وَقَالَ غَيْرُهُ فَرُّوجٌ حَرِيرٌ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari [Abu Al Khair] dari ['Uqbah bin 'Amir] radliallahu 'anhu bahwa dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah diberi hadiah baju yang terbuat dari kain sutera, lalu beliau mengenakannya untuk shalat, seusai shalat beliau melepasnya dengan paksa seakan-akan beliau benci mengenakan baju tersebut, kemudian beliau bersabda: \"Baju ini tidak layak dipakai oleh orang-orang yang bertakwa.\" Hadits ini juga dikuatkan oleh [Abdullah bin Yusuf] dari [Al Laits], dan yang lainnya juga mengatakan; \"Farraujun min hariirin (baju yang terbuat dari sutera).\""},"5051":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ مَا يَلْبَسُ الْمُحْرِمُ مِنْ الثِّيَابِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَلْبَسُوا الْقُمُصَ وَلَا الْعَمَائِمَ وَلَا السَّرَاوِيلَاتِ وَلَا الْبَرَانِسَ وَلَا الْخِفَافَ إِلَّا أَحَدٌ لَا يَجِدُ النَّعْلَيْنِ فَلْيَلْبَسْ خُفَّيْنِ وَلْيَقْطَعْهُمَا أَسْفَلَ مِنْ الْكَعْبَيْنِ وَلَا تَلْبَسُوا مِنْ الثِّيَابِ شَيْئًا مَسَّهُ زَعْفَرَانٌ وَلَا الْوَرْسُ","id":"Telah menceritakan kepada kami [Isma'il] dia berkata; telah menceritakan kepadaku [Malik] dari [Nafi'] dari [Abdullah bin Umar] bahwa seorang laki-laki berkata; \"Wahai Rasulullah, pakaian yang bagaimanakah yang dikenakan oleh orang yang berihram?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Ia tidak boleh memakai gamis (jubah), surban, celana panjang, baju panjang yang bertutup kepala, dan tidak memakai sepatu kecuali bagi orang yang tidak mendapatkan dua sandal, hendaknya ia memakai sepatu dan memotongnya hingga dibawah kedua mata kaki, dan janganlah kalian mengenakan pakaian yang dicampur dengan minyak za'faron dan tidak pula wars (sejenis tumbuhan yang berwarna kuning atau kunyit).\""},"5052":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ جَابِرِ بْنِ زَيْدٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ لَمْ يَجِدْ إِزَارًا فَلْيَلْبَسْ سَرَاوِيلَ وَمَنْ لَمْ يَجِدْ نَعْلَيْنِ فَلْيَلْبَسْ خُفَّيْنِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari ['Amru] dari [Jabir bin Zaid] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Barangsiapa tidak mendapat sarung (ketika berihram), hendaknya ia mengenakan celana panjang, dan siapa yang tidak mendapatkan sandal, hendaknya ia mengenakan sepatu.\""},"5053":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا جُوَيْرِيَةُ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ قَالَقَامَ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ مَا تَأْمُرُنَا أَنْ نَلْبَسَ إِذَا أَحْرَمْنَا قَالَ لَا تَلْبَسُوا الْقَمِيصَ وَالسَّرَاوِيلَ وَالْعَمَائِمَ وَالْبَرَانِسَ وَالْخِفَافَ إِلَّا أَنْ يَكُونَ رَجُلٌ لَيْسَ لَهُ نَعْلَانِ فَلْيَلْبَسْ الْخُفَّيْنِ أَسْفَلَ مِنْ الْكَعْبَيْنِ وَلَا تَلْبَسُوا شَيْئًا مِنْ الثِّيَابِ مَسَّهُ زَعْفَرَانٌ وَلَا وَرْسٌ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Juwairiyah] dari [Nafi'] dari [Abdullah] dia berkata; seorang laki-laki berdiri dan berkata; \"Wahai Rasulullah, pakaian apakah yang engkau perintahkan untuk kami kenakan ketika berihram?\" beliau bersabda: \"Janganlah kalian mengenakan gamis (jubah), celana panjang, surban, baju panjang yang bertutup kepala dan tidak pula sepatu kecuali jika seseorang tidak mendapatkan sandal, maka ia boleh mengenakan sepatu di bawah mata kaki, dan janganlah kalian mengenakan pakaian yang dicampuri dengan minyak za'faran dan tidak juga wars (sejenis tumbuhan yang berwarna kuning atau kunyit).\""},"5054":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ سَمِعْتُ الزُّهْرِيَّ قَالَ أَخْبَرَنِي سَالِمٌ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَلْبَسُ الْمُحْرِمُ الْقَمِيصَ وَلَا الْعِمَامَةَ وَلَا السَّرَاوِيلَ وَلَا الْبُرْنُسَ وَلَا ثَوْبًا مَسَّهُ زَعْفَرَانٌ وَلَا وَرْسٌ وَلَا الْخُفَّيْنِ إِلَّا لِمَنْ لَمْ يَجِدْ النَّعْلَيْنِ فَإِنْ لَمْ يَجِدْهُمَا فَلْيَقْطَعْهُمَا أَسْفَلَ مِنْ الْكَعْبَيْنِ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] dia berkata; aku mendengar [Az Zuhri], dia berkata; telah mengabarkan kepadaku [Salim] dari [Ayahnya] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Janganlah seorang yang berihram mengenakan kain gamis (jubah), surban, celana panjang, baju lengan panjang yang bertutup kepala dan tidak pula pakaian yang tercampuri dengan minyak za'faran dan wars (sejenis tumbuhan berwarna kuning atau kunyit) serta tidak pula mengenakan sepatu, kecuali jika ia tidak mendapatkan sandal, dan harus memotongnya lebih rendah dari kedua mata kaki.\""},"5055":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامٌ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْهَاجَرَ نَاسٌ إِلَى الْحَبَشَةِ مِنْ الْمُسْلِمِينَ وَتَجَهَّزَ أَبُو بَكْرٍ مُهَاجِرًا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى رِسْلِكَ فَإِنِّي أَرْجُو أَنْ يُؤْذَنَ لِي فَقَالَ أَبُو بَكْرٍ أَوَ تَرْجُوهُ بِأَبِي أَنْتَ قَالَ نَعَمْ فَحَبَسَ أَبُو بَكْرٍ نَفْسَهُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِصُحْبَتِهِ وَعَلَفَ رَاحِلَتَيْنِ كَانَتَا عِنْدَهُ وَرَقَ السَّمُرِ أَرْبَعَةَ أَشْهُرٍ قَالَ عُرْوَةُ قَالَتْ عَائِشَةُ فَبَيْنَا نَحْنُ يَوْمًا جُلُوسٌ فِي بَيْتِنَا فِي نَحْرِ الظَّهِيرَةِ فَقَالَ قَائِلٌ لِأَبِي بَكْرٍ هَذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُقْبِلًا مُتَقَنِّعًا فِي سَاعَةٍ لَمْ يَكُنْ يَأْتِينَا فِيهَا قَالَ أَبُو بَكْرٍ فِدًا لَكَ أَبِي وَأُمِّي وَاللَّهِ إِنْ جَاءَ بِهِ فِي هَذِهِ السَّاعَةِ إِلَّا لِأَمْرٍ فَجَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَأْذَنَ فَأَذِنَ لَهُ فَدَخَلَ فَقَالَ حِينَ دَخَلَ لِأَبِي بَكْرٍ أَخْرِجْ مَنْ عِنْدَكَ قَالَ إِنَّمَا هُمْ أَهْلُكَ بِأَبِي أَنْتَ يَا رَسُولَ اللَّهِ قَالَ فَإِنِّي قَدْ أُذِنَ لِي فِي الْخُرُوجِ قَالَ فَالصُّحْبَةُ بِأَبِي أَنْتَ وَأُمِّي يَا رَسُولَ اللَّهِ قَالَ نَعَمْ قَالَ فَخُذْ بِأَبِي أَنْتَ يَا رَسُولَ اللَّهِ إِحْدَى رَاحِلَتَيَّ هَاتَيْنِ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالثَّمَنِ قَالَتْ فَجَهَّزْنَاهُمَا أَحَثَّ الْجِهَازِ وَضَعْنَا لَهُمَا سُفْرَةً فِي جِرَابٍ فَقَطَعَتْ أَسْمَاءُ بِنْتُ أَبِي بَكْرٍ قِطْعَةً مِنْ نِطَاقِهَا فَأَوْكَأَتْ بِهِ الْجِرَابَ وَلِذَلِكَ كَانَتْ تُسَمَّى ذَاتَ النِّطَاقِ ثُمَّ لَحِقَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ بِغَارٍ فِي جَبَلٍ يُقَالُ لَهُ ثَوْرٌ فَمَكُثَ فِيهِ ثَلَاثَ لَيَالٍ يَبِيتُ عِنْدَهُمَا عَبْدُ اللَّهِ بْنُ أَبِي بَكْرٍ وَهُوَ غُلَامٌ شَابٌّ لَقِنٌ ثَقِفٌ فَيَرْحَلُ مِنْ عِنْدِهِمَا سَحَرًا فَيُصْبِحُ مَعَ قُرَيْشٍ بِمَكَّةَ كَبَائِتٍ فَلَا يَسْمَعُ أَمْرًا يُكَادَانِ بِهِ إِلَّا وَعَاهُ حَتَّى يَأْتِيَهُمَا بِخَبَرِ ذَلِكَ حِينَ يَخْتَلِطُ الظَّلَامُ وَيَرْعَى عَلَيْهِمَا عَامِرُ بْنُ فُهَيْرَةَ مَوْلَى أَبِي بَكْرٍ مِنْحَةً مِنْ غَنَمٍ فَيُرِيحُهَا عَلَيْهِمَا حِينَ تَذْهَبُ سَاعَةٌ مِنْ الْعِشَاءِ فَيَبِيتَانِ فِي رِسْلِهِمَا حَتَّى يَنْعِقَ بِهَا عَامِرُ بْنُ فُهَيْرَةَ بِغَلَسٍ يَفْعَلُ ذَلِكَ كُلَّ لَيْلَةٍ مِنْ تِلْكَ اللَّيَالِي الثَّلَاثِ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] telah mengabarkan kepada kami [Hisyam] dari [Ma'mar] dari [Az Zuhri] dari ['Urwah] dari [Aisyah] radliallahu 'anha dia berkata; \"Kaum Muslimin berhijrah ke negeri Habsyah, sementara Abu Bakar tengah mempersiapkan dirinya untuk berhijrah, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Tunggulah, dan aku berharap supaya diizinkan untuk berhijrah.\" Lantas Abu Bakar berkata; \"Demi ayahku, apakah engkau berharap seperti itu?\" beliau menjawab; \"Ya.\" Maka Abu Bakr mengurungkan dirinya supaya dapat menyertai Nabi shallallahu 'alaihi wasallam berhijrah, dia pun memberi makan kedua untanya dengan dedaunan selama empat bulan, Urwah berkata; Aisyah melanjutkan; \"Di waktu menjelang siang, ketika kami sedang duduk-duduk di rumah, tiba-tiba seseorang berkata kepada Abu Bakr; \"Ini Nabi shallallahu 'alaihi wasallam ingin bertemu, dan beliau datang sambil menutupi sebagian kepala dan wajah beliau, dan beliau tidak pernah datang kepada kami di saat-saat seperti itu.\" Abu Bakr berkata; Demi ayah dan ibuku sebagai tebusannya, tidaklah beliau datang di waktu-waktu seperti ini melainkan ada sesuatu yang sangat penting.\" Lalu Nabi shallallahu 'alaihi wasallam datang dan meminta izin, maka Abu Bakr pun mengizinkannya masuk. Ketika beliau masuk, beliau berkata kepada Abu Bakr; \"Suruhlah orang-orang yang ada di sini untuk keluar.\" Abu Bakr menjawab; \"Demi ayahmu wahai Rasulullah, mereka semua adalah keluarga anda.\" Beliau bersabda: \"Sesungguhnya aku telah diizinkan untuk keluar (hijrah).\" Abu Bakr berkata; \"Demi ayah dan ibuku, apakah aku yang menyertai engkau wahai Rasulullah?\" beliau menjawab; \"Ya.\" Abu Bakr berkata; \"Kalau begitu, demi ayahku, ambillah salah satu tunggangan ini wahai Rasulullah.\" Nabi shallallahu 'alaihi wasallam bersabda: \"Yang terbaik.\" Aisyah melanjutkan; \"Lalu kami mempersiapkan untuknya bekal dengan cepat dan sigap, kami membuat untuk keduanya Sufroh (tempat membawa makanan untuk musafir) dalam Jirab (bejana tempat menaruh perbekalan).\" Kemudian Asma' binti Abu Bakr memotong ikat pinggangnya, dan mengikatkan ke bejana tersebut. Dari situlah ia dinamai dengan dzatunnithaq (yang memiliki ikat pinggang). Kemudian, Rasulullah shallaallahu 'alaihi wa sallam dan Abu Bakr berangkat menuju gua di salah satu pegunungan yang dikenal dengan nama Tsur, mereka tinggal di sana selama tiga malam. Sementara Abdullah bin Abu Bakr juga ikut menginap bersama keduanya, dia adalah seorang pemuda yang cerdas dan berwawasan tinggi, ketika menjelang waktu sahur dia keluar (dari gua) dan berbaur dengan orang-orang Quraisy Makkah di pagi harinya untuk mencari informasi, dan tidaklah seseorang mendengar perkara tersebut melainkan ia akan menyimpan rahasia tersebut dan datang kepada keduanya untuk menyampaikan berita ketika malam telah gelap, sementara 'Amir bin Fuhairah bekas budak Abu Bakr sebagai penggembala domba untuk menghilangkan jejak, ia berangkat pada waktu Isya' dan bermalam di tempat penggembalaan sampai 'Amir bin Fuhairah datang membangunkannya di akhir malam (menjelang subuh), hal itu ia lakukan setiap malam hingga berlalu tiga malam.\""},"5056":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا مَالِكٌ عَنْ الزُّهْرِيِّ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ مَكَّةَ عَامَ الْفَتْحِ وَعَلَى رَأْسِهِ الْمِغْفَرُ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Malik] dari [Az Zuhri] dari [Anas] radliallahu 'anhu bahwa Nabi shallallahu 'alaihi wasallam masuk kota Makkah ketika penaklukan kota Makkah dengan mengenakan topi baju besi di kepalanya.\""},"5057":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكُنْتُ أَمْشِي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْهِ بُرْدٌ نَجْرَانِيٌّ غَلِيظُ الْحَاشِيَةِ فَأَدْرَكَهُ أَعْرَابِيٌّ فَجَبَذَهُ بِرِدَائِهِ جَبْذَةً شَدِيدَةً حَتَّى نَظَرْتُ إِلَى صَفْحَةِ عَاتِقِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَثَّرَتْ بِهَا حَاشِيَةُ الْبُرْدِ مِنْ شِدَّةِ جَبْذَتِهِ ثُمَّ قَالَ يَا مُحَمَّدُ مُرْ لِي مِنْ مَالِ اللَّهِ الَّذِي عِنْدَكَ فَالْتَفَتَ إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ ضَحِكَ ثُمَّ أَمَرَ لَهُ بِعَطَاءٍ","id":"Telah menceritakan kepada kami [Isma'il bin Abdullah] dia berkata; telah menceritakan kepadaku [Malik] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik] dia berkata; \"Saya berjalan bersama Rasulullah Shallallahu'alaihi wa Sallam, ketika itu beliau mengenakan kain (selimut) Najran yang tebal ujungnya, lalu ada seorang Arab badui (dusun) yang menemui beliau. Langsung ditariknya Rasulullah dengan kuat hingga saya melihat permukaan bahu beliau membekas lantaran ujung selimut akibat tarikan Arab badui yang kasar. Arab badui tersebut berkata; \"Wahai Muhammad berikan kepadaku dari harta yang diberikan Allah padamu\", maka Rasulullah Shallallahu'alaihi wa Sallam menoleh kepadanya diiringi senyum serta menyuruh salah seorang sahabat untuk memberikan sesuatu kepadanya.\""},"5058":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا يَعْقُوبُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَجَاءَتْ امْرَأَةٌ بِبُرْدَةٍ قَالَ سَهْلٌ هَلْ تَدْرِي مَا الْبُرْدَةُ قَالَ نَعَمْ هِيَ الشَّمْلَةُ مَنْسُوجٌ فِي حَاشِيَتِهَا قَالَتْ يَا رَسُولَ اللَّهِ إِنِّي نَسَجْتُ هَذِهِ بِيَدِي أَكْسُوكَهَا فَأَخَذَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُحْتَاجًا إِلَيْهَا فَخَرَجَ إِلَيْنَا وَإِنَّهَا لَإِزَارُهُ فَجَسَّهَا رَجُلٌ مِنْ الْقَوْمِ فَقَالَ يَا رَسُولَ اللَّهِ اكْسُنِيهَا قَالَ نَعَمْ فَجَلَسَ مَا شَاءَ اللَّهُ فِي الْمَجْلِسِ ثُمَّ رَجَعَ فَطَوَاهَا ثُمَّ أَرْسَلَ بِهَا إِلَيْهِ فَقَالَ لَهُ الْقَوْمُ مَا أَحْسَنْتَ سَأَلْتَهَا إِيَّاهُ وَقَدْ عَرَفْتَ أَنَّهُ لَا يَرُدُّ سَائِلًا فَقَالَ الرَّجُلُ وَاللَّهِ مَا سَأَلْتُهَا إِلَّا لِتَكُونَ كَفَنِي يَوْمَ أَمُوتُ قَالَ سَهْلٌ فَكَانَتْ كَفَنَهُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Ya'qub bin Abdurrahman] dari [Abu Hazim] dari [Sahl bin Sa'd] dia berkata; \"Seorang wanita datang sambil membawa selimut bersulam yang ada rendanya. Sahal berkata; Apa kamu tahu selimut apakah itu? Abu Hazm menjawab: Ya, ia adalah mantel bertutup kepala yang ujungnya berenda. Wanita itu berkata; \"Wahai Rasulullah! Aku menenun selimut ini dengan tanganku, aku membawanya untuk mengenakannya pada baginda. Lalu Rasulullah shallallahu 'alaihi wasallam mengambilnya karena memang membutuhkannya. Lalu beliau keluar menemui kami ternyata selimut itu berupa kain sarung, kemudian seseorang dari suatu kaum datang menemui beliau dan berkata; \"Kenakanlah untukku wahai Rasulullah! Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya.\" Kemudian beliau duduk di majlis sebagaimana yang di kehendaki Allah, lalu pulang. Setelah itu beliau melipat kain tersebut dan memberikannya pada orang itu. Orang-orang berkata pada orang itu; \"Demi Allah, kau berlaku kurang ajar. Kamu telah memintanya dia saat beliau memerlukannya, padahal kau tahu beliau tidak pernah menolak seorang peminta pun.\" Orang itu berkata; \"Demi Allah, aku tidak memintanya melainkan untuk aku jadikan sebagai kafanku pada saat aku meninggal.\" Sahal berkata; \"Maka selimut itu dijadikan kafannya saat ia meninggal.\""},"5059":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي سَعِيدُ بْنُ الْمُسَيَّبِ أَنَّ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَدْخُلُ الْجَنَّةَ مِنْ أُمَّتِي زُمْرَةٌ هِيَ سَبْعُونَ أَلْفًا تُضِيءُ وُجُوهُهُمْ إِضَاءَةَ الْقَمَرِ فَقَامَ عُكَاشَةُ بْنُ مِحْصَنٍ الْأَسَدِيُّ يَرْفَعُ نَمِرَةً عَلَيْهِ قَالَ ادْعُ اللَّهَ لِي يَا رَسُولَ اللَّهِ أَنْ يَجْعَلَنِي مِنْهُمْ فَقَالَ اللَّهُمَّ اجْعَلْهُ مِنْهُمْ ثُمَّ قَامَ رَجُلٌ مِنْ الْأَنْصَارِ فَقَالَ يَا رَسُولَ اللَّهِ ادْعُ اللَّهَ أَنْ يَجْعَلَنِي مِنْهُمْ فَقَالَ رَسُولُ اللَّهِ سَبَقَكَ عُكَاشَةُ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; telah menceritakan kepadaku [Sa'id bin Al Musayyab] bahwa [Abu Hurairah] radliallahu 'anhu berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ada satu rombongan dari umatku yang akan masuk surga, jumlah mereka tujuh puluh ribu, wajah mereka bersinar seperti rembulan di malam purnama, \" lalu Ukasyah bin Mihshan Al Asadi mengangkat namirah (semacam kain wool) yang ia kenakan seraya berkata; \"Wahai Rasulullah, do'akanlah aku agar termasuk dari mereka, \" maka beliau bersabda: \"Ya Allah, jadikanlah ia termasuk dari mereka, \" kemudian seorang laki-laki dari Anshar bangun dan berkata; \"Wahai Rasulullah, do'akanlah aku agar termasuk dari mereka, \" maka beliau bersabda: \"Engkau telah didahului Ukasyah.\""},"5060":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَاصِمٍ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَ قُلْتُ لَهُأَيُّ الثِّيَابِ كَانَ أَحَبَّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَلْبَسَهَا قَالَ الْحِبَرَةُ","id":"Telah menceritakan kepada kami ['Amru bin 'Ashim] telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Anas], (Qatadah) bertanya kepadanya; \"Pakaian apakah yang paling disukai Nabi shallallahu 'alaihi wasallam?\" dia menjawab; \"Al hibarah (kain yang direnda atau bergaris).\""},"5061":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي الْأَسْوَدِ حَدَّثَنَا مُعَاذٌ قَالَ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ أَحَبُّ الثِّيَابِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَلْبَسَهَا الْحِبَرَةَ","id":"Telah menceritakan kepadaku [Abdullah bin Abu Al Aswad] telah menceritakan kepada kami [Mu'adz] dia berkata; telah menceritakan kepadaku [Ayahku] dari [Qatadah] dari [Anas bin Malik] radliallahu 'anhu dia berkata; \"Pakaian yang paling disukai oleh Nabi shallallahu 'alaihi wasallam adalah memakai hibarah (kain yang direnda atau bergaris).\""},"5062":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ تُوُفِّيَ سُجِّيَ بِبُرْدٍ حِبَرَةٍ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku [Abu Salamah bin Abdurrahman bin Auf] bahwa [Aisyah] radliallahu 'anha isteri Nabi shallallahu 'alaihi wasallam telah mengabarkan kepadanya bahwa ketika Rasulullah shallallahu 'alaihi wasallam meninggal dunia, beliau ditutupi dengan kain hibarah (kain yang direnda atau bergaris)."},"5063":{"ar":"حَدَّثَنِي يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّ عَائِشَةَ وَعَبْدَ اللَّهِ بْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمْ قَالَالَمَّا نَزَلَ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَفِقَ يَطْرَحُ خَمِيصَةً لَهُ عَلَى وَجْهِهِ فَإِذَا اغْتَمَّ كَشَفَهَا عَنْ وَجْهِهِ فَقَالَ وَهُوَ كَذَلِكَ لَعْنَةُ اللَّهِ عَلَى الْيَهُودِ وَالنَّصَارَى اتَّخَذُوا قُبُورَ أَنْبِيَائِهِمْ مَسَاجِدَ يُحَذِّرُ مَا صَنَعُوا","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dia berkata; telah mengabarkan kepadaku ['Ubaidullah bin Abdullah bin 'Utbah] bahwa [Aisyah] dan [Abdullah bin Abbas] radliallahu 'anhum berkata; \"Tatkala diturunkan kepada Rasulullah Shallallahu'alaihi wasallam (penyakit yang mengakibatkan kematiannya) maka beliau menutupkan kain di wajahnya, ketika beliau tidak bisa keluar maka beliau membuka selimutnya dari wajahnya. Lalu beliau bersabda: \"Allah melaknat orang-orang Yahudi dan Nasrani yang telah menjadikan kuburan nabi-nabi mereka sebagai masjid.\" Beliau memberi peringatan atas perbuatan mereka.\""},"5064":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ حَدَّثَنَا ابْنُ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي خَمِيصَةٍ لَهُ لَهَا أَعْلَامٌ فَنَظَرَ إِلَى أَعْلَامِهَا نَظْرَةً فَلَمَّا سَلَّمَ قَالَ اذْهَبُوا بِخَمِيصَتِي هَذِهِ إِلَى أَبِي جَهْمٍ فَإِنَّهَا أَلْهَتْنِي آنِفًا عَنْ صَلَاتِي وَأْتُونِي بِأَنْبِجَانِيَّةِ أَبِي جَهْمِ بْنِ حُذَيْفَةَ بْنِ غَانِمٍ مِنْ بَنِي عَدِيِّ بْنِ كَعْبٍ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Ibrahim bin Sa'd] telah menceritakan kepada kami [Ibnu Syihab] dari ['Urwah] dari [Aisyah] dia berkata; Rasulullah shallallahu 'alaihi wasallam pernah shalat dengan mengenakan pakaian bercorak (bergaris atau berbatik), lalu beliau melihat corak tersebut (ketika shalat), seusai salam beliau Shallallahu'alaihi wasallam bersabda: 'Pergilah kalian dengan pakaianku ini kepada Abu Jahm, karena ia telah mengganggu shalatku tadi, dan ambilkan untukku baju lain yang tidak bercorak atau berbatik milik Abu Jahm bin Hudzaifah bin Ghanim dari Bani 'Adi bin Ka'b.\""},"5065":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا أَيُّوبُ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ أَبِي بُرْدَةَ قَالَ أَخْرَجَتْ إِلَيْنَا عَائِشَةُكِسَاءً وَإِزَارًا غَلِيظًا فَقَالَتْ قُبِضَ رُوحُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَيْنِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Isma'il] telah menceritakan kepada kami [Ayyub] dari [Humaid bin Hilal] dari [Abu Burdah] dia berkata; [Aisyah] penah mengeluarkan pakaian dan kain sarung yang kasar, lalu dia berkata; \"Ruhnya Nabi shallallahu 'alaihi wasallam diambil ketika beliau mengenakan dua kain ini.\""},"5066":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ خُبَيْبٍ عَنْ حَفْصِ بْنِ عَاصِمٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمُلَامَسَةِ وَالْمُنَابَذَةِ وَعَنْ صَلَاتَيْنِ بَعْدَ الْفَجْرِ حَتَّى تَرْتَفِعَ الشَّمْسُ وَبَعْدَ الْعَصْرِ حَتَّى تَغِيبَ وَأَنْ يَحْتَبِيَ بِالثَّوْبِ الْوَاحِدِ لَيْسَ عَلَى فَرْجِهِ مِنْهُ شَيْءٌ بَيْنَهُ وَبَيْنَ السَّمَاءِ وَأَنْ يَشْتَمِلَ الصَّمَّاءَ","id":"Telah menceritakan kepadaku [Muhammad bin Basyar] telah menceritakan kepada kami [Abdul Wahab] telah menceritakan kepada kami ['Ubaidullah] dari [Khubaib] dari [Hafsh bin 'Ashim] dari [Abu Hurairah] radliallahu 'anhu dia berkata; Nabi shallallahu 'alaihi wasallam melarang (praktek jual beli) dengan system Mulamasah (wajib membeli jika ada pembeli yang menyentuh barang penjual) dan Munabadzah (wajib membeli jika ada penjual yang melempar dagangannya ke pembeli tanpa memeriksa terlebih dahulu), dan melarang shalat (sunnah) setelah subuh hingga matahari meninggi dan shalat setelah Ashar hingga matahari terbenam, dan melarang duduk ihtiba' (dengan menekuk kedua lututnya dan menempelkan ke dadanya) dengan mengenakan satu kain yang menengadahkan kemaluannya ke langit, dan melarang isytimalus shama' (seseorang berselimut dengan bajunya dan tidak memberikan celah sedikitpun, hingga jika tersingkap auratnya rawan terbuka)."},"5067":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عَامِرُ بْنُ سَعْدٍ أَنَّ أَبَا سَعِيدٍ الْخُدْرِيَّ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ لِبْسَتَيْنِ وَعَنْ بَيْعَتَيْنِ نَهَى عَنْ الْمُلَامَسَةِ وَالْمُنَابَذَةِ فِي الْبَيْعِ وَالْمُلَامَسَةُ لَمْسُ الرَّجُلِ ثَوْبَ الْآخَرِ بِيَدِهِ بِاللَّيْلِ أَوْ بِالنَّهَارِ وَلَا يُقَلِّبُهُ إِلَّا بِذَلِكَ وَالْمُنَابَذَةُ أَنْ يَنْبِذَ الرَّجُلُ إِلَى الرَّجُلِ بِثَوْبِهِ وَيَنْبِذَ الْآخَرُ ثَوْبَهُ وَيَكُونَ ذَلِكَ بَيْعَهُمَا عَنْ غَيْرِ نَظَرٍ وَلَا تَرَاضٍ وَاللِّبْسَتَيْنِ اشْتِمَالُ الصَّمَّاءِ وَالصَّمَّاءُ أَنْ يَجْعَلَ ثَوْبَهُ عَلَى أَحَدِ عَاتِقَيْهِ فَيَبْدُو أَحَدُ شِقَّيْهِ لَيْسَ عَلَيْهِ ثَوْبٌ وَاللِّبْسَةُ الْأُخْرَى احْتِبَاؤُهُ بِثَوْبِهِ وَهُوَ جَالِسٌ لَيْسَ عَلَى فَرْجِهِ مِنْهُ شَيْءٌ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [AL Laits] dari [Yunus] dari [Ibnu Syihab] dia berkata; telah mengabarkan kepadaku ['Amir bin Sa'd] bahwa [Abu Sa'id Al khudri] berkata; Rasulullah shallallahu 'alaihi wasallam melarang mengenakan dua pakaian dan dua transaksi jual beli, melarang mulamasah dan munabadzah dalam jual beli, sedangkan mulamasah adalah seseorang yang memegang pakaian orang lain pada malam hari atau siang hari dan tidak membalikkannya (memeriksanya) kecuali dengan itu, dan Munabadzah ialah seseorang melempar pakaiannya ke orang lain dan sebaliknya, lalu terjadilah transaksi jual beli tanpa boleh memeriksa dan juga kerelaan dari dua belah ihak. dan melarang mengenakan dua pakaian yaitu isytimalus shama', shama' ialah meletakkan (menggantungkan) pakaiannya disalah satu pundaknya dan membuka salah satu betisnya tanpa mengenakan pakaian (dalam) lainnya, dan yang lain adalah menutup (seluruh badannya) dengan kainnya sambil duduk, sementara kemaluannya tidak mengenakan apa-apa.\""},"5068":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ لِبْسَتَيْنِ أَنْ يَحْتَبِيَ الرَّجُلُ فِي الثَّوْبِ الْوَاحِدِ لَيْسَ عَلَى فَرْجِهِ مِنْهُ شَيْءٌ وَأَنْ يَشْتَمِلَ بِالثَّوْبِ الْوَاحِدِ لَيْسَ عَلَى أَحَدِ شِقَّيْهِ وَعَنْ الْمُلَامَسَةِ وَالْمُنَابَذَةِ","id":"Telah menceritakan kepada kami [Isma'il] dia berkata; telah menceritakan kepadaku [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] radliallahu 'anhu dia berkata; Rasulullah shallallahu 'alaihi wasallam melarang mengenakan dua kain yaitu seseorang menutup seluruh badannya dengan kain (sarung) nya sementara kemaluannya tidak ditutupi (dengan sesuatu yang lain) dan berselimutkan kain tanpa menutup salah satu dari betisnya, dan melarang mulamasah (wajib membeli jika ada pembeli yang menyentuh barang penjual) dan Munabadzah (wajib membeli jika ada penjual yang melempar dagangannya ke pembeli tanpa memeriksa terlebih dahulu), "},"5069":{"ar":"حَدَّثَنِي مُحَمَّدٌ قَالَ أَخْبَرَنِي مَخْلَدٌ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي ابْنُ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ اشْتِمَالِ الصَّمَّاءِ وَأَنْ يَحْتَبِيَ الرَّجُلُ فِي ثَوْبٍ وَاحِدٍ لَيْسَ عَلَى فَرْجِهِ مِنْهُ شَيْءٌ","id":"Telah menceritakan kepadaku [Muhammad] dia berkata; telah mengabarkan kepadaku [Makhlad] telah mengabarkan kepada kami [Ibnu Juraij] dia berkata; telah mengabarkan kepadaku [Ibnu Syihab] dari ['Ubaidullah bin Abdullah] dari [Abu Sa'id Al Khudri] radliallahu 'anhu bahwa Nabi shallallahu 'alaihi wasallam melarang isytimalus shama' (seseorang berselimut dengan bajunya dan tidak memberikan celah sedikitpun, hingga jika tersingkap auratnya rawan terbuka) dan seseorang yang berselimutkan kain satu lembar tanpa mengenakan kemaluannya dengan kain yang lain.\""},"5070":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا إِسْحَاقُ بْنُ سَعِيدٍ عَنْ أَبِيهِ سَعِيدِ بْنِ فُلَانٍ هُوَ عَمْرُو بْنُ سَعِيدِ بْنِ الْعَاصِ عَنْ أُمِّ خَالِدٍ بِنْتِ خَالِدٍأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِثِيَابٍ فِيهَا خَمِيصَةٌ سَوْدَاءُ صَغِيرَةٌ فَقَالَ مَنْ تَرَوْنَ أَنْ نَكْسُوَ هَذِهِ فَسَكَتَ الْقَوْمُ قَالَ ائْتُونِي بِأُمِّ خَالِدٍ فَأُتِيَ بِهَا تُحْمَلُ فَأَخَذَ الْخَمِيصَةَ بِيَدِهِ فَأَلْبَسَهَا وَقَالَ أَبْلِي وَأَخْلِقِي وَكَانَ فِيهَا عَلَمٌ أَخْضَرُ أَوْ أَصْفَرُ فَقَالَ يَا أُمَّ خَالِدٍ هَذَا سَنَاهْ وَسَنَاهْ بِالْحَبَشِيَّةِ حَسَنٌ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Ishaq bin Sa'id] dari ayahnya [Sa'id bin Fulan] yaitu 'Amru bin Sa'id bin Al 'Ash dari [Ummu Khalid binti Khalid] bahwa Nabi shallallahu 'alaihi wasallam pernah diberi kain kecil yang ada renda suteranya. Lalu beliau bertanya: \"Menurut kalian siapa yang paling berhak untuk mendapat kain ini?\", orang-orang pun diam. Beliau lalu bersabda: \"Datangkanlah Ummu Khalid kepadaku.\" Beliau lantas memberikan kain tersebut dan memakaikannya kepadanya. Setelah itu beliau bersabda: 'Semoga tahan lama hingga Allah menggantinya dengan yang baru (panjang umur).' Beliau kemudian melihat corak berwarna hijau atau kuning yang ada pada kain bersulam sutera tersebut, beliau bersabda: \"Wahai Ummu Khalid, ini sanah, sanah.\" Sanah adalah perkataan bahasa Habasyah yang berarti bagus.\""},"5071":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنِي ابْنُ أَبِي عَدِيٍّ عَنْ ابْنِ عَوْنٍ عَنْ مُحَمَّدٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا وَلَدَتْ أُمُّ سُلَيْمٍ قَالَتْ لِي يَا أَنَسُ انْظُرْ هَذَا الْغُلَامَ فَلَا يُصِيبَنَّ شَيْئًا حَتَّى تَغْدُوَ بِهِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحَنِّكُهُ فَغَدَوْتُ بِهِ فَإِذَا هُوَ فِي حَائِطٍ وَعَلَيْهِ خَمِيصَةٌ حُرَيْثِيَّةٌ وَهُوَ يَسِمُ الظَّهْرَ الَّذِي قَدِمَ عَلَيْهِ فِي الْفَتْحِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepadaku [Ibnu Abu 'Adi] dari [Ibnu 'Aun] dari [Muhammad] dari [Anas] radliallahu 'anhu dia berkata; Ketika Ummu Sulaim melahirkan, dia berkata kepadaku; \"Wahai Anas, lihatlah bayi kecil ini, dan jangan sampai ia mendapatkan sesuatu (untuk dimakan) sehingga besok pagi kita menemui nabi shallallahu 'alaihi wasallam supaya beliau mentahniknya (mengunyahkan buah kurma kemudian dimasukkan ke dalam mulut bayi), keesokan harinya aku bersamanya menemui Nabi, ketika itu beliau tengah berada di kebun, beliau mengenakan kain yang ada renda suteranya dan tengah membuat tanda pada binatang yang diberikan kepada beliau di hari penaklukan kota Makkah.\""},"5072":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الْوَهَّابِ أَخْبَرَنَا أَيُّوبُ عَنْ عِكْرِمَةَأَنَّ رِفَاعَةَ طَلَّقَ امْرَأَتَهُ فَتَزَوَّجَهَا عَبْدُ الرَّحْمَنِ بْنُ الزَّبِيرِ الْقُرَظِيُّ قَالَتْ عَائِشَةُ وَعَلَيْهَا خِمَارٌ أَخْضَرُ فَشَكَتْ إِلَيْهَا وَأَرَتْهَا خُضْرَةً بِجِلْدِهَا فَلَمَّا جَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنِّسَاءُ يَنْصُرُ بَعْضُهُنَّ بَعْضًا قَالَتْ عَائِشَةُ مَا رَأَيْتُ مِثْلَ مَا يَلْقَى الْمُؤْمِنَاتُ لَجِلْدُهَا أَشَدُّ خُضْرَةً مِنْ ثَوْبِهَا قَالَ وَسَمِعَ أَنَّهَا قَدْ أَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ وَمَعَهُ ابْنَانِ لَهُ مِنْ غَيْرِهَا قَالَتْ وَاللَّهِ مَا لِي إِلَيْهِ مِنْ ذَنْبٍ إِلَّا أَنَّ مَا مَعَهُ لَيْسَ بِأَغْنَى عَنِّي مِنْ هَذِهِ وَأَخَذَتْ هُدْبَةً مِنْ ثَوْبِهَا فَقَالَ كَذَبَتْ وَاللَّهِ يَا رَسُولَ اللَّهِ إِنِّي لَأَنْفُضُهَا نَفْضَ الْأَدِيمِ وَلَكِنَّهَا نَاشِزٌ تُرِيدُ رِفَاعَةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنْ كَانَ ذَلِكِ لَمْ تَحِلِّي لَهُ أَوْ لَمْ تَصْلُحِي لَهُ حَتَّى يَذُوقَ مِنْ عُسَيْلَتِكِ قَالَ وَأَبْصَرَ مَعَهُ ابْنَيْنِ لَهُ فَقَالَ بَنُوكَ هَؤُلَاءِ قَالَ نَعَمْ قَالَ هَذَا الَّذِي تَزْعُمِينَ مَا تَزْعُمِينَ فَوَاللَّهِ لَهُمْ أَشْبَهُ بِهِ مِنْ الْغُرَابِ بِالْغُرَابِ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abdul Wahhab] telah mengabarkan kepada kami [Ayyub] dari [Ikrimah] bahwa Rifa'ah telah menceraikan isterinya, kemudian isterinya menikah dengan Abdurrahman bin Zubair Al Qurdli, [Aisyah] berkata; \"Ketika itu mantan isteri Rifa'ah tengah mengenakan kerudung hijau, lalu mantan isteri Rifa'ah mengadukan permasalahannya kepada Aisyah, mantan isteri Rifaah memperlihatkan bekas hijau di kulitnya. Ketika Rasulullah shallallahu 'alaihi wasallam datang -kala itu para wanita membela satu sama lainnya. Kata 'Aisyah 'Sungguh yang kulihat padanya, seperti yang ditemui wanita mukminah lainnya, sungguh kulitnya jauh lebih hijau dari pada bajunya. Kata Ikrimah, tiba-tiba Abdurrahman datang bersama dua anaknya yang di hasilkan bukan dari isteri keduanya (mantan isteri Rifa'ah). Isterinya berkata; \"Demi Allah, tidaklah aku berdosa ketika bersamanya melainkan karena ia tidak dapat memuaskan diriku.\" Sambil memegang ujung kainnya. Abdurrahman berkata; \"Demi Allah, ia dusta wahai Rasulullah, sesungguhnya aku dapat memuaskannya, akan tetapi ia berbuat nusyuz (membangkang terhadap perintah suami) karena ia hendak kembali kepada Rifa'ah. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila seperti itu, maka kamu tidak halal bagi Rifa'ah atau tidak sah bagi Rifa'ah hingga ia (suami kedua) merasakan madumu.\" Ikrimah berkata; \"Lalu Abdurrahman memperlihatkan kedua anaknya, beliau pun bersabda: \"Apakah mereka semua anak-anakmu?\" Abdurrahman menjawab; \"Ya.\" Beliau bersabda: \"Demi Allah, ini adalah sesuatu yang kamu sangka? demi Allah, mereka lebih menyerupai dengan ayahnya dari pada burung gagak dengan induknya.\""},"5073":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ أَخْبَرَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا مِسْعَرٌ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِيهِ عَنْ سَعْدٍ قَالَرَأَيْتُ بِشِمَالِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيَمِينِهِ رَجُلَيْنِ عَلَيْهِمَا ثِيَابٌ بِيضٌ يَوْمَ أُحُدٍ مَا رَأَيْتُهُمَا قَبْلُ وَلَا بَعْدُ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim Al Hanzhali] telah mengabarkan kepada kami [Muhammad bin Bisyr] telah menceritakan kepada kami [Mis'ar] dari [Sa'd bin Ibrahim] dari [Ayahnya] dari [Sa'd] dia berkata; saya melihat di samping kanan dan kiri Nabi shallallahu 'alaihi wasallam dua orang laki-laki tengah mengenakan pakaian serba putih pada waktu perang Uhud, aku tidak pernah melihat sebelum dan sesudahnya.\""},"5074":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ الْحُسَيْنِ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ يَحْيَى بْنِ يَعْمَرَ حَدَّثَهُ أَنَّ أَبَا الْأَسْوَدِ الدُّؤَلِيَّ حَدَّثَهُ أَنَّ أَبَا ذَرٍّ رَضِيَ اللَّهُ عَنْهُ حَدَّثَهُ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْهِ ثَوْبٌ أَبْيَضُ وَهُوَ نَائِمٌ ثُمَّ أَتَيْتُهُ وَقَدْ اسْتَيْقَظَ فَقَالَ مَا مِنْ عَبْدٍ قَالَ لَا إِلَهَ إِلَّا اللَّهُ ثُمَّ مَاتَ عَلَى ذَلِكَ إِلَّا دَخَلَ الْجَنَّةَ قُلْتُ وَإِنْ زَنَى وَإِنْ سَرَقَ قَالَ وَإِنْ زَنَى وَإِنْ سَرَقَ قُلْتُ وَإِنْ زَنَى وَإِنْ سَرَقَ قَالَ وَإِنْ زَنَى وَإِنْ سَرَقَ قُلْتُ وَإِنْ زَنَى وَإِنْ سَرَقَ قَالَ وَإِنْ زَنَى وَإِنْ سَرَقَ عَلَى رَغْمِ أَنْفِ أَبِي ذَرٍّ وَكَانَ أَبُو ذَرٍّ إِذَا حَدَّثَ بِهَذَا قَالَ وَإِنْ رَغِمَ أَنْفُ أَبِي ذَرٍّقَالَ أَبُو عَبْد اللَّهِ هَذَا عِنْدَ الْمَوْتِ أَوْ قَبْلَهُ إِذَا تَابَ وَنَدِمَ وَقَالَ لَا إِلَهَ إِلَّا اللَّهُ غُفِرَ لَهُ","id":"Telah menceritakan kepada kami [Abu Ma'mar] telah menceritakan kepada kami [Abdul Warits] dari [Al Husain] dari [Abdullah bin Buraidah] dari [Yahya bin Ya'mar] dia menceritakan kepadanya bahwa [Abu Aswad Ad Du`ali] telah menceritakan kepadanya bahwa [Abu Dzar] radliallahu 'anhu telah menceritakan kepadanya, dia berkata; \"Saya pernah menemui Nabi shallallahu 'alaihi wasallam sementara beliau sedang tidur sambil mengenakan baju putih, lalu aku datang menemuinya dan beliau pun terbangun, beliau bersabda: \"Tidaklah seorang hamba yang mengucapkan \"LA ILAAHA ILLALLAH\" kemudian mati karena itu melainkan ia akan masuk surga.\" Tanyaku selanjutnya; \"Walaupun dia berzina dan mencuri?\" beliau menimpali: \"Walaupun dia pernah berzina dan mencuri.\" Tanyaku lagi; \"Walaupun dia pernah berzina dan mencuri?\" beliau menjawab: \"Walaupun dia pernah berzina dan mencuri.\" Tanyaku lagi; 'Walaupun dia pernah berzina dan mencuri?\" beliau menjawab: \"Walaupun dia pernah berzina dan mencuri.\" -walaupun sepertinya Abu Dzar kurang puas- Apabila Abu Dzar menceritakan hal ini, maka dia akan mengatakan; \"Walaupun\" sepertinya Abu Dzar kurang puas. Abu Abdullah mengatakan; \"Hal ini jika terjadi ketika seorang hamba itu meninggal atau sebelum dia meninggal lalu bertaubat dan menyesali perbuatannya serta mengucapkan \"LAA ILAAHA ILLALLAH\", maka dosa-dosanya akan terampuni.\""},"5075":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا قَتَادَةُ قَالَ سَمِعْتُ أَبَا عُثْمَانَ النَّهْدِيَّ أَتَانَا كِتَابُ عُمَرَوَنَحْنُ مَعَ عُتْبَةَ بْنِ فَرْقَدٍ بِأَذْرَبِيجَانَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْحَرِيرِ إِلَّا هَكَذَا وَأَشَارَ بِإِصْبَعَيْهِ اللَّتَيْنِ تَلِيَانِ الْإِبْهَامَ قَالَ فِيمَا عَلِمْنَا أَنَّهُ يَعْنِي الْأَعْلَامَ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Qatadah] dia berkata; saya mendengar [Abu Utsman An Nahdi] telah datang dengan membawa kitabnya [Umar] sementara kami waktu itu tengah bersama Utbah bin Farqad di Adrabijan bahwa Rasulullah shallallahu 'alaihi wasallam melarang mengenakan kain sutera kecuali hanya sebatas ini dan ini, dan beliau mengisyaratkan dengan kedua jarinya yaitu jari telunjuk dan jari tengah, Abu Utsman mengatakan; \"Sebagaimana yang kami ketahui yang di maksud itu adalah coraknya atau garis-garis.\""},"5076":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا عَاصِمٌ عَنْ أَبِي عُثْمَانَ قَالَ كَتَبَ إِلَيْنَا عُمَرُوَنَحْنُ بِأَذْرَبِيجَانَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ لُبْسِ الْحَرِيرِ إِلَّا هَكَذَا وَصَفَّ لَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِصْبَعَيْهِ وَرَفَعَ زُهَيْرٌ الْوُسْطَى وَالسَّبَّابَةَ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami ['Ashim] dari [Abu Utsman] dia berkata; [Umar] pernah mengirim surat kepada kami ketika kami berada di Adribijan bahwa Nabi shallallahu 'alaihi wasallam melarang mengenakan kain sutera kecuali hanya sebatas ini, dan Nabi shallallahu 'alaihi wasallam mengisyarakan dengan kedua jarinya, lalu Zuhair mengangkat jari telunjuk dan jari tengahnya.\""},"5077":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ التَّيْمِيِّ عَنْ أَبِي عُثْمَانَ قَالَكُنَّا مَعَ عُتْبَةَ فَكَتَبَ إِلَيْهِ عُمَرُ رَضِيَ اللَّهُ عَنْهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يُلْبَسُ الْحَرِيرُ فِي الدُّنْيَا إِلَّا لَمْ يُلْبَسْ فِي الْآخِرَةِ مِنْهُحَدَّثَنَا الْحَسَنُ بْنُ عُمَرَ حَدَّثَنَا مُعْتَمِرٌ حَدَّثَنَا أَبِي حَدَّثَنَا أَبُو عُثْمَانَ وَأَشَارَ أَبُو عُثْمَانَ بِإِصْبَعَيْهِ الْمُسَبِّحَةِ وَالْوُسْطَى","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [At Taimi] dari [Abu Utsman] dia berkata; \"Ketika kami tengah bersama Utbah, [Umar] radliallahu 'anhu menulis surat kepadanya bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Tidaklah seseorang mengenakan kain sutera ketika di dunia, melainkan tidak akan dikenakan kepadanya kelak di Akhirat.\" Telah menceritakan kepada kami [Al Hasan bin Umar] telah menceritakan kepada kami [Mu'tamir] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Abu Utsman] kemudian Abu Utsman mengisyaratkan dengan jari telunjuknya dan jari tengahnya.\""},"5078":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ ابْنِ أَبِي لَيْلَى قَالَ كَانَ حُذَيْفَةُبِالْمَدَايِنِ فَاسْتَسْقَى فَأَتَاهُ دِهْقَانٌ بِمَاءٍ فِي إِنَاءٍ مِنْ فِضَّةٍ فَرَمَاهُ بِهِ وَقَالَ إِنِّي لَمْ أَرْمِهِ إِلَّا أَنِّي نَهَيْتُهُ فَلَمْ يَنْتَهِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الذَّهَبُ وَالْفِضَّةُ وَالْحَرِيرُ وَالدِّيبَاجُ هِيَ لَهُمْ فِي الدُّنْيَا وَلَكُمْ فِي الْآخِرَةِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Ibnu Abu Laila] dia berkata; \"Ketika [Hudzaifah] berada di negeri Mada'in, dia meminta air minum, lalu Dihqan (kepala suku) memberinya air dari tempat yang terbuat dari perak, maka Hudzaifah langsung melemparnya sambil berkata; \"Sesungguhnya aku tidak melemparnya melainkan aku telah melarangnya, namun ia tidak juga jera (menggunakan tempat minum dari perak) padahal Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Emas, perak, kain sutera dan dibaj (campuran kain sutera) adalah milik mereka (orang-orang kafir) semasa di dunia, dan untuk kalian di Akhirat.\""},"5079":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ صُهَيْبٍ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ قَالَ شُعْبَةُ فَقُلْتُ أَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ شَدِيدًاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَنْ لَبِسَ الْحَرِيرَ فِي الدُّنْيَا فَلَنْ يَلْبَسَهُ فِي الْآخِرَةِ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Abdul Aziz bin Shuhaib] dia berkata; saya mendengar [Anas bin Malik], Syu'bah berkata; \"Tentang apakah nabi shallallahu 'alaihi wasallam marah?\" Anas menjawab; \"Nabi shallallahu 'alaihi wasallam sangat marah sekali, dia melanjutkan; \"yaitu barangsiapa mengenakan kain sutera di dunia, maka ia tidak akan memakainya di Akhirat kelak.\""},"5080":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ ثَابِتٍ قَالَ سَمِعْتُ ابْنَ الزُّبَيْرِ يَخْطُبُ يَقُولُقَالَ مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لَبِسَ الْحَرِيرَ فِي الدُّنْيَا لَمْ يَلْبَسْهُ فِي الْآخِرَةِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Tsabit] dia berkata; saya mendengar [Ibnu Zubair] berkhutbah, katanya; \"Muhammad shallallahu 'alaihi wasallam telah bersabda: \"Barangsiapa mengenakan kain sutera di dunia, maka ia tidak akan memakainya di Akhirat kelak.\""},"5081":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْجَعْدِ أَخْبَرَنَا شُعْبَةُ عَنْ أَبِي ذِبْيَانَ خَلِيفَةَ بْنِ كَعْبٍ قَالَ سَمِعْتُ ابْنَ الزُّبَيْرِ يَقُولُ سَمِعْتُ عُمَرَ يَقُولُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لَبِسَ الْحَرِيرَ فِي الدُّنْيَا لَمْ يَلْبَسْهُ فِي الْآخِرَةِوَقَالَ أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ يَزِيدَ قَالَتْ مُعَاذَةُ أَخْبَرَتْنِي أُمُّ عَمْرٍو بِنْتُ عَبْدِ اللَّهِ سَمِعْتُ عَبْدَ اللَّهِ بْنَ الزُّبَيْرِ سَمِعَ عُمَرَ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Ali bin Al Ja'd] telah mengabarkan kepada kami [Syu'bah] dari [Abu Dzibyan Khalifah bin Ka'b] dia berkata; saya mendengar [Ibnu Az Zubair] berkata; saya mendengar [Umar] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"barangsiapa mengenakan kain sutera di dunia, maka tidak akan dikenakan kepadanya di Akhirat kelak.\" [Abu Ma'mar] mengatakan; telah menceritakan kepada kami [Abdul Warits] dari [Yazid], [Mu'adzah] mengatakan; telah menceritakan kepadaku [Ummu 'Amru binti Abdullah] saya mendengar [Abdullah bin Zubair] mendengar [Umar] bahwa dia mendengar Nabi shallallahu 'alaihi wasallam seperti hadits di atas.\""},"5082":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا عَلِيُّ بْنُ الْمُبَارَكِ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عِمْرَانَ بْنِ حِطَّانَقَالَ سَأَلْتُ عَائِشَةَ عَنْ الْحَرِيرِ فَقَالَتْ ائْتِ ابْنَ عَبَّاسٍ فَسَلْهُ قَالَ فَسَأَلْتُهُ فَقَالَ سَلْ ابْنَ عُمَرَ قَالَ فَسَأَلْتُ ابْنَ عُمَرَ فَقَالَ أَخْبَرَنِي أَبُو حَفْصٍ يَعْنِي عُمَرَ بْنَ الْخَطَّابِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا يَلْبَسُ الْحَرِيرَ فِي الدُّنْيَا مَنْ لَا خَلَاقَ لَهُ فِي الْآخِرَةِ فَقُلْتُ صَدَقَ وَمَا كَذَبَ أَبُو حَفْصٍ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَوَقَالَ عَبْدُ اللَّهِ بْنُ رَجَاءٍ حَدَّثَنَا حَرْبٌ عَنْ يَحْيَى حَدَّثَنِي عِمْرَانُ وَقَصَّ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Utsman bin Umar] telah menceritakan kepada kami [Ali bin Al Mubarrak] dari [Yahya bin Abu Katsir] dari [Imran bin Hitthan] dia berkata; saya bertanya kepada Aisyah mengenai kain sutera, lalu dia berkata; datanglah kepada Ibnu Abbas dan bertanyalah kepadanya, Imran berkata; \"lalu aku bertanya kepada Ibnu Abbas, namun dia menjawab; \"Tanyakanlah kepada Ibnu Umar, Imran melanjutkan; \"Lalu saya bertanya kepada [Ibnu Umar], dia menjawab; telah mengabarkan kepadaku [Abu Hafsh Umar bin AL Khatthab] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hanya saja yang mengenakan kain sutera di dunia, yaitu orang yang tidak mendapatkan bagiannya di akhirat kelak.\" Maka kataku; \"Benar, dan Abu Hafsh tidak mungkin berdusta atas nama Rasulullah shallallahu 'alaihi wasallam.\" [Abdullah bin Raja`] mengatakan; telah menceritakan kepada kami [Harb] dari [Yahya] telah menceritakan kepadaku [Imran] lalu dia menceritakan hadits tersebut.\""},"5083":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَاقَ عَنْ الْبَرَاءِ رَضِيَ اللَّهُ عَنْهُ قَالَأُهْدِيَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَوْبُ حَرِيرٍ فَجَعَلْنَا نَلْمُسُهُ وَنَتَعَجَّبُ مِنْهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَعْجَبُونَ مِنْ هَذَا قُلْنَا نَعَمْ قَالَ مَنَادِيلُ سَعْدِ بْنِ مُعَاذٍ فِي الْجَنَّةِ خَيْرٌ مِنْ هَذَا","id":"Telah menceritakan kepada kami [Abdullah bin Musa] dari [Isra`il] dari [Abu Ishaq] dari [Al Barra`] radliallahu 'anhu dia berkata; Nabi shallallahu 'alaihi wasallam diberi hadiah sepotong kain sutera, kamipun memegangnya dan merasa heran dengan kain tersebut, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Apakah kalian heran dengan kain ini?\" kami menjawab; \"Ya.\" Beliau bersabda: \"Saputangan Mu'adz di surga lebih bagus dari pada ini.\""},"5084":{"ar":"حَدَّثَنَا عَلِيٌّ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا أَبِي قَالَ سَمِعْتُ ابْنَ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ أَبِي لَيْلَى عَنْ حُذَيْفَةَ رَضِيَ اللَّهُ عَنْهُ قَالَنَهَانَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَشْرَبَ فِي آنِيَةِ الذَّهَبِ وَالْفِضَّةِ وَأَنْ نَأْكُلَ فِيهَا وَعَنْ لُبْسِ الْحَرِيرِ وَالدِّيبَاجِ وَأَنْ نَجْلِسَ عَلَيْهِ","id":"Telah menceritakan kepada kami [Ali] telah menceritakan kepada kami [Wahb bin Jarir] telah menceritakan kepada kami [Ayahku] dia berkata; saya mendengar [Ibnu Abu Najih] dari [Mujahid] dari [Ibnu Abu Laila] dari [Hudzaifah] radliallahu 'anhu dia berkata; \"Nabi shallallahu 'alaihi wasallam melarang kami minum dari tempat yang terbuat dari emas dan perak, beliau juga melarang kami makan dari tempat tersebut, memakai kain sutera dan dibaj (kain sutera campuran) serta melarang duduk di atas kain tersebut.\""},"5085":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا سُفْيَانُ عَنْ أَشْعَثَ بْنِ أَبِي الشَّعْثَاءِ حَدَّثَنَا مُعَاوِيَةُ بْنُ سُوَيْدِ بْنِ مُقَرِّنٍ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَنَهَانَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمَيَاثِرِ الْحُمْرِ وَالْقَسِّيِّ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Sufyan] dari [Asy'ats bin Abu Asy Sya'tsa'] telah menceritakan kepada kami [Mu'awiyah bin Suwaid bin Muqarrin] dari [Al Barra` bin 'Azib] dia berkata; \"Nabi shallallahu 'alaihi wasallam melarang kami mengenakan tirai yang terbuat dari sutera dan Qasiy (sutera campuran).\""},"5086":{"ar":"حَدَّثَنِي مُحَمَّدٌ أَخْبَرَنَا وَكِيعٌ أَخْبَرَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَرَخَّصَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلزُّبَيْرِ وَعَبْدِ الرَّحْمَنِ فِي لُبْسِ الْحَرِيرِ لِحِكَّةٍ بِهِمَا","id":"Telah menceritakan kepada kami [Muhammad] telah mengabarkan kepada kami [Waki'] telah mengabarkan kepada kami [Syu'bah] dari [Qatadah] dari [Anas] dia berkata; Nabi shallallahu 'alaihi wasallam pernah memberi izin kepada Zubair dan Abdurrahman untuk memakai kain sutera karena penyakit gatal yang dideritanya.\""},"5087":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ ح و حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْمَلِكِ بْنِ مَيْسَرَةَ عَنْ زَيْدِ بْنِ وَهْبٍ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ قَالَكَسَانِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُلَّةً سِيَرَاءَ فَخَرَجْتُ فِيهَا فَرَأَيْتُ الْغَضَبَ فِي وَجْهِهِ فَشَقَّقْتُهَا بَيْنَ نِسَائِي","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Syu'bah]. Dan diriwayatkan dari jalur lain, telah menceritakan kepadaku [Muhammad bin Basysyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Abdul Malik bin Maisarah] dari [Zaid bin Wahb] dari [Ali bin Abu Thalib] radliallahu 'anhu dia berkata; \"Nabi shallallahu 'alaihi wasallam memberiku sejenis mantel yang bersulam sutera, kemudian aku keluar dengan mengenakannya, namun aku melihat kemarahan di wajah beliau, maka baju itu kubagikan kepada para saudara-saudara perempuanku.\""},"5088":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ قَالَ حَدَّثَنِي جُوَيْرِيَةُ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِأَنَّ عُمَرَ رَضِيَ اللَّهُ عَنْهُ رَأَى حُلَّةَ سِيَرَاءَ تُبَاعُ فَقَالَ يَا رَسُولَ اللَّهِ لَوْ ابْتَعْتَهَا تَلْبَسُهَا لِلْوَفْدِ إِذَا أَتَوْكَ وَالْجُمُعَةِ قَالَ إِنَّمَا يَلْبَسُ هَذِهِ مَنْ لَا خَلَاقَ لَهُ وَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ بَعْدَ ذَلِكَ إِلَى عُمَرَ حُلَّةَ سِيَرَاءَ حَرِيرٍ كَسَاهَا إِيَّاهُ فَقَالَ عُمَرُ كَسَوْتَنِيهَا وَقَدْ سَمِعْتُكَ تَقُولُ فِيهَا مَا قُلْتَ فَقَالَ إِنَّمَا بَعَثْتُ إِلَيْكَ لِتَبِيعَهَا أَوْ تَكْسُوَهَا","id":"Telah menceritakan kepada kami [Musa bin Isma'il] dia berkata; telah menceritakan kepadaku [Juwairiyah] dari [Nafi'] dari [Abdullah] bahwa Umar radliallahu 'anhu pernah melihat sejenis mantel yang bersulam sutera dijual, lalu dia berkata; \"Wahai Rasulullah, andaikan baginda mau membelinya dan memakainya untuk menemui para utusan ketika berkunjung menemui anda atau untuk dikenakan waktu shalat Jum'at.\" Beliau lalu bersabda: \"Yang memakai pakaian ini hanyalah mereka yang tidak mendapatkan bagian di akhirat.\" Hari berikutnya beliau memberi Umar sejenis mantel yang terbuat dari sutera, Umar pun protes; \"Wahai Rasulullah! Anda memberikannya kepadaku padahal anda berujar tidak boleh memakainya.\" Beliau menjawab: \"Saya memberikan kepadamu bukan untuk dipakai, tetapi agar kamu jual atau kamu berikan kepada istrimu.\""},"5089":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي أَنَسُ بْنُ مَالِكٍأَنَّهُ رَأَى عَلَى أُمِّ كُلْثُومٍ عَلَيْهَا السَّلَام بِنْتِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بُرْدَ حَرِيرٍ سِيَرَاءَ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku [Anas bin Malik] bahwa dia pernah melihat Ummu Kultsum 'alaiha salam puteri Rasulullah shallallahu 'alaihi wasallam mengenakan kain yang bersulam sutera.\""},"5090":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عُبَيْدِ بْنِ حُنَيْنٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَبِثْتُ سَنَةً وَأَنَا أُرِيدُ أَنْ أَسْأَلَ عُمَرَ عَنْ الْمَرْأَتَيْنِ اللَّتَيْنِ تَظَاهَرَتَا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَعَلْتُ أَهَابُهُ فَنَزَلَ يَوْمًا مَنْزِلًا فَدَخَلَ الْأَرَاكَ فَلَمَّا خَرَجَ سَأَلْتُهُ فَقَالَ عَائِشَةُ وَحَفْصَةُ ثُمَّ قَالَ كُنَّا فِي الْجَاهِلِيَّةِ لَا نَعُدُّ النِّسَاءَ شَيْئًا فَلَمَّا جَاءَ الْإِسْلَامُ وَذَكَرَهُنَّ اللَّهُ رَأَيْنَا لَهُنَّ بِذَلِكَ عَلَيْنَا حَقًّا مِنْ غَيْرِ أَنْ نُدْخِلَهُنَّ فِي شَيْءٍ مِنْ أُمُورِنَا وَكَانَ بَيْنِي وَبَيْنَ امْرَأَتِي كَلَامٌ فَأَغْلَظَتْ لِي فَقُلْتُ لَهَا وَإِنَّكِ لَهُنَاكِ قَالَتْ تَقُولُ هَذَا لِي وَابْنَتُكَ تُؤْذِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَيْتُ حَفْصَةَ فَقُلْتُ لَهَا إِنِّي أُحَذِّرُكِ أَنْ تَعْصِي اللَّهَ وَرَسُولَهُ وَتَقَدَّمْتُ إِلَيْهَا فِي أَذَاهُ فَأَتَيْتُ أُمَّ سَلَمَةَ فَقُلْتُ لَهَا فَقَالَتْ أَعْجَبُ مِنْكَ يَا عُمَرُ قَدْ دَخَلْتَ فِي أُمُورِنَا فَلَمْ يَبْقَ إِلَّا أَنْ تَدْخُلَ بَيْنَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَزْوَاجِهِ فَرَدَّدَتْ وَكَانَ رَجُلٌ مِنْ الْأَنْصَارِ إِذَا غَابَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَشَهِدْتُهُ أَتَيْتُهُ بِمَا يَكُونُ وَإِذَا غِبْتُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَشَهِدَ أَتَانِي بِمَا يَكُونُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ مَنْ حَوْلَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ اسْتَقَامَ لَهُ فَلَمْ يَبْقَ إِلَّا مَلِكُ غَسَّانَ بِالشَّأْمِ كُنَّا نَخَافُ أَنْ يَأْتِيَنَا فَمَا شَعَرْتُ إِلَّا بِالْأَنْصَارِيِّ وَهُوَ يَقُولُ إِنَّهُ قَدْ حَدَثَ أَمْرٌ قُلْتُ لَهُ وَمَا هُوَ أَجَاءَ الْغَسَّانِيُّ قَالَ أَعْظَمُ مِنْ ذَاكَ طَلَّقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِسَاءَهُ فَجِئْتُ فَإِذَا الْبُكَاءُ مِنْ حُجَرِهِنَّ كُلِّهَا وَإِذَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ صَعِدَ فِي مَشْرُبَةٍ لَهُ وَعَلَى بَابِ الْمَشْرُبَةِ وَصِيفٌ فَأَتَيْتُهُ فَقُلْتُ اسْتَأْذِنْ لِي فَأَذِنَ لِي فَدَخَلْتُ فَإِذَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى حَصِيرٍ قَدْ أَثَّرَ فِي جَنْبِهِ وَتَحْتَ رَأْسِهِ مِرْفَقَةٌ مِنْ أَدَمٍ حَشْوُهَا لِيفٌ وَإِذَا أُهُبٌ مُعَلَّقَةٌ وَقَرَظٌ فَذَكَرْتُ الَّذِي قُلْتُ لِحَفْصَةَ وَأُمِّ سَلَمَةَ وَالَّذِي رَدَّتْ عَلَيَّ أُمُّ سَلَمَةَ فَضَحِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَبِثَ تِسْعًا وَعِشْرِينَ لَيْلَةً ثُمَّ نَزَلَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Yahya bin Sa'id] dari ['Ubaid bin Hunain] dari [Ibnu Abbas] radliallahu 'anhuma dia berkata; telah setahun lamanya saya hendak bertanya kepada [Umar bin Khattab] tentang dua isteri Nabi shallallahu 'alaihi wasallam yang bersekongkol menentang kebijaksanaan beliau, tiba-tiba aku merasa segan kepadanya. Suatu hari, ia singgah di suatu tempat, lalu dia masuk ke semak-semak (untuk buang hajat), ketika dia keluar, akupun langsung menanyakan hal itu kepadanya, dia menjawab; \"Mereka adalah Aisyah dan Hafshah.\" Lalu dia melanjutkan kisahnya; Di masa Jahiliyah dulu, kami tidak pernah mengikut sertakan wanita dalam suatu urusan, namun ketika Islam datang, sehingga Allah menyebutkan kebenaran peranan mereka atas kami daripada kami tidak mengikut sertakan mereka pada urusan kami, suatu ketika terjadi percekcokan antara aku dan istriku yang menyebabkan istriku bersikeras kepadaku, maka kukatakan padanya; \"Kamu tidak usah ikut campur memikirkan urusanku.\" istriku berkata; \"Kamu mengatakan seperti ini! Padahal putrimu tengah menyakiti hati Nabi shallallahu 'alaihi wasallam.\" kemudian saya pergi menemui Hafshah dan bertanya kepadanya; \"Sesungguhnya aku memperingatimu, betulkah kamu telah bermaksiat kepada Allah dan Rasul-Nya (maksudnya membantah Nabi)? Lalu aku pun memperingatkan kepadanya akibat dari menyakiti nabi. Kemudian saya menemui Ummu Salamah, dan kuceritakan (kasus tersebut) kepadanya; maka dia berkata kepadaku; \"Sungguh aneh kamu wahai Umar, kamu telah mencampuri segala urusan sampai kepada urusan rumah tangga Rasulullah shallallahu 'alaihi wasallam dan para istrinya.\" perkataan (Ummu Salamah) sangat menyinggung perasaanku. Dan saya memiliki seorang sahabat dari Anshar, apabila dia tidak hadir dari Rasulullah shallallahu 'alaihi wasallam sementara aku hadir, maka aku menemuinya dan memberitahukannya sesuatu yang kudapat dari beliau, begitu sebaliknya, bila saya tidak hadir dari Rasulullah shallallahu 'alaihi wasallam sedangkan dia hadir, maka dia akan menemuiku dan menyampaikan apa yang ia dapat dari Rasulullah shallallahu 'alaihi wasallam. Ketika itu kami sedang berjaga-jaga di sekitar Rasulullah shallallahu 'alaihi wasallam dari raja Ghassan yang berada di Syam, kami sangat khawatir bila raja Ghassan tiba-tiba menyerang kami. Hati kami waktu itu terpusat (pada serangan tersebut), tiba-tiba sahabat Ansharku datang sambil berkata; \"Telah terjadi suatu perkara yang penting!.\" Aku pun bertanya kepadanya; \"apakah perkara itu? Apakah pasukan Ghassan telah datang? Dia menjawab; bahkan lebih dari itu, Rasulullah shallallahu 'alaihi wasallam telah menceraikan para istri beliau.\" Maka aku pun datang, dan aku mendengarkan tangisan dari kamar-kamar mereka (isteri Nabi) sementara Nabi shallallahu 'alaihi wasallam tengah berada di suatu ruangan yang dapat naik dengan tangga, dan pelayan beliau berada di depan ruangan itu, lalu saya mendatanginya dan berkata; \"Izinkanlah saya!.\" Lalu beliau memberi izin, setelah itu saya masuk, tiba-tiba saya melihat Nabi shallallahu 'alaihi wasallam berada di atas alas, terlihat jelas bekas tikar pada pinggang beliau dan di bawah kepala beliau terdapat bantal kulit yang terbuat dari sabut, sementara dekat kepalanya tergantung kulit yang baru disamak. Setelah itu aku sampaikan ucapanku terhadap Hafshah dan Ummu Salamah, serta jawaban Ummu Salamah terhadapku, mendengar itu Rasulullah shallallahu 'alaihi wasallam tersenyum, akhirnya beliau menetap di ruangan itu selama dua sembilan hari, setelah itu beliau turun.\""},"5091":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا هِشَامٌ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ أَخْبَرَتْنِي هِنْدُ بِنْتُ الْحَارِثِ عَنْ أُمِّ سَلَمَةَ قَالَتْاسْتَيْقَظَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ اللَّيْلِ وَهُوَ يَقُولُ لَا إِلَهَ إِلَّا اللَّهُ مَاذَا أُنْزِلَ اللَّيْلَةَ مِنْ الْفِتْنَةِ مَاذَا أُنْزِلَ مِنْ الْخَزَائِنِ مَنْ يُوقِظُ صَوَاحِبَ الْحُجُرَاتِ كَمْ مِنْ كَاسِيَةٍ فِي الدُّنْيَا عَارِيَةٍ يَوْمَ الْقِيَامَةِقَالَ الزُّهْرِيُّ وَكَانَتْ هِنْدٌ لَهَا أَزْرَارٌ فِي كُمَّيْهَا بَيْنَ أَصَابِعِهَا","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] telah menceritakan kepada kami [Hisyam] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] telah mengabarkan kepadaku [Hindun binti Al Harits] dari [Ummu Salamah] dia berkata; \"Pada suatu malam Nabi shallahu'alaihi wa sallam bangun sambil menuturkan; 'Tiada ilah kecuali Allah, fitnah apakah yang diturunkan di malam hari? Dan perbendaharaan apakah yang diturunkan pada orang yang membangunkan para penghuni kamar, dan berapa banyak orang yang mengenakan pakaian di dunia, tapi telanjang di akhirat.\""},"5092":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا إِسْحَاقُ بْنُ سَعِيدِ بْنِ عَمْرِو بْنِ سَعِيدِ بْنِ الْعَاصِ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَتْنِي أُمُّ خَالِدٍ بِنْتُ خَالِدٍ قَالَتْأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِثِيَابٍ فِيهَا خَمِيصَةٌ سَوْدَاءُ قَالَ مَنْ تَرَوْنَ نَكْسُوهَا هَذِهِ الْخَمِيصَةَ فَأُسْكِتَ الْقَوْمُ قَالَ ائْتُونِي بِأُمِّ خَالِدٍ فَأُتِيَ بِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَلْبَسَنِيهَا بِيَدِهِ وَقَالَ أَبْلِي وَأَخْلِقِي مَرَّتَيْنِ فَجَعَلَ يَنْظُرُ إِلَى عَلَمِ الْخَمِيصَةِ وَيُشِيرُ بِيَدِهِ إِلَيَّ وَيَقُو��ُ يَا أُمَّ خَالِدٍ هَذَا سَنَا وَيَا أُمَّ خَالِدٍ هَذَا سَنَا وَالسَّنَا بِلِسَانِ الْحَبَشِيَّةِ الْحَسَنُ قَالَ إِسْحَاقُ حَدَّثَتْنِي امْرَأَةٌ مِنْ أَهْلِي أَنَّهَا رَأَتْهُ عَلَى أُمِّ خَالِدٍ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Ishaq bin Sa'id bin 'Amru bin Sa'id Al 'Ash] dia berkata; telah menceritakan kepadaku [Ayahku] telah menceritakan kepadaku [Ummu Khalid binti Khalid] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah diberi baju yang bersulam sutera, lalu beliau bersabda: \"Menurut kalian siapa yang paling berhak untuk memakai kain ini?\", orang-orang pun diam. Beliau lalu bersabda: \"Datangkanlah Ummu Khalid kepadaku.\" Beliau lantas memberikan kain tersebut dan memakaikannya kepadanya. Setelah itu beliau bersabda: 'Semoga tahan lama hingga Allah menggantinya dengan yang baru (panjang umur).' Beliau mengatakannya hingga dua kali, lalu beliau melihat corak warna baju itu, sambil menunjukkan tangannya kepadaku beliau bersabda: \"Wahai Ummu Khalid, ini sanah, wahai Ummu Khalid ini sanah.\" Sanah bagai orang-orang Habasyah bermakna bagus.\" Ishaq mengatakan; telah menceritakan kepadaku seorang wanita dari keluargaku bahwa dia pernah melihat Ummu Khalid mengenakan pakaian tersebut.\""},"5093":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ عَبْدِ الْعَزِيزِ عَنْ أَنَسٍ قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَتَزَعْفَرَ الرَّجُلُ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abdul Warits] dari [Abdul Aziz] dari [Anas] dia berkata; Nabi shallallahu 'alaihi wasallam melarang seorang laki-laki memakai minyak za'faran."},"5094":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَلْبَسَ الْمُحْرِمُ ثَوْبًا مَصْبُوغًا بِوَرْسٍ أَوْ بِزَعْفَرَانٍ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Abdullah bin Dinar] dari [Ibnu Umar] radliallahu 'anhuma dia berkata; \"Nabi shallallahu 'alaihi wasallam melarang orang yang berihram mengenakan pakaian yang diwarnai dengan wars (sejenis tanaman yang barbau harum dan berwarna kuning) atau dengan minyak za'faran.\""},"5095":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ سَمِعَ الْبَرَاءَ رَضِيَ اللَّهُ عَنْهُ يَقُولُكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرْبُوعًا وَقَدْ رَأَيْتُهُ فِي حُلَّةٍ حَمْرَاءَ مَا رَأَيْتُ شَيْئًا أَحْسَنَ مِنْهُ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dia mendengar [Al Barra`] radliallahu 'anhu berkata; \"Rasulullah shallallahu 'alaihi wasallam adalah seorang laki-laki yang berperawakan sedang (tidak tinggi dan tidak pendek), saya melihat beliau mengenakan pakaian merah, dan saya tidak pernah melihat orang yang lebih bagus dari beliau.\""},"5096":{"ar":"حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ أَشْعَثَ عَنْ مُعَاوِيَةَ بْنِ سُوَيْدِ بْنِ مُقَرِّنٍ عَنْ الْبَرَاءِ رَضِيَ اللَّهُ عَنْهُ قَالَأَمَرَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِسَبْعٍ عِيَادَةِ الْمَرِيضِ وَاتِّبَاعِ الْجَنَائِزِ وَتَشْمِيتِ الْعَاطِسِ وَنَهَانَا عَنْ سَبْعٍ عَنْ لُبْسِ الْحَرِيرِ وَالدِّيبَاجِ وَالْقَسِّيِّ وَالْإِسْتَبْرَقِ وَالْمَيَاثِرِ الْحُمْرِ","id":"Telah menceritakan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari [Asy'ats] dari [Mu'awiyah bin Suwaid bin Muqarrin] dari [Al Barra'] radliallahu 'anhu dia berkata; \"Nabi shallallahu 'alaihi wasallam memerintahkan tujuh perkara diantaranya menjenguk orang sakit, mengiringi jenazah, mendo'akan orang yang bersin. Dan melarang tujuh perkara, yaitu memakai kain sutera, dibaj, Qasiy, istabraq, mayasir dan al humr (jenis kain sutera yang direnda).\""},"5097":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ سَعِيدٍ أَبِي مَسْلَمَةَ قَالَ سَأَلْتُ أَنَسًاأَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي نَعْلَيْهِ قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Sa'id Abu Maslamah] dia berkata; saya bertanya kepada [Anas] \"Apakah Nabi shallallahu 'alaihi wasallam pernah shalat dengan menggunakan sandal?\" Dia menjawab; 'Ya, pernah.'"},"5098":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ عُبَيْدِ بْنِ جُرَيْجٍ أَنَّهُ قَالَ لِعَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَارَأَيْتُكَ تَصْنَعُ أَرْبَعًا لَمْ أَرَ أَحَدًا مِنْ أَصْحَابِكَ يَصْنَعُهَا قَالَ مَا هِيَ يَا ابْنَ جُرَيْجٍ قَالَ رَأَيْتُكَ لَا تَمَسُّ مِنْ الْأَرْكَانِ إِلَّا الْيَمَانِيَيْنِ وَرَأَيْتُكَ تَلْبَسُ النِّعَالَ السِّبْتِيَّةَ وَرَأَيْتُكَ تَصْبُغُ بِالصُّفْرَةِ وَرَأَيْتُكَ إِذَا كُنْتَ بِمَكَّةَ أَهَلَّ النَّاسُ إِذَا رَأَوْا الْهِلَالَ وَلَمْ تُهِلَّ أَنْتَ حَتَّى كَانَ يَوْمُ التَّرْوِيَةِ فَقَالَ لَهُ عَبْدُ اللَّهِ بْنُ عُمَرَ أَمَّا الْأَرْكَانُ فَإِنِّي لَمْ أَرَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمَسُّ إِلَّا الْيَمَانِيَيْنِ وَأَمَّا النِّعَالُ السِّبْتِيَّةُ فَإِنِّي رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَلْبَسُ النِّعَالَ الَّتِي لَيْسَ فِيهَا شَعَرٌ وَيَتَوَضَّأُ فِيهَا فَأَنَا أُحِبُّ أَنْ أَلْبَسَهَا وَأَمَّا الصُّفْرَةُ فَإِنِّي رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْبُغُ بِهَا فَأَنَا أُحِبُّ أَنْ أَصْبُغَ بِهَا وَأَمَّا الْإِهْلَالُ فَإِنِّي لَمْ أَرَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُهِلُّ حَتَّى تَنْبَعِثَ بِهِ رَاحِلَتُهُ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Sa'id Al Maqburi] dari ['Ubaid bin Juraij] bahwa dia berkata kepada [Abdullah bin Umar] radliallahu 'anhuma; \"Aku melihatmu mengerjakan empat perkara yang belum pernah kulihat dari para sahabatmu melakukan hal itu.\" Ibnu Umar bertanya; 'Apa perkara itu wahai Ibnu Juraij? ' Ibnu Juraij menjawab; 'Aku melihatmu tidak menyentuh rukun kecuali dua rukun yamani, aku melihat engkau memakai sandal sibti (yang tidak berbulu), dan aku melihat engkau mencelup dengan shufrah (minyak yang terbuat dari campuran kunyit dan yang lainnya), dan aku melihat engkau apabila berada di Mekkah orang-orang bertalbiyah apabila melihat hilal sementara engkau tidak bertalbiyah hingga hari Tarwiyah (yaitu tanggal delapan Dzul Hijjah). Kemudian Abdullah bin Umar berkata kepadanya; 'Adapun rukun, maka sesungguhnya aku tidak melihat Rasulullah shallallahu 'alaihi wasallam menyentuh kecuali dua rukun Yamani, adapun sandal sibti (sandal yang tidak berbulu), maka sesungguhnya aku melihat Rasulullah shallallahu 'alaihi wasallam memakai sandal yang tidak berbulu, dan berwudlu dengan memakai sandal tersebut maka aku ingin memakainya, adapun shufrah, sesungguhnya aku telah melihat Rasulullah shallallahu 'alaihi wasallam mencelup rambut dengan shufrah, maka aku ingin mencelup dengannya, adapun talbiyah, sesungguhnya aku tidak melihat Rasulullah shallallahu 'alaihi wasallam bertalbiyah hingga kendaraan beliau berdiri.'"},"5099":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَلْبَسَ الْمُحْرِمُ ثَوْبًا مَصْبُوغًا بِزَعْفَرَانٍ أَوْ وَرْسٍ وَقَالَ مَنْ لَمْ يَجِدْ نَعْلَيْنِ فَلْيَلْبَسْ خُفَّيْنِ وَلْيَقْطَعْهُمَا أَسْفَلَ مِنْ الْكَعْبَيْنِ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf]; telah mengabarkan kepada kami [Malik] dari [Abdullah bin Dinar] dari [Abdullah bin Umar] radliallahu 'anhuma dia berkata; Rasulullah shallallahu 'alaihi wasallam melarang orang yang berihram mengenakan pakaian yang dicelup dengan minyak za'faran atau wars (sejenis tanaman yang barbau harum dan berwarna kuning), dan beliau bersabda: \"Barangsiapa tidak mendapatkan dua sandal hendaknya ia mengenakan sepatu dan dipotong hingga di bawah mata kaki.\""},"5100":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ جَابِرِ بْنِ زَيْدٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لَمْ يَكُنْ لَهُ إِزَارٌ فَلْيَلْبَسْ السَّرَاوِيلَ وَمَنْ لَمْ يَكُنْ لَهُ نَعْلَانِ فَلْيَلْبَسْ خُفَّيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari ['Amru bin Dinar] dari [Jabir bin Zaid] dari [Ibnu Abbas] radliallahu 'anhuma dia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa tidak mendapatkan kain sarung, hendaknya ia mengenakan celana panjang, dan barangsiapa tidak mendapatkan sandal, hendaknya ia mengenakan sepatu (bagi yang berihram -red).\""},"5101":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي أَشْعَثُ بْنُ سُلَيْمٍ سَمِعْتُ أَبِي يُحَدِّثُ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحِبُّ التَّيَمُّنَ فِي طُهُورِهِ وَتَرَجُّلِهِ وَتَنَعُّلِهِ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Syu'bah] dia berkata; telah mengabarkan kepadaku [Asy'ats bin Sulaim] saya mendengar [Ayahku] menceritakan dari [Masruq] dari ['Aisyah] radliallahu 'anha dia berkata; \"Nabi shallallahu 'alaihi wasallam menyukai tayamun (mendahulukan yang kanan) ketika bersuci, menyisir rambut dan memakai sandal.\""},"5102":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا انْتَعَلَ أَحَدُكُمْ فَلْيَبْدَأْ بِالْيَمِينِ وَإِذَا نَزَعَ فَلْيَبْدَأْ بِالشِّمَالِ لِيَكُنْ الْيُمْنَى أَوَّلَهُمَا تُنْعَلُ وَآخِرَهُمَا تُنْزَعُ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Abu Az Zinnad] dari [Al A'raj] dari [Abu Hurairah] radliallahu 'anhu bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian memakai sandal, hendaknya memulai dengan yang kanan, dan apabila melepas hendaknya mulai dengan yang kiri, supaya yang kanan pertama kali mengenakan sandal dan yang terakhir melepasnya.\""},"5103":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَمْشِي أَحَدُكُمْ فِي نَعْلٍ وَاحِدَةٍ لِيُحْفِهِمَا جَمِيعًا أَوْ لِيُنْعِلْهُمَا جَمِيعًا","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Abu Az Zinnad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang dari kalian berjalan dengan satu sandal, hendaknya ia melepas semua atau memakai semua.\""},"5104":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ حَدَّثَنَا أَنَسٌ رَضِيَ اللَّهُ عَنْهُأَنَّ نَعْلَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ لَهَا قِبَالَانِ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammam] dari [Qatadah] telah menceritakan kepada kami [Anas] radliallahu 'anhu bahwa sandal Nabi shallallahu 'alaihi wasallam memiliki dua utas tali.\""},"5105":{"ar":"حَدَّثَنِي مُحَمَّدٌ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا عِيسَى بْنُ طَهْمَانَ قَالَ خَرَجَ إِلَيْنَا أَنَسُ بْنُ مَالِكٍبِنَعْلَيْنِ لَهُمَا قِبَالَانِ فَقَالَ ثَابِتٌ الْبُنَانِيُّ هَذِهِ نَعْلُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepadaku [Muhammad] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Isa bin Thuhman] dia berkata; [Anas bin Malik] keluar menemui kami dengan mengenakan sandal yang memiliki dua utas tali, lantas Tsabit Al Bunani mengatakan; \"Ini adalah sandal Nabi shallallahu 'alaihi wasallam.\""},"5106":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَرْعَرَةَ قَالَ حَدَّثَنِي عُمَرُ بْنُ أَبِي زَائِدَةَ عَنْ عَوْنِ بْنِ أَبِي جُحَيْفَةَ عَنْ أَبِيهِ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي قُبَّةٍ حَمْرَاءَ مِنْ أَدَمٍ وَرَأَيْتُ بِلَالًا أَخَذَ وَضُوءَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّاسُ يَبْتَدِرُونَ الْوَضُوءَ فَمَنْ أَصَابَ مِنْهُ شَيْئًا تَمَسَّحَ بِهِ وَمَنْ لَمْ يُصِبْ مِنْهُ شَيْئًا أَخَذَ مِنْ بَلَلِ يَدِ صَاحِبِهِ","id":"Telah menceritakan kepada kami [Muhammad bin 'Ar'arah] dia berkata; telah menceritakan kepadaku [Umar bin Abu Za`idah] dari ['Aun bin Abu Juhaifah] dari [Ayahnya] dia berkata; saya menemui Nabi shallallahu 'alaihi wasallam ketika beliau tengah berada di tenda besar yang terbuat dari kulit, dan saya melihat Bilal tengah mengambilkan tempat air wudlu Nabi shallallahu 'alaihi wasallam sementara orang-orang berlomba-lomba untuk mendapatkan bekas wudlu beliau, dan siapa yang mendapatkannya maka ia akan membasuhkannya namun bagi yang tidak mendapatkannya, maka ia mengambil dari sisa air yang menetes dari temannya.\""},"5107":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ أَخْبَرَنِي أَنَسُ بْنُ مَالِكٍ وَقَالَ اللَّيْثُ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي أَنَسُ بْنُ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَأَرْسَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْأَنْصَارِ وَجَمَعَهُمْ فِي قُبَّةٍ مِنْ أَدَمٍ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] telah mengabarkan kepadaku [Anas bin Malik] dan [Al Laits] mengatakan; telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab] dia berkata; telah mengabarkan kepadaku [Anas bin Malik] radliallahu 'anhu dia berkata; \"Nabi shallallahu 'alaihi wasallam menyuruh seseorang menemui orang-orang Anshar, sementara mereka tengah berkumpul di dalam kemah besar yang terbuat dari kulit.\""},"5108":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي بَكْرٍ حَدَّثَنَا مُعْتَمِرٌ عَنْ عُبَيْدِ اللَّهِ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَحْتَجِرُ حَصِيرًا بِاللَّيْلِ فَيُصَلِّي عَلَيْهِ وَيَبْسُطُهُ بِالنَّهَارِ فَيَجْلِسُ عَلَيْهِ فَجَعَلَ النَّاسُ يَثُوبُونَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيُصَلُّونَ بِصَلَاتِهِ حَتَّى كَثُرُوا فَأَقْبَلَ فَقَالَ يَا أَيُّهَا النَّاسُ خُذُوا مِنْ الْأَعْمَالِ مَا تُطِيقُونَ فَإِنَّ اللَّهَ لَا يَمَلُّ حَتَّى تَمَلُّوا وَإِنَّ أَحَبَّ الْأَعْمَالِ إِلَى اللَّهِ مَا دَامَ وَإِنْ قَلَّ","id":"Telah menceritakan kepadaku [Muhammad bin Abu Bakr] telah menceritakan kepada kami [Mu'tamir] dari ['Ubaidullah] dari [Sa'id bin Abu Sa'id] dari [Abu Salamah bin Abdurrahman] dari [Aisyah] radliallahu 'anha bahwa pada suatu malam Nabi shallallahu 'alaihi wasallam pernah membuat sekat (di dalam masjid) dengan tikar lalu shalat di dalamnya, dan menghamparkannya di siang hari untuk duduk, ternyata orang-orang berkumpul di sekeliling Nabi shallallahu 'alaihi wasallam untuk mengerjakan shalat sebagaimana beliau shalat, hingga orang-orang semakin banyak, lalu beliau menghadap (kepada mereka) dan bersabda: \"Wahai sekalian manusia, beramalah menurut yang kalian sanggupi, sesungguhnya Allah tidak akan bosan sehingga kalian merasa bosan, sesungguhnya amalan yang paling dicintai Allah adalah yang dikerjakan secara kontinyu walaupun sedikit.\""},"5109":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا أَشْعَثُ بْنُ سُلَيْمٍ قَالَ سَمِعْتُ مُعَاوِيَةَ بْنَ سُوَيْدِ بْنِ مُقَرِّنٍ قَالَ سَمِعْتُ الْبَرَاءَ بْنَ عَازِبٍ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُنَهَانَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ سَبْعٍ نَهَانَا عَنْ خَاتَمِ الذَّهَبِ أَوْ قَالَ حَلْقَةِ الذَّهَبِ وَعَنْ الْحَرِيرِ وَالْإِسْتَبْرَقِ وَالدِّيبَاجِ وَالْمِيثَرَةِ الْحَمْرَاءِ وَالْقَسِّيِّ وَآنِيَةِ الْفِضَّةِ وَأَمَرَنَا بِسَبْعٍ بِعِيَادَةِ الْمَرِيضِ وَاتِّبَاعِ الْجَنَائِزِ وَتَشْمِيتِ الْعَاطِسِ وَرَدِّ السَّلَامِ وَإِجَابَةِ الدَّاعِي وَإِبْرَارِ الْمُقْسِمِ وَنَصْرِ الْمَظْلُومِ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Asy'ats bin Sulaim] dia berkata; saya mendengar [Mu'awiyah bin Suwaid bin Muqarrin] berkata; saya mendengar [Barra` bin 'Azib] radliallahu 'anhuma berkata; \"Nabi shallallahu 'alaihi wasallam melarang kami tujuh perkara yaitu melarang mengenakan cincin dari emas atau kalung dari emas, memakai kain sutera, istibraq, dibaj, misarah, hamra`, Qasiy (sejenis kain sutera campuran) dan tempat air dari perak, dan memerintahkan kami tujuh perkara, yaitu menjenguk orang sakit, mengiringi jenazah, mendo'akan orang bersin, menjawab salam, memenuhi undangan, menunaikan sumpah dan menolong orang yang terzhalimi.\""},"5110":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ النَّضْرِ بْنِ أَنَسٍ عَنْ بَشِيرِ بْنِ نَهِيكٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى عَنْ خَاتَمِ الذَّهَبِوَقَالَ عَمْرٌو أَخْبَرَنَا شُعْبَةُ عَنْ قَتَادَةَ سَمِعَ النَّضْرَ سَمِعَ بَشِيرًا مِثْلَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Nadlr bin Anas] dari [Basyir bin Nahik] dari [Abu Hurairah] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam bahwa beliau melarang mengenakan cincin emas. ['Amru] mengatakan; Telah mengabarkan kepada kami [Syu'bah] dari [Qatadah] bahwa dia mendengar [Nadlr]; dia mendengar [Basyir] seperti hadits di atas."},"5111":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنِي نَافِعٌ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اتَّخَذَ خَاتَمًا مِنْ ذَهَبٍ وَجَعَلَ فَصَّهُ مِمَّا يَلِي كَفَّهُ فَاتَّخَذَهُ النَّاسُ فَرَمَى بِهِ وَاتَّخَذَ خَاتَمًا مِنْ وَرِقٍ أَوْ فِضَّةٍ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] dia berkata; telah menceritakan kepadaku [Nafi'] dari [Abdullah] radliallahu 'anhu bahwa Rasulullah shallallahu 'alaihi wasallam pernah membuat cincin dari emas dan menghadapkan mata cincinnya ke arah telapak tangan, orang-orang lalu ikut memakai cincin hingga Nabi shallallahu 'alaihi wasallam membuang cincin tersebut dan membuat dari perak.\""},"5112":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ مُوسَى حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اتَّخَذَ خَاتَمًا مِنْ ذَهَبٍ أَوْ فِضَّةٍ وَجَعَلَ فَصَّهُ مِمَّا يَلِي كَفَّهُ وَنَقَشَ فِيهِ مُحَمَّدٌ رَسُولُ اللَّهِ فَاتَّخَذَ النَّاسُ مِثْلَهُ فَلَمَّا رَآهُمْ قَدْ اتَّخَذُوهَا رَمَى بِهِ وَقَالَ لَا أَلْبَسُهُ أَبَدًا ثُمَّ اتَّخَذَ خَاتَمًا مِنْ فِضَّةٍ فَاتَّخَذَ النَّاسُ خَوَاتِيمَ الْفِضَّةِ قَالَ ابْنُ عُمَرَ فَلَبِسَ الْخَاتَمَ بَعْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبُو بَكْرٍ ثُمَّ عُمَرُ ثُمَّ عُثْمَانُ حَتَّى وَقَعَ مِنْ عُثْمَانَ فِي بِئْرِ أَرِيسَ","id":"Telah menceritakan kepada kami [Yusuf bin Musa] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhuma bahwa Rasulullah shallallahu 'alaihi wasallam pernah membuat cincin dari emas atau perak, dan menghadapkan mata cincinnya di telapak tangan serta mengukirnya dengan tulisan \"Muhammad Rasulullah\", maka orang-orang pun membuat seperti itu juga, ketika beliau mengetahui orang-orang membuatnya, maka beliau langsung melempar cincin tersebut sambil bersabda: \"Saya tidak akan memakainya selama-lamanya.\" Setelah itu beliau membuatnya dari perak dan orang-orang pun ikut membuat cincin dari perak, Ibnu Umar mengatakan; \"Cincin itu dipakai oleh Abu Bakr setelah Nabi shallallahu 'alaihi wasallam, kemudian Umar dan Utsman, sehingga Utsman menjatuhkannya di sumur Aris."},"5113":{"ar":"بَاب حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَلْبَسُ خَاتَمًا مِنْ ذَهَبٍ فَنَبَذَهُ فَقَالَ لَا أَلْبَسُهُ أَبَدًا فَنَبَذَ النَّاسُ خَوَا��ِيمَهُمْ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Abdullah bin Dinar] dari [Abdullah bin Umar] radliallahu 'anhuma dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah memakai cincin emas, kemudian beliau membuangnya sambil bersabda: \"Saya tidak akan memakainya lagi selama-lamanya.\" Maka orang-orang pun ikut membuang cincin yang mereka kenakan."},"5114":{"ar":"حَدَّثَنِي يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي أَنَسُ بْنُ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّهُ رَأَى فِي يَدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَاتَمًا مِنْ وَرِقٍ يَوْمًا وَاحِدًا ثُمَّ إِنَّ النَّاسَ اصْطَنَعُوا الْخَوَاتِيمَ مِنْ وَرِقٍ وَلَبِسُوهَا فَطَرَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَاتَمَهُ فَطَرَحَ النَّاسُ خَوَاتِيمَهُمْتَابَعَهُ إِبْرَاهِيمُ بْنُ سَعْدٍ وَزِيَادٌ وَشُعَيْبٌ عَنْ الزُّهْرِيِّ وَقَالَ ابْنُ مُسَافِرٍ عَنْ الزُّهْرِيِّ أَرَى خَاتَمًا مِنْ وَرِقٍ","id":"Telah menceritakan kepadaku [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Yunus] dari [Ibnu Syihab] dia berkata; telah menceritakan kepadaku [Anas bin Malik] radliallahu 'anhu bahwa dia pernah melihat Rasulullah shallallahu 'alaihi wasallam memakai cincin perak di tangannya selama satu hari, kemudian orang-orang pun ikut membuat cincin dari perak dan memakainya, lalu Rasulullah shallallahu 'alaihi wasallam pun membuang cincin tersebut dan orang-orang pun ikut membuang cincin yang mereka kenakan.\" Hadits ini juga diperkuat dengan riwayat [Ibrahim bin Sa'd], [Ziyad] dan [Syu'aib] dari [Az Zuhri]. [Ibnu Musafir] mengatakan; dari [Az Zuhri] bahwa pendapatku itu adalah cincin yang terbuat dari perak.\""},"5115":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا يَزِيدُ بْنُ زُرَيْعٍ أَخْبَرَنَا حُمَيْدٌ قَالَ سُئِلَ أَنَسٌهَلْ اتَّخَذَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَاتَمًا قَالَ أَخَّرَ لَيْلَةً صَلَاةَ الْعِشَاءِ إِلَى شَطْرِ اللَّيْلِ ثُمَّ أَقْبَلَ عَلَيْنَا بِوَجْهِهِ فَكَأَنِّي أَنْظُرُ إِلَى وَبِيصِ خَاتَمِهِ قَالَ إِنَّ النَّاسَ قَدْ صَلَّوْا وَنَامُوا وَإِنَّكُمْ لَمْ تَزَالُوا فِي صَلَاةٍ مَا انْتَظَرْتُمُوهَا","id":"Telah menceritakan kepada kami ['Abdan] telah mengabarkan kepada kami [Yazid bin Zurai'] telah mengabarkan kepada kami [Humaid] dia berkata; [Anas] pernah ditanya; \"Apakah Nabi shallallahu 'alaihi wasallam pernah membuat (mengenakan) cincin?” Dia menjawab; 'Beliau pernah mengakhirkan shalat Isya' sampai menjelang tengah malam, kemudian beliau menemui kami, seakan-akan saya melihat kilauan cincin beliau, beliau bersabda: “Orang-orang telah melaksanakan shalat dan tidur, sementara kalian senantiasa dalam keadaan shalat selagi kalian menunggu shalat.'"},"5116":{"ar":"حَدَّثَنَا إِسْحَاقُ أَخْبَرَنَا مُعْتَمِرٌ قَالَ سَمِعْتُ حُمَيْدًا يُحَدِّثُ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ خَاتَمُهُ مِنْ فِضَّةٍ وَكَانَ فَصُّهُ مِنْهُوَقَالَ يَحْيَى بْنُ أَيُّوبَ حَدَّثَنِي حُمَيْدٌ سَمِعَ أَنَسًا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ishaq] telah mengabarkan kepada kami [Mu'tamir] dia berkata; saya mendengar [Humaid] bercerita dari [Anas] radliallahu 'anhu bahwa Nabi shallallahu 'alaihi wasallam memiliki cincin yang terbuat dari perak sedangkan batu cincinnya dari perak juga.\" [Yahya bin Ayyub] mengatakan; telah menceritakan kepadaku [Humaid] dia mendengar [Anas] dari Nabi shallallahu 'alaihi wasallam."},"5117":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ أَبِيهِ أَنَّهُ سَمِعَ سَهْلًا يَقُولُجَاءَتْ امْرَأَةٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ جِئْتُ أَهَبُ نَفْسِي فَقَامَتْ طَوِيلًا فَنَظَرَ وَصَوَّبَ فَلَمَّا طَالَ مُقَامُهَا فَقَالَ رَجُلٌ زَوِّجْنِيهَا إِنْ لَمْ يَكُنْ لَكَ بِهَا حَاجَةٌ قَالَ عِنْدَكَ شَيْءٌ تُصْدِقُهَا قَالَ لَا قَالَ انْظُرْ فَذَهَبَ ثُمَّ رَجَعَ فَقَالَ وَاللَّهِ إِنْ وَجَدْتُ شَيْئًا قَالَ اذْهَبْ فَالْتَمِسْ وَلَوْ خَاتَمًا مِنْ حَدِيدٍ فَذَهَبَ ثُمَّ رَجَعَ قَالَ لَا وَاللَّهِ وَلَا خَاتَمًا مِنْ حَدِيدٍ وَعَلَيْهِ إِزَارٌ مَا عَلَيْهِ رِدَاءٌ فَقَالَ أُصْدِقُهَا إِزَارِي فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِزَارُكَ إِنْ لَبِسَتْهُ لَمْ يَكُنْ عَلَيْكَ مِنْهُ شَيْءٌ وَإِنْ لَبِسْتَهُ لَمْ يَكُنْ عَلَيْهَا مِنْهُ شَيْءٌ فَتَنَحَّى الرَّجُلُ فَجَلَسَ فَرَآهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُوَلِّيًا فَأَمَرَ بِهِ فَدُعِيَ فَقَالَ مَا مَعَكَ مِنْ الْقُرْآنِ قَالَ سُورَةُ كَذَا وَكَذَا لِسُوَرٍ عَدَّدَهَا قَالَ قَدْ مَلَّكْتُكَهَا بِمَا مَعَكَ مِنْ الْقُرْآنِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] telah menceritakan kepada kami [Abdul Aziz bin Abdul Abu Hazim] dari [Ayahnya] bahwa dia mendengar [Sahl] berkata; seorang wanita datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; \"Saya datang kepada anda untuk menyerahkan diriku kepada anda, \" Beliau lalu berdiri lama dan menelitinya dengan seksama, ketika beliau berdiri lama seorang laki-laki berkata; 'Wahai Rasulullah, jika anda tidak berkenan dengannya, maka nikahkanlah aku dengannya.' Rasulullah shallallahu 'alaihi wasallam bertanya kepada laki-laki tersebut: 'Apakah kamu mempunyai sesuatu yang dapat dijadikan mahar untuknya? ' Laki-laki itu menjawab; 'Tidak.' Beliau bersabda: 'Carilah terlebih dahulu.' Lalu laki-laki itu pergi, sesaat kemudian dia kembali dan berkata; 'Demi Allah, aku tidak mendapatkan sesuatupun.' Beliau bersabda: 'Pergi dan carilah lagi walaupun hanya dengan cincin dari besi.' Kemudian laki-laki itu pergi, tidak berapa lama dia kembali sambil berkata; 'Aku tidak mendapatkan apa-apa walau cincin dari besi.' -Saat itu laki-laki tersebut tengah mengenakan kain sarung, lantas dia berkata; 'Aku akan menjadikan kain sarung ini sebagai mahar.' Maka Nabi shallallahu 'alaihi wasallam bersabda: 'Jika kamu memakaikan kain sarung itu padanya, maka kamu tidak memakai apa-apa, sementara jika kamu yang memakai sarung tersebut, dia tidak memakai apa-apa.' Laki-laki itu duduk termenung, ternyata Nabi shallallahu 'alaihi wasallam melihatnya berpaling, lalu beliau memerintahkan seseorang untuk memanggilnya, maka dipanggilah laki-laki tersebut, beliau bertanya: 'Apakah kamu mempunyai hafalan dari Al Qur'an? ' Laki-laki itu menjawab; 'Ya, saya telah hafal surat ini dan ini.' Lalu beliau bersabda: 'Maka aku nikahkan kamu dengan wanita itu, dengan mahar apa yang telah engkau hafal dari surat Al Qur'an.'"},"5118":{"ar":"حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرَادَ أَنْ يَكْتُبَ إِلَى رَهْطٍ أَوْ أُنَاسٍ مِنْ الْأَعَاجِمِ فَقِيلَ لَهُ إِنَّهُمْ لَا يَقْبَلُونَ كِتَابًا إِلَّا عَلَيْهِ خَاتَمٌ فَاتَّخَذَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَاتَمًا مِنْ فِضَّةٍ نَقْشُهُ مُحَمَّدٌ رَسُولُ اللَّهِ فَكَأَنِّي بِوَبِيصِ أَوْ بِبَصِيصِ الْخَاتَمِ فِي إِصْبَعِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ فِي كَفِّهِ","id":"Telah menceritakan kepada kami [Abdul A'la] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Anas bin Malik] radliallahu 'anhu bahwa Nabiyullah shallallahu 'alaihi wasallam hendak menulis surat kepada pemuka kaum atau sekelompok orang asing, lantas diberitahukan kepada beliau; \"Sesungguhnya mereka tidak akan menerima surat anda kecuali jika surat tersebut dibubuhi stempel, maka Nabi shallallahu 'alaihi wasallam membuat stempel (cincin) dari perak yang diukir dengan tulisan 'Muhammad Rasulullah', seolah-olah saya melihat kilauan atau kilatan cincin berada di jari tangan Nabi shallallahu 'alaihi wasallam atau di telapak tangan beliau.\""},"5119":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ سَلَامٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَاتَّخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَاتَمًا مِنْ وَرِقٍ وَكَانَ فِي يَدِهِ ثُمَّ كَانَ بَعْدُ فِي يَدِ أَبِي بَكْرٍ ثُمَّ كَانَ بَعْدُ فِي يَدِ عُمَرَ ثُمَّ كَانَ بَعْدُ فِي يَدِ عُثْمَانَ حَتَّى وَقَعَ بَعْدُ فِي بِئْرِ أَرِيسَ نَقْشُهُ مُحَمَّدٌ رَسُولُ اللَّهِ","id":"Telah menceritakan kepada kami [Muhammad bin Salam] telah mengabarkan kepada kami [Abdullah bin Numair] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhuma dia berkata; Rasulullah shallallahu 'alaihi wasallam pernah membuat cincin dari perak, cincin tersebut masih berada di tangan beliau, setelah (beliau meninggal) cincin tersebut pindah ke tangan Abu Bakr, lalu setelah Abu Bakr pindah ke tangan Umar, setelah Umar pindah ke tangan Utsman hingga setelah itu Utsman menjatuhkannya di sumur Aris, cincin itu bertuliskan 'Muhammad Rasulullah'.\""},"5120":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ صُهَيْبٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَصَنَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَاتَمًا قَالَ إِنَّا اتَّخَذْنَا خَاتَمًا وَنَقَشْنَا فِيهِ نَقْشًا فَلَا يَنْقُشَنَّ عَلَيْهِ أَحَدٌ قَالَ فَإِنِّي لَأَرَى بَرِيقَهُ فِي خِنْصَرِهِ","id":"Telah menceritakan kepada kami [Abu Ma'mar] telah menceritakan kepada kami [Abdul Warits] telah menceritakan kepada kami [Abdul Aziz bin Shuhaib] dari [Anas] radliallahu 'anhu dia berkata; \"Nabi shallallahu 'alaihi wasallam pernah membuat cincin, lalu beliau bersabda: 'Sesungguhnya kami telah membuat cincin yang kami ukir dengan suatu tulisan, maka janganlah salah seorang dari kalian mengukir seperti itu.' Anas melanjutkan; 'Sungguh saya pernah melihat kilatan dari cincin tersebut berada di jari manis beliau.'"},"5121":{"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا أَرَادَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَكْتُبَ إِلَى الرُّومِ قِيلَ لَهُ إِنَّهُمْ لَنْ يَقْرَءُوا كِتَابَكَ إِذَا لَمْ يَكُنْ مَخْتُومًا فَاتَّخَذَ خَاتَمًا مِنْ فِضَّةٍ وَنَقْشُهُ مُحَمَّدٌ رَسُولُ اللَّهِ فَكَأَنَّمَا أَنْظُرُ إِلَى بَيَاضِهِ فِي يَدِهِ","id":"Telah menceritakan kepada kami [Adam bin Abu Iyas] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas bin Malik] radliallahu 'anhu dia berkata; \"Ketika Nabi shallallahu 'alaihi wasallam hendak menulis surat ke raja Romawi, maka diberitahukan kepada beliau; 'Sesungguhnya mereka tidak akan mau membaca surat anda karena tidak ada stempel.' Setelah itu beliau membuat cincin (stempel) yang terbuat dari perak dan mengukirnya dengan tulisan 'Muhammad Rasulullah' seakan-akan saya melihat putihnya (cahaya) dari tangan beliau.\""},"5122":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا جُوَيْرِيَةُ عَنْ نَافِعٍ أَنَّ عَبْدَ اللَّهِ حَدَّثَهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اصْطَنَعَ خَاتَمًا مِنْ ذَهَبٍ وَجَعَلَ فَصَّهُ فِي بَطْنِ كَفِّهِ إِذَا لَبِسَهُ فَاصْطَنَعَ النَّاسُ خَوَاتِيمَ مِنْ ذَهَبٍ فَرَقِيَ الْمِنْبَرَ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ فَقَالَ إِنِّي كُنْتُ اصْطَنَعْتُهُ وَإِنِّي لَا أَلْبَسُهُ فَنَبَذَهُ فَنَبَذَ النَّاسُ قَالَ جُوَيْرِيَةُ وَلَا أَحْسِبُهُ إِلَّا قَالَ فِي يَدِهِ الْيُمْنَى","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Juwairiyah] dari [Nafi'] bahwa [Abdullah] pernah menceritakan kepadanya bahwa Nabi shallallahu 'alaihi wasallam pernah membuat cincin dari emas, dan menghadapkan mata cincinnya ke telapak tangan beliau apabila beliau mengenakannya, maka orang-orang pun ramai membuat cincin dari emas, lalu beliau naik mimbar, setelah memuji Allah dan menyanjung-Nya beliau bersabda: \"Sesungguhnya saya telah membuat cincin dari emas, dan sungguh saat ini saya tidak akan mengenakannya.\" Maka orang-orang pun membuang cincin mereka. Juwairiyah mengatakan; 'Aku tidak mengira lagi kecuali Nafi' mengatakan; 'Beliau mengenakannya di tangan kanan beliau.'"},"5123":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادٌ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اتَّخَذَ خَاتَمًا مِنْ فِضَّةٍ وَنَقَشَ فِيهِ مُحَمَّدٌ رَسُولُ اللَّهِ وَقَالَ إِنِّي اتَّخَذْتُ خَاتَمًا مِنْ وَرِقٍ وَنَقَشْتُ فِيهِ مُحَمَّدٌ رَسُولُ اللَّهِ فَلَا يَنْقُشَنَّ أَحَدٌ عَلَى نَقْشِهِ","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Hammad] dari [Abdul Aziz bin Shuhaib] dari [Anas bin Malik] radliallahu 'anhu bahwa Rasulullah shallallahu 'alaihi wasallam pernah membuat cincin dari perak dan mengukirnya dengan tulisan \"Muhammad Rasulullah\" kemudian beliau bersabda: \"Sesungguhnya saya telah membuat cincin dari perak dan telah kuukir dengan tulisan 'Muhammad Rasulullah' maka janganlah kalian mengukir dengan ukiran seperti itu.\""},"5124":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْأَنْصَارِيُّ قَالَ حَدَّثَنِي أَبِي عَنْ ثُمَامَةَ عَنْ أَنَسٍ أَنَّ أَبَا بَكْرٍ رَضِيَ اللَّهُ عَنْهُ لَمَّا اسْتُخْلِفَ كَتَبَ لَهُ وَكَانَ نَقْشُ الْخَاتَمِ ثَلَاثَةَ أَسْطُرٍ مُحَمَّدٌ سَطْرٌ وَرَسُولُ سَطْرٌ وَاللَّهِ سَطْرٌ قَالَ أَبُو عَبْد اللَّهِ وَزَادَنِي أَحْمَدُ حَدَّثَنَا الْأَنْصَارِيُّ قَالَ حَدَّثَنِي أَبِي عَنْ ثُمَامَةَ عَنْ أَنَسٍ قَالَكَانَ خَاتَمُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي يَدِهِ وَفِي يَدِ أَبِي بَكْرٍ بَعْدَهُ وَفِي يَدِ عُمَرَ بَعْدَ أَبِي بَكْرٍ فَلَمَّا كَانَ عُثْمَانُ جَلَسَ عَلَى بِئْرِ أَرِيسَ قَالَ فَأَخْرَجَ الْخَاتَمَ فَجَعَلَ يَعْبَثُ بِهِ فَسَقَطَ قَالَ فَاخْتَلَفْنَا ثَلَاثَةَ أَيَّامٍ مَعَ عُثْمَانَ فَنَزَحَ الْبِئْرَ فَلَمْ يَجِدْهُ","id":"Telah menceritakan kepadaku [Muhammad bin Abdullah Al Anshari] dia berkata; telah menceritakan kepadaku [Ayahku] dari [Tsumamah] dari [Anas] bahwa ketika Abu Bakr diangkat menjadi Khalifah dia menulis surat kepadanya (tentang zakat) sedangkan ukiran pada cincin tersebut terdapat tiga baris, baris pertama bertuliskan Muhammad, baris kedua bertuliskan Rasul dan dibaris ketiga bertuliskan Allah, \" Abu Abdullah mengatakan; \"Sedangkan [Ahmad] menambahkan kepadaku telah menceritakan kepada kami [Al Anshari] dia berkata; telah menceritakan kepadaku [Ayahku] dari [Tsumamah] dari [Anas] dia berkata; \"Cincin Nabi shallallahu 'alaihi wasallam berada di tangan beliau, lalu di tangan Abu Bakr, lalu di tangan Umar, ketika berada di tangan Utsman, dia duduk-duduk di dekat sumur Aris (Anas) melanjutkan; 'Lalu dia mengeluarkan cincin tersebut (dari tangannya) dan mempermainkannya, tiba-tiba cincin tersebut terjatuh ke dalam sumur, lalu kami berusaha mencarinya bersama Utsman selama tiga hari, dengan mengeluarkan air sumur tersebut sedikit demi sedikit, namun tidak juga menemukannya.'"},"5125":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنَا الْحَسَنُ بْنُ مُسْلِمٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاشَهِدْتُ الْعِيدَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى قَبْلَ الْخُطْبَةِقَالَ أَبُو عَبْد اللَّهِ وَزَادَ ابْنُ وَهْبٍ عَنْ ابْنِ جُرَيْجٍ فَأَتَى النِّسَاءَ فَجَعَلْنَ يُلْقِينَ الْفَتَخَ وَالْخَوَاتِيمَ فِي ثَوْبِ بِلَالٍ","id":"Telah menceritakan kepada kami [Abu 'Ashim] telah mengabarkan kepada kami [Ibnu Juraij] telah mengabarkan kepada kami [Al Hasan bin Muslim] dari [Thawus] dari [Ibnu Abbas] radliallahu 'anhuma; \"Saya pernah mengikuti shalat Ied bersama Nabi shallallahu 'alaihi wasallam, beliau mengerjakan shalat sebelum berkhutbah.\" Abu Abdullah berkata; [Ibnu Wahb] menambahkan dari [Ibnu Juraij]; 'Kemudian beliau menemui para wanita, lantas para wanita segera melempar cincin mereka baik yang kecil maupun yang besar ke kainnya Bilal.'"},"5126":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَرْعَرَةَ حَدَّثَنَا شُعْبَةُ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ عِيدٍ فَصَلَّى رَكْعَتَيْنِ لَمْ يُصَلِّ قَبْلُ وَلَا بَعْدُ ثُمَّ أَتَى النِّسَاءَ فَأَمَرَهُنَّ بِالصَّدَقَةِ فَجَعَلَتْ الْمَرْأَةُ تَصَدَّقُ بِخُرْصِهَا وَسِخَابِهَا","id":"Telah menceritakan kepada kami [Muhammad bin 'Ar'arah] telah menceritakan kepada kami [Syu'bah] dari ['Adi bin Tsabit] dari [Sa'id bin Jubair] dari [Ibnu Abbas] radliallahu 'anhuma dia berkata; \"Nabi shallallahu 'alaihi wasallam keluar untuk mengerjakn shalat Ied, kemudian beliau shalat dua raka'at, tidak shalat baik sebelum dan sesudahnya, setelah itu beliau mendatangi para wanita dan memerintahkan mereka untuk bersedekah, hingga para wanita ramai-ramai menyedekahkan anting dan kalung mereka.\""},"5127":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا عَبْدَةُ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْهَلَكَتْ قِلَادَةٌ لِأَسْمَاءَ فَبَعَثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي طَلَبِهَا رِجَالًا فَحَضَرَتْ الصَّلَاةُ وَلَيْسُوا عَلَى وُضُوءٍ وَلَمْ يَجِدُوا مَاءً فَصَلَّوْا وَهُمْ عَلَى غَيْرِ وُضُوءٍ فَذَكَرُوا ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّهُ آيَةَ التَّيَمُّمِزَادَ ابْنُ نُمَيْرٍ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ اسْتَعَارَتْ مِنْ أَسْمَاءَ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah menceritakan kepada kami ['Abdah] telah menceritakan kepada kami [Hisyam bin Urwah] dari [Ayahnya] dari [Aisyah] radliallahu 'anha dia berkata; \"Kalung Asma` pernah hilang, lalu Nabi shallallahu 'alaihi wasallam mengutus beberapa orang laki-laki untuk mencarinya, sementara waktu shalat telah tiba sedangkan mereka tidak ada yang membawa air untuk berwudlu', lantas mereka mengerjakan shalat tanpa berwudlu', setelah itu mereka memberitahukan peristiwa tersebut kepada Nabi shallallahu 'alaihi wasallam, maka Allah menurunkan ayat tayammum.\" [Ibnu Numair] menambahkan dari [Hisyam] dari [Ayahnya] dari [Aisyah] bahwa dialah yang meminjam kalungnya Asma'."},"5128":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي عَدِيٌّ قَالَ سَمِعْتُ سَعِيدًا عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى يَوْمَ الْعِيدِ رَكْعَتَيْنِ لَمْ يُصَلِّ قَبْلَهَا وَلَا بَعْدَهَا ثُمَّ أَتَى النِّسَاءَ وَمَعَهُ بِلَالٌ فَأَمَرَهُنَّ بِالصَّدَقَةِ فَجَعَلَتْ الْمَرْأَةُ تُلْقِي قُرْطَهَا","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Syu'bah] dia berkata; telah mengabarkan kepadaku ['Adi] dia berkata; saya mendengar [Sa'id] dari [Ibnu Abbas] radliallahu 'anhuma bahwa Nabi shallallahu 'alaihi wasallam shalat Ied dua raka'at, beliau tidak mengerjakan shalat (sunnah) sebeum maupun sesudahnya, kemudian beliau menemui para wanita bersama Bilal, beliau memerintahkan mereka untuk bersedekah, hingga para wanita banyak yang melempar anting mereka.\""},"5129":{"ar":"حَدَّثَنِي إِسْحَاقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ أَخْبَرَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا وَرْقَاءُ بْنُ عُمَرَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي يَزِيدَ عَنْ نَافِعِ بْنِ جُبَيْرٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَكُنْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سُوقٍ مِنْ أَسْوَاقِ الْمَدِينَةِ فَانْصَرَفَ فَانْصَرَفْتُ فَقَالَ أَيْنَ لُكَعُ ثَلَاثًا ادْعُ الْحَسَنَ بْنَ عَلِيٍّ فَقَامَ الْحَسَنُ بْنُ عَلِيٍّ يَمْشِي وَفِي عُنُقِهِ السِّخَابُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهِ هَكَذَا فَقَالَ الْحَسَنُ بِيَدِهِ هَكَذَا فَالْتَزَمَهُ فَقَالَ اللَّهُمَّ إِنِّي أُحِبُّهُ فَأَحِبَّهُ وَأَحِبَّ مَنْ يُحِبُّهُ وَقَالَ أَبُو هُرَيْرَةَ فَمَا كَانَ أَحَدٌ أَحَبَّ إِلَيَّ مِنْ الْحَسَنِ بْنِ عَلِيٍّ بَعْدَ مَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا قَالَ","id":"Telah menceritakan kepadaku [Ishaq bin Ibrahim Al Handlali] telah mengabarkan kepada kami [Yahya bin Adam] telah menceritakan kepada kami [Warqa`bin Umar] dari ['Ubaidullah bin Abu Yazid] dari [Nafi' bin Jubair] dari [Abu Hurairah] radliallahu 'anhu dia berkata; \"Aku pernah bersama Nabi shallallahu 'alaihi wasallam di salah satu pasar Madinah, lalu beliau pergi dan akupun ikut pergi bersama beliau, kemudian beliau bersabda: 'Dimanakah anak kecil, -beliau memangil-manggil sampai tiga kali- Panggillah Al Hasan bin Ali Lalu datanglah Al Hasan bin Ali sambil berjalan, sementara pada lehernya terdapat sikha` (benang yang dibentuk semacam kalung), maka Rasulullah shallallahu 'alaihi wasallam mendekapnya dan ia juga mendekap, lalu beliau bersabda: 'Ya Allah, sesungguhnya aku mencintainya maka cintailah ia dan cintailah orang-orang yang mencintainya.' Abu Hurairah mengatakan; 'Maka tidak ada seorang pun yang lebih aku cintai daripada Al Hasan bin Ali setelah aku mendengar sabda Rasulullah shallallahu 'alaihi wasallam tersebut.'"},"5130":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُتَشَبِّهِينَ مِنْ الرِّجَالِ بِالنِّسَاءِ وَالْمُتَشَبِّهَاتِ مِنْ النِّسَاءِ بِالرِّجَالِتَابَعَهُ عَمْرٌو أَخْبَرَنَا شُعْبَةُ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Ikrimah] dari [Ibnu Abbas] radliallahu 'anhuma dia berkata; \"Allah melaknat laki-laki yang menyerupai wanita dan wanita yang meyerupai laki-laki.\" Hadits ini diperkuat juga dengan hadits ['Amru] telah mengabarkan kepada kami [Syu'bah]."},"5131":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ فَضَالَةَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَلَعَنَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُخَنَّثِينَ مِنْ الرِّجَالِ وَالْمُتَرَجِّلَاتِ مِنْ النِّسَاءِ وَقَالَ أَخْرِجُوهُمْ مِنْ بُيُوتِكُمْ قَالَ فَأَخْرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فُلَانًا وَأَخْرَجَ عُمَرُ فُلَانًا","id":"Telah menceritakan kepada kami [Mu'adz bin Fadlalah] telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Ikrimah] dari [Ibnu Abbas] dia berkata; Nabi shallallahu 'alaihi wasallam melaknat para laki-laki yang menyerupai wanita dan para wanita yang menyerupai laki-laki, sabdanya: \"Keluarkanlah mereka dari rumah kalian.\"Ibnu Abbas melanjutkan; 'Maka Nabi shallallahu 'alaihi wasallam pernah mengeluarkan seorang fulan begitu juga dengan Umar.'"},"5132":{"ar":"حَدَّثَنَا مَالِكُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ أَنَّ عُرْوَةَ أَخْبَرَهُ أَنَّ زَيْنَبَ بِنْتَ أَبِي سَلَمَةَ أَخْبَرَتْهُ أَنَّ أُمَّ سَلَمَةَ أَخْبَرَتْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ عِنْدَهَا وَفِي الْبَيْتِ مُخَنَّثٌ فَقَالَ لِعَبْدِ اللَّهِ أَخِي أُمِّ سَلَمَةَ يَا عَبْدَ اللَّهِ إِنْ فَتَحَ اللَّهُ لَكُمْ غَدًا الطَّائِفَ فَإِنِّي أَدُلُّكَ عَلَى بِنْتِ غَيْلَانَ فَإِنَّهَا تُقْبِلُ بِأَرْبَعٍ وَتُدْبِرُ بِثَمَانٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَدْخُلَنَّ هَؤُلَاءِ عَلَيْكُنَّقَالَ أَبُو عَبْد اللَّهِ تُقْبِلُ بِأَرْبَعٍ وَتُدْبِرُ يَعْنِي أَرْبَعَ عُكَنِ بَطْنِهَا فَهِيَ تُقْبِلُ بِهِنَّ وَقَوْلُهُ وَتُدْبِرُ بِثَمَانٍ يَعْنِي أَطْرَافَ هَذِهِ الْعُكَنِ الْأَرْبَعِ لِأَنَّهَا مُحِيطَةٌ بِالْجَنْبَيْنِ حَتَّى لَحِقَتْ وَإِنَّمَا قَالَ بِثَمَانٍ وَلَمْ يَقُلْ بِثَمَانِيَةٍ وَوَاحِدُ الْأَطْرَافِ وَهُوَ ذَكَرٌ لِأَنَّهُ لَمْ يَقُلْ ثَمَانِيَةَ أَطْرَافٍ","id":"Telah menceritakan kepada kami [Malik bin Isma'il] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Hisyam bin 'Urwah] bahwa ['Urwah] telah mengabarkan kepadanya bahwa [Zainab binti Abu Salamah] telah mengabarkan kepadanya bahwa [Ummu Salamah] telah mengabarkan kepadanya bahwa Nabi shallallahu 'alaihi wasallam pernah berada di sisinya, sementara di rumah dia ada banci, maka beliau bersabda kepada Abdullah yaitu saudara laki-laki Ummu Salamah: \"Wahai Abdullah, sekiranya esok hari Allah memenangkan Tha'if buat kalian, maka aku akan menunjukkan kepadamu anak perempuan Ghailan, karena dia menghadap dengan empat muka dan membelakangi dengan delapan.\" Nabi shallallahu 'alaihi wasallam melanjutkan: 'Maka jangan sampai mereka itu masuk ke rumah kalian.' Abu Abdullah mengatakan; 'Maksud dari menghadap dengan empat dan membelakangi dengan delapan adalah gerutan yang ada di perut karena terlalu gemuk, dan maksud dari membelakangi dengan delapan maksudnya adalah ujung dari empat gerutan tersebut, sebab hal itu akan terlihat bergerut apabila dari samping hingga melekat. Perawi mengatakan; 'Bitsamanin (dengan delapan) dan tidak mengatakan; 'Bitsamaniyah' karena mufradnya 'athraf' mudzakar, karena itu perawi tidak mengatakan 'Tsamaniyata athraf'.\""},"5133":{"ar":"حَدَّثَنَا الْمَكِّيُّ بْنُ إِبْرَاهِيمَ عَنْ حَنْظَلَةَ عَنْ نَافِعٍ ح قَالَ أَصْحَابُنَا عَنْ الْمَكِّيِّ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مِنْ الْفِطْرَةِ قَصُّ الشَّارِبِ","id":"Telah menceritakan kepada kami [Al Makki bin Ibrahim] dari [Hanzhalah] dari [Nafi'], dan diriwayatkan dari jalur lain, [sahabat-sahabat kami] mengatakan; dari [Al Makki] dari [Ibnu Umar] radliallahu 'anhuma dari Nabi shallallahu 'alaihi wasallam bersabda: \"Termasuk dari (sunnah) fitrah adalah mencukur kumis.\""},"5134":{"ar":"حَدَّثَنَا عَلِيٌّ حَدَّثَنَا سُفْيَانُ قَالَ الزُّهْرِيُّ حَدَّثَنَا عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ رِوَايَةًالْفِطْرَةُ خَمْسٌ أَوْ خَمْسٌ مِنْ الْفِطْرَةِ الْخِتَانُ وَالِاسْتِحْدَادُ وَنَتْفُ الْإِبْطِ وَتَقْلِيمُ الْأَظْفَارِ وَقَصُّ الشَّارِبِ","id":"Telah menceritakan kepada kami [Ali] telah menceritakan kepada kami [Sufyan], [Az Zuhri] mengatakan; telah menceritakan kepada kami dari [Sa'id bin Musayyab] dari [Abu Hurairah] secara periwayatan, (sunnah-sunnah) fitrah itu ada lima, atau lima dari sunnah-sunnah fitrah, yaitu; berkhitan, mencukur bulu kemaluan, mencabut bulu ketiak, memotong kuku dan mencukur kumis.\""},"5135":{"ar":"حَدَّثَنَا أَحْمَدُ ابْنُ أَبِي رَجَاءٍ حَدَّثَنَا إِسْحَاقُ بْنُ سُلَيْمَانَ قَالَ سَمِعْتُ حَنْظَلَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مِنْ الْفِطْرَةِ حَلْقُ الْعَانَةِ وَتَقْلِيمُ الْأَظْفَارِ وَقَصُّ الشَّارِبِ","id":"Telah menceritakan kepada kami [Ahmad bin Abu Raja`] telah menceritakan kepada kami [Ishaq bin Sulaiman] dia berkata; saya mendengar [Hanzhalah] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhuma bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Termasuk sunnah-sunnah fitrah adalah mencukur bulu kemaluan, memotong kuku dan mencukur kumis.\""},"5136":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ حَدَّثَنَا ابْنُ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْفِطْرَةُ خَمْسٌ الْخِتَانُ وَالِاسْتِحْدَادُ وَقَصُّ الشَّارِبِ وَتَقْلِيمُ الْأَظْفَارِ وَنَتْفُ الْآبَاطِ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Ibrahim bin Sa'd] telah menceritakan kepada kami [Ibnu Syihab] dari [Sa'id bin Musayyab] dari [Abu Hurairah] radliallahu 'anhu saya mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Sunnah-sunnah fitrah itu ada lima, yaitu; berkhitan, mencukur bulu kemaluan, memotong kumis, memotong kuku dan mencabut bulu ketiak.\""},"5137":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مِنْهَالٍ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا عُمَرُ بْنُ مُحَمَّدِ بْنِ زَيْدٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَالِفُوا الْمُشْرِكِينَ وَفِّرُوا اللِّحَى وَأَحْفُوا الشَّوَارِبَ وَكَانَ ابْنُ عُمَرَ إِذَا حَجَّ أَوْ اعْتَمَرَ قَبَضَ عَلَى لِحْيَتِهِ فَمَا فَضَلَ أَخَذَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Minhal] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Umar bin Muhammad bin Zaid] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Selisihilah orang-orang musyrik, panjangkanlah jenggot dan cukurlah kumis kalian.\" Sedangkan apabila Ibnu Umar berhaji atau Umrah dia memegang jenggotnya dan memotong selebihnya.\""},"5138":{"ar":"حَدَّثَنِي مُحَمَّدٌ أَخْبَرَنَا عَبْدَةُ أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْهَكُوا الشَّوَارِبَ وَأَعْفُوا اللِّحَى","id":"Telah menceritakan kepadaku [Muhammad] telah mengabarkan kepada kami [Abdah] telah mengabarkan kepada kami [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhuma dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Cukurlah kumis kalian dan biarkanlah jenggot kalian (panjang).\""},"5139":{"ar":"حَدَّثَنَا مُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا وُهَيْبٌ عَنْ أَيُّوبَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ قَالَ سَأَلْتُ أَنَسًاأَخَضَبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَمْ يَبْلُغْ الشَّيْبَ إِلَّا قَلِيلًا","id":"Telah menceritakan kepada kami [Mu'alla bin Asad] telah menceritakan kepada kami [Wuhaib] dari [Ayyub] dari [Muhammad bin Sirin] dia berkata; saya bertanya kepada [Anas] \"Apakah Nabi shallallahu 'alaihi wasallam pernah menyemir rambutnya?\" dia menjawab; \"Beliau tidak menyemir rambut karena ubannya kecuali hanya sedikit.\""},"5140":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ ثَابِتٍ قَالَ سُئِلَ أَنَسٌعَنْ خِضَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّهُ لَمْ يَبْلُغْ مَا يَخْضِبُ لَوْ شِئْتُ أَنْ أَعُدَّ شَمَطَاتِهِ فِي لِحْيَتِهِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Tsabit] dia berkata; [Anas] di tanya mengenai semir rambut nabi shallallahu 'alaihi wasallam, Anas menjawab; \"Beliau tidak menyemirnya, jika aku mau maka saya akan menghitung rambut hitam yang bercampur di rambut putih pada jenggot beliau.\""},"5141":{"ar":"حَدَّثَنَا مَالِكُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا إِسْرَائِيلُ عَنْ عُثْمَانَ بْنِ عَبْدِ اللَّهِ بْنِ مَوْهَبٍ قَالَ أَرْسَلَنِي أَهْلِي إِلَى أُمِّ سَلَمَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَبِقَدَحٍ مِنْ مَاءٍ وَقَبَضَ إِسْرَائِيلُ ثَلَاثَ أَصَابِعَ مِنْ قُصَّةٍ فِيهِ شَعَرٌ مِنْ شَعَرِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ إِذَا أَصَابَ الْإِنْسَانَ عَيْنٌ أَوْ شَيْءٌ بَعَثَ إِلَيْهَا مِخْضَبَهُ فَاطَّلَعْتُ فِي الْجُلْجُلِ فَرَأَيْتُ شَعَرَاتٍ حُمْرًا","id":"Telah menceritakan kepada kami [Malik bin Isma'il] telah menceritakan kepada kami [Isra`il] dari [Utsman bin Abdullah bin Mauhab] berkata; \"Keluargaku pernah menyuruhku menemui [Ummu Salamah] isteri Nabi shallallahu 'alaihi wasallam dengan membawa mangkuk berisi air, sementara Isra'il memegang mangkuk tersebut menggunakan tiga jarinya yang didalamnya terdapat beberapa helai rambut Nabi shallallahu 'alaihi wasallam yang diikat, apabila ada seseorang yang terkena sihir atau sesuatu, maka tempat mewarnai rambut beliau diberikan kepada Ummu Salamah, lalu aku mendongakkan kepala ke wadah yang menyerupai lonceng, aku melihat rambut beliau sudah berubah merah.\""},"5142":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا سَلَّامٌ عَنْ عُثْمَانَ بْنِ عَبْدِ اللَّهِ بْنِ مَوْهَبٍ قَالَ دَخَلْتُ عَلَى أُمِّ سَلَمَةَفَأَخْرَجَتْ إِلَيْنَا شَعَرًا مِنْ شَعَرِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَخْضُوبًاوَ قَالَ لَنَا أَبُو نُعَيْمٍ حَدَّثَنَا نُصَيْرُ بْنُ أَبِي الْأَشْعَثِ عَنْ ابْنِ مَوْهَبٍ أَنَّ أُمَّ سَلَمَةَ أَرَتْهُ شَعَرَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحْمَرَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Sallam] dari [Utsman bin Abdullah bin Mauhab] dia berkata; aku pernah menemui [Ummu Salamah] lalu dia mengeluarkan kepada kami beberapa helai rambut Nabi shallallahu 'alaihi wasallam yang telah diwarnai dengan inai.\" [Abu Nu'aim] berkata kepada kami; telah menceritakan kepada kami [Nushair bin Abu Al Asy'ats] dari [Ibnu Mauhab] bahwa [Ummu Salamah] pernah memperlihatkan rambut Nabi shallallahu 'alaihi wasallam berwarna merah.\""},"5143":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا الزُّهْرِيُّ عَنْ أَبِي سَلَمَةَ وَسُلَيْمَانَ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْيَهُودَ وَالنَّصَارَى لَا يَصْبُغُونَ فَخَالِفُوهُمْ","id":"Telah menceritakan kepada kami [Al Humaidi] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Az Zuhri] dari [Abu Salamah] dan [Sulaiman bin Yasar] dari [Abu Hurairah] radliallahu 'anhu, bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya orang-orang Yahudi dan Nashrani tidak mewarnai rambut mereka, maka selisihilah mereka.\""},"5144":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكُ بْنُ أَنَسٍ عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ أَنَّهُ سَمِعَهُ يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ بِالطَّوِيلِ الْبَائِنِ وَلَا بِالْقَصِيرِ وَلَيْسَ بِالْأَبْيَضِ الْأَمْهَقِ وَلَيْسَ بِالْآدَمِ وَلَيْسَ بِالْجَعْدِ الْقَطَطِ وَلَا بِالسَّبْطِ بَعَثَهُ اللَّهُ عَلَى رَأْسِ أَرْبَعِينَ سَنَةً فَأَقَامَ بِمَكَّةَ عَشْرَ سِنِينَ وَبِالْمَدِينَةِ عَشْرَ سِنِينَ وَتَوَفَّاهُ اللَّهُ عَلَى رَأْسِ سِتِّينَ سَنَةً وَلَيْسَ فِي رَأْسِهِ وَلِحْيَتِهِ عِشْرُونَ شَعَرَةً بَيْضَاءَ","id":"Telah menceritakan kepada kami [Isma'il] dia berkata; telah menceritakan kepadaku [Malik bin Anas] dari [Rabi'ah bin Abu Abdurrahman] dari [Anas bin Malik] radliallahu 'anhu bahwa dia mendengar Anas berkata; \"Rasulullah shallallahu 'alaihi wasallam adalah orang yang berpawakan tidak tinggi sekali dan tidak pula pendek, (kulitnya) tidak putih bule dan tidak pula terlalu coklat, (rambutnya) tidak keriting dan tidak pula lurus, beliau diutus Allah ketika berusia empat puluh tahun, tinggal di Makkah selama sepuluh tahun dan di Madinah sepuluh tahun, sementara rambut yang putih di kepala dan jenggot beliau tidak sampai berjumlah dua puluh helai.\""},"5145":{"ar":"حَدَّثَنَا مَالِكُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَاقَ سَمِعْتُ الْبَرَاءَ يَقُولُمَا رَأَيْتُ أَحَدًا أَحْسَنَ فِي حُلَّةٍ حَمْرَاءَ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ بَعْضُ أَصْحَابِي عَنْ مَالِكٍ إِنَّ جُمَّتَهُ لَتَضْرِبُ قَرِيبًا مِنْ مَنْكِبَيْهِ قَالَ أَبُو إِسْحَاقَ سَمِعْتُهُ يُحَدِّثُهُ غَيْرَ مَرَّةٍ مَا حَدَّثَ بِهِ قَطُّ إِلَّا ضَحِكَ قَالَ شُعْبَةُ شَعَرُهُ يَبْلُغُ شَحْمَةَ أُذُنَيْهِ","id":"Telah menceritakan kepada kami [Malik bin Isma'il] telah menceritakan kepada kami [Isra`il] dari [Abu Ishaq] saya mendengar [Al Barra`] berkata; saya belum pernah melihat seseorang yang paling bagus dari Nabi shallallahu 'alaihi wasallam ketika mengenakan baju berwarna merah, Sebagian sahabatku mengatakan; dari Malik bahwa rambut beliau menjuntai hingga mendekati kedua bahunya.\" Abu Ishaq mengatakan; bahwa saya mendengar ia menceritakan hadits ini tidak hanya sekali, dan tidaklah ia menceritakan hal ini kecuali ia tersenyum.\" [Syu'bah] mengatakan; \"Bahwa rambut beliau hingga melebihi kedua telinganya.\""},"5146":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أُرَانِي اللَّيْلَةَ عِنْدَ الْكَعْبَةِ فَرَأَيْتُ رَجُلًا آدَمَ كَأَحْسَنِ مَا أَنْتَ رَاءٍ مِنْ أُدْمِ الرِّجَالِ لَهُ لِمَّةٌ كَأَحْسَنِ مَا أَنْتَ رَاءٍ مِنْ اللِّمَمِ قَدْ رَجَّلَهَا فَهِيَ تَقْطُرُ مَاءً مُتَّكِئًا عَلَى رَجُلَيْنِ أَوْ عَلَى عَوَاتِقِ رَجُلَيْنِ يَطُوفُ بِالْبَيْتِ فَسَأَلْتُ مَنْ هَذَا فَقِيلَ الْمَسِيحُ ابْنُ مَرْيَمَ وَإِذَا أَنَا بِرَجُلٍ جَعْدٍ قَطَطٍ أَعْوَرِ الْعَيْنِ الْيُمْنَى كَأَنَّهَا عِنَبَةٌ طَافِيَةٌ فَسَأَلْتُ مَنْ هَذَا فَقِيلَ الْمَسِيحُ الدَّجَّالُ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Nafi'] dari [Abdullah bin Umar] radliallahu 'anhuma bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Di saat saya tengah bermimpi pada malam hari di dekat Ka'bah saya melihat seorang laki-laki yang berkulit sawo matang, berperawakan sangat rupawan yang pernah saya lihat dari seorang laki-laki dan berambut lurus, dipapah dua orang laki-laki atau berada di antara dua pundak laki-laki dan rambutnya meneteskan air, tengah thawaf di Ka'bah, Saya bertanya, 'Siapa orang ini? ' di beritahukan, 'Ibnu Maryam.' Tiba-tiba ada seorang lelaki berambut keriting, dan buta mata kanannya, seolah-olah matanya seperti buah anggur yang menjorok. Lalu Saya bertanya, 'Siapakah orang ini? ' diberitahukan; 'Ad Dajjal.\""},"5147":{"ar":"حَدَّثَنَا إِسْحَاقُ أَخْبَرَنَا حِبَّانُ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ حَدَّثَنَا أَنَسٌأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَضْرِبُ شَعَرُهُ مَنْكِبَيْهِ","id":"Telah menceritakan kepada kami [Ishaq] telah mengabarkan kepada kami [Hibban] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] telah menceritakan kepada kami [Anas] bahwa Rambut Nabi shallallahu 'alaihi wasallam menjuntai sampai ke kedua bahu beliau.\""},"5148":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍكَانَ يَضْرِبُ شَعَرُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْكِبَيْهِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Anas] bahwa rambut Nabi shallallahu 'alaihi wasallam menjuntai hingga kebahu beliau.\""},"5149":{"ar":"حَدَّثَنِي عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ قَالَ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ قَالَ سَأَلْتُ أَنَسَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُعَنْ شَعَرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ كَانَ شَعَرُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجِلًا لَيْسَ بِالسَّبِطِ وَلَا الْجَعْدِ بَيْنَ أُذُنَيْهِ وَعَاتِقِهِ","id":"Telah menceritakan kepadaku ['Amru bin Ali] telah menceritakan kepada kami [Wahb bin Jarir] dia berkata; telah menceritakan kepadaku [Ayahku] dari [Qatadah] dia berkata; saya bertanya kepada [Anas bin Malik] radliallahu 'anhu mengenai rambut Rasulullah shallallahu 'alaihi wasallam, dia berkata; \"Rambut Rasulullah shallallahu 'alaihi wasallam tidak lurus dan tidak pula keriting yaitu (menjuntai) antara kedua telinga hingga bahu beliau.\""},"5150":{"ar":"حَدَّثَنَا مُسْلِمٌ حَدَّثَنَا جَرِيرٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَخْمَ الْيَدَيْنِ لَمْ أَرَ بَعْدَهُ مِثْلَهُ وَكَانَ شَعَرُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجِلًا لَا جَعْدَ وَلَا سَبِطَ","id":"Telah menceritakan kepada kami [Muslim] telah menceritakan kepada kami [Jarir] dari [Qatadah] dari [Anas] dia berkata; \"Nabi shallallahu 'alaihi wasallam adalah seseorang yang berlengan kekar, aku tidak pernah melihat orang yang menyerupainya, sedangkan rambut Nabi shallallahu 'alaihi wasallam ikal, tidak terlalu lurus dan tidak pula keriting.\""},"5151":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ عَنْ قَتَادَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَخْمَ الْيَدَيْنِ وَالْقَدَمَيْنِ حَسَنَ الْوَجْهِ لَمْ أَرَ بَعْدَهُ وَلَا قَبْلَهُ مِثْلَهُ وَكَانَ بَسِطَ الْكَفَّيْنِ","id":"Telah menceritakan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Jarir bin Hazim] dari [Qatadah] dari [Anas] radliallahu 'anhu dia berkata; Nabi shallallahu 'alaihi wasallam adalah seseorang yang lengan dan kakinya besar, bagus wajahnya, saya belum pernah melihat orang yang menyerupainya baik sebelum dan sesudahnya, telapak tangan beliau juga lebar.\""},"5152":{"ar":"حَدَّثَنِي عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا مُعَاذُ بْنُ هَانِئٍ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسِ بْنِ مَالِكٍ أَوْ عَنْ رَجُلٍ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَخْمَ الْقَدَمَيْنِ حَسَنَ الْوَجْهِ لَمْ أَرَ بَعْدَهُ مِثْلَهُوَقَالَ هِشَامٌ عَنْ مَعْمَرٍ عَنْ قَتَادَةَ عَنْ أَنَسٍ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَثْنَ الْقَدَمَيْنِ وَالْكَفَّيْنِ وَقَالَ أَبُو هِلَالٍ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ أَوْ جَابِرِ بْنِ عَبْدِ اللَّهِ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَخْمَ الْكَفَّيْنِ وَالْقَدَمَيْنِ لَمْ أَرَ بَعْدَهُ شَبَهًا لَهُ","id":"Telah menceritakan kepadaku ['Amru bin Ali] telah menceritakan kepada kami [Mu'adz bin Hani'] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] dari [Anas bin Malik] atau dari [seorang laki-laki] dari [Abu Hurairah] dia berkata; \"Nabi shallallahu 'alaihi wasallam adalah seorang yang besar kakinya, bagus perawakannya, saya belum pernah melihat seseorang seperti itu sesudah beliau.\" [Hisyam] mengatakan; dari [Ma'mar] dari [Qatadah] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam adalah seseorang yang lebar telapak kaki dan telapak tangannya.\" [Abu Hilal] mengatakan; telah menceritakan kepada kami [Qatadah] dari [Anas] atau [Jabir bin Abdullah] bahwa Nabi shallallahu 'alaihi wasallam adalah seseorang yang lebar telapak tangan dan telapak kakinya, saya belum pernah melihat orang yang menyerupai setelah beliau.\""},"5153":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنِي ابْنُ أَبِي عَدِيٍّ عَنْ ابْنِ عَوْنٍ عَنْ مُجَاهِدٍ قَالَ كُنَّا عِنْدَ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَافَذَكَرُوا الدَّجَّالَ فَقَالَ إِنَّهُ مَكْتُوبٌ بَيْنَ عَيْنَيْهِ كَافِرٌ وَقَالَ ابْنُ عَبَّاسٍ لَمْ أَسْمَعْهُ قَالَ ذَاكَ وَلَكِنَّهُ قَالَ أَمَّا إِبْرَاهِيمُ فَانْظُرُوا إِلَى صَاحِبِكُمْ وَأَمَّا مُوسَى فَرَجُلٌ آدَمُ جَعْدٌ عَلَى جَمَلٍ أَحْمَرَ مَخْطُومٍ بِخُلْبَةٍ كَأَنِّي أَنْظُرُ إِلَيْهِ إِذْ انْحَدَرَ فِي الْوَادِي يُلَبِّي","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepadaku [Ibnu Abu 'Adi] dari [Ibnu 'Aun] dari [Mujahid] dia berkata; Kami pernah berada di samping [Ibnu Abbas] radliallahu 'anhuma, lalu orang-orang menyebut-nyebut Dajjal, lantas Ibnu Abbas mengatakan; \"Sesungguhnya di antara kedua mata Dajjal tertulis \"Kafir\", Ibnu Abbas mengatakan; \"Namun saya belum pernah mendengar beliau (secara langsung) mengatakan hal itu, akan tetapi beliau (Nabi) mengatakan: \"Adapun Ibrahim, maka lihatlah pada teman kalian, sedangkan Musa, ia adalah seorang laki-laki (berkulit) kecoklatan dan bertubuh kekar tengah (menunggang) unta merah yang kendalinya terbuat dari sabut kurma, seolah-olah aku melihat kepadanya ketika menuruni lembah sambil bertalbiyah.\""},"5154":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ قَالَ سَمِعْتُ عُمَرَ رَضِيَ اللَّهُ عَنْهُ يَقُولُ مَنْ ضَفَّرَ فَلْيَحْلِقْ وَلَا تَشَبَّهُوا بِالتَّلْبِيدِ وَكَانَ ابْنُ عُمَرَ يَقُولُلَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُلَبِّدًا","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku [Salim bin Abdullah] bahwa [Abdullah bin Umar] berkata; saya mendengar Umar radliallahu 'anhu berkata; \"Barangsiapa mengepang rambutnya hendaknya ia mencukurnya (ketika haji) dan janganlah ia seperti orang yang mengikat rambutnya (menguncir), sementara Ibnu Umar mengatakan; \"Sesungguhnya saya pernah melihat Rasulullah shallallahu 'alaihi wasallam mengikat (menguncir) rambutnya.\""},"5155":{"ar":"حَدَّثَنِي حِبَّانُ بْنُ مُوسَى وَأَحْمَدُ بْنُ مُحَمَّدٍ قَالَا أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُهِلُّ مُلَبِّدًا يَقُولُ لَبَّيْكَ اللَّهُمَّ لَبَّيْكَ لَبَّيْكَ لَا شَرِيكَ لَكَ لَبَّيْكَ إِنَّ الْحَمْدَ وَالنِّعْمَةَ لَكَ وَالْمُلْكَ لَا شَرِيكَ لَكَ لَا يَزِيدُ عَلَى هَؤُلَاءِ الْكَلِمَاتِ","id":"Telah menceritakan kepada kami [Hibban bin Musa] dan [Ahmad bin Muhammad] keduanya mengatakan; telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Yunus] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar] radliallahu 'anhuma dia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bertalbiyah dengan mengikat rambutnya (menguncir) sambil mengucapkan: \"LABBAIKALLAAHUMMA LABBAIK LABBAIKALAA SYARIIKA LABBAIK INNAL HAMDA WAN NI'MATA LAKA WAL MULK LAA SYARIIKALAK\" dan tidak lebih dari mengucapkan kalimat tersebut.\""},"5156":{"ar":"حَدَّثَنِي إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ حَفْصَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ قُلْتُيَا رَسُولَ اللَّهِ مَا شَأْنُ النَّاسِ حَلُّوا بِعُمْرَةٍ وَلَمْ تَحْلِلْ أَنْتَ مِنْ عُمْرَتِكَ قَالَ إِنِّي لَبَّدْتُ رَأْسِي وَقَلَّدْتُ هَدْيِي فَلَا أَحِلُّ حَتَّى أَنْحَرَ","id":"Telah menceritakan kepadaku [Isma'il] dia berkata; telah menceritakan kepadaku [Malik] dari [Nafi'] dari [Abdullah bin Umar] dari [Hafshah] radliallahu 'anha isteri Nabi shallallahu 'alaihi wasallam dia berkata; saya bertanya; \"Wahai Rasulullah, kenapa orang-orang telah bertahallul dari umrahnya sedangkan anda belum bertahallul dari umrahmu? Beliau menjawab: \"Saya telah mengikat kepalaku dan mengalungi hewan kurbanku, dan saya tidak akan bertahallul hingga menyembelih kurban.\""},"5157":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ حَدَّثَنَا ابْنُ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحِبُّ مُوَافَقَةَ أَهْلِ الْكِتَابِ فِيمَا لَمْ يُؤْمَرْ فِيهِ وَكَانَ أَهْلُ الْكِتَابِ يَسْدِلُونَ أَشْعَارَهُمْ وَكَانَ الْمُشْرِكُونَ يَفْرُقُونَ رُءُوسَهُمْ فَسَدَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَاصِيَتَهُ ثُمَّ فَرَقَ بَعْدُ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Ibrahim bin Sa'd] telah menceritakan kepada kami [Ibnu Syihab] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] radliallahu 'anhuma berkata; \"Nabi shallallahu 'alaihi wasallam suka menyamai Ahli Kitab di sebagian perkara yang tidak diperintahkan, Ahli Kitab suka mengurai rambut mereka, sedangkan orang-orang Musyrik biasa membelah rambut mereka, maka beliau lebih suka mengurai rambut bagian depannya, lalu beliau membelahnya.\""},"5158":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ وَعَبْدُ اللَّهِ بْنُ رَجَاءٍ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَأَنِّي أَنْظُرُ إِلَى وَبِيصِ الطِّيبِ فِي مَفَارِقِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مُحْرِمٌ قَالَ عَبْدُ اللَّهِ فِي مَفْرِقِ النَّبِيِّ","id":"Telah menceritakan kepada kami [Abu Al Walid] dan [Abdullah bin Raja'] keduanya berkata; telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah] radliallahu 'anha berkata; \"Seakan-akan saya melihat kilatan minyak yang berada di ubun-ubun (rambut) Nabi shallallahu 'alaihi wasallam ketika beliau tengah berihram.\" Abdullah mengatakan; \"Di ubun-ubun (rambut) Nabi.\""},"5159":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا الْفَضْلُ بْنُ عَنْبَسَةَ أَخْبَرَنَا هُشَيْمٌ أَخْبَرَنَا أَبُو بِشْرٍ ح و حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا هُشَيْمٌ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَبِتُّ لَيْلَةً عِنْدَ مَيْمُونَةَ بِنْتِ الْحَارِثِ خَالَتِي وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَهَا فِي لَيْلَتِهَا قَالَ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي مِنْ اللَّيْلِ فَقُمْتُ عَنْ يَسَارِهِ قَالَ فَأَخَذَ بِذُؤَابَتِي فَجَعَلَنِي عَنْ يَمِينِهِحَدَّثَنَا عَمْرُو بْنُ مُحَمَّدٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا أَبُو بِشْرٍ بِهَذَا وَقَالَ بِذُؤَابَتِي أَوْ بِرَأْسِي","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Al Fadl bin 'Anbasah] telah mengabarkan kepada kami [Husyaim] telah mengabarkan kepada kami [Abu Bisyr]. Dan di riwayatkan dari jalur lain, telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Husyaim] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibnu Abbas] radliallahu 'anhuma dia berkata; \"Saya pernah bermalam di rumah bibiku yaitu Maimunah binti Al Harits, sementara Rasulullah shallallahu 'alaihi wasallam malam itu berada di sampingnya, Ibnu Abbas melanjutkan; \"Lalu beliau mengerjakan shalat malam dan akupun ikut shalat di sebelah kirinya, Ibnu Abbas menuturkan; \"Kemudian beliau memegang rambutku yang terkuncir dan memposisikanku di sebelah kanannya.\" Telah menceritakan kepada kami ['Amru bin Muhammad] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Abu Bisyr] dengan hadits ini, dia mengatakan; \"(memegang) kuncir rambutku atau kepalaku.\""},"5160":{"ar":"حَدَّثَنِي مُحَمَّدٌ قَالَ أَخْبَرَنِي مَخْلَدٌ قَالَ أَخْبَرَنِي ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ حَفْصٍ أَنَّ عُمَرَ بْنَ نَافِعٍ أَخْبَرَهُ عَنْ نَافِعٍ مَوْلَى عَبْدِ اللَّهِ أَنَّهُ سَمِعَ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عَنْ الْقَزَعِ قَالَ عُبَيْدُ اللَّهِ قُلْتُ وَمَا الْقَزَعُ فَأَشَارَ لَنَا عُبَيْدُ اللَّهِ قَالَ إِذَا حَلَقَ الصَّبِيَّ وَتَرَكَ هَا هُنَا شَعَرَةً وَهَا هُنَا وَهَا هُنَا فَأَشَارَ لَنَا عُبَيْدُ اللَّهِ إِلَى نَاصِيَتِهِ وَجَانِبَيْ رَأْسِهِ قِيلَ لِعُبَيْدِاللَّهِ فَالْجَارِيَةُ وَالْغُلَامُ قَالَ لَا أَدْرِي هَكَذَا قَالَ الصَّبِيُّ قَالَ عُبَيْدُ اللَّهِ وَعَاوَدْتُهُ فَقَالَ أَمَّا الْقُصَّةُ وَالْقَفَا لِلْغُلَامِ فَلَا بَأْسَ بِهِمَا وَلَكِنَّ الْقَزَعَ أَنْ يُتْرَكَ بِنَاصِيَتِهِ شَعَرٌ وَلَيْسَ فِي رَأْسِهِ غَيْرُهُ وَكَذَلِكَ شَقُّ رَأْسِهِ هَذَا وَهَذَا","id":"Telah menceritakan kepada kami [Muhammad] dia berkata; telah mengabarkan kepadaku [Makhlad] dia berkata; telah mengabarkan kepadaku [Ibnu Juraij] dia berkata; telah mengabarkan kepadaku ['Ubaidullah bin Hafsh] bahwa [Umar bin Nafi'] mengabarkan kepadanya dari [Nafi'] bekas budak Abdullah pernah mendengar [Ibnu Umar] radliallahu 'anhuma berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam melarang dari qaza' (mencukur sebagian rambut kepala dan membiarkan sebagian yang lain).\" 'Ubaidullah mengatakan; \"saya bertanya; \"Apakah qaza' itu\" 'Ubaidullah lalu mengisyaratkan kepada kami sambil mengatakan; \"Jika rambut anak kecil dicukur, lalu membiarkan sebagian yang ini, yang ini dan yang ini.\" 'Ubaidullah menunjukkan kepada kami pada ubun-ubun dan samping (kanan dan kiri) kepalanya.\" Ditanyakan kepada 'Ubaidullah; \"Apakah hal itu berlaku untuk anak laki-laki dan perempuan?\" dia menjawab; \"Saya tidak tahu yang seperti ini.\" Penanya bertanya lagi; \"Apakah khusus untuk anak laki-laki.\" 'Ubaidullah mengatakan (kepada syaikhnya); \"Pertanyaan itu pernah juga aku ulangi (kepada syaikhku), lalu dia berkata; \"Dan tidak mengapa (membiarkan) rambut depan kepala dan rambut tengkuk bagi anak-anak, akan tetapi maksud qaza' adalah membiarkan sebagian rambut yang ada di ubun-ubun, hingga di kepala hanya tersisa itu, begitu pula dengan memangkas rambut kepalanya ini dan ini.\""},"5161":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُثَنَّى بْنِ عَبْدِ اللَّهِ بْنِ أَنَسِ بْنِ مَالِكٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دِينَارٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْقَزَعِ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Abdullah bin Mutsanna bin Abdullah bin Anas bin Malik] telah menceritakan kepada kami [Abdullah bin Dinar] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam melarang qaza' (mencukur sebagian rambut kepala dan membiarkan sebagian yang lain).\""},"5162":{"ar":"حَدَّثَنِي أَحْمَدُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يَحْيَى بْنُ سَعِيدٍ أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْطَيَّبْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِي لِحُرْمِهِ وَطَيَّبْتُهُ بِمِنًى قَبْلَ أَنْ يُفِيضَ","id":"Telah menceritakan kepadaku [Ahmad bin Muhammad] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Yahya bin Sa'id] telah mengabarkan kepada kami [Abdurrahman bin Al Qasim] dari [Ayahnya] dari [Aisyah] dia berkata; \"Saya pernah meminyaki Nabi shallallahu 'alaihi wasallam ketika ihramnya, dan saya juga pernah meminyaki beliau sebelum beliau mengerjakan ifadlah (dalam haji).\""},"5163":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ نَصْرٍ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَاقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكُنْتُ أُطَيِّبُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَطْيَبِ مَا يَجِدُ حَتَّى أَجِدَ وَبِيصَ الطِّيبِ فِي رَأْسِهِ وَلِحْيَتِهِ","id":"Telah menceritakan kepada kami [Ishaq bin Nashr] telah menceritakan kepada kami [Yahya bin Adam] telah menceritakan kepada kami [Isra'il] dari [Abu Ishaq] dari [Abdurrahman bin Al Aswad] dari [Ayahnya] dari [Aisyah] dia berkata; \"Saya pernah memberi minyak wangi kepada Nabi shallallahu 'alaihi wasallam dengan minyak wangi yang terbaik yang saya dapatkan sehingga saya dapati kilauan minyak wangi tersebut di kepala beliau dan jenggot beliau.\""},"5164":{"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ سَهْلِ بْنِ سَعْدٍأَنَّ رَجُلًا اطَّلَعَ مِنْ جُحْرٍ فِي دَارِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَحُكُّ رَأْسَهُ بِالْمِدْرَى فَقَالَ لَوْ عَلِمْتُ أَنَّكَ تَنْظُرُ لَطَعَنْتُ بِهَا فِي عَيْنِكَ إِنَّمَا جُعِلَ الْإِذْنُ مِنْ قِبَلِ الْأَبْصَارِ","id":"Telah menceritakan kepada kami [Adam bin Abu Iyas] telah menceritakan kepada kami [Ibnu Abu Dzi'b] dari [Az Zuhri] dari [Sahl bin Sa'd] bahwa seorang laki-laki sedang mengintip dari kamar rumah Nabi shallallahu 'alaihi wasallam, sementara Nabi shallallahu 'alaihi wasallam tengah menyisir rambutnya dengan midra (sejenis sisir), maka beliau bersabda: \"Sekiranya aku mengetahui kamu mengintip, sungguh aku akan mencolok kedua matamu, bukankah diberlakukannya meminta ijin demi pandangan.\""},"5165":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكُنْتُ أُرَجِّلُ رَأْسَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا حَائِضٌحَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Urwah bin Zubair] dari [Aisyah] radliallahu 'anha dia berkata; \"Saya pernah menyisir rambut Rasulullah shallallahu 'alaihi wasallam sementara diriku sedang haidl.\" Telah menceritakan kepada kami [Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Hisyam] dari [Ayahnya] dari [Aisyah] seperti hadits di atas.\""},"5166":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ أَشْعَثَ بْنِ سُلَيْمٍ عَنْ أَبِيهِ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يُعْجِبُهُ التَّيَمُّنُ مَا اسْتَطَاعَ فِي تَرَجُّلِهِ وَوُضُوئِهِ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari [Asy'ats bin Sulaim] dari [Ayahnya] dari [Masruq] dari [Aisyah] dari Nabi shallallahu 'alaihi wasallam bahwa beliau menyukai tayamun (mendahulukan yang kanan) ketika menyisir rambut dan berwudlu'.\""},"5167":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا هِشَامٌ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ ابْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُّ عَمَلِ ابْنِ آدَمَ لَهُ إِلَّا الصَّوْمَ فَإِنَّهُ لِي وَأَنَا أَجْزِي بِهِ وَلَخُلُوفُ فَمِ الصَّائِمِ أَطْيَبُ عِنْدَ اللَّهِ مِنْ رِيحِ الْمِسْكِ","id":"Telah menceritakan kepadaku [Abdullah bin Muhammad] telah menceritakan kepada kami [Hisyam] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ibnu Musayyab] dari [Abu Hurairah] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Semua amalan bani Adam adalah untuknya kecuali puasa, sesungguhnya puasa adalah untuk-Ku (Allah), dan Aku lah yang membalasnya, sungguh bau mulut orang yang berpuasa itu lebih wangi di sisi Allah dari pada harumnya minyak wangi.\""},"5168":{"ar":"حَدَّثَنَا مُوسَى حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا هِشَامٌ عَنْ عُثْمَانَ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكُنْتُ أُطَيِّبُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ إِحْرَامِهِ بِأَطْيَبِ مَا أَجِدُ","id":"Telah menceritakan kepada kami [Musa] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Hisyam] dari [Utsman bin Urwah] dari [Ayahnya] dari [Aisyah] radliallahu 'anha dia berkata; \"Saya pernah memberi minyak wangi kepada Nabi shallallahu 'alaihi wasallam ketika beliau berihram dengan sebaik-baik minyak wangi yang saya dapatkan.\""},"5169":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا عَزْرَةُ بْنُ ثَابِتٍ الْأَنْصَارِيُّ قَالَ حَدَّثَنِي ثُمَامَةُ بْنُ عَبْدِ اللَّهِ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُأَنَّهُ كَانَ لَا يَرُدُّ الطِّيبَ وَزَعَمَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ لَا يَرُدُّ الطِّيبَ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Azrah bin Tsabit Al Anshari] dia berkata; telah menceritakan kepadaku [Tsumamah bin Abdullah] dari [Anas] radliallahu 'anhu bahwa dia tidak pernah menolak (pemberian) minyak wangi, dan dia mengira bahwa Nabi shallallahu 'alaihi wasallam juga tidak pernah menolak (pemberian) minyak wangi.\""},"5170":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ الْهَيْثَمِ أَوْ مُحَمَّدٌ عَنْهُ عَنْ ابْنِ جُرَيْجٍ أَخْبَرَنِي عُمَرُ بْنُ عَبْدِ اللَّهِ بْنِ عُرْوَةَ سَمِعَ عُرْوَةَ وَالْقَاسِمَ يُخْبِرَانِ عَنْ عَائِشَةَ قَالَتْطَيَّبْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدَيَّ بِذَرِيرَةٍ فِي حَجَّةِ الْوَدَاعِ لِلْحِلِّ وَالْإِحْرَامِ","id":"Telah menceritakan kepada kami [Utsman bin Haitsam] atau [Muhammad] dari [Ibnu Juraij] telah menceritakan kepadaku [Umar bin Abdullah bin Urwah] dia mendengar [Urwah] dan [Al Qasim] keduanya mengabarkan dari [Aisyah] dia berkata; \"Saya pernah memberi minyak wangi dzarirah (sejenis minyak wangi) kepada Rasulullah shallallahu 'alaihi wasallam untuk tahallul dan ihramnya ketika haji wada'.\""},"5171":{"ar":"حَدَّثَنَا عُثْمَانُ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ قَالَ عَبْدُ اللَّهِلَعَنَ اللَّهُ الْوَاشِمَاتِ وَالْمُسْتَوْشِمَاتِ وَالْمُتَنَمِّصَاتِ وَالْمُتَفَلِّجَاتِ لِلْحُسْنِ الْمُغَيِّرَاتِ خَلْقَ اللَّهِ تَعَالَى مَالِي لَا أَلْعَنُ مَنْ لَعَنَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي كِتَابِ اللَّهِ{ وَمَا آتَاكُمْ الرَّسُولُ فَخُذُوهُ }","id":"Telah menceritakan kepada kami [Utsman] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] dari [Alqamah], [Abdullah] mengatakan; \"Allah melaknat orang yang mentato dan orang yang meminta ditato, orang yang mencukur habis alis dan merenggangkan gigi untuk kecantikan dengan merubah ciptaan Allah Ta'ala, kenapa saya tidak melaknat orang yang dilaknat Nabi shallallahu 'alaihi wasallam sementara dalam kitabullah telah termaktub Dan sesuatu yang datang dari rasul, maka ambillah (QS Al Hasyr; 7).\""},"5172":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ أَنَّهُ سَمِعَ مُعَاوِيَةَ بْنَ أَبِي سُفْيَانَعَامَ حَجَّ وَهُوَ عَلَى الْمِنْبَرِ وَهُوَ يَقُولُ وَتَنَاوَلَ قُصَّةً مِنْ شَعَرٍ كَانَتْ بِيَدِ حَرَسِيٍّ أَيْنَ عُلَمَاؤُكُمْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عَنْ مِثْلِ هَذِهِ وَيَقُولُ إِنَّمَا هَلَكَتْ بَنُو إِسْرَائِيلَ حِينَ اتَّخَذَ هَذِهِ نِسَاؤُهُمْوَقَالَ ابْنُ أَبِي شَيْبَةَ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا فُلَيْحٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَعَنَ اللَّهُ الْوَاصِلَةَ وَالْمُسْتَوْصِلَةَ وَالْوَاشِمَةَ وَالْمُسْتَوْشِمَةَ","id":"Telah menceritakan kepada kami [Isma'il] dia berkata; telah menceritakan kepadaku [Malik] dari [Ibnu Syihab] dari [Humaid bin Abdurrahman bin 'Auf] bahwa dia mendengar [Mu'awiyah bin Abu Sufyan] berkhutbah di atas mimbar ketika musim haji, sambil memeggang seikat rambut (sambungan rambut) dari tangan pengawalnya, katanya; \"Dimanakah ulama kalian! Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam melarang dari yang seperti ini, beliau bersabda: \"Bani Isra'il celaka ketika wanita-wanita mereka mengambil (memakai) yang seperti ini.\" Ibnu Abu Syaibah mengatakan; telah menceritakan kepada kami Yunus bin Muhammad telah menceritakan kepada kami Fulaih dari Zaid bin Aslam dari 'Atha` bin Yasar dari Abu Hurairah radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Allah melaknat orang yang menyambung rambutnya dan yang minta disambung rambutnya dan melaknat orang yang mentato dan yang minta ditato.\""},"5173":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ قَالَ سَمِعْتُ الْحَسَنَ بْنَ مُسْلِمِ بْنِ يَنَّاقٍ يُحَدِّثُ عَنْ صَفِيَّةَ بِنْتِ شَيْبَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ جَارِيَةً مِنْ الْأَنْصَارِ تَزَوَّجَتْ وَأَنَّهَا مَرِضَتْ فَتَمَعَّطَ شَعَرُهَا فَأَرَادُوا أَنْ يَصِلُوهَا فَسَأَلُوا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَعَنَ اللَّهُ الْوَاصِلَةَ وَالْمُسْتَوْصِلَةَتَابَعَهُ ابْنُ إِسْحَاقَ عَنْ أَبَانَ بْنِ صَالِحٍ عَنْ الْحَسَنِ عَنْ صَفِيَّةَ عَنْ عَائِشَةَ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Murrah] dia berkata; saya mendengar [Al Hasan bin Muslim bin Yannaq] menceritakan dari [Shafiyah binti Syaibah] dari [Aisyah] radliallahu 'anha bahwa seorang budak perempuan milik orang Anshar hendak menikah, sementara dirinya tengah sakit hingga rambutnya rontok, maka orang-orang pun hendak menyambungnya, lalu mereka bertanya kepada Nabi shallallahu 'alaihi wasallam, beliau pun bersabda: \"Allah melaknat orang yang menyambung rambutnya dan yang minta disambung rambutnya.\" Hadits ini diperkuat oleh riwayat [Ibnu Ishaq] dari [Aban bin Shalih] dari [Al Hasan] dari [Shafiyyah] dari [Aisyah]."},"5174":{"ar":"حَدَّثَنِي أَحْمَدُ بْنُ الْمِقْدَامِ حَدَّثَنَا فُضَيْلُ بْنُ سُلَيْمَانَ حَدَّثَنَا مَنْصُورُ بْنُ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَتْنِي أُمِّي عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ امْرَأَةً جَاءَتْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ إِنِّي أَنْكَحْتُ ابْنَتِي ثُمَّ أَصَابَهَا شَكْوَى فَتَمَرَّقَ رَأْسُهَا وَزَوْجُهَا يَسْتَحِثُّنِي بِهَا أَفَأَصِلُ رَأْسَهَا فَسَبَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَاصِلَةَ وَالْمُسْتَوْصِلَةَ","id":"Telah menceritakan kepadaku [Ahmad bin Miqdam] telah menceritakan kepada kami [Fudlail bin Sulaiman] telah menceritakan kepada kami [Manshur bin Abdurrahman] dia berkata; telah menceritakan kepadaku [ibuku] dari [Asma` binti Abu Bakr] radliallahu 'anhuma bahwa seorang wanita datang kepada Rasulullah shallallahu 'alaihi wasallam seraya berkata; \"Sesungguhnya saya hendak menikahkan putriku, ternyata putriku menderita suatu penyakit yang menyebabkan rambutnya rontok sedangkan calon suaminya sangat kasihan kepadanya, apakah saya boleh menyambung rambutnya?\" maka Rasulullah shallallahu 'alaihi wasallam mencela orang yang menyambung rambutnya dan yang minta disambung rambutnya.\""},"5175":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ امْرَأَتِهِ فَاطِمَةَ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ قَالَتْلَعَنَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَاصِلَةَ وَالْمُسْتَوْصِلَةَ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] dari [Hisyam bin 'Urwah] dari [isterinya, Fathimah] dari [Asma' binti Abu Bakr] dia berkata; Nabi shallallahu 'alaihi wasallam melaknat orang yang menyambung rambut dan yang minta disambung rambutnya.\""},"5176":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَعَنَ اللَّهُ الْوَاصِلَةَ وَالْمُسْتَوْصِلَةَ وَالْوَاشِمَةَ وَالْمُسْتَوْشِمَةَوَقَالَ نَافِعٌ الْوَشْمُ فِي اللِّثَةِ","id":"Telah menceritakan kepadaku [Muhammad bin Muqatil] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhuma bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah melaknat orang yang menyambung rambutnya dan yang minta disambung rambutnya serta melaknat orang yang mentato dan yang minta ditato.\" Nafi' mengatakan; \"Terkadang mentato itu juga bisa di gusi (membikin gigi bagus dengan memberi kawat dll).\""},"5177":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا عَمْرُو بْنُ مُرَّةَ سَمِعْتُ سَعِيدَ بْنَ الْمُسَيَّبِ قَالَ قَدِمَ مُعَاوِيَةُالْمَدِينَةَ آخِرَ قَدْمَةٍ قَدِمَهَا فَخَطَبَنَا فَأَخْرَجَ كُبَّةً مِنْ شَعَرٍ قَالَ مَا كُنْتُ أَرَى أَحَدًا يَفْعَلُ هَذَا غَيْرَ الْيَهُودِ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمَّاهُ الزُّورَ يَعْنِي الْوَاصِلَةَ فِي الشَّعَرِ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami ['Amru bin Murrah] saya mendengar [Sa'id bin Musayyab] berkata; [Mu'awiyah] tiba di Madinah yaitu di akhir ia tiba di Madinah, kemudian dia berkhutbah di hadapan kami, sambil mengeluarkan sambungan rambut, katanya; \"Saya tidak pernah melihat seorangpun yang mengenakan ini kecuali orang Yahudi dan sesungguhnya Nabi shallallahu 'alaihi wasallam menamakan ini dengan az zuur yaitu sambungan pada rambut.\""},"5178":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ قَالَلَعَنَ عَبْدُ اللَّهِ الْوَاشِمَاتِ وَالْمُتَنَمِّصَاتِ وَالْمُتَفَلِّجَاتِ لِلْحُسْنِ الْمُغَيِّرَاتِ خَلْقَ اللَّهِ فَقَالَتْ أُمُّ يَعْقُوبَ مَا هَذَا قَالَ عَبْدُ اللَّهِ وَمَا لِي لَا أَلْعَنُ مَنْ لَعَنَ رَسُولُ اللَّهِ وَفِي كِتَابِ اللَّهِ قَالَتْ وَاللَّهِ لَقَدْ قَرَأْتُ مَا بَيْنَ اللَّوْحَيْنِ فَمَا وَجَدْتُهُ قَالَ وَاللَّهِ لَئِنْ قَرَأْتِيهِ لَقَدْ وَجَدْتِيهِ{ وَمَا آتَاكُمْ الرَّسُولُ فَخُذُوهُ وَمَا نَهَاكُمْ عَنْهُ فَانْتَهُوا }","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] dari ['Alqamah] dia berkata; [Abdullah] melaknat orang yang mentato, mencukur habis alis mata, merenggangkan gigi (denga kawat dll) untuk kecantikan dengan merubah ciptaan Allah, Ummu Ya'qub berkata; \"Apa maksudnya ini?\" Abdullah mengatakan; \"Bagaimana aku tidak melaknat orang yang dilaknat Rasulullah dan telah tercatat pula dalam kitabullah. Ummu Ya'qub berkata; \"Saya telah membaca dalam mushaf, namun saya tidak mendapatkan hal itu.\" Abdullah berkata; \"Demi Allah, sekiranya kamu membacanya, niscaya kamu akan mendapatkannya yaitu Dan sesuatu yang datang dari Rasul maka ambillah dan yang di larang olehnya maka jauhilah QS Al Hasyr: 7."},"5179":{"ar":"حَدَّثَنِي مُحَمَّدٌ حَدَّثَنَا عَبْدَةُ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَعَنَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَاصِلَةَ وَالْمُسْتَوْصِلَةَ وَالْوَاشِمَةَ وَالْمُسْتَوْشِمَةَ","id":"Telah menceritakan kepadaku [Muhammad] telah menceritakan kepada kami ['Abdah] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhuma dia berkata; Nabi shallallahu 'alaihi wasallam melaknat orang yang menyambung rambutnya dan yang minta disambung rambutnya, dan orang yang mentato dan orang yang minta ditato.\""},"5180":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا هِشَامٌ أَنَّهُ سَمِعَ فَاطِمَةَ بِنْتَ الْمُنْذِرِ تَقُولُ سَمِعْتُ أَسْمَاءَ قَالَتْسَأَلَتْ امْرَأَةٌ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ ابْنَتِي أَصَابَتْهَا الْحَصْبَةُ فَامَّرَقَ شَعَرُهَا وَإِنِّي زَوَّجْتُهَا أَفَأَصِلُ فِيهِ فَقَالَ لَعَنَ اللَّهُ الْوَاصِلَةَ وَالْمَوْصُولَةَ","id":"Telah menceritakan kepada kami [Al Humaidi] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Hisyam] bahwa dia mendengar [Fathimah binti Mundzir] berkata; saya mendengar [Asma'] berkata; seorang wanita bertanya kepada Nabi shallallahu 'alaihi wasallam katanya; \"Wahai Rasulullah, sesungguhnya puteriku menderita penyakit gatal (cacar) hingga rambutnya rontok, sementara saya hendak menikahkannya, apakah saya boleh menyambung rambutnya? Beliau bersabda: \"Sesungguhnya Allah melaknat orang yang menyambung rambutnya dan yang minta disambung.\""},"5181":{"ar":"حَدَّثَنِي يُوسُفُ بْنُ مُوسَى حَدَّثَنَا الْفَضْلُ بْنُ دُكَيْنٍ حَدَّثَنَا صَخْرُ بْنُ جُوَيْرِيَةَ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَاشِمَةُ وَالْمُوتَشِمَةُ وَالْوَاصِلَةُ وَالْمُسْتَوْصِلَةُ يَعْنِي لَعَنَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepadaku [Yusuf bin Musa] telah menceritakan kepada kami [Al Fadhl bin Dukain] telah menceritakan kepada kami [Shakhr bin Juwairiyah] dari [Nafi'] dari [Abdullah bin Umar] radliallahu 'anhuma saya mendengar Nabi shallallahu 'alaihi wasallam atau Nabi shallallahu 'alaihi wasallam bersabda: \"Orang yang mentato dan yang minta ditato serta orang yang menyambung rambutnya dan yang minta disambung rambutnya.\" Maksudnya adalah Nabi shallallahu 'alaihi wasallam melaknatnya.\""},"5182":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ ابْنِ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُ قَالَلَعَنَ اللَّهُ الْوَاشِمَاتِ وَالْمُسْتَوْشِمَاتِ وَالْمُتَنَمِّصَاتِ وَالْمُتَفَلِّجَاتِ لِلْحُسْنِ الْمُغَيِّرَاتِ خَلْقَ اللَّهِ مَا لِي لَا أَلْعَنُ مَنْ لَعَنَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي كِتَابِ اللَّهِ","id":"Telah menceritakan kepadaku [Muhammad bin Muqatil] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Sufyan] dari [Manshur] dari [Ibrahim] dari ['Alqamah] dari [Ibnu Mas'ud] radliallahu 'anhu dia berkata; \"Allah melaknat orang yang mentato dan yang minta ditato dan mencukur habis alis mata serta merenggangkan gigi (dengan kawat dll) untuk kecantikan dengan merubah ciptaan Allah, kenapa saya tidak melaknat orang yang dilaknat Rasulullah shallallahu 'alaihi wasallam sementara telah tertulis dalam kitabullah.\""},"5183":{"ar":"حَدَّثَنِي يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ هَمَّامٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَيْنُ حَقٌّ وَنَهَى عَنْ الْوَشْمِحَدَّثَنِي ابْنُ بَشَّارٍ حَدَّثَنَا ابْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ قَالَ ذَكَرْتُ لِعَبْدِ الرَّحْمَنِ بْنِ عَابِسٍ حَدِيثَ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ فَقَالَ سَمِعْتُهُ مِنْ أُمِّ يَعْقُوبَ عَنْ عَبْدِ اللَّهِ مِثْلَ حَدِيثِ مَنْصُورٍ","id":"Telah menceritakan kepadaku [Yahya] telah menceritakan kepada kami [Abdurrazaq] dari [Ma'mar] dari [Hammam] dari [Abu Hurairah] radliallahu 'anhu dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"penyakit ain (gangguan jin atau sihir) adalah benar adanya, \" dan beliau melarang mentato. Telah menceritakan kepadaku [Ibnu Basyar] telah menceritakan kepada kami [Ibnu Mahdi] telah menceritakan kepada kami [Sufyan] dia berkata; saya menyebutkan haditsnya [Manshur] kepada [Abdurrahman bin Abis] dari [Ibrahim] dari ['Alqamah] dari [Abdullah], maka dia berkata; \"Saya juga pernah mendengar hadits tersebut dari [Ummu Ya'qub] dari [Abdullah] seperti haditsnya Manshur.\""},"5184":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ عَوْنِ بْنِ أَبِي جُحَيْفَةَ قَالَ رَأَيْتُ أَبِي فَقَالَإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ ثَمَنِ الدَّمِ وَثَمَنِ الْكَلْبِ وَآكِلِ الرِّبَا وَمُوكِلِهِ وَالْوَاشِمَةِ وَالْمُسْتَوْشِمَةِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Syu'bah] dari ['Aun bin Abu Juhaifah] dia berkata; aku pernah melihat [Ayahku] berkata; sesungguhnya Nabi shallallahu 'alaihi wasallam melarang hasil (menjual) darah dan hasil penjualan anjing, memakan riba dan yang memberi makan dan yang mentato dan yang meminta ditato.\""},"5185":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا جَرِيرٌ عَنْ عُمَارَةَ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَأُتِيَ عُمَرُ بِامْرَأَةٍ تَشِمُ فَقَامَ فَقَالَ أَنْشُدُكُمْ بِاللَّهِ مَنْ سَمِعَ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْوَشْمِ فَقَالَ أَبُو هُرَيْرَةَ فَقُمْتُ فَقُلْتُ يَا أَمِيرَ الْمُؤْمِنِينَ أَنَا سَمِعْتُ قَالَ مَا سَمِعْتَ قَالَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَشِمْنَ وَلَا تَسْتَوْشِمْنَ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Jarir] dari ['Umarah] dari [Abu Zar'ah] dari [Abu Hurairah] dia berkata; \"Umar pernah menemui seorang wanita yang mentato, lalu Umar berdiri dan berkata; \"Saya peringatkan kepada kalian, siapakah di antara kalian yang mendengar dari Nabi shallallahu 'alaihi wasallam tentang tato?\" Abu Hurairah berkata; \"Lalu aku berdiri dan berkata; \"Saya pernah mendengarnya wahai Amirul mukminin.\" Dia berkata; \"Apa yang pernah kamu dengar?\" Abu Hurairah berkata; \"Saya mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian mentato dan jangan pula minta untuk ditato.\""},"5186":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ أَخْبَرَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ قَالَلَعَنَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَاصِلَةَ وَالْمُسْتَوْصِلَةَ وَالْوَاشِمَةَ وَالْمُسْتَوْشِمَةَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Ubaidullah] telah mengabarkan kepadaku [Nafi'] dari [Ibnu Umar] dia berkata; Nabi shallallahu 'alaihi wasallam melaknat orang yang menyambung rambutnya dan yang minta disambung rambutnya serta orang yang mentato dan yang minta ditato.\""},"5187":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُلَعَنَ اللَّهُ الْوَاشِمَاتِ وَالْمُسْتَوْشِمَاتِ وَالْمُتَنَمِّصَاتِ وَالْمُتَفَلِّجَاتِ لِلْحُسْنِ الْمُغَيِّرَاتِ خَلْقَ اللَّهِ مَا لِي لَا أَلْعَنُ مَنْ لَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي كِتَابِ اللَّهِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Abdurrahman] dari [Sufyan] dari [Manshur] dari [Ibrahim] dari [Alqamah] dari [Abdullah] radliallahu 'anhu bahwa Allah melaknat wanita yang mentato dan yang minta ditato dan wanita yang mencukur alis matanya serta yang merenggangkan giginya (dengan kawat dll) untuk kecantikan dengan merubah ciptaan Allah, kenapa saya tidak melaknat orang yang dilaknat Rasulullah shallallahu 'alaihi wasallam sementara telah tertulis dalam kitabullah.\""},"5188":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍ عَنْ أَبِي طَلْحَةَ رَضِيَ اللَّهُ عَنْهُمْ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَدْخُلُ الْمَلَائِكَةُ بَيْتًا فِيهِ كَلْبٌ وَلَا تَصَاوِيرُوَقَالَ اللَّيْثُ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عُبَيْدُ اللَّهِ سَمِعَ ابْنَ عَبَّاسٍ سَمِعْتُ أَبَا طَلْحَةَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Ibnu Abu Dzi`b] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah bin 'Utbah] dari [Ibnu Abbas] dari [Abu Thalhah] radliallahu 'anhum dia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Malaikat tidak akan masuk ke rumah yang di dalamnya terdapat anjing dan patung.\" [Al Laits] berkata; telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab] telah mengabarkan kepadaku ['Ubaidullah] dia mendengar [Ibnu Abbas] bahwa saya mendengar [Abu Thalhah] bahwa saya mendengar Nabi shallallahu 'alaihi wasallam.\""},"5189":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا الْأَعْمَشُ عَنْ مُسْلِمٍ قَالَ كُنَّا مَعَ مَسْرُوقٍفِي دَارِ يَسَارِ بْنِ نُمَيْرٍ فَرَأَى فِي صُفَّتِهِ تَمَاثِيلَ فَقَالَ سَمِعْتُ عَبْدَ اللَّهِ قَالَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ أَشَدَّ النَّاسِ عَذَابًا عِنْدَ اللَّهِ يَوْمَ الْقِيَامَةِ الْمُصَوِّرُونَ","id":"Telah menceritakan kepada kami [Al Humaidi] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Al A'masy] dari [Muslim] dia berkata; Kami bersama [Masruq] berada di rumah Yasar bin Numair, lantas dia melihat patung di dalam (gambar) patung rumahnya, lantas Masruq berkata; \"Saya pernah mendengar [Abdullah] berkata; saya mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya orang yang paling keras siksaannya di sisi Allah pada hari Kiamat adalah orang-orang yang suka menggambar.\""},"5190":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الَّذِينَ يَصْنَعُونَ هَذِهِ الصُّوَرَ يُعَذَّبُونَ يَوْمَ الْقِيَامَةِ يُقَالُ لَهُمْ أَحْيُوا مَا خَلَقْتُمْ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir] telah menceritakan kepada kami [Anas bin Iyadl] dari ['Ubaidullah] dari [Nafi'] bahwa [Abdullah bin Umar] radliallahu 'anhuma telah mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya orang-orang yang membuat gambar-gambar ini akan disiksa di hari Kiamat, di katakan kepadanya; \"Hidupkanlah apa yang telah kamu gambar ini.\""},"5191":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ فَضَالَةَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ عِمْرَانَ بْنِ حِطَّانَ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا حَدَّثَتْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَكُنْ يَتْرُكُ فِي بَيْتِهِ شَيْئًا فِيهِ تَصَالِيبُ إِلَّا نَقَضَهُ","id":"Telah menceritakan kepada kami [Mu'adz bin Fadlalah] telah menceritakan kepada kami [Hisyam] dari [Yahya] dari ['Imran bin Hithan] bahwa [Aisyah] radliallahu 'anhu telah menceritakan kepadanya bahwa Nabi shallallahu 'alaihi wasallam tidak pernah meninggalkan (gambar) salib melainkan beliau akan menghancurkannya.\""},"5192":{"ar":"حَدَّثَنَا مُوسَى حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا عُمَارَةُ حَدَّثَنَا أَبُو زُرْعَةَ قَالَدَخَلْتُ مَعَ أَبِي هُرَيْرَةَ دَارًا بِالْمَدِينَةِ فَرَأَى أَعْلَاهَا مُصَوِّرًا يُصَوِّرُ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ وَمَنْ أَظْلَمُ مِمَّنْ ذَهَبَ يَخْلُقُ كَخَلْقِي فَلْيَخْلُقُوا حَبَّةً وَلْيَخْلُقُوا ذَرَّةً ثُمَّ دَعَا بِتَوْرٍ مِنْ مَاءٍ فَغَسَلَ يَدَيْهِ حَتَّى بَلَغَ إِبْطَهُ فَقُلْتُ يَا أَبَا هُرَيْرَةَ أَشَيْءٌ سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مُنْتَهَى الْحِلْيَةِ","id":"Telah menceritakan kepada kami [Musa] telah menceritakan kepada kami [Abdul Wahid] telah menceritakan kepada kami ['Umarah] telah menceritakan kepada kami [Abu Zar'ah] dia berkata; saya masuk rumah (milik salah seorang) penduduk Madinah bersama [Abu Hurairah], lalu dia melihat ke atap rumah ada sesuatu yang bergambar, dia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Dan siapakah yang lebih lalim dari pada orang-orang yang pergi untuk membuat ciptaan seperti halnya ciptaan-Ku. Maka hendaklah mereka menciptakan jagung, atau biji-bijian atau biji gandum'\"!. Kemudian Abu Hurairah meminta tempat air wudlu dan beliaupun berwudlu, mencuci kedua tangannya hingga ketiaknya, saya bertanya; \"Wahai Abu Hurairah, apakah anda mendengar sesuatu dari Rasulullah shallallahu 'alaihi wasallam (tentang hal ini)? Dia menjawab: \"inilah yang akan menjadi cahaya di hari kiamat.\""},"5193":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ الْقَاسِمِ وَمَا بِالْمَدِينَةِ يَوْمَئِذٍ أَفْضَلُ مِنْهُ قَالَ سَمِعْتُ أَبِي قَالَ سَمِعْتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاقَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ سَفَرٍ وَقَدْ سَتَرْتُ بِقِرَامٍ لِي عَلَى سَهْوَةٍ لِي فِيهَا تَمَاثِيلُ فَلَمَّا رَآهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَتَكَهُ وَقَالَ أَشَدُّ النَّاسِ عَذَابًا يَوْمَ الْقِيَامَةِ الَّذِينَ يُضَاهُونَ بِخَلْقِ اللَّهِ قَالَتْ فَجَعَلْنَاهُ وِسَادَةً أَوْ وِسَادَتَيْنِ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] dia berkata; saya mendengar [Abdurrahman bin Al Qasim] -dan tidak ada seorang pun di Madinah yang lebih utama dari pada dia- dia berkata; saya mendengar [Ayahku] berkata; saya mendengar [Aisyah] radliallahu 'anha menemui Rasulullah shallallahu 'alaihi wasallam sekembalinya beliau dari safarnya, waktu itu saya telah membuat pembatas (satir) dari kain yang bergambar dalam ruanganku, ketika Rasulullah shallallahu 'alaihi wasallam melihatnya beliau langsung memotongnya sambil bersabda: \"Sesungguhnya orang-orang yang paling keras siksanya pada hari kiamat adalah orang-orang yang membuat sesuatu yang menyamai ciptaan Allah.\" Aisyah melanjutkan; \"Kemudian saya membuatnya menjadi satu bantal atau dua bantal.\""},"5194":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دَاوُدَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْقَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ سَفَرٍ وَعَلَّقْتُ دُرْنُوكًا فِيهِ تَمَاثِيلُ فَأَمَرَنِي أَنْ أَنْزِعَهُ فَنَزَعْتُهُ وَكُنْتُ أَغْتَسِلُ أَنَا وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ إِنَاءٍ وَاحِدٍ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abdullah bin Daud] dari [Hisyam] dari [ayahnya] dari [Aisyah] dia berkata; \"Setibanya Nabi shallallahu 'alaihi wasallam dari safar (bepergian), saya menggantungkan satir pembatas yang bergambar, lalu beliau memerintahkanku melepas satir tersebut, maka aku pun melepasnya. Dan saya juga mandi bersama Nabi shallallahu 'alaihi wasallam dari satu wadah.\""},"5195":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا جُوَيْرِيَةُ عَنْ نَافِعٍ عَنْ الْقَاسِمِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّهَا اشْتَرَتْ نُمْرُقَةً فِيهَا تَصَاوِيرُ فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْبَابِ فَلَمْ يَدْخُلْ فَقُلْتُ أَتُوبُ إِلَى اللَّهِ مِمَّا أَذْنَبْتُ قَالَ مَا هَذِهِ النُّمْرُقَةُ قُلْتُ لِتَجْلِسَ عَلَيْهَا وَتَوَسَّدَهَا قَالَ إِنَّ أَصْحَابَ هَذِهِ الصُّوَرِ يُعَذَّبُونَ يَوْمَ الْقِيَامَةِ يُقَالُ لَهُمْ أَحْيُوا مَا خَلَقْتُمْ وَإِنَّ الْمَلَائِكَةَ لَا تَدْخُلُ بَيْتًا فِيهِ الصُّورَةُ","id":"Telah menceritakan kepadaku [Hajjaj bin Minhal] telah menceritakan kepada kami [Juwairiyah] dari [Nafi'] dari [Al Qasim] dari [Aisyah] radliallahu 'anha bahwa dia telah membeli numruqah (bantal yang digunakan untuk duduk) yang ada gambarnya. Nabi shallallahu 'alaihi wasallampun berdiri di depan pintu dan tidak masuk ke dalam rumah. maka saya bertanya; \"Wahai Rasulullah, aku bertaubat kepada Allah, sebenarnya dosa apa yang telah aku perbuat?\" beliau bersabda: \"Bantal apakah ini?\" Dia menjawab; \"Aku telah membelinya agar anda duduk di atasnya atau anda jadikan sebagai bantal.\" Beliau bersabda: \"Sesungguhnya orang yang menggambar gambar ini akan disiksa pada Hari Kiamat. Dikatakan kepada mereka; 'Hidupkan yang telah kalian buat, ' (beliau bersabda): \"Sesungguhnya malaikat tidak akan masuk ke dalam rumah yang ada gambarnya.\""},"5196":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ بُكَيْرٍ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ زَيْدِ بْنِ خَالِدٍ عَنْ أَبِي طَلْحَةَ صَاحِبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْمَلَائِكَةَ لَا تَدْخُلُ بَيْتًا فِيهِ الصُّورَةُقَالَ بُسْرٌ ثُمَّ اشْتَكَى زَيْدٌ فَعُدْنَاهُ فَإِذَا عَلَى بَابِهِ سِتْرٌ فِيهِ صُورَةٌ فَقُلْتُ لِعُبَيْدِاللَّهِ رَبِيبِ مَيْمُونَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَمْ يُخْبِرْنَا زَيْدٌ عَنْ الصُّوَرِ يَوْمَ الْأَوَّلِ فَقَالَ عُبَيْدُ اللَّهِ أَلَمْ تَسْمَعْهُ حِينَ قَالَ إِلَّا رَقْمًا فِي ثَوْبٍ وَقَالَ ابْنُ وَهْبٍ أَخْبَرَنَا عَمْرٌو هُوَ ابْنُ الْحَارِثِ حَدَّثَهُ بُكَيْرٌ حَدَّثَهُ بُسْرٌ حَدَّثَهُ زَيْدٌ حَدَّثَهُ أَبُو طَلْحَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Bukair] dari [Busr bin Sa'id] dari [Zaid bin Khalid] dari [Abu Thalhah] seorang sahabat Rasulullah shallallahu 'alaihi wasallam dia berkata; Sesungguhnya Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Sesungguhnya Malaikat tidak akan masuk ke rumah yang di dalamnya ada gambar.\" [Busr] berkata; kemudian [Zaid] menderita sakit, maka kami pun menjenguknya, ternyata di pintunya terdapat tirai yang bergambar, lantas kataku kepada Ubaidullah anak tiri Maimunah isteri nabi shallallahu 'alaihi wasallam; \"Tidakkah Zaid pernah mengabarkan kepada kami tentang gambar di hari pertama?\" [Ubaidullah] menjawab; \"Apakah kamu tidak mendengarnya waktu dia mengatakan; \"Kecuali nomer di pakaian?\" [Ibnu Wahb] berkata; telah mengabarkan kepada kami ['Amru yaitu Ibnu Al Harits] telah menceritakan kepadanya [Bukair] telah menceritakan kepadanya [Busr] telah menceritakan kepadanya [Zaid] telah menceritakan kepadanya [Abu Thalhah] dari Nabi shallallahu 'alaihi wasallam."},"5197":{"ar":"حَدَّثَنَا عِمْرَانُ بْنُ مَيْسَرَةَ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ صُهَيْبٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ قِرَامٌ لِعَائِشَةَ سَتَرَتْ بِهِ جَانِبَ بَيْتِهَا فَقَالَ لَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمِيطِي عَنِّي فَإِنَّهُ لَا تَزَالُ تَصَاوِيرُهُ تَعْرِضُ لِي فِي صَلَاتِي","id":"Telah menceritakan kepada kami [Imran bin Maisarah] telah menceritakan kepada kami [Abdul Warits] telah menceritakan kepada kami [Abdul Aziz bin Shuhaib] dari [Anas] radliallahu 'anhu dia berkata; \"Bahwa Aisyah memiliki sehelai kain yang bergambar dan digunakan sebagai tabir rumahnya, lalu Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Singkirkanlah ia dariku, karena gambarnya selalu memalingkanku dalam shalat.\""},"5198":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سُلَيْمَانَ قَالَ حَدَّثَنِي ابْنُ وَهْبٍ قَالَ حَدَّثَنِي عُمَرُ هُوَ ابْنُ مُحَمَّدٍ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَوَعَدَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جِبْرِيلُ فَرَاثَ عَلَيْهِ حَتَّى اشْتَدَّ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَقِيَهُ فَشَكَا إِلَيْهِ مَا وَجَدَ فَقَالَ لَهُ إِنَّا لَا نَدْخُلُ بَيْتًا فِيهِ صُورَةٌ وَلَا كَلْبٌ","id":"Telah menceritakan kepada kami [Yahya bin Sulaiman] dia berkata; telah menceritakan kepadaku [Ibnu Wahb] dia berkata; telah menceritakan kepadaku [Umar yaitu Ibnu Muhammad] dari [Salim] dari [Ayahnya] dia berkata; \"Jibril pernah berjanji kepada Nabi shallallahu 'alaihi wasallam, namun Jibril terlambat datang hingga Nabi shallallahu 'alaihi wasallam menunggu sangat lama, lalu Nabi shallallahu 'alaihi wasallam keluar dan menemuinya lalu menanyakan sebenarnya apa yang tengah terjadi, maka Jibril berkata kepada beliau: \"Sesungguhnya kami tidak memasuki rumah yang di dalamnya terdapat gambar dan anjing.\""},"5199":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهَا أَخْبَرَتْهُأَنَّهَا اشْتَرَتْ نُمْرُقَةً فِيهَا تَصَاوِيرُ فَلَمَّا رَآهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ عَلَى الْبَابِ فَلَمْ يَدْخُلْ فَعَرَفَتْ فِي وَجْهِهِ الْكَرَاهِيَةَ قَالَتْ يَا رَسُولَ اللَّهِ أَتُوبُ إِلَى اللَّهِ وَإِلَى رَسُولِهِ مَاذَا أَذْنَبْتُ قَالَ مَا بَالُ هَذِهِ النُّمْرُقَةِ فَقَالَتْ اشْتَرَيْتُهَا لِتَقْعُدَ عَلَيْهَا وَتَوَسَّدَهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَصْحَابَ هَذِهِ الصُّوَرِ يُعَذَّبُونَ يَوْمَ الْقِيَامَةِ وَيُقَالُ لَهُمْ أَحْيُوا مَا خَلَقْتُمْ وَقَالَ إِنَّ الْبَيْتَ الَّذِي فِيهِ الصُّوَرُ لَا تَدْخُلُهُ الْمَلَائِكَةُ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Nafi'] dari [Al Qasim bin Muhammad] dari [Aisyah] radliallahu 'anha isteri Nabi shallallahu 'alaihi wasallam, bahwa dia mengabarkan kepadanya; bahwa dirinya pernah membeli numruqah (bantal yang digunakan untuk duduk) yang ada gambarnya. Nabi shallallahu 'alaihi wasallampun berdiri di depan pintu dan tidak masuk ke dalam rumah. Seolah-olah Aisyah melihat kemarahan di wajah beliau, maka dia bertanya; \"Wahai Rasulullah, aku bertaubat kepada Allah dan kepada Rasul-Nya, sebenarnya dosa apa yang telah aku perbuat?\" beliau bersabda: \"Ada apa dengan bantal ini?\" Dia menjawab; \"Aku telah membelinya agar anda duduk di atasnya atau anda jadikan sebagai bantal.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya orang yang menggambar gambar ini akan disiksa pada hari Kiamat. Dikatakan kepada mereka; 'Hidupkan yang telah kalian buat, ' kemudian beliau bersabda: \"Sesungguhnya malaikat tidak akan masuk ke dalam rumah yang ada gambarnya.\" "},"5200":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنِي غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ عَوْنِ بْنِ أَبِي جُحَيْفَةَ عَنْ أَبِيهِأَنَّهُ اشْتَرَى غُلَامًا حَجَّامًا فَقَالَ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ ثَمَنِ الدَّمِ وَثَمَنِ الْكَلْبِ وَكَسْبِ الْبَغِيِّ وَلَعَنَ آكِلَ الرِّبَا وَمُوكِلَهُ وَالْوَاشِمَةَ وَالْمُسْتَوْشِمَةَ وَالْمُصَوِّرَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepadaku [Ghundar] telah menceritakan kepada kami [Syu'bah] dari ['Aun bin Abu Juhaifah] dari [Ayahnya] bahwa dia pernah membeli seorang budak tukang bekam, lalu dia berkata; \"Sesungguhnya Nabi shallallahu 'alaihi wasallam melarang hasil penjualan darah, hasil penjualan anjing dan hasil pelacuran, beliau juga melaknat pemakan riba dan yang memberi makan, orang yang mentato dan yang minta ditato serta melaknat penggambar.\""},"5201":{"ar":"حَدَّثَنَا عَيَّاشُ بْنُ الْوَلِيدِ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا سَعِيدٌ قَالَ سَمِعْتُ النَّضْرَ بْنَ أَنَسِ بْنِ مَالِكٍ يُحَدِّثُقَتَادَةَ قَالَ كُنْتُ عِنْدَ ابْنِ عَبَّاسٍ وَهُمْ يَسْأَلُونَهُ وَلَا يَذْكُرُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى سُئِلَ فَقَالَ سَمِعْتُ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ صَوَّرَ صُورَةً فِي الدُّنْيَا كُلِّفَ يَوْمَ الْقِيَامَةِ أَنْ يَنْفُخَ فِيهَا الرُّوحَ وَلَيْسَ بِنَافِخٍ","id":"Telah menceritakan kepada kami [Ayyas bin Al Walid] telah menceritakan kepada kami [Abdul A'la] telah menceritakan kepada kami [Sa'id] dia berkata; saya mendengar [An Nadlr bin Anas bin Malik] bercerita kepada Ibnu Abbas, katanya; \"Saya pernah berada di sisi [Ibnu Abbas] sementara orang-orang bertanya tanpa menyebutkan Nabi shallallahu 'alaihi wasallam hingga dia di tanya, lantas Ibnu Abbas menjawab: \"Barangsiapa menggambar suatu gambar di dunia, maka pada hari Kiamat akan dibebankan baginya untuk meniupkan ruh padahal ia tidak akan mampu meniupkan ruh.\""},"5202":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو صَفْوَانَ عَنْ يُونُسَ بْنِ يَزِيدَ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ أُسَامَةَ بْنِ زَيْدٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكِبَ عَلَى حِمَارٍ عَلَى إِكَافٍ عَلَيْهِ قَطِيفَةٌ فَدَكِيَّةٌ وَأَرْدَفَ أُسَامَةَ وَرَاءَهُ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abu Shafwan] dari [Yunus bin Yazid] dari [Ibnu Syihab] dari ['Urwah] dari [Usamah bin Zaid] radliallahu 'anhuma bahwa Rasulullah shallallahu 'alaihi wasallam menaiki keledainya yang berpelana dari kain fadak, sementara Usamah membonceng di belakangnya.\""},"5203":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا خَالِدٌ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَمَّا قَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ اسْتَقْبَلَهُ أُغَيْلِمَةُ بَنِي عَبْدِ الْمُطَّلِبِ فَحَمَلَ وَاحِدًا بَيْنَ يَدَيْهِ وَالْآخَرَ خَلْفَهُ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Khalid] dari [Ikrimah] dari [Ibnu Abbas] radliallahu 'anhuma dia berkata; \"Setibanya Nabi shallallahu 'alaihi wasallam di Makkah, beliau disambut anak-anak Bani Abdul Mutthalib, lalu beliau menggendong salah satu diantara mereka di depan dan yang lain di belakang beliau.\""},"5204":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا أَيُّوبُ ذُكِرَ شَرُّ الثَّلَاثَةِ عِنْدَ عِكْرِمَةَ فَقَالَ قَالَ ابْنُ عَبَّاسٍأَتَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ حَمَلَ قُثَمَ بَيْنَ يَدَيْهِ وَالْفَضْلَ خَلْفَهُ أَوْ قُثَمَ خَلْفَهُ وَالْفَضْلَ بَيْنَ يَدَيْهِ فَأَيُّهُمْ شَرٌّ أَوْ أَيُّهُمْ خَيْرٌ","id":"Telah menceritakan kepadaku [Muhammad bin Basyar] telah menceritakan kepada kami [Abdul Wahhab] telah menceritakan kepada kami [Ayyub] dia menyebutkan tiga keburukan di samping [Ikrimah], lalu dia berkata; [Ibnu Abbas] berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah datang sambil menggendong Qutsam di hadapannya dan Al Fadl di depannya atau Qutsam di belakangnya dan Al Fadl di depannya, lalu manakah diantara mereka yang jelek atau manakah di antara keduanya yang lebih utama.\""},"5205":{"ar":"حَدَّثَنَا هُدْبَةُ بْنُ خَالِدٍ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍ عَنْ مُعَاذِ بْنِ جَبَلٍ رَضِيَ اللَّهُ عَنْهُ قَالَبَيْنَا أَنَا رَدِيفُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ بَيْنِي وَبَيْنَهُ إِلَّا أَخِرَةُ الرَّحْلِ فَقَالَ يَا مُعَاذُ بْنَ جَبَلٍ قُلْتُ لَبَّيْكَ رَسُولَ اللَّهِ وَسَعْدَيْكَ ثُمَّ سَارَ سَاعَةً ثُمَّ قَالَ يَا مُعَاذُ قُلْتُ لَبَّيْكَ رَسُولَ اللَّهِ وَسَعْدَيْكَ ثُمَّ سَارَ سَاعَةً ثُمَّ قَالَ يَا مُعَاذُ قُلْتُ لَبَّيْكَ رَسُولَ اللَّهِ وَسَعْدَيْكَ قَالَ هَلْ تَدْرِي مَا حَقُّ اللَّهِ عَلَى عِبَادِهِ قُلْتُ اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ حَقُّ اللَّهِ عَلَى عِبَادِهِ أَنْ يَعْبُدُوهُ وَلَا يُشْرِكُوا بِهِ شَيْئًا ثُمَّ سَارَ سَاعَةً ثُمَّ قَالَ يَا مُعَاذُ بْنَ جَبَلٍ قُلْتُ لَبَّيْكَ رَسُولَ اللَّهِ وَسَعْدَيْكَ فَقَالَ هَلْ تَدْرِي مَا حَقُّ الْعِبَادِ عَلَى اللَّهِ إِذَا فَعَلُوهُ قُلْتُ اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ حَقُّ الْعِبَادِ عَلَى اللَّهِ أَنْ لَا يُعَذِّبَهُمْ","id":"Telah menceritakan kepada kami [Hudbah bin Khalid] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] telah menceritakan kepada kami [Anas bin Malik] dari [Mu'adz bin Jabal] radliallahu 'anhu dia berkata; \"Ketika saya membonceng Nabi shallallahu 'alaihi wasallam dan tidak ada yang menengahi keduanya melainkan hanya kursi kecil diatas pelana. Beliau bersabda, \"Wahai Muadz bin Jabal!\" Jawabku, \"Ya wahai Rasulullah! saya penuhi pangilan anda\", kemudian berjalan sesaat lalu bertanya, \"Wahai Muadz bin Jabal!\" jawabku, \"Ya, wahai Rasulullah saya penuhi panggilan anda\", kemudian beliau berjalan sesaat dan bertanya, \"Wahai Mua'dz bin Jabal.\" Jawabku, \"Ya wahai Rasulullah! saya penuhi pangilan anda\", beliau bersabda: \"Apakah engkau tahu apa hak Allah atas para hamba?\" Jawabku, \"Allah dan Rasul-Nya yang lebih tahu.\" Beliau bersabda: \"Hak Allah atas para hamba-Nya adalah agar mereka beribadah kepada-Nya semata dan tidak menyekutukan-Nya dengan suatu apapun\", Kemudian beliau berjalan sesaat dan bersertu, \"Wahai Mua'adz bin Jabal.\" Jawabku; \"Ya wahai Rasulullah, saya penuhi panggilan anda.\" Beliau bersabda: \"Apakah engkau tahu hak hamba atas Allah, jika mereka melakukan itu?\" Jawabku; \"Allah dan Rasul-Nya yang lebih tahu\", beliau bersabda: \"Hak para hamba atas Allah adalah Dia tidak akan menyiksa mereka.\""},"5206":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ مُحَمَّدِ بْنِ صَبَّاحٍ حَدَّثَنَا يَحْيَى بْنُ عَبَّادٍ حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي يَحْيَى بْنُ أَبِي إِسْحَاقَ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَأَقْبَلْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ خَيْبَرَ وَإِنِّي لَرَدِيفُ أَبِي طَلْحَةَ وَهُوَ يَسِيرُ وَبَعْضُ نِسَاءِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَدِيفُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ عَثَرَتْ النَّاقَةُ فَقُلْتُ الْمَرْأَةَ فَنَزَلْتُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهَا أُمُّكُمْ فَشَدَدْتُ الرَّحْلَ وَرَكِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا دَنَا أَوْ رَأَى الْمَدِينَةَ قَالَ آيِبُونَ تَائِبُونَ عَابِدُونَ لِرَبِّنَا حَامِدُونَ","id":"Telah menceritakan kepada kami [Al Hasan bin Muhammad bin Shabah] telah menceritakan kepada kami [Yahya bin 'Abbad] telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepadaku [Yahya bin Abu Ishaq] dia berkata; saya mendengar [Anas bin Malik] radliallahu 'anhu berkata; \"Kami bersama Rasulullah shallallahu 'alaihi wasallam pernah kembali dari Khaibar, sedangkan saya membonceng Abu Thalhah yang sedang berjalan (dengan berkendara) sementara sebagian isteri Rasulullah shallallahu 'alaihi wasallam ada yang membonceng di belakang Rasulullah shallallahu 'alaihi wasallam, tiba-tiba unta beliau terjatuh, spontan aku berkata; \"Seorang wanita...\" lalu aku pun turun, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya ia adalah ibu kalian.\" Lalu aku mempersiapkan kendaraan beliau dan Rasulullah shallallahu 'alaihi wasallam pun menaikinya, ketika Madinah telah dekat dan terlihat oleh kami, beliau bersabda: \"Kami kembali dengan bertaubat, beribadah dan memuji Rabb kami.\""},"5207":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ حَدَّثَنَا ابْنُ شِهَابٍ عَنْ عَبَّادِ بْنِ تَمِيمٍ عَنْ عَمِّهِأَنَّهُ أَبْصَرَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَضْطَجِعُ فِي الْمَسْجِدِ رَافِعًا إِحْدَى رِجْلَيْهِ عَلَى الْأُخْرَى","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Ibrahim bin Sa'd] telah menceritakan kepada kami [Ibnu Syihab] dari ['Abbad bin Tamim] dari [Pamannya] bahwa dia pernah melihat Nabi shallallahu 'alaihi wasallam tengah terlentang di masjid sambil meletakkan salah satu kakinya di atas kaki yang lain.\""},"5208":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ قَالَ الْوَلِيدُ بْنُ عَيْزَارٍ أَخْبَرَنِي قَالَ سَمِعْتُ أَبَا عَمْرٍو الشَّيْبَانِيَّ يَقُولُ أَخْبَرَنَا صَاحِبُ هَذِهِ الدَّارِ وَأَوْمَأَ بِيَدِهِ إِلَى دَارِ عَبْدِ اللَّهِ قَالَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ الْعَمَلِ أَحَبُّ إِلَى اللَّهِ قَالَ الصَّلَاةُ عَلَى وَقْتِهَا قَالَ ثُمَّ أَيٌّ قَالَ بِرُّ الْوَالِدَيْنِ قَالَ ثُمَّ أَيٌّ قَالَ الْجِهَادُ فِي سَبِيلِ اللَّهِ قَالَ حَدَّثَنِي بِهِنَّ وَلَوْ اسْتَزَدْتُهُ لَزَادَنِي","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] berkata; [Al Walid bin 'Aizar] telah mengabarkan kepadaku dia berkata; saya mendengar [Abu 'Amru Asy Syaibani] berkata; telah mengabarkan kepada kami pemilik rumah ini, sambil menunjuk kerumah [Abdullah] dia berkata; saya bertanya kepada Nabi shallallahu 'alaihi wasallam; \"Amalan apakah yang paling dicintai Allah? Beliau bersabda: \"Shalat tepat pada waktunya.\" Dia bertanya lagi; \"Kemudian apa?\" beliau menjawab: \"Berbakti kepada kedua orang tua.\" Dia bertanya; \"Kemudian apa lagi?\" beliau menjawab: \"Berjuang di jalan Allah.\" Abu 'Amru berkata; \"Dia (Abdullah) telah menceritakan kepadaku semuanya, sekiranya aku menambahkan niscaya dia pun akan menambahkan (amalan) tersebut kepadaku.\""},"5209":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا جَرِيرٌ عَنْ عُمَارَةَ بْنِ الْقَعْقَاعِ بْنِ شُبْرُمَةَ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَجَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ مَنْ أَحَقُّ النَّاسِ بِحُسْنِ صَحَابَتِي قَالَ أُمُّكَ قَالَ ثُمَّ مَنْ قَالَ ثُمَّ أُمُّكَ قَالَ ثُمَّ مَنْ قَالَ ثُمَّ أُمُّكَ قَالَ ثُمَّ مَنْ قَالَ ثُمَّ أَبُوكَوَقَالَ ابْنُ شُبْرُمَةَ وَيَحْيَى بْنُ أَيُّوبَ حَدَّثَنَا أَبُو زُرْعَةَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Jarir] dari ['Umarah bin Al Qa'qa' bin Syubrumah] dari [Abu Zur'ah] dari [Abu Hurairah] radliallahu 'anhu dia berkata; \"Seorang laki-laki datang kepada Rasulullah shallallahu 'alaihi wasallam sambil berkata; \"Wahai Rasulullah, siapakah orang yang paling berhak aku berbakti kepadanya?\" beliau menjawab: \"Ibumu.\" Dia bertanya lagi; \"Kemudian siapa?\" beliau menjawab: \"Ibumu.\" Dia bertanya lagi; \"kemudian siapa lagi?\" beliau menjawab: \"Ibumu.\" Dia bertanya lagi; \"Kemudian siapa?\" dia menjawab: \"Kemudian ayahmu.\" [Ibnu Syubrumah] dan [Yahya bin Ayyub] berkata; telah menceritakan kepada kami [Abu Zur'ah] hadits seperti di atas.\""},"5210":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ وَشُعْبَةَ قَالَا حَدَّثَنَا حَبِيبٌ قَالَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ حَبِيبٍ عَنْ أَبِي الْعَبَّاسِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَجُلٌ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُجَاهِدُ قَالَ لَكَ أَبَوَانِ قَالَ نَعَمْ قَالَ فَفِيهِمَا فَجَاهِدْ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Sufyan] dan [Syu'bah] keduanya berkata; telah menceritakan kepada kami [Habib] dia berkata. Dan diriwayatkan dari jalur lain, telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dari [Habib] dari [Abu Al 'Abbas] dari [Abdullah bin 'Amru] dia berkata; seorang laki-laki berkata kepada Nabi shallallahu 'alaihi wasallam; \"Saya hendak ikut berjihad.\" Beliau lalu bersabda: \"Apakah kamu masih memiliki kedua orang tua?\" dia menjawab; \"Ya, masih.\" Beliau bersabda: \"Kepada keduanya lah kamu berjihad.\""},"5211":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ أَبِيهِ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ أَكْبَرِ الْكَبَائِرِ أَنْ يَلْعَنَ الرَّجُلُ وَالِدَيْهِ قِيلَ يَا رَسُولَ اللَّهِ وَكَيْفَ يَلْعَنُ الرَّجُلُ وَالِدَيْهِ قَالَ يَسُبُّ الرَّجُلُ أَبَا الرَّجُلِ فَيَسُبُّ أَبَاهُ وَيَسُبُّ أُمَّهُ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Ayahnya] dari [Humaid bin Abdurrahman] dari [Abdullah bin 'Amru] radliallahu 'anhuma dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya termasuk dari dosa besar adalah seseorang melaknat kedua orang tuanya sendiri, \" beliau ditanya; \"Kenapa hal itu bisa terjadi wahai Rasulullah?\" beliau menjawab: \"Seseorang mencela (melaknat) ayah orang lain, kemudian orang tersebut membalas mencela ayah dan ibu orang yang pertama.\""},"5212":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ بْنِ عُقْبَةَ قَالَ أَخْبَرَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَمَا ثَلَاثَةُ نَفَرٍ يَتَمَاشَوْنَ أَخَذَهُمْ الْمَطَرُ فَمَالُوا إِلَى غَارٍ فِي الْجَبَلِ فَانْحَطَّتْ عَلَى فَمِ غَارِهِمْ صَخْرَةٌ مِنْ الْجَبَلِ فَأَطْبَقَتْ عَلَيْهِمْ فَقَالَ بَعْضُهُمْ لِبَعْضٍ انْظُرُوا أَعْمَالًا عَمِلْتُمُوهَا لِلَّهِ صَالِحَةً فَادْعُوا اللَّهَ بِهَا لَعَلَّهُ يَفْرُجُهَا فَقَالَ أَحَدُهُمْ اللَّهُمَّ إِنَّهُ كَانَ لِي وَالِدَانِ شَيْخَانِ كَبِيرَانِ وَلِي صِبْيَةٌ صِغَارٌ كُنْتُ أَرْعَى عَلَيْهِمْ فَإِذَا رُحْتُ عَلَيْهِمْ فَحَلَبْتُ بَدَأْتُ بِوَالِدَيَّ أَسْقِيهِمَا قَبْلَ وَلَدِي وَإِنَّهُ نَاءَ بِيَ الشَّجَرُ فَمَا أَتَيْتُ حَتَّى أَمْسَيْتُ فَوَجَدْتُهُمَا قَدْ نَامَا فَحَلَبْتُ كَمَا كُنْتُ أَحْلُبُ فَجِئْتُ بِالْحِلَابِ فَقُمْتُ عِنْدَ رُءُوسِهِمَا أَكْرَهُ أَنْ أُوقِظَهُمَا مِنْ نَوْمِهِمَا وَأَكْرَهُ أَنْ أَبْدَأَ بِالصِّبْيَةِ قَبْلَهُمَا وَالصِّبْيَةُ يَتَضَاغَوْنَ عِنْدَ قَدَمَيَّ فَلَمْ يَزَلْ ذَلِكَ دَأْبِي وَدَأْبَهُمْ حَتَّى طَلَعَ الْفَجْرُ فَإِنْ كُنْتَ تَعْلَمُ أَنِّي فَعَلْتُ ذَلِكَ ابْتِغَاءَ وَجْهِكَ فَافْرُجْ لَنَا فُرْجَةً نَرَى مِنْهَا السَّمَاءَ فَفَرَجَ اللَّهُ لَهُمْ فُرْجَةً حَتَّى يَرَوْنَ مِنْهَا السَّمَاءَ وَقَالَ الثَّانِي اللَّهُمَّ إِنَّهُ كَانَتْ لِي ابْنَةُ عَمٍّ أُحِبُّهَا كَأَشَدِّ مَا يُحِبُّ الرِّجَالُ النِّسَاءَ فَطَلَبْتُ إِلَيْهَا نَفْسَهَا فَأَبَتْ حَتَّى آتِيَهَا بِمِائَةِ دِينَارٍ فَسَعَيْتُ حَتَّى جَمَعْتُ مِائَةَ دِينَارٍ فَلَقِيتُهَا بِهَا فَلَمَّا قَعَدْتُ بَيْنَ رِجْلَيْهَا قَالَتْ يَا عَبْدَ اللَّهِ اتَّقِ اللَّهَ وَلَا تَفْتَحْ الْخَاتَمَ فَقُمْتُ عَنْهَا اللَّهُمَّ فَإِنْ كُنْتَ تَعْلَمُ أَنِّي قَدْ فَعَلْتُ ذَلِكَ ابْتِغَاءَ وَجْهِكَ فَافْرُجْ لَنَا مِنْهَا فَفَرَجَ لَهُمْ فُرْجَةً وَقَالَ الْآخَرُ اللَّهُمَّ إِنِّي كُنْتُ اسْتَأْجَرْتُ أَجِيرًا بِفَرَقِ أَرُزٍّ فَلَمَّا قَضَى عَمَلَهُ قَالَ أَعْطِنِي حَقِّي فَعَرَضْتُ عَلَيْهِ حَقَّهُ فَتَرَكَهُ وَرَغِبَ عَنْهُ فَلَمْ أَزَلْ أَزْرَعُهُ حَتَّى جَمَعْتُ مِنْهُ بَقَرًا وَرَاعِيَهَا فَجَاءَنِي فَقَالَ اتَّقِ اللَّهَ وَلَا تَظْلِمْنِي وَأَعْطِنِي حَقِّي فَقُلْتُ اذْهَبْ إِلَى ذَلِكَ الْبَقَرِ وَرَاعِيهَا فَقَالَ اتَّقِ اللَّهَ وَلَا تَهْزَأْ بِي فَقُلْتُ إِنِّي لَا أَهْزَأُ بِكَ فَخُذْ ذَلِكَ الْبَقَرَ وَرَاعِيَهَا فَأَخَذَهُ فَانْطَلَقَ بِهَا فَإِنْ كُنْتَ تَعْلَمُ أَنِّي فَعَلْتُ ذَلِكَ ابْتِغَاءَ وَجْهِكَ فَافْرُجْ مَا بَقِيَ فَفَرَجَ اللَّهُ عَنْهُمْ","id":"Telah menceritakan kepada kami [Sa'id bin Abu Maryam] telah menceritakan kepada kami [Isma'il bin Ibrahim bin 'Uqbah] dia berkata; telah mengabarkan kepadaku [Nafi'] dari [Ibnu Umar] radliallahu 'anhuma dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Suatu ketika tiga orang laki-laki sedang berjalan, tiba-tiba hujan turun hingga mereka berlindung ke dalam suatu gua yang terdapat di gunung. Tanpa diduga sebelumnya, ada sebongkah batu besar jatuh menutup mulut goa dan mengurung mereka di dalamnya. Kemudian salah seorang dari mereka berkata kepada temannya yang lain; 'lngat-ingatlah amal shalih yang pernah kalian lakukan hanya karena mengharap ridla Allah semata. Setelah itu, berdoa dan memohonlah pertolongan kepada Allah dengan perantaraan amal shalih tersebut, mudah-mudahan Allah akan menghilangkan kesulitan kalian. Kemudian salah seorang dari mereka berkata; 'Ya Allah ya Tuhanku, dulu saya mempunyai dua orang tua yang sudah lanjut usia. Selain itu, saya juga mempunyai seorang istri dan beberapa orang anak yang masih kecil. Saya menghidupi mereka dengan menggembalakan ternak. Apabila pulang dari menggembala, saya pun segera memerah susu dan saya dahulukan untuk kedua orang tua saya. Lalu saya berikan air susu tersebut kepada kedua orang tua saya sebelum saya berikan kepada anak-anak saya. Pada suatu ketika, tempat penggembalaan saya jauh, hingga saya baru pulang pada sore hari. Ternyata saya dapati kedua orang tua saya sedang tertidur pulas. Lalu, seperti biasa, saya segera memerah susu. Saya berdiri di dekat keduanya karena tidak mau membangunkan dari tidur mereka. Akan tetapi, saya juga tidak ingin memberikan air susu tersebut kepada anak-anak saya sebelum diminum oleh kedua orang tua saya, meskipun mereka, anak-anak saya, telah berkerumun di telapak kaki saya untuk meminta minum karena rasa lapar yang sangat. Keadaan tersebut saya dan anak-anak saya jalankan dengan sepenuh hati hingga terbit fajar. Ya Allah, jika Engkau tahu bahwa saya melakukan perbuatan tersebut hanya untuk mengharap ridla-Mu, maka bukakanlah celah untuk kami hingga kami dapat melihat langit! ' Akhirnya Allah membuka celah lubang gua tersebut, hingga mereka dapat melihat langit. Orang yang kedua dari mereka berdiri sambil berkata; 'Ya Allah, dulu saya mempunyai seorang sepupu perempuan (anak perempuan paman) yang saya cintai sebagaimana cintanya kaum laki-laki yang menggebu-gebu terhadap wanita. Pada suatu ketika saya pernah mengajaknya untuk berbuat mesum, tetapi ia menolak hingga saya dapat memberinya uang seratus dinar. Setelah bersusah payah mengumpulkan uang seratus dinar, akhirnya saya pun mampu memberikan uang tersebut kepadanya. Ketika saya berada diantara kedua pahanya (telah siap untuk menggaulinya), tiba-tiba ia berkata; 'Hai hamba Allah, takutlah kepada Allah dan janganlah kamu membuka cincin (menggauliku) kecuali setelah menjadi hakmu.' Lalu saya bangkit dan meninggalkannya. Ya Allah, sesungguhnya Engkau pun tahu bahwa saya melakukan hal itu hanya untuk mengharapkan ridhla-Mu. Oleh karena itu, bukakanlah suatu celah lubang untuk kami! ' Akhirnya Allah membukakan sedikit celah lubang lagi untuk mereka bertiga. Seorang lagi berdiri dan berkata; 'Ya Allah ya Tuhanku, dulu saya pernah menyuruh seseorang untuk mengerjakan sawah saya dengan cara bagi hasil. Ketika ia telah menyelesaikan pekerjaannya, ia pun berkata; 'Berikanlah hak saya kepada saya! ' Namun saya tidak dapat memberikan kepadanya haknya tersebut hingga ia merasa sangat jengkel. Setelah itu, saya pun menanami sawah saya sendiri hingga hasilnya dapat saya kumpulkan untuk membeli beberapa ekor sapi dan menggaji beberapa penggembalanya. Selang berapa lama kemudian, orang yang haknya dahulu tidak saya berikan datang kepada saya dan berkata; 'Takutlah kamu kepada Allah dan janganlah berbuat zhalim terhadap hak orang lain! ' Lalu saya berkata kepada orang tersebut; 'Pergilah ke beberapa ekor sapi beserta para penggembalanya itu dan ambillah semuanya untukmu! ' Orang tersebut menjawab; 'Takutlah kepada Allah dan janganlah kamu mengolok-olok saya! ' Kemudian saya katakan lagi kepadanya; 'Sungguh saya tidak bermaksud mengolok-olokmu. Oleh karena itu, ambillah semua sapi itu beserta para pengggembalanya untukmu! ' Akhirnya orang tersebut memahaminya dan membawa pergi semua sapi itu. Ya Allah, sesungguhnya Engkau telah mengetahui bahwa apa yang telah saya lakukan dahulu adalah hanya untuk mencari ridla-Mu. Oleh karena itu, bukalah bagian pintu goa yang belum terbuka! ' Akhirnya Allah pun membukakan sisanya untuk mereka.\""},"5213":{"ar":"حَدَّثَنَا سَعْدُ بْنُ حَفْصٍ حَدَّثَنَا شَيْبَانُ عَنْ مَنْصُورٍ عَنْ الْمُسَيَّبِ عَنْ وَرَّادٍ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ حَرَّمَ عَلَيْكُمْ عُقُوقَ الْأُمَّهَاتِ وَمَنْعًا وَهَاتِ وَوَأْدَ الْبَنَاتِ وَكَرِهَ لَكُمْ قِيلَ وَقَالَ وَكَثْرَةَ السُّؤَالِ وَإِضَاعَةَ الْمَالِ","id":"Telah menceritakan kepada kami [Sa'd bin Hafsh] telah menceritakan kepada kami [Syaiban] dari [Manshur] dari [Al Musayyib] dari [Warrad] dari [Al Mughirah bin Syu'bah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Sesungguhnya Allah mengharamkan atas kalian durhaka kepada kedua orang tua, tidak suka memberi namun suka meminta-minta dan mengubur anak perempuan hidup-hidup. Dan membenci atas kalian tiga perkara, yaitu; suka desas-desus, banyak bertanya dan menyia-nyiakan harta.\""},"5214":{"ar":"حَدَّثَنِي إِسْحَاقُ حَدَّثَنَا خَالِدٌ الْوَاسِطِيُّ عَنْ الْجُرَيْرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ عَنْ أَبِيهِ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا أُنَبِّئُكُمْ بِأَكْبَرِ الْكَبَائِرِ قُلْنَا بَلَى يَا رَسُولَ اللَّهِ قَالَ الْإِشْرَاكُ بِاللَّهِ وَعُقُوقُ الْوَالِدَيْنِ وَكَانَ مُتَّكِئًا فَجَلَسَ فَقَالَ أَلَا وَقَوْلُ الزُّورِ وَشَهَادَةُ الزُّورِ أَلَا وَقَوْلُ الزُّورِ وَشَهَادَةُ الزُّورِ فَمَا زَالَ يَقُولُهَا حَتَّى قُلْتُ لَا يَسْكُتُ","id":"Telah menceritakan kepadaku [Ishaq] telah menceritakan kepada kami [Khalid Al Wasithi] dari [Al Jurairi] dari [Abdurrahman bin Abu Bakrah] dari [Ayahnya] radliallahu 'anhu dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak maukah aku beritahukan kepada kalian sesuatu yang termasuk dari dosa besar? Kami menjawab; \"Tentu wahai Rasulullah.\" Beliau bersabda: \"Menyekutukan Allah dan mendurhakai kedua orang tua.\" -ketika itu beliau tengah bersandar, kemudian duduk lalu melanjutkan sabdanya: \"Perkataan dusta dan kesaksian palsu, perkataan dusta dan kesaksian palsu.\" Beliau terus saja mengulanginya hingga saya mengira beliau tidak akan berhenti.\""},"5215":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ الْوَلِيدِ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ أَبِي بَكْرٍ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَذَكَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْكَبَائِرَ أَوْ سُئِلَ عَنْ الْكَبَائِرِ فَقَالَ الشِّرْكُ بِاللَّهِ وَقَتْلُ النَّفْسِ وَعُقُوقُ الْوَالِدَيْنِ فَقَالَ أَلَا أُنَبِّئُكُمْ بِأَكْبَرِ الْكَبَائِرِ قَالَ قَوْلُ الزُّورِ أَوْ قَالَ شَهَادَةُ الزُّورِ قَالَ شُعْبَةُ وَأَكْثَرُ ظَنِّي أَنَّهُ قَالَ شَهَادَةُ الزُّورِ","id":"Telah menceritakan kepadaku [Muhammad bin Al Walid] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dia berkata; telah menceritakan kepadaku ['Ubaidullah bin Abu Bakr] dia berkata; saya mendengar [Anas bin Malik] radliallahu 'anhu berkata; \"Rasulullah shallallahu 'alaihi wasallam menyebutkan tentang dosa besar atau beliau ditanya tentang dosa besar, lalu beliau menjawab: \"Menyekutukan Allah, membunuh jiwa dan durhaka kepada kedua orang tua.\" Lalu beliau bersabda: \"Maukah aku beritahukan kepada kalian yang termasuk dari dosa besar?\" beliau bersabda: \"Perkataan dusta atau beliau bersabda: \"Kesaksian palsu.\" Syu'bah mengatakan; \"Dan saya menyangka bahwa beliau mengatakan; \"Kesaksian palsu.\""},"5216":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ أَخْبَرَنِي أَبِي أَخْبَرَتْنِي أَسْمَاءُ بِنْتُ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَتْأَتَتْنِي أُمِّي رَاغِبَةً فِي عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ آصِلُهَا قَالَ نَعَمْقَالَ ابْنُ عُيَيْنَةَ فَأَنْزَلَ اللَّهُ تَعَالَى فِيهَا{ لَا يَنْهَاكُمْ اللَّهُ عَنْ الَّذِينَ لَمْ يُقَاتِلُوكُمْ فِي الدِّينِ }","id":"Telah menceritakan kepada kami [Al Humaidi] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Hisyam bin 'Urwah] telah mengabarkan kepadaku [Ayahku] telah mengabarkan kepadaku [Asma` binti Abu Bakr] radliallahu 'anhuma dia berkata; \"Ibuku datang pada masa Nabi shallallahu 'alaihi wasallam menemuiku dalam keadaan mengharapkan baktiku, lalu saya bertanya kepada Nabi shallallahu 'alaihi wasallam; \"Apakah saya boleh berhubungan dengannya?\" beliau menjawab: \"Ya.\" Ibnu 'Uyainah lalu berkata; \"Kemudian Allah Ta'ala menurunkan ayat Allah tidak melarang kalian dari orang-orang yang tidak memerangi agama kalian (QS Al Mumtahanah; 8).\""},"5217":{"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ أَخْبَرَهُ أَنَّ أَبَا سُفْيَانَ أَخْبَرَهُأَنَّ هِرَقْلَ أَرْسَلَ إِلَيْهِ فَقَالَ يَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُنَا بِالصَّلَاةِ وَالصَّدَقَةِ وَالْعَفَافِ وَالصِّلَةِ","id":"Telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari ['Ubaidullah bin Abdullah] bahwa [Abdullah bin Abbas] telah mengabarkan kepadanya, bahwa [Abu Sufyan] telah mengabarkan kepadanya bahwa Heraklius pernah mengutusnya kepada Nabi, lalu beliau yaitu Nabi shallallahu 'alaihi wasallam bersabda: \"Kami di perintahkan (oleh Allah) untuk menegakkan shalat, bersedekah, mema'afkan dan menjaling hubungan persaudaraan.\""},"5218":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُسْلِمٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دِينَارٍ قَالَ سَمِعْتُ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُرَأَى عُمَرُ حُلَّةَ سِيَرَاءَ تُبَاعُ فَقَالَ يَا رَسُولَ اللَّهِ ابْتَعْ هَذِهِ وَالْبَسْهَا يَوْمَ الْجُمُعَةِ وَإِذَا جَاءَكَ الْوُفُودُ قَالَ إِنَّمَا يَلْبَسُ هَذِهِ مَنْ لَا خَلَاقَ لَهُ فَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهَا بِحُلَلٍ فَأَرْسَلَ إِلَى عُمَرَ بِحُلَّةٍ فَقَالَ كَيْفَ أَلْبَسُهَا وَقَدْ قُلْتَ فِيهَا مَا قُلْتَ قَالَ إِنِّي لَمْ أُعْطِكَهَا لِتَلْبَسَهَا وَلَكِنْ تَبِيعُهَا أَوْ تَكْسُوهَا فَأَرْسَلَ بِهَا عُمَرُ إِلَى أَخٍ لَهُ مِنْ أَهْلِ مَكَّةَ قَبْلَ أَنْ يُسْلِمَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Abdul Aziz bin Muslim] telah menceritakan kepada kami [Abdullah bin Dinar] dia berkata; saya mendengar [Ibnu Umar] radliallahu 'anhuma berkata; \"Umar pernah melihat baju sutera yang bercorak dijual, lalu dia berkata; \"Wahai Rasulullah, Alangkah bagusnya seandainya Anda membelinya untuk Anda pakai berkhutbah pada hari jum'at', dan di saat menerima para utusan.\" Rasulullah shallallahu 'alaihi wasallam menjawab: 'Yang memakai sutera ini hanyalah orang yang tidak mendapat bagian di akhirat. Tidak berapa lama Nabi shallallahu 'alaihi wasallam diberi seseorang beberapa helai pakaian diantaranya kain sutera. Lalu beliau kirimkan sehelai kain sutera kepada 'Umar. Maka Umar bertanya; \"Ya Rasulullah! Bagaimana anda menyuruhku untuk memakai baju sutera ini? Bukankah kemarin Anda telah berkata kepadaku tentang baju ini?\" beliau menjawab: 'Aku tidak mengirimkannya kepadamu untuk kamu pakai, namun untuk kamu jual atau kamu pakaikan kepada orang lain' Lalu Umar memberikan kain itu kepada saudaranya yang masih musyrik di kota Makkah.\""},"5219":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي ابْنُ عُثْمَانَ قَالَ سَمِعْتُ مُوسَى بْنَ طَلْحَةَ عَنْ أَبِي أَيُّوبَ قَالَ قِيلَ يَا رَسُولَ اللَّهِ أَخْبِرْنِي بِعَمَلٍ يُدْخِلُنِي الْجَنَّةَ و حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ بِشْرٍ حَدَّثَنَا بَهْزُ بْنُ أَسَدٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا ابْنُ عُثْمَانَ بْنِ عَبْدِ اللَّهِ بْنِ مَوْهَبٍ وَأَبُوهُ عُثْمَانُ بْنُ عَبْدِ اللَّهِ أَنَّهُمَا سَمِعَا مُوسَى بْنَ طَلْحَةَ عَنْ أَبِي أَيُّوبَ الْأَنْصَارِيِّ رَضِيَ اللَّهُ عَنْهُأَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ أَخْبِرْنِي بِعَمَلٍ يُدْخِلُنِي الْجَنَّةَ فَقَالَ الْقَوْمُ مَا لَهُ مَا لَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرَبٌ مَا لَهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَعْبُدُ اللَّهَ لَا تُشْرِكُ بِهِ شَيْئًا وَتُقِيمُ الصَّلَاةَ وَتُؤْتِي الزَّكَاةَ وَتَصِلُ الرَّحِمَ ذَرْهَا قَالَ كَأَنَّهُ كَانَ عَلَى رَاحِلَتِهِ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dia berkata; telah mengabarkan kepadaku [Ibnu Utsman] dia berkata; saya mendengar [Musa bin Thalhah] dari [Abu Ayyub] dia berkata; beliau (Nabi) pernah di tanya; \"Wahai Rasulullah, beritahukanlah kepadaku suatu amalan yang dapat memasukkanku ke surga.\" Dan telah menceritakan kepadaku [Abdurrahman bin Bisyr] telah menceritakan kepada kami [Bahz bin Asad] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Ibnu Utsman bin Abdullah bin Mauhab] dan ayahnya [Utsman bin Abdullah] bahwa keduanya mendengar [Musa bin Thalhah] dari [Abu Ayyub Al Anshari] radliallahu 'anhu bahwa seorang laki-laki berkata; \"Wahai Rasulullah, beritahukanlah kepadaku suatu amalan yang dapat memasukkanku ke surga.\" Orang-orang pun berkata; \"Ada apa dengan orang ini, ada apa dengan orang ini.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Biarkanlah urusan orang ini.\" Lalu Nabi shallallahu 'alaihi wasallam melanjutkan sabdanya: \"Kamu beribadah kepada Allah dan tidak menyekutukannya, menegakkan shalat, dan membayar zakat serta menjalin tali silaturrahmi.\" Abu Ayyub berkata; \"Ketika itu beliau berada di atas kendaraannya.\""},"5220":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ أَنَّ مُحَمَّدَ بْنَ جُبَيْرِ بْنِ مُطْعِمٍ قَالَ إِنَّ جُبَيْرَ بْنَ مُطْعِمٍ أَخْبَرَهُأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَدْخُلُ الْجَنَّةَ قَاطِعٌ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] bahwa [Muhammad bin Jubair bin Muth'im] berkata; bahwa [Jubair bin Muth'im] telah mengabarkan kepadanya bahwa dia mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak akan masuk surga orang yang memutus tali silaturrahmi.\""},"5221":{"ar":"حَدَّثَنِي إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا مُحَمَّدُ بْنُ مَعْنٍ قَالَ حَدَّثَنِي أَبِي عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ سَرَّهُ أَنْ يُبْسَطَ لَهُ فِي رِزْقِهِ وَأَنْ يُنْسَأَ لَهُ فِي أَثَرِهِ فَلْيَصِلْ رَحِمَهُ","id":"Telah menceritakan kepadaku [Ibrahim bin Al Mundzir] telah menceritakan kepada kami [Muhammad bin Ma'an] dia berkata; telah menceritakan kepadaku [Ayahku] dari [Sa'id bin Abu Sa'id] dari [Abu Hurairah] radliallahu 'anhu dia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa ingin dibentangkan pintu rizki untuknya dan dipanjangkan ajalnya hendaknya ia menyambung tali silaturrahmi.\""},"5222":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي أَنَسُ بْنُ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَحَبَّ أَنْ يُبْسَطَ لَهُ فِي رِزْقِهِ وَيُنْسَأَ لَهُ فِي أَثَرِهِ فَلْيَصِلْ رَحِمَهُ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dia berkata; telah mengabarkan kepadaku [Anas bin Malik] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa ingin lapangkan pintu rizqi untuknya dan dipanjangkan umurnya hendaknya ia menyambung tali silaturrahmi.\""},"5223":{"ar":"حَدَّثَنِي بِشْرُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مُعَاوِيَةُ بْنُ أَبِي مُزَرِّدٍ قَالَ سَمِعْتُ عَمِّي سَعِيدَ بْنَ يَسَارٍ يُحَدِّثُ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ خَلَقَ الْخَلْقَ حَتَّى إِذَا فَرَغَ مِنْ خَلْقِهِ قَالَتْ الرَّحِمُ هَذَا مَقَامُ الْعَائِذِ بِكَ مِنْ الْقَطِيعَةِ قَالَ نَعَمْ أَمَا تَرْضَيْنَ أَنْ أَصِلَ مَنْ وَصَلَكِ وَأَقْطَعَ مَنْ قَطَعَكِ قَالَتْ بَلَى يَا رَبِّ قَالَ فَهُوَ لَكِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاقْرَءُوا إِنْ شِئْتُمْ{ فَهَلْ عَسَيْتُمْ إِنْ تَوَلَّيْتُمْ أَنْ تُفْسِدُوا فِي الْأَرْضِ وَتُقَطِّعُوا أَرْحَامَكُمْ }","id":"Telah menceritakan kepadaku [Bisyr bin Muhammad] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Mu'awiyah bin Abu Muzarrid] dia berkata; saya mendengar pamanku [Sa'id bin Yasar] bercerita dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Setelah Allah menciptakan semua makhluk, maka rahim pun berkata; 'Inikah tempat bagi yang berlindung dari terputusnya silaturahim (Menyambung silaturahim).' Allah menjawab: 'Benar. Tidakkah kamu rela bahwasanya Aku akan menyambung orang yang menyambungmu dan memutuskan yang memutuskanmu? ' Rahim menjawab; 'Tentu, wahai Rabb' Allah berfirman: 'ltulah yang kamu miliki.' Setelah itu Rasulullah shallallahu 'alaihi wasallam bersabda: 'Jika kamu mau, maka bacalah ayat berikut ini: Maka apakah kiranya jika kamu berkuasa kamu akan berbuat kerusakan di muka bumi dan memutuskan hubungan kekeluargaan? QS Muhammad: 22."},"5224":{"ar":"حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا سُلَيْمَانُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دِينَارٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الرَّحِمَ شَجْنَةٌ مِنْ الرَّحْمَنِ فَقَالَ اللَّهُ مَنْ وَصَلَكِ وَصَلْتُهُ وَمَنْ قَطَعَكِ قَطَعْتُهُ","id":"Telah menceritakan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Sulaiman] telah menceritakan kepada kami [Abdullah bin Dinar] dari [Abu Shalih] dari [Abu Hurairah] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Sesungguhnya penamaan rahim itu diambil dari (nama Allah) Ar Rahman, lalu Allah berfirman: Barangsiapa menyambungmu maka Akupun menyambungnya dan barangsiapa memutuskanmu maka Akupun akan memutuskannya.\""},"5225":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ قَالَ أَخْبَرَنِي مُعَاوِيَةُ بْنُ أَبِي مُزَرِّدٍ عَنْ يَزِيدَ بْنِ رُومَانَ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الرَّحِمُ شِجْنَةٌ فَمَنْ وَصَلَهَا وَصَلْتُهُ وَمَنْ قَطَعَهَا قَطَعْتُهُ","id":"Telah menceritakan kepada kami [Sa'id bin Abu Maryam] telah menceritakan kepada kami [Sulaiman bin Bilal] dia berkata; telah mengabarkan kepadaku [Mu'awiyah bin Abu Muzarrid] dari [Yazid bin Ruman] dari ['Urwah] dari [Aisyah] radliallahu 'anha isteri Nabi shallallahu 'alaihi wasallam dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Ar rahim (silaturahim) adalah syijnah (daun pohon yang rindang) barangsiapa menyambungnya maka aku akan menyambungnya dan barangsiapa memutuskannya maka akupun akan memutuskannya.\""},"5226":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَبَّاسٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ إِسْمَاعِيلَ بْنِ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ أَنَّ عَمْرَو بْنَ الْعَاصِ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جِهَارًا غَيْرَ سِرٍّ يَقُولُ إِنَّ آلَ أَبِي قَالَ عَمْرٌو فِي كِتَابِ مُحَمَّدِ بْنِ جَعْفَرٍ بَيَاضٌ لَيْسُوا بِأَوْلِيَائِي إِنَّمَا وَلِيِّيَ اللَّهُ وَصَالِحُ الْمُؤْمِنِينَزَادَ عَنْبَسَةُ بْنُ عَبْدِ الْوَاحِدِ عَنْ بَيَانٍ عَنْ قَيْسٍ عَنْ عَمْرِو بْنِ الْعَاصِ قَالَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَكِنْ لَهُمْ رَحِمٌ أَبُلُّهَا بِبَلَاهَا يَعْنِي أَصِلُهَا بِصِلَتِهَا قَالَ أَبُو عَبْد اللَّهِ بِبَلَاهَا كَذَا وَقَعَ وَبِبَلَالِهَا أَجْوَدُ وَأَصَحُّ وَبِبَلَاهَا لَا أَعْرِفُ لَهُ وَجْهًا","id":"Telah menceritakan kepada kami ['Amru bin Abbas] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Isma'il bin Abu Khalid] dari [Qais bin Abu Hazim] dari ['Amru bin Al 'Ash] dia berkata; saya mendengar Nabi shallallahu 'alaihi wasallam secara jelas dan terang-terangan bersabda: \"Sesungguhnya keluarga Abu (fulan) -Amru berkata; di dalam kitab putihnya Muhammad bin Ja'far- bukanlah dari para waliku (penolongku), sesungguhnya waliku adalah Allah dan orang-orang shalih dari kaum Mukminin.\" ['Anbasah bin Abdul Wahid] menambahkan, dari [Bayan] dari [Qais] dari ['Amru bin Al 'Ash] dia berkata; saya mendengar Nabi shallallahu 'alaihi wasallam (bersabda): \"Akan tetapi mereka (keluarga Abu fulan) masih memiliki tali silaturrahmi yang aku tetap akan menyambungnya dengan tali silaturrahim itu.\" Abu Abdullah mengatakan; dan yang tertulis menggunakan redaksi \"bibalaha (menyambungnya).\" Namun yang shahih dan yang lebih pantas adalah \"Bibalaaliha (menyambungnya).\" Aku tidak tahu dari segimana kalimat \"Bibalaha (menyambungnya) \" didapatkan."},"5227":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ الْأَعْمَشِ وَالْحَسَنِ بْنِ عَمْرٍو وَفِطْرٍ عَنْ مُجَاهِدٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ سُفْيَانُ لَمْ يَرْفَعْهُ الْأَعْمَشُإِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَفَعَهُ حَسَنٌ وَفِطْرٌ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ الْوَاصِلُ بِالْمُكَافِئِ وَلَكِنْ الْوَاصِلُ الَّذِي إِذَا قُطِعَتْ رَحِمُهُ وَصَلَهَا","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dari [Al A'masy], [Hasan bin 'Amru] dan [Fithr] dari [Mujahid] dari [Abdullah bin 'Amru], Sufyan mengatakan; Namun Al A'masy tidak merafa'kannya kepada Nabi shallallahu 'alaihi wasallam, sedangkan Hasan dan Fithr merafa'kannya (menyambungkannya) kepada Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Orang yang menyambung silaturrahmi bukanlah orang yang memenuhi (kebutuhan) akan tetapi orang yang menyambung silaturrahmi adalah orang yang menyambungnya kembali ketika tali silaturrahmi itu sempat terputus.\""},"5228":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ حَكِيمَ بْنَ حِزَامٍ أَخْبَرَهُ أَنَّهُ قَالَيَا رَسُولَ اللَّهِ أَرَأَيْتَ أُمُورًا كُنْتُ أَتَحَنَّثُ بِهَا فِي الْجَاهِلِيَّةِ مِنْ صِلَةٍ وَعَتَاقَةٍ وَصَدَقَةٍ هَلْ لِي فِيهَا مِنْ أَجْرٍ قَالَ حَكِيمٌ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْلَمْتَ عَلَى مَا سَلَفَ مِنْ خَيْرٍوَيُقَالُ أَيْضًا عَنْ أَبِي الْيَمَانِ أَتَحَنَّثُ وَقَالَ مَعْمَرٌ وَصَالِحٌ وَابْنُ الْمُسَافِرِ أَتَحَنَّثُ وَقَالَ ابْنُ إِسْحَاقَ التَّحَنُّثُ التَّبَرُّرُ وَتَابَعَهُمْ هِشَامٌ عَنْ أَبِيهِ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku ['Urwah bin Zubair] bahwa [Hakim bin Hizam] telah mengabarkan kepadanya bahwa dia berkata; \"Wahai Rasulullah, bagaimana pendapat anda tentang perkara-perkara kebaikan yang pernah saya lakukan pada masa Jahiliyyah seperti menyambung tali kekerabatan, memerdekakan budak dan sedekah, apakah saya mendapatkan pahala darinya? Hakim berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Setelah kamu masuk Islam, kamu akan mendapatkan pahala atas kebaikan yang pernah kamu lakukan.\" Dan dikatakan pula dari Abu Al Yaman dengan redaksi \"Atahannatsu (telah aku kerjakan), begitu juga [Ma'mar], [Shalih] dan [Ibnu Musafir] menggunakan redaksi \"atahannatsu (telah aku kerjakan).\" Ibnu Ishaq mengatakan; \"at tahannatsu wat tabarraru (telah aku kerjakan dan berbuat baik).\" Hal ini diperkuat juga oleh [Hisyam] dari [Ayahnya].\""},"5229":{"ar":"حَدَّثَنَا حِبَّانُ أَخْبَرَنَا عَبْدُ اللَّهِ عَنْ خَالِدِ بْنِ سَعِيدٍ عَنْ أَبِيهِ عَنْ أُمِّ خَالِدٍ بِنْتِ خَالِدِ بْنِ سَعِيدٍ قَالَتْأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَ أَبِي وَعَلَيَّ قَمِيصٌ أَصْفَرُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَنَهْ سَنَهْ قَالَ عَبْدُ اللَّهِ وَهِيَ بِالْحَبَشِيَّةِ حَسَنَةٌ قَالَتْ فَذَهَبْتُ أَلْعَبُ بِخَاتَمِ النُّبُوَّةِ فَزَبَرَنِي أَبِي قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعْهَا ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبْلِي وَأَخْلِقِي ثُمَّ أَبْلِي وَأَخْلِقِي ثُمَّ أَبْلِي وَأَخْلِقِي قَالَ عَبْدُ اللَّهِ فَبَقِيَتْ حَتَّى ذَكَرَ يَعْنِي مِنْ بَقَائِهَا","id":"Telah menceritakan kepada kami [Hibban] telah mengabarkan kepada kami [Abdullah] dari [Khalid bin Sa'id] dari [Ayahnya] dari [Ummu Khalid binti Khalid bin Sa'id] dia berkata; saya mengunjungi Rasulullah shallallahu 'alaihi wasallam bersama ayahku, sedangkan aku tengah mengenakan baju berwarna kuning, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bagus, bagus.\" Abdullah mengatakan; \"Menurut orang-orang Habsyah sanah artinya adalah hasan (bagus).\" Ummu Khalid berkata; \"Lalu aku beranjak untuk mempermainkan cincin kenabian beliau, maka ayahku langsung menghardikku, namun Rasulullah shallallahu 'alaihi wasallam bersabda: \"Biarkanlah ia.\" Kemudian beliau bersabda: \"Pakailah (kain tersebut) semoga panjang umur (tidak cepat rusak) dan pakailah semoga panjang umur dan pakailah semoga panjang umur.\" Abdullah berkata; \"Dan pakaian tersebut masih ada bekasnya hingga ia pun menyebutkan dari sisa kain tersebut.\""},"5230":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا مَهْدِيٌّ حَدَّثَنَا ابْنُ أَبِي يَعْقُوبَ عَنْ ابْنِ أَبِي نُعْمٍ قَالَ كُنْتُ شَاهِدًا لِابْنِ عُمَرَوَسَأَلَهُ رَجُلٌ عَنْ دَمِ الْبَعُوضِ فَقَالَ مِمَّنْ أَنْتَ فَقَالَ مِنْ أَهْلِ الْعِرَاقِ قَالَ انْظُرُوا إِلَى هَذَا يَسْأَلُنِي عَنْ دَمِ الْبَعُوضِ وَقَدْ قَتَلُوا ابْنَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ هُمَا رَيْحَانَتَايَ مِنْ الدُّنْيَا","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Mahdi] telah menceritakan kepada kami [Ibnu Abu Ya'qub] dari [Ibnu Abu Nu'm] dia berkata; saya pernah menyaksikan [Ibnu Umar] bahwa dia ditanya seorang laki-laki tentang darah nyamuk, Ibnu Umar bertanya; \"Dari manakah kamu?\" laki-laki itu menjawab; \"Dari negeri Irak.\" Ibnu Umar berkata; \"Lihatlah kepada orang ini, dia bertanya kepadaku tentang darah nyamuk, sementara mereka (penduduk Irak) telah membunuh cucu Nabi shallallahu 'alaihi wasallam, dan saya mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"keduanya (Hasan dan Husain) adalah kebanggaanku di dunia.\""},"5231":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي بَكْرٍ أَنَّ عُرْوَةَ بْنَ الزُّبَيْرِ أَخْبَرَهُ أَنَّ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَتْهُ قَالَتْجَاءَتْنِي امْرَأَةٌ مَعَهَا ابْنَتَانِ تَسْأَلُنِي فَلَمْ تَجِدْ عِنْدِي غَيْرَ تَمْرَةٍ وَاحِدَةٍ فَأَعْطَيْتُهَا فَقَسَمَتْهَا بَيْنَ ابْنَتَيْهَا ثُمَّ قَامَتْ فَخَرَجَتْ فَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَدَّثْتُهُ فَقَالَ مَنْ يَلِي مِنْ هَذِهِ الْبَنَاتِ شَيْئًا فَأَحْسَنَ إِلَيْهِنَّ كُنَّ لَهُ سِتْرًا مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; telah menceritakan kepadaku [Abdullah bin Abu Bakr] bahwa ['Urwah bin Zubair] telah mengabarkan kepadanya bahwa [Aisyah isteri nabi shallallahu 'alaihi wasallam] telah menceritakan kepadanya, katanya; \"Seorang wanita bersama dua anaknya pernah datang kepadaku, dia meminta (makanan) kepadaku, namun aku tidak memiliki sesuatu yang dapat dimakan melainkan satu buah kurma, kemudian aku memberikan kepadanya dan membagi untuk kedua anaknya, setelah itu wanita tersebut berdiri dan beranjak keluar, tiba-tiba Nabi shallallahu 'alaihi wasallam datang dan aku pun memberitahukan peristiwa yang baru aku alami, beliau bersabda: \"Barangsiapa yang diuji sesuatu karena anak-anak perempuannya lalu ia berlaku baik terhadap mereka maka mereka akan melindunginya dari api neraka.\""},"5232":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا اللَّيْثُ حَدَّثَنَا سَعِيدٌ الْمَقْبُرِيُّ حَدَّثَنَا عَمْرُو بْنُ سُلَيْمٍ حَدَّثَنَا أَبُو قَتَادَةَ قَالَخَرَجَ عَلَيْنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأُمَامَةُ بِنْتُ أَبِي الْعَاصِ عَلَى عَاتِقِهِ فَصَلَّى فَإِذَا رَكَعَ وَضَعَ وَإِذَا رَفَعَ رَفَعَهَا","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Al Laits] telah menceritakan kepada kami [Sa'id Al Maqburi] telah menceritakan kepada kami ['Amru bin Sulaim] telah menceritakan kepada kami [Abu Qatadah] dia berkata; \"Nabi shallallahu 'alaihi wasallam keluar menemui kami, sementara Umamah binti Abu Al 'Ash berada dipundak beliau, kemudian beliau mengerjakan shalat, apabila hendak ruku' beliau meletakkannya dan apabila bangkit dari ruku beliau pun mengangkatnya kembali.\""},"5233":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ حَدَّثَنَا أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَبَّلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْحَسَنَ بْنَ عَلِيٍّ وَعِنْدَهُ الْأَقْرَعُ بْنُ حَابِسٍ التَّمِيمِيُّ جَالِسًا فَقَالَ الْأَقْرَعُ إِنَّ لِي عَشَرَةً مِنْ الْوَلَدِ مَا قَبَّلْتُ مِنْهُمْ أَحَدًا فَنَظَرَ إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ مَنْ لَا يَرْحَمُ لَا يُرْحَمُ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] telah menceritakan kepada kami [Abu Salamah bin Abdurrahman] bahwa [Abu Hurairah] radliallahu 'anhu berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah mencium Al Hasan bin Ali sedangkan disamping beliau ada Al Aqra' bin Habis At Tamimi sedang duduk, lalu Aqra' berkata; \"Sesungguhnya aku memiliki sepuluh orang anak, namun aku tidak pernah mencium mereka sekali pun, maka Rasulullah shallallahu 'alaihi wasallam memandangnya dan bersabda: \"Barangsiapa tidak mengasihi maka ia tidak akan dikasihi.\""},"5234":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ هِشَامٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْجَاءَ أَعْرَابِيٌّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ تُقَبِّلُونَ الصِّبْيَانَ فَمَا نُقَبِّلُهُمْ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوَأَمْلِكُ لَكَ أَنْ نَزَعَ اللَّهُ مِنْ قَلْبِكَ الرَّحْمَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Hisyam] dari ['Urwah] dari ['Aisyah] radliallahu 'anha dia berkata; \"Seorang Arab Badui datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; \"Kalian menciumi anak-anak kalian, padahal kami tidak pernah menciumi anak-anak kami.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Apakah aku memiliki apa yang telah Allah hilangkan dari hatimu berupa sikap kasih sayang?\""},"5235":{"ar":"حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ حَدَّثَنَا أَبُو غَسَّانَ قَالَ حَدَّثَنِي زَيْدُ بْنُ أَسْلَمَ عَنْ أَبِيهِ عَنْ عُمَرَ بْنِ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُقَدِمَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبْيٌ فَإِذَا امْرَأَةٌ مِنْ السَّبْيِ قَدْ تَحْلُبُ ثَدْيَهَا تَسْقِي إِذَا وَجَدَتْ صَبِيًّا فِي السَّبْيِ أَخَذَتْهُ فَأَلْصَقَتْهُ بِبَطْنِهَا وَأَرْضَعَتْهُ فَقَالَ لَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتُرَوْنَ هَذِهِ طَارِحَةً وَلَدَهَا فِي النَّارِ قُلْنَا لَا وَهِيَ تَقْدِرُ عَلَى أَنْ لَا تَطْرَحَهُ فَقَالَ لَلَّهُ أَرْحَمُ بِعِبَادِهِ مِنْ هَذِهِ بِوَلَدِهَا","id":"Telah menceritakan kepada kami [Ibnu Abu Maryam] telah menceritakan kepada kami [Abu Ghassan] dia berkata; telah menceritakan kepadaku [Zaid bin Aslam] dari [Ayahnya] dari [Umar bin Al Khatthab] radliallahu 'anhu (katanya); \"Rasulullah shallallahu 'alaihi wasallam pernah memperoleh beberapa orang tawanan perang. Ternyata dari tawanan tersebut ada seorang perempuan yang biasa menyusui anak kecil, apabila dia mendapatkan anak kecil dalam tawanan tersebut, maka ia akan mengambilnya dan menyusuinya, lalu Nabi shallallahu 'alaihi wasallam bersabda kepada kami: 'Menurut kalian, apakah perempuan itu tega melemparkan bayinya ke dalam api? ' Kami menjawab; 'Sesungguhnya ia tidak akan tega melemparkan anaknya ke dalam api selama ia masih sanggup menghindarkannya dari api tersebut.' Lalu beliau bersabda: 'Sungguh, kasih sayang Allah terhadap hamba-Nya melebihi kasih sayang perempuan itu terhadap anaknya.'"},"5236":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ الْحَكَمُ بْنُ نَافِعٍ الْبَهْرَانِيُّ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ أَخْبَرَنَا سَعِيدُ بْنُ الْمُسَيَّبِ أَنَّ أَبَا هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ جَعَلَ اللَّهُ الرَّحْمَةَ مِائَةَ جُزْءٍ فَأَمْسَكَ عِنْدَهُ تِسْعَةً وَتِسْعِينَ جُزْءًا وَأَنْزَلَ فِي الْأَرْضِ جُزْءًا وَاحِدًا فَمِنْ ذَلِكَ الْجُزْءِ يَتَرَاحَمُ الْخَلْقُ حَتَّى تَرْفَعَ الْفَرَسُ حَافِرَهَا عَنْ وَلَدِهَا خَشْيَةَ أَنْ تُصِيبَهُ","id":"Telah menceritakan kepada kami [Abu Al Yaman Al Hakam bin Nafi' Al Bahrani] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] telah mengabarkan kepada kami [Sa'id bin Al Musayyib] bahwa [Abu Hurairah] berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah menjadikan rahmat (kasih sayang) seratus bagian, maka dipeganglah disisi-Nya sembilan puluh sembilan bagian dan diturunkan-Nya satu bagian ke bumi. Dari yang satu bagian inilah seluruh makhluk berkasih sayang sesamanya, sehingga seekor kuda mengangkat kakinya karena takut anaknya akan terinjak olehnya.\""},"5237":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ عَمْرِو بْنِ شُرَحْبِيلَ عَنْ عَبْدِ اللَّهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَيُّ الذَّنْبِ أَعْظَمُ قَالَ أَنْ تَجْعَلَ لِلَّهِ نِدًّا وَهُوَ خَلَقَكَ قُلْتُ ثُمَّ أَيُّ قَالَ أَنْ تَقْتُلَ وَلَدَكَ خَشْيَةَ أَنْ يَأْكُلَ مَعَكَ قَالَ ثُمَّ أَيُّ قَالَ أَنْ تُزَانِيَ حَلِيلَةَ جَارِكَ وَأَنْزَلَ اللَّهُ تَصْدِيقَ قَوْلِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ }الْآيَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dari [Manshur] dari [Abu Wa`il] dari ['Amru bin Syurahbil] dari [Abdullah] dia berkata; saya bertanya; Wahai Rasulullah, dosa apakah yang paling besar? Beliau menjawab: \"Kamu menjadikan tandingan bagi Allah, padahal Dia adalah yang menciptakanmu.\" Kemudian apalagi?\" beliau bersabda: \"Kamu membunuh anakmu karena takut dia makan bersamamu.\" Dia berkata; \"Kemudian apalagi?\" beliau bersabda: \"Kamu mencinahi isteri tetanggamu sendiri.\" Dan Allah telah menurunkan kebenaran sabda Nabi-Nya shallallahu 'alaihi wasallam Dan orang-orang yang tidak menyeru Allah dengan tuhan-tuhan yang lain. QS Al Furqan; 68."},"5238":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ هِشَامٍ قَالَ أَخْبَرَنِي أَبِي عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَضَعَ صَبِيًّا فِي حَجْرِهِ يُحَنِّكُهُ فَبَالَ عَلَيْهِ فَدَعَا بِمَاءٍ فَأَتْبَعَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Hisyam] dia berkata; telah mengabarkan kepadaku [Ayahku] dari [Aisyah] bahwa Nabi shallallahu 'alaihi wasallam pernah meletakkan seorang bayi di pangkuannya kemudian beliau mentahniknya (mengunyahkan buah kurma kemudian memasukkan ke mulut bayi) lalu bayi itu ngompol, maka beliau meminta diambilkan air dan memercikinya.\""},"5239":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا عَارِمٌ حَدَّثَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ يُحَدِّثُ عَنْ أَبِيهِ قَالَ سَمِعْتُ أَبَا تَمِيمَةَ يُحَدِّثُ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ يُحَدِّثُهُ أَبُو عُثْمَانَ عَنْ أُسَامَةَ بْنِ زَيْدٍ رَضِيَ اللَّهُ عَنْهُمَاكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْخُذُنِي فَيُقْعِدُنِي عَلَى فَخِذِهِ وَيُقْعِدُ الْحَسَنَ عَلَى فَخِذِهِ الْأُخْرَى ثُمَّ يَضُمُّهُمَا ثُمَّ يَقُولُ اللَّهُمَّ ارْحَمْهُمَا فَإِنِّي أَرْحَمُهُمَاوَعَنْ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى حَدَّثَنَا سُلَيْمَانُ عَنْ أَبِي عُثْمَانَ قَالَ التَّيْمِيُّ فَوَقَعَ فِي قَلْبِي مِنْهُ شَيْءٌ قُلْتُ حَدَّثْتُ بِهِ كَذَا وَكَذَا فَلَمْ أَسْمَعْهُ مِنْ أَبِي عُثْمَانَ فَنَظَرْتُ فَوَجَدْتُهُ عِنْدِي مَكْتُوبًا فِيمَا سَمِعْتُ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] telah menceritakan kepada kami ['Arim] telah menceritakan kepada kami [Al Mu'tamir bin Sulaiman] ia bercerita dari [Ayahnya] dia berkata; saya mendengar [Abu Tamimah] bercerita dari [Abu Utsman An Nahdi], Abu Utsman bercerita dari [Usamah bin Zaid] radliallahu 'anhuma bahwa Rasulullah shallallahu 'alaihi wasallam pernah mengambilku dan mendudukkanku di atas pangkuannya serta meletakkan Hasan di pangkuan beliau yang satu, lalu beliau mendekap keduanya dan berdo'a: \"Ya Allah kasihilah keduanya karena aku mengasihi keduanya.\" Dan dari [Ali] dia berkata; telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Sulaiman] dari [Abu Utsman], At Taimi berkata; \"Lalu aku merasa janggal, kataku; Aku menceritakan ini dan ini namun aku sendiri tidak mendengar dari Abu Utsman, kemudian aku mengeceknya, ternyata aku mendapatinya tertulis di bukuku sebagaimana yang aku dengar.\""},"5240":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْمَا غِرْتُ عَلَى امْرَأَةٍ مَا غِرْتُ عَلَى خَدِيجَةَ وَلَقَدْ هَلَكَتْ قَبْلَ أَنْ يَتَزَوَّجَنِي بِثَلَاثِ سِنِينَ لِمَا كُنْتُ أَسْمَعُهُ يَذْكُرُهَا وَلَقَدْ أَمَرَهُ رَبُّهُ أَنْ يُبَشِّرَهَا بِبَيْتٍ فِي الْجَنَّةِ مِنْ قَصَبٍ وَإِنْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيَذْبَحُ الشَّاةَ ثُمَّ يُهْدِي فِي خُلَّتِهَا مِنْهَا","id":"Telah menceritakan kepada kami [Ubaid bin Isma'il] telah menceritakan kepada kami [Abu Usamah] dari [Hisyam] dari [Ayahnya] dari [Aisyah] radliallahu 'anha dia berkata; \"Aku tidak pernah merasa cemburu kepada siapapun melebihi kecemburuanku kepada Khadijah sungguh dia telah wafat tiga tahun sebelum beliau menikahiku. Menurut apa yang aku dengar beliau suka menyebut-nyebutnya. Sungguh, Rabbnya telah memerintahkan kepada beliau agar memberi kabar gembira kepadanya dengan istana dari permata di surga. Apabila Rasulullah shallallahu 'alaihi wasallam menyembelih seekor kambing, maka beliau suka menghadiahkannya kepada para sahabat-sahabatnya Khadijah dari pada dirinya.\""},"5241":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الْوَهَّابِ قَالَ حَدَّثَنِي عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ قَالَ حَدَّثَنِي أَبِي قَالَ سَمِعْتُ سَهْلَ بْنَ سَعْدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَنَا وَكَافِلُ الْيَتِيمِ فِي الْجَنَّةِ هَكَذَا وَقَالَ بِإِصْبَعَيْهِ السَّبَّابَةِ وَالْوُسْطَى","id":"Telah menceritakan kepada kami [Abdullah bin Abdul Wahab] dia berkata; telah menceritakan kepadaku [Abdul Aziz bin Abu Hazim] dia berkata; telah menceritakan kepadaku [Ayahku] dia berkata; saya mendengar [Sahl bin Sa'd] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Aku dan orang yang menanggung anak yatim berada di surga seperti ini.\" Beliau mengisyaratkan dengan kedua jarinya yaitu telunjuk dan jari tengah.\""},"5242":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ صَفْوَانَ بْنِ سُلَيْمٍيَرْفَعُهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ السَّاعِي عَلَى الْأَرْمَلَةِ وَالْمِسْكِينِ كَالْمُجَاهِدِ فِي سَبِيلِ اللَّهِ أَوْ كَالَّذِي يَصُومُ النَّهَارَ وَيَقُومُ اللَّيْلَحَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ ثَوْرِ بْنِ زَيْدٍ الدِّيلِيِّ عَنْ أَبِي الْغَيْثِ مَوْلَى ابْنِ مُطِيعٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Isma'il bin Abdullah] dia berkata; telah menceritakan kepadaku [Malik] dari [Shafwan bin Sulaim] yang merafa'kan (menyandarkannya) kepada Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Orang yang membantu para janda dan orang-orang miskin seperti orang yang berjihad dijalan Allah atau seperti orang yang selalu berpuasa siang harinya dan selalu shalat malam pada malam harinya.\" Telah menceritakan kepada kami [Isma'il] dia berkata; telah menceritakan kepadaku [Malik] dari [Tsaur bin Zaid Ad Daili] dari [Abu Al Ghaits] bekas budak Ibnu Muthi' dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas."},"5243":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا مَالِكٌ عَنْ ثَوْرِ بْنِ زَيْدٍ عَنْ أَبِي الْغَيْثِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ السَّاعِي عَلَى الْأَرْمَلَةِ وَالْمِسْكِينِ كَالْمُجَاهِدِ فِي سَبِيلِ اللَّهِ وَأَحْسِبُهُ قَالَ يَشُكُّ الْقَعْنَبِيُّ كَالْقَائِمِ لَا يَفْتُرُ وَكَالصَّائِمِ لَا يُفْطِرُ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] telah menceritakan kepada kami [Malik] dari [Tsaur bin Zaid] dari [Abu Al Ghaits] dari [Abu Hurairah] radliallahu 'anhu dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang membantu para janda dan orang-orang miskin seperti orang yang berjihad dijalan Allah -aku mengira beliau juga bersabda -(Al Qa'nabi ragu) -: Dan seperti orang yang shalat malam tidak pernah istirahat- dan seperti orang puasa tidak berbuka.\""},"5244":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي سُلَيْمَانَ مَالِكِ بْنِ الْحُوَيْرِثِ قَالَأَتَيْنَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ شَبَبَةٌ مُتَقَارِبُونَ فَأَقَمْنَا عِنْدَهُ عِشْرِينَ لَيْلَةً فَظَنَّ أَنَّا اشْتَقْنَا أَهْلَنَا وَسَأَلَنَا عَمَّنْ تَرَكْنَا فِي أَهْلِنَا فَأَخْبَرْنَاهُ وَكَانَ رَفِيقًا رَحِيمًا فَقَالَ ارْجِعُوا إِلَى أَهْلِيكُمْ فَعَلِّمُوهُمْ وَمُرُوهُمْ وَصَلُّوا كَمَا رَأَيْتُمُونِي أُصَلِّي وَإِذَا حَضَرَتْ الصَّلَاةُ فَلْيُؤَذِّنْ لَكُمْ أَحَدُكُمْ ثُمَّ لِيَؤُمَّكُمْ أَكْبَرُكُمْ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Isma'il] telah menceritakan kepada kami [Ayyub] dari [Abu Qilabah] dari [Abu Sulaiman Malik bin Al Huwairits] dia berkata; \"Kami datang kepada Nabi Shallallahu'alaihi wasallam sedangkan waktu itu kami adalah pemuda yang sebaya. Kami tinggal bersama beliau selama dua puluh malam. Beliau mengira kalau kami merindukan keluarga kami, maka beliau bertanya tentang keluarga kami yang kami tinggalkan. Kami pun memberitahukannya, beliau adalah seorang yang sangat penyayang dan sangat lembut. Beliau bersabda: \"Pulanglah ke keluarga kalian. Tinggallah bersama mereka dan ajari mereka serta perintahkan mereka dan shalatlah kalian sebagaimana kalian melihatku shalat. Jika telah datang waktu shalat, maka hendaklah salah seorang dari kalian mengumandangkan adzan, dan yang paling tua dari kalian hendaknya menjadi imam kalian'.\""},"5245":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنِي مَالِكٌ عَنْ سُمَيٍّ مَوْلَى أَبِي بَكْرٍ عَنْ أَبِي صَالِحٍ السَّمَّانِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَمَا رَجُلٌ يَمْشِي بِطَرِيقٍ اشْتَدَّ عَلَيْهِ الْعَطَشُ فَوَجَدَ بِئْرًا فَنَزَلَ فِيهَا فَشَرِبَ ثُمَّ خَرَجَ فَإِذَا كَلْبٌ يَلْهَثُ يَأْكُلُ الثَّرَى مِنْ الْعَطَشِ فَقَالَ الرَّجُلُ لَقَدْ بَلَغَ هَذَا الْكَلْبَ مِنْ الْعَطَشِ مِثْلُ الَّذِي كَانَ بَلَغَ بِي فَنَزَلَ الْبِئْرَ فَمَلَأَ خُفَّهُ ثُمَّ أَمْسَكَهُ بِفِيهِ فَسَقَى الْكَلْبَ فَشَكَرَ اللَّهُ لَهُ فَغَفَرَ لَهُ قَالُوا يَا رَسُولَ اللَّهِ وَإِنَّ لَنَا فِي الْبَهَائِمِ أَجْرًا فَقَالَ نَعَمْ فِي كُلِّ ذَاتِ كَبِدٍ رَطْبَةٍ أَجْرٌ","id":"Telah menceritakan kepada kami [Isma'il] telah menceritakan kepadaku [Malik] dari [Sumayya] bekas budak Abu Bakr, dari [Abu Shalih As Samman] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada suatu ketika ada seorang laki-laki sedang berjalan melalui suatu jalan, lalu dia merasa sangat kehausan. Kebetulan dia menemukan sebuah sumur, maka dia turun ke sumur itu untuk minum. Setelah keluar dari sumur, dia melihat seekor anjing menjulurkan lidahnya menjilat-jilat tanah karena kehausan. Orang itu berkata dalam hatinya; 'Alangkah hausnya anjing itu, seperti yang baru ku alami.' Lalu dia turun kembali ke sumur, kemudian dia menciduk air dengan sepatunya, dibawanya ke atas dan diminumkannya kepada anjing itu. Maka Allah berterima kasih kepada orang itu (diterima-Nya amalnya) dan diampuni-Nya dosanya.' Para sahabat bertanya; 'Ya, Rasulullah! Dapat pahalakah kami bila menyayangi hewan-hewan ini? ' Jawab beliau: 'Ya, setiap menyayangi makhluk hidup adalah berpahala.\""},"5246":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ قَالَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي صَلَاةٍ وَقُمْنَا مَعَهُ فَقَالَ أَعْرَابِيٌّ وَهُوَ فِي الصَّلَاةِ اللَّهُمَّ ارْحَمْنِي وَمُحَمَّدًا وَلَا تَرْحَمْ مَعَنَا أَحَدًا فَلَمَّا سَلَّمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِلْأَعْرَابِيِّ لَقَدْ حَجَّرْتَ وَاسِعًا يُرِيدُ رَحْمَةَ اللَّهِ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku [Abu Salamah bin Abdurrahman] bahwa [Abu Hurairah] berkata; \"Rasulullah Shalallah 'Alaihi Wa Sallam berdiri untuk shalat dan kami ikut berdiri dengannya, di tengah-tengah shalat ada seorang Badui yang berbicara; 'Ya Allah, rahmatilah aku dan Muhammad, dan janganlah Engkau merahmati seorangpun selain kami! ' Setelah salam, Rasulullah Shalallah 'Alaihi Wa Sallam bersabda kepada orang Badui tersebut: 'Engkau telah menyempitkan sesuatu yang luas! ' Maksudnya adalah rahmat Allah.\""},"5247":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زَكَرِيَّاءُ عَنْ عَامِرٍ قَالَ سَمِعْتُهُ يَقُولُ سَمِعْتُ النُّعْمَانَ بْنَ بَشِيرٍ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَرَى الْمُؤْمِنِينَ فِي تَرَاحُمِهِمْ وَتَوَادِّهِمْ وَتَعَاطُفِهِمْ كَمَثَلِ الْجَسَدِ إِذَا اشْتَكَى عُضْوًا تَدَاعَى لَهُ سَائِرُ جَسَدِهِ بِالسَّهَرِ وَالْحُمَّى","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Zakariya`] dari ['Amir] dia berkata; saya mendengar [An Nu'man bin Basyir] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kamu akan melihat orang-orang mukmin dalam hal saling mengasihi, mencintai, dan menyayangi bagaikan satu tubuh. Apabila ada salah satu anggota tubuh yang sakit, maka seluruh tubuhnya akan ikut terjaga dan panas (turut merasakan sakitnya).\""},"5248":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ مُسْلِمٍ غَرَسَ غَرْسًا فَأَكَلَ مِنْهُ إِنْسَانٌ أَوْ دَابَّةٌ إِلَّا كَانَ لَهُ بِهِ صَدَقَةٌ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Tidaklah seorang muslim yang bercocok tanam, lalu tanaman tersebut dimakan orang lain atau binatang ternak, melainkan baginya adalah sedekah.\""},"5249":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ قَالَ حَدَّثَنِي زَيْدُ بْنُ وَهْبٍ قَالَ سَمِعْتُ جَرِيرَ بْنَ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ لَا يَرْحَمُ لَا يُرْحَمُ","id":"Telah menceritakan kepada kami ['Amru bin Hafsh] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Al A'masy] dia berkata; telah menceritakan kepadaku [Zaid bin Wahb] dia berkata; saya mendengar [Jarir bin Abdullah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Barangsiapa tidak mengasihi maka dia tidak akan di kasihi.\""},"5250":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ أَبِي أُوَيْسٍ قَالَ حَدَّثَنِي مَالِكٌ عَنْ يَحْيَى بْنِ سَعِيدٍ قَالَ أَخْبَرَنِي أَبُو بَكْرِ بْنُ مُحَمَّدٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا زَالَ يُوصِينِي جِبْرِيلُ بِالْجَارِ حَتَّى ظَنَنْتُ أَنَّهُ سَيُوَرِّثُهُ","id":"Telah menceritakan kepada kami [Isma'il bin Abu Uwais] dia berkata; telah menceritakan kepadaku [Malik] dari [Yahya bin Sa'id] dia berkata; telah mengabarkan kepadaku [Abu Bakr bin Muhammad] dari ['Amrah] dari [Aisyah] radliallahu 'anha dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Jibril senantiasa mewasiatkanku untuk berbuat baik terhadap tetangga sehingga aku mengira tetangga juga akan mendapatkan harta waris.\""},"5251":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مِنْهَالٍ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا عُمَرُ بْنُ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا زَالَ جِبْرِيلُ يُوصِينِي بِالْجَارِ حَتَّى ظَنَنْتُ أَنَّهُ سَيُوَرِّثُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Minhal] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Umar bin Muhammad] dari [Ayahnya] dari [Ibnu Umar] radliallahu 'anhuma dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jibril senantiasa mewasiatkanku untuk berbuat baik terhadap tetangga sehingga aku mengira tetangga juga akan mendapatkan harta waris.\""},"5252":{"ar":"حَدَّثَنَا عَاصِمُ بْنُ عَلِيٍّ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ سَعِيدٍ عَنْ أَبِي شُرَيْحٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَاللَّهِ لَا يُؤْمِنُ وَاللَّهِ لَا يُؤْمِنُ وَاللَّهِ لَا يُؤْمِنُ قِيلَ وَمَنْ يَا رَسُولَ اللَّهِ قَالَ الَّذِي لَا يَأْمَنُ جَارُهُ بَوَايِقَهُتَابَعَهُ شَبَابَةُ وَأَسَدُ بْنُ مُوسَى وَقَالَ حُمَيْدُ بْنُ الْأَسْوَدِ وَعُثْمَانُ بْنُ عُمَرَ وَأَبُو بَكْرِ بْنُ عَيَّاشٍ وَشُعَيْبُ بْنُ إِسْحَاقَ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ","id":"Telah menceritakan kepada kami [Ashim bin Ali] telah menceritakan kepada kami [Ibnu Abu Dzi'ib] dari [Sa'id] dari [Abu Syuraih] bahwasanya Nabi shallallahu 'alaihi wasallam bersabda: \"Demi Allah, tidak beriman, demi Allah tidak beriman, demi Allah tidak beriman.\" Ditanyakan kepada beliau; \"Siapa yang tidak beriman wahai Rasulullah?\" beliau bersabda: \"Yaitu orang yang tetangganya tidak merasa aman dengan gangguannya.\" Riwayat ini dikuatkan pula oleh [Syababah] dan [Asad bin Musa]. Dan berkata [Humaid bin Al Aswad], [Utsman bin Umar], [Abu Bakr bin 'Ayyasy] dan [Syu'aib bin Ishaq] dari [Ibnu Abu Dzi'b] dari [Al Maqburi] dari [Abu Hurairah].\""},"5253":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ حَدَّثَنَا سَعِيدٌ هُوَ الْمَقْبُرِيُّ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَا نِسَاءَ الْمُسْلِمَاتِ لَا تَحْقِرَنَّ جَارَةٌ لِجَارَتِهَا وَلَوْ فِرْسِنَ شَاةٍ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah menceritakan kepada kami [Al Laits] telah menceritakan kepada kami [Sa'id yaitu Al Maqburi] dari [Ayahnya] dari [Abu Hurairah] dia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Wahai para wanita muslimah, janganlah antara tetangga yang satu dengan yang lainnya saling meremehkan walaupun hanya dengan memberi kaki kambing.\""},"5254":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي حَصِينٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلَا يُؤْذِ جَارَهُ وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيُكْرِمْ ضَيْفَهُ وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيَقُلْ خَيْرًا أَوْ لِيَصْمُتْ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Abu Al Ahwash] dari [Abu Hashin] dari [Abu Shalih] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berimana kepada Allah dan hari Akhir, janganlah ia mengganggu tetangganya, barangsiapa beriman kepada Allah dan hari Akhir hendaknya ia memuliakan tamunya dan barangsiapa beriman kepada Allah dan hari Akhir hendaknya ia berkata baik atau diam.\""},"5255":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ قَالَ حَدَّثَنِي سَعِيدٌ الْمَقْبُرِيُّ عَنْ أَبِي شُرَيْحٍ الْعَدَوِيِّ قَالَسَمِعَتْ أُذُنَايَ وَأَبْصَرَتْ عَيْنَايَ حِينَ تَكَلَّمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيُكْرِمْ جَارَهُ وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيُكْرِمْ ضَيْفَهُ جَائِزَتَهُ قَالَ وَمَا جَائِزَتُهُ يَا رَسُولَ اللَّهِ قَالَ يَوْمٌ وَلَيْلَةٌ وَالضِّيَافَةُ ثَلَاثَةُ أَيَّامٍ فَمَا كَانَ وَرَاءَ ذَلِكَ فَهُوَ صَدَقَةٌ عَلَيْهِ وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيَقُلْ خَيْرًا أَوْ لِيَصْمُتْ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah menceritakan kepada kami [Al Laits] dia berkata; telah menceritakan kepadaku [Sa'id Al Maqburi] dari [Abu Syuraih Al 'Adawi] dia berkata; \"Saya telah mendengar dengan kedua telingaku dan melihat dengan kedua mataku ketika Rasulullah shallallahu 'alaihi wasallam mengucapkan sabdanya: \"Barangsiapa beriman kepada Allah dan hari akhir hendaknya ia memuliakan tetangganya, dan barangsiapa beriman kepada Allah dan hari Akhir hendaknya ia memuliakan tamunya, dan menjamunya\" dia bertanya; 'Apa yang dimaksud dengan menjamunya wahai Rasulullah?\" beliau menjawab: \"yaitu pada siang dan malam harinya, bertamu itu tiga hari, lebih dari itu adalah sedekah bagi tamu tersebut.\" Dan beliau bersabda: \"Barang siapa beriman kepada Allah dan hari akhir, hendaknya dia berkata dengan baik atau diam.\""},"5256":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي أَبُو عِمْرَانَ قَالَ سَمِعْتُ طَلْحَةَ عَنْ عَائِشَةَ قَالَتْ قُلْتُيَا رَسُولَ اللَّهِ إِنَّ لِي جَارَيْنِ فَإِلَى أَيِّهِمَا أُهْدِي قَالَ إِلَى أَقْرَبِهِمَا مِنْكِ بَابًا","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Syu'bah] dia berkata; telah mengabarkan kepadaku [Abu 'Imran] dia berkata; saya mendengar [Thalhah] dari [Aisyah] dia berkata; saya bertanya; \"Wahai Rasulullah, saya memiliki dua tetangga, lalu manakah yang lebih aku beri hadiah terlebih dahulu?\" beliau menjawab: \"Yang lebih dekat dengan pintu rumahmu.\""},"5257":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَيَّاشٍ حَدَّثَنَا أَبُو غَسَّانَ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُّ مَعْرُوفٍ صَدَقَةٌ","id":"Telah menceritakan kepada kami [Ali bin 'Ayasy] telah menceritakan kepada kami [Abu Ghassan] dia berkata; telah menceritakan kepadaku [Muhammad bin Al Munkadir] dari [Jabir bin Abdullah] radliallahu 'anhuma dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Setiap perbuatan baik adalah sedekah.\""},"5258":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا سَعِيدُ بْنُ أَبِي بُرْدَةَ بْنِ أَبِي مُوسَى الْأَشْعَرِيِّ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى كُلِّ مُسْلِمٍ صَدَقَةٌ قَالُوا فَإِنْ لَمْ يَجِدْ قَالَ فَيَعْمَلُ بِيَدَيْهِ فَيَنْفَعُ نَفْسَهُ وَيَتَصَدَّقُ قَالُوا فَإِنْ لَمْ يَسْتَطِعْ أَوْ لَمْ يَفْعَلْ قَالَ فَيُعِينُ ذَا الْحَاجَةِ الْمَلْهُوفَ قَالُوا فَإِنْ لَمْ يَفْعَلْ قَالَ فَيَأْمُرُ بِالْخَيْرِ أَوْ قَالَ بِالْمَعْرُوفِ قَالَ فَإِنْ لَمْ يَفْعَلْ قَالَ فَيُمْسِكُ عَنْ الشَّرِّ فَإِنَّهُ لَهُ صَدَقَةٌ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Sa'id bin Abu Burdah bin Abu Musa Al Asy'ari] dari [Ayahnya] dari [Kakeknya] dia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Wajib bagi setiap muslim untuk bersedekah.\" Para sahabat bertanya; \"Bagaimana jika ia tidak mendapatkannya? ' Beliau bersabda:: 'Berusaha dengan tangannya, sehingga ia bisa memberi manfaat untuk dirinya dan bersedekah.' Mereka bertanya; 'Bagaimana jika ia tidak bisa melakukannya? ' Beliau bersabda: 'Menolong orang yang sangat memerlukan bantuan.' Mereka bertanya; 'Bagaimana jika ia tidak bisa melakukannya? ' Beliau bersabda: 'Menyuruh untuk melakukan kebaikan atau bersabda; menyuruh melakukan yang ma'ruf' dia berkata; 'Bagaimana jika ia tidak dapat melakukannya? ' Beliau bersabda: 'Menahan diri dari kejahatan, karena itu adalah sedekah baginya.'"},"5259":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي عَمْرٌو عَنْ خَيْثَمَةَ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَذَكَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّارَ فَتَعَوَّذَ مِنْهَا وَأَشَاحَ بِوَجْهِهِ ثُمَّ ذَكَرَ النَّارَ فَتَعَوَّذَ مِنْهَا وَأَشَاحَ بِوَجْهِهِ قَالَ شُعْبَةُ أَمَّا مَرَّتَيْنِ فَلَا أَشُكُّ ثُمَّ قَالَ اتَّقُوا النَّارَ وَلَوْ بِشِقِّ تَمْرَةٍ فَإِنْ لَمْ تَجِدْ فَبِكَلِمَةٍ طَيِّبَةٍ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dia berkata; telah mengabarkan kepadaku ['Amru] dari [Khaitsamah] dari ['Adi bin Hatim] dia berkata; \"Nabi shallallahu 'alaihi wasallam menyebutkan tentang neraka, lalu beliau meminta berlindungan darinya sambil mengusap wajahnya, kemudian beliau menyebutkan tentang neraka lagi lalu meminta berlindungan darinya sambil mengusap wajahnya.\" -Syu'bah berkata; saya tidak ragu beliau melakukannya hingga dua kali- kemudian beliau bersabda: \"Takutlah kalian kepada neraka walau dengan secuil kurma, jika tidak mendapatkan, hendaknya dengan perkataan yang baik.\""},"5260":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْدَخَلَ رَهْطٌ مِنْ الْيَهُودِ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا السَّامُ عَلَيْكُمْ قَالَتْ عَائِشَةُ فَفَهِمْتُهَا فَقُلْتُ وَعَلَيْكُمْ السَّامُ وَاللَّعْنَةُ قَالَتْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَهْلًا يَا عَائِشَةُ إِنَّ اللَّهَ يُحِبُّ الرِّفْقَ فِي الْأَمْرِ كُلِّهِ فَقُلْتُ يَا رَسُولَ اللَّهِ أَوَلَمْ تَسْمَعْ مَا قَالُوا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ قُلْتُ وَعَلَيْكُمْ","id":"Telah menceritakan kepada kami [Abdul Aziz bin Abdullah] telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Shalih] dari [Ibnu Syihab] dari ['Urwah bin Az Zubair] bahwa [Aisyah] radliallahu 'anha isteri Nabi shallallahu 'alaihi wasallam berkata; \"Sekelompok orang Yahudi datang menemui Rasulullah shallaallahu 'alaihi wa sallam, mereka lalu berkata; \"Assaamu 'alaikum (semoga kecelakaan atasmu). Aisyah berkata; \"Saya memahaminya maka saya menjawab; 'wa'alaikum as saam wal la'nat (semoga kecelakaan dan laknat tertimpa atas kalian).\" Aisyah berkata; \"Lalu Rasulullah shallaallahu 'alaihi wa sallam bersabda: \"Tenanglah wahai Aisyah, sesungguhnya Allah mencintai sikap lemah lembut pada setiap perkara.\" Saya berkata; \"Wahai Rasulullah! Apakah engkau tidak mendengar apa yang telah mereka katakan?\" Rasulullah shallaallahu 'alaihi wa sallam menjawab: \"Saya telah menjawab, 'WA 'ALAIKUM (dan semoga atas kalian juga).\""},"5261":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الْوَهَّابِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ قَالَ حَدَّثَنَا ثَابِتٌ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ أَعْرَابِيًّا بَالَ فِي الْمَسْجِدِ فَقَامُوا إِلَيْهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُزْرِمُوهُ ثُمَّ دَعَا بِدَلْوٍ مِنْ مَاءٍ فَصُبَّ عَلَيْهِ","id":"Telah menceritakan kepada kami [Abdullah bin Abdul Wahhab] telah menceritakan kepada kami [Hammad bin Zaid] dia berkata; telah menceritakan kepada kami [Tsabit] dari [Anas bin Malik] bahwa seorang Arab Badui kencing di masjid, lalu orang-orang mendatanginya, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Biarkanlah.\" Kemudian beliau meminta diambilkan air lalu beliau menyiramnya.\""},"5262":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي بُرْدَةَ بُرَيْدِ بْنِ أَبِي بُرْدَةَ قَالَ أَخْبَرَنِي جَدِّي أَبُو بُرْدَةَ عَنْ أَبِيهِ أَبِي مُوسَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمُؤْمِنُ لِلْمُؤْمِنِ كَالْبُنْيَانِ يَشُدُّ بَعْضُهُ بَعْضًا ثُمَّ شَبَّكَ بَيْنَ أَصَابِعِهِ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسًا إِذْ جَاءَ رَجُلٌ يَسْأَلُ أَوْ طَالِبُ حَاجَةٍ أَقْبَلَ عَلَيْنَا بِوَجْهِهِ فَقَالَ اشْفَعُوا فَلْتُؤْجَرُوا وَلْيَقْضِ اللَّهُ عَلَى لِسَانِ نَبِيِّهِ مَا شَاءَ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Abu Burdah Buraidah bin Abu Burdah] dia berkata; telah mengabarkan kepadaku kakekku [Abu Burdah] dari ayahnya [Abu Musa] dari nabi shallallahu 'alaihi wasallam beliau bersabda: \"Seorang mukmin dengan mukmin yang lain ibarat bangunan yang saling menguatkan antara satu dengan yang lain.\" Kemudian beliau menganyam jari-jemarinya, setelah itu Nabi shallallahu 'alaihi wasallam duduk, jika ada seorang laki-laki memerlukan atau meminta suatu kebutuhan datang kepada beliau, maka beliau akan menghadapkan wajahnya kepada kami, lalu beliau bersabda: 'Berikanlah pertolongan agar kalian saling memperoleh pahala dan semoga Allah melaksanakan apa yang disenangi-Nya melalui ucapan nabi-Nya.'\""},"5263":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ إِذَا أَتَاهُ السَّائِلُ أَوْ صَاحِبُ الْحَاجَةِ قَالَ اشْفَعُوا فَلْتُؤْجَرُوا وَلْيَقْضِ اللَّهُ عَلَى لِسَانِ رَسُولِهِ مَا شَاءَ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`] telah menceritakan kepada kami [Abu Usamah] dari [Buraid] dari [Abu Burdah] dari [Abu Musa] dari Nabi shallallahu 'alaihi wasallam \"ApabiIa ada seseorang meminta atau memerlukan suatu kebutuhan datang kepada beliau, maka beliau bersabda: 'Berikanlah pertolongan agar kalian saling memperoleh pahala dan semoga Allah melaksanakan apa yang disenangi-Nya melalui ucapan Rasul-Nya.'"},"5264":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ سَمِعْتُ أَبَا وَائِلٍ سَمِعْتُ مَسْرُوقًا قَالَ قَالَ عَبْدُ اللَّهِ بْنُ عَمْرٍو ح و حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ شَقِيقِ بْنِ سَلَمَةَ عَنْ مَسْرُوقٍ قَالَ دَخَلْنَا عَلَى عَبْدِ اللَّهِ بْنِ عَمْرٍوحِينَ قَدِمَ مَعَ مُعَاوِيَةَ إِلَى الْكُوفَةِ فَذَكَرَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَمْ يَكُنْ فَاحِشًا وَلَا مُتَفَحِّشًا وَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ أَخْيَرِكُمْ أَحْسَنَكُمْ خُلُقًا","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Syu'bah] dari [Sulaiman] saya mendengar [Abu Wa`il] saya mendengar [Masruq] dia berkata; [Abdullah bin 'Amru] berkata. Dan diriwayatkan dari jalur lain, telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Syaqiq bin Salamah] dari [Masruq] dia berkata; \"Kami pernah menemui [Abdullah bin 'Amru] ketika kami tiba di Kufah bersama Mu'awiyah, kemudian dia ingat Rasulullah shallallahu 'alaihi wasallam seraya berkata; \"Beliau tidak pernah berbuat kejelekan dan tidak menyuruh untuk berbuat kejelekan.\" Lalu (Abdullah bin Amru) berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya orang yang terbaik di antara kalian ialah yang paling bagus akhlaknya.\""},"5265":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَامٍ أَخْبَرَنَا عَبْدُ الْوَهَّابِ عَنْ أَيُّوبَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي مُلَيْكَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ يَهُودَ أَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا السَّامُ عَلَيْكُمْ فَقَالَتْ عَائِشَةُ عَلَيْكُمْ وَلَعَنَكُمْ اللَّهُ وَغَضِبَ اللَّهُ عَلَيْكُمْ قَالَ مَهْلًا يَا عَائِشَةُ عَلَيْكِ بِالرِّفْقِ وَإِيَّاكِ وَالْعُنْفَ وَالْفُحْشَ قَالَتْ أَوَلَمْ تَسْمَعْ مَا قَالُوا قَالَ أَوَلَمْ تَسْمَعِي مَا قُلْتُ رَدَدْتُ عَلَيْهِمْ فَيُسْتَجَابُ لِي فِيهِمْ وَلَا يُسْتَجَابُ لَهُمْ فِيَّ","id":"Telah menceritakan kepada kami [Muhammad bin Salam] telah mengabarkan kepada kami [Abdul Wahhab] dari [Ayyub] dari [Abdullah bin Abu Mulaikah] dari [Aisyah] radliallahu 'anha bahwa sekelompok orang Yahudi datang kepada Nabi shallallahu 'alaihi wasallam sambil berkata; \"Kebinasaan atasmu.\" Maka Aisyah berkata; \"Semoga atas kalian juga, dan semoga laknat dan murka Allah juga menimpa kalian.\" Beliau bersabda: \"Tenanglah wahai Aisyah, berlemah lembutlah dan janganlah kamu bersikeras dan janganlah kamu berkata keji.\" Aisyah berkata; \"Apakah anda tidak mendengar apa yang mereka katakan?\" beliau bersabda: \"Tidakkah kamu mendengar apa yang saya ucapkan, saya telah membalasnya, adapun jawabanku akan dikabulkan sementara do'a mereka tidak akan diijabahi.\""},"5266":{"ar":"حَدَّثَنَا أَصْبَغُ قَالَ أَخْبَرَنِي ابْنُ وَهْبٍ أَخْبَرَنَا أَبُو يَحْيَى هُوَ فُلَيْحُ بْنُ سُلَيْمَانَ عَنْ هِلَالِ بْنِ أُسَامَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَلَمْ يَكُنْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبَّابًا وَلَا فَحَّاشًا وَلَا لَعَّانًا كَانَ يَقُولُ لِأَحَدِنَا عِنْدَ الْمَعْتِبَةِ مَا لَهُ تَرِبَ جَبِينُهُ","id":"Telah menceritakan kepada kami [Asbagh] dia berkata; telah mengabarkan kepadaku [Ibnu Wahb] telah mengabarkan kepada kami [Abu Yahya yaitu Fulaih bin Sulaiman] dari [Hilal bin Usamah] dari [Anas bin Malik] radliallahu 'anhu dia berkata; \"Nabi shallallahu 'alaihi wasallam adalah sosok yang tidak pernah mencela, berkata keji dan melaknat, apabila beliau mencela salah satu dari kami, maka beliau akan berkata: \"Mengapa dahinya berdebu (dengan sindiran).\""},"5267":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عِيسَى حَدَّثَنَا مُحَمَّدُ بْنُ سَوَاءٍ حَدَّثَنَا رَوْحُ بْنُ الْقَاسِمِ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ رَجُلًا اسْتَأْذَنَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا رَآهُ قَالَ بِئْسَ أَخُو الْعَشِيرَةِ وَبِئْسَ ابْنُ الْعَشِيرَةِ فَلَمَّا جَلَسَ تَطَلَّقَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي وَجْهِهِ وَانْبَسَطَ إِلَيْهِ فَلَمَّا انْطَلَقَ الرَّجُلُ قَالَتْ لَهُ عَائِشَةُ يَا رَسُولَ اللَّهِ حِينَ رَأَيْتَ الرَّجُلَ قُلْتَ لَهُ كَذَا وَكَذَا ثُمَّ تَطَلَّقْتَ فِي وَجْهِهِ وَانْبَسَطْتَ إِلَيْهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَائِشَةُ مَتَى عَهِدْتِنِي فَحَّاشًا إِنَّ شَرَّ النَّاسِ عِنْدَ اللَّهِ مَنْزِلَةً يَوْمَ الْقِيَامَةِ مَنْ تَرَكَهُ النَّاسُ اتِّقَاءَ شَرِّهِ","id":"Telah menceritakan kepada kami ['Amru bin Isa] telah menceritakan kepada kami [Muhammad bin Sawa`] telah menceritakan kepada kami [Rauh bin Al Qasim] dari [Muhammad bin Al Munkadir] dari ['Urwah] dari [Aisyah] Bahwa seorang laki-laki meminta izin kepada nabi Shallalahu 'alaihi wa sallam, ketika beliau melihat orang tersebut, beliau bersabda: \"Amat buruklah saudara Kabilah ini atau seburuk-buruk saudara Kabilah ini.\" Saat orang itu duduk, beliau menampakkan wajahnya yang berseri-seri, setelah orang itu keluar 'A`isyah berkata; \"Wahai Rasulullah, ketika anda melihat (kedatangan) orang tersebut, anda berkata seperti ini dan ini, namun setelah itu wajah anda nampak berseri-seri, Maka Rasulullah Shallalahu 'alaihi wa sallam bersabda: \"Wahai 'A`isyah, kapankah kamu melihatku mengatakan perkataan keji? Sesungguhnya seburuk-buruk kedudukan manusia di sisi Allah pada hari kiamat adalah orang yang ditinggalkan oleh manusia karena takut akan kekejiannya.\""},"5268":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ حَدَّثَنَا حَمَّادٌ هُوَ ابْنُ زَيْدٍ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحْسَنَ النَّاسِ وَأَجْوَدَ النَّاسِ وَأَشْجَعَ النَّاسِ وَلَقَدْ فَزِعَ أَهْلُ الْمَدِينَةِ ذَاتَ لَيْلَةٍ فَانْطَلَقَ النَّاسُ قِبَلَ الصَّوْتِ فَاسْتَقْبَلَهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ سَبَقَ النَّاسَ إِلَى الصَّوْتِ وَهُوَ يَقُولُ لَنْ تُرَاعُوا لَنْ تُرَاعُوا وَهُوَ عَلَى فَرَسٍ لِأَبِي طَلْحَةَ عُرْيٍ مَا عَلَيْهِ سَرْجٌ فِي عُنُقِهِ سَيْفٌ فَقَالَ لَقَدْ وَجَدْتُهُ بَحْرًا أَوْ إِنَّهُ لَبَحْرٌ","id":"Telah menceritakan kepada kami ['Amru bin 'Aun] telah menceritakan kepada kami [Hammad yaitu Ibnu Zaid] dari [Tsabit] dari [Anas] dia berkata; Nabi shallallahu 'alaihi wasallam adalah sosok yang paling baik (perawakannya), orang yang paling dermawan dan pemberani, Pada suatu malam penduduk Madinah dikejutkan oleh suatu suara, lalu orang-orang keluar ke arah datangnya suara itu. Di tengah jalan mereka bertemu dengan Rasulullah shallallahu 'alaihi wasallam yang hendak pulang. Rupanya beliau telah mendahului mereka ke tempat datangnya suara itu. Beliau mengendarai kuda yang dipinjamnya dari Abu Thalhah, beliau tidak membawa lampu sambil menyandang pedang beliau bersabda: \"Jangan takut! Jangan takut!\" kata Anas; \"Kami dapati beliau tengah menunggang kuda yang berjalan cepat atau sesungguhnya kudanya berlari kencang.\""},"5269":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ ابْنِ الْمُنْكَدِرِ قَالَ سَمِعْتُ جَابِرًا رَضِيَ اللَّهُ عَنْهُ يَقُولُمَا سُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ شَيْءٍ قَطُّ فَقَالَ لَا","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dari [Ibnu Al Munkadir] dia berkata; saya mendengar [Jabir] radliallahu 'anhu berkata; Nabi shallallahu 'alaihi wasallam tidak pernah dimintai sesuatu lalu beliau berkata; \"Tidak.\""},"5270":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ قَالَ حَدَّثَنِي شَقِيقٌ عَنْ مَسْرُوقٍ قَالَ كُنَّا جُلُوسًا مَعَ عَبْدِ اللَّهِ بْنِ عَمْرٍو يُحَدِّثُنَاإِذْ قَالَ لَمْ يَكُنْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاحِشًا وَلَا مُتَفَحِّشًا وَإِنَّهُ كَانَ يَقُولُ إِنَّ خِيَارَكُمْ أَحَاسِنُكُمْ أَخْلَاقًا","id":"Telah menceritakan kepada kami ['Umar bin Hafsh] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Al A'masy] dia berkata; telah menceritakan kepadaku [Syaqiq] dari [Masruq] dia berkata; \"Kami pernah duduk-duduk sambil berbincang-bincang bersama [Abdullah bin 'Amru], tiba-tiba dia berkata; \"Rasulullah shallallahu 'alaihi wasallam tidak pernah berbuat keji dan tidak pula menyuruh berbuat keji, bahwa beliau bersabda: \"Sesungguhnya sebaik-baik kalian adalah yang paling mulia akhlaknya.\""},"5271":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ حَدَّثَنَا أَبُو غَسَّانَ قَالَ حَدَّثَنِي أَبُو حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَجَاءَتْ امْرَأَةٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِبُرْدَةٍ فَقَالَ سَهْلٌ لِلْقَوْمِ أَتَدْرُونَ مَا الْبُرْدَةُ فَقَالَ الْقَوْمُ هِيَ الشَّمْلَةُ فَقَالَ سَهْلٌ هِيَ شَمْلَةٌ مَنْسُوجَةٌ فِيهَا حَاشِيَتُهَا فَقَالَتْ يَا رَسُولَ اللَّهِ أَكْسُوكَ هَذِهِ فَأَخَذَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُحْتَاجًا إِلَيْهَا فَلَبِسَهَا فَرَآهَا عَلَيْهِ رَجُلٌ مِنْ الصَّحَابَةِ فَقَالَ يَا رَسُولَ اللَّهِ مَا أَحْسَنَ هَذِهِ فَاكْسُنِيهَا فَقَالَ نَعَمْ فَلَمَّا قَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَامَهُ أَصْحَابُهُ قَالُوا مَا أَحْسَنْتَ حِينَ رَأَيْتَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَذَهَا مُحْتَاجًا إِلَيْهَا ثُمَّ سَأَلْتَهُ إِيَّاهَا وَقَدْ عَرَفْتَ أَنَّهُ لَا يُسْأَلُ شَيْئًا فَيَمْنَعَهُ فَقَالَ رَجَوْتُ بَرَكَتَهَا حِينَ لَبِسَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَلِّي أُكَفَّنُ فِيهَا","id":"Telah menceritakan kepada kami [Sa'id bin Abu Maryam] telah menceritakan kepada kami [Abu Ghassan] dia berkata; telah menceritakan kepadaku [Abu Hazim] dari [Sahl bin Sa'd] dia berkata; \"Seorang wanita datang kepada Nabi shallallahu 'alaihi wasallam dengan membawa selimut bersulam. Sahal bertanya: Apa kalian tahu selimut apakah itu? Mereka menjawab; \"Ya, ia adalah mantel.\" Sahal berkata; Ia adalah mantel bersulam yang ada rendanya. Lalu wanita itu berkata; \"Wahai Rasulullah! aku membawanya untuk mengenakannya pada anda.\" Lalu Nabi shallallahu 'alaihi wasallam mengambilnya karena beliau sangat memerlukannya. Kemudian beliau mengenakan mantel tersebut ternyata salah seorang dari sahabat melihat beliau mengenakan mantel itu lalu berkata; \"Alangkah bagusnya selimut ini, kenakanlah untukku wahai Rasulullah!\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya.\" Ketika Nabi shallallahu 'alaihi wasallam beranjak pergi, orang-orang pun mencela sahabat tersebut sambil berkata; \"Demi Allah, kau berlaku kurang ajar. Kamu tahu, Rasulullah shallallahu 'alaihi wasallam diberi selimut itu saat beliau memerlukannya, malahan kau memintanya, padahal kau tahu beliau tidak pernah menolak seorang peminta pun.\" Sahabat itu berkata; \"Aku hanya mengharap keberkahannya ketika Nabi shallallahu 'alaihi wasallam mengenakannya semoga kain itu menjadi kafanku pada saat aku meninggal.\""},"5272":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَقَارَبُ الزَّمَانُ وَيَنْقُصُ الْعَمَلُ وَيُلْقَى الشُّحُّ وَيَكْثُرُ الْهَرْجُ قَالُوا وَمَا الْهَرْجُ قَالَ الْقَتْلُ الْقَتْلُ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku [Humaid bin Abdurrahman] bahwa [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Zaman semakin dekat, amalan kian berkurang, kekikiran semakin banyak dan al Harj semakin merajalela.\" Mereka bertanya; \"Apakah al Harj itu? Beliau menjawab: \"Pembunuhan, pembunuhan.\""},"5273":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ سَمِعَ سَلَّامَ بْنَ مِسْكِينٍ قَالَ سَمِعْتُ ثَابِتًا يَقُولُ حَدَّثَنَا أَنَسٌ رَضِيَ اللَّهُ عَنْهُ قَالَخَدَمْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَشْرَ سِنِينَ فَمَا قَالَ لِي أُفٍّ وَلَا لِمَ صَنَعْتَ وَلَا أَلَّا صَنَعْتَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] dia mendengar [Sallam bin Miskin] dia berkata; saya mendengar [Tsabit] berkata; telah menceritakan kepada kami [Anas] radliallahu 'anhu dia berkata; \"Aku menjadi pelayan Nabi shallallahu 'alaihi wasallam selama sepuluh tahun, dan beliau sama sekali tidak pernah mengatakan \"ah\", apa yang kamu perbuat? Dan kenapa kamu tidak melakukannya? (maksudnya menghardik).\""},"5274":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ قَالَ سَأَلْتُ عَائِشَةَمَا كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْنَعُ فِي أَهْلِهِ قَالَتْ كَانَ فِي مِهْنَةِ أَهْلِهِ فَإِذَا حَضَرَتْ الصَّلَاةُ قَامَ إِلَى الصَّلَاةِ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Ibrahim] dari [Al Aswad] dia berkata; saya bertanya kepada [Aisyah] \"Apakah Nabi shallallahu 'alaihi wasallam pernah ikut membantu pekerjaan rumah isterinya?\" Aisyah menjawab; \"Beliau suka membantu pekerjaan rumah isterinya, apabila tiba waktu shalat, maka beliau beranjak untuk melaksanakan shalat.\""},"5275":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي مُوسَى بْنُ عُقْبَةَ عَنْ نَافِعٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَحَبَّ اللَّهُ عَبْدًا نَادَى جِبْرِيلَ إِنَّ اللَّهَ يُحِبُّ فُلَانًا فَأَحِبَّهُ فَيُحِبُّهُ جِبْرِيلُ فَيُنَادِي جِبْرِيلُ فِي أَهْلِ السَّمَاءِ إِنَّ اللَّهَ يُحِبُّ فُلَانًا فَأَحِبُّوهُ فَيُحِبُّهُ أَهْلُ السَّمَاءِ ثُمَّ يُوضَعُ لَهُ الْقَبُولُ فِي أَهْلِ الْأَرْضِ","id":"Telah menceritakan kepada kami ['Amru bin Ali] telah menceritakan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dia berkata; telah mengabarkan kepadaku [Musa bin 'Uqbah] dari [Nafi'] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Apabila Allah mencintai seorang hamba, maka Dia akan menyeru Jibril; \"Sesunggunya Allah mencintai fulan, maka cintailah ia.\" Maka Jibril pun mencintai orang tersebut, lalu Jibril menyeru kepada penghuni langit; \"Sesungguhnya Allah mencintai fulan, maka cintailah fulan\" maka penduduk langit pun mencintai orang tersebut, hingga akhirnya ditetapkan bagi fulan untuk diterima di bumi.\""},"5276":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَجِدُ أَحَدٌ حَلَاوَةَ الْإِيمَانِ حَتَّى يُحِبَّ الْمَرْءَ لَا يُحِبُّهُ إِلَّا لِلَّهِ وَحَتَّى أَنْ يُقْذَفَ فِي النَّارِ أَحَبُّ إِلَيْهِ مِنْ أَنْ يَرْجِعَ إِلَى الْكُفْرِ بَعْدَ إِذْ أَنْقَذَهُ اللَّهُ وَحَتَّى يَكُونَ اللَّهُ وَرَسُولُهُ أَحَبَّ إِلَيْهِ مِمَّا سِوَاهُمَا","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas bin Malik] radliallahu 'anhu dia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak akan mendapatkan manisnya iman sehingga ia mencintai seseorang dan ia tidak mencintainya kecuali karena Allah, dan sehingga ia lebih suka dimasukkan ke dalam api dari pada kembali kepada kekufuran setelah Allah menyelamatkannya, dan sehingga Allah dan Rasul-Nya lebih ia cintai dari pada yang lain.\""},"5277":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ زَمْعَةَ قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَضْحَكَ الرَّجُلُ مِمَّا يَخْرُجُ مِنْ الْأَنْفُسِ وَقَالَ بِمَ يَضْرِبُ أَحَدُكُمْ امْرَأَتَهُ ضَرْبَ الْفَحْلِ أَوْ الْعَبْدِ ثُمَّ لَعَلَّهُ يُعَانِقُهَاوَقَالَ الثَّوْرِيُّ وَوُهَيْبٌ وَأَبُو مُعَاوِيَةَ عَنْ هِشَامٍ جَلْدَ الْعَبْدِ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] dari [Hisyam] dari [ayahnya] dari [Abdullah bin Zam'ah] dia berkata; Nabi shallallahu 'alaihi wasallam melarang seseorang menertawakan sesuatu yang keluar dari orang lain (maknanya mengejek orang lain).\" Beliau juga bersabda: \"Kenapa salah seorang dari kalian memukul isterinya sebagaimana memukul kudanya atau budaknya, semoga saja ia dapat memeluk isterinya.\" [Ats Tsauri], [Wuhaib] dan [Abu Mu'awiyah] mengatakan dari [Hisyam] yaitu; \"Sebagaimana mencambuk budak.\""},"5278":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا عَاصِمُ بْنُ مُحَمَّدِ بْنِ زَيْدٍ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِنًى أَتَدْرُونَ أَيُّ يَوْمٍ هَذَا قَالُوا اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ فَإِنَّ هَذَا يَوْمٌ حَرَامٌ أَفَتَدْرُونَ أَيُّ بَلَدٍ هَذَا قَالُوا اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ بَلَدٌ حَرَامٌ أَتَدْرُونَ أَيُّ شَهْرٍ هَذَا قَالُوا اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ شَهْرٌ حَرَامٌ قَالَ فَإِنَّ اللَّهَ حَرَّمَ عَلَيْكُمْ دِمَاءَكُمْ وَأَمْوَالَكُمْ وَأَعْرَاضَكُمْ كَحُرْمَةِ يَوْمِكُمْ هَذَا فِي شَهْرِكُمْ هَذَا فِي بَلَدِكُمْ هَذَا","id":"Telah menceritakan kepadaku [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami ['Ashim bin Muhammad bin Zaid] dari [Ayahnya] dari [Ibnu Umar] radliallahu 'anhuma dia berkata; Nabi shallallahu 'alaihi wasallam bersabda ketika di Mina: \"Apakah kalian tahu hari apakah ini?\" orang-orang menjawab; \"Allah dan Rasul-Nya yang lebih tahu.\" Beliau bersabda: \"Sesungguhnya hari ini adalah hari haram (yang dimuliakan), apakah kalian tahu negeri apakah ini?\" orang-orang menjawab; \"Allah dan Rasul-Nya yang lebih tahu.\" Beliau menjawab: \"Ini adalah negeri haram, apakah kalian tahu bulan apakah sekarang?\"orang-orang menjawab; \"Allah dan Rasul-Nya yang lebih tahu.\" Beliau bersabda: \"Ini adalah bulan haram.\" Beliau melanjutkan: \"Sesungguhnya Allah telah mengharamkan atas kalian darah kalian, harta benda kalian dan kehormatan kalian sebagaimana kehormatan pada hari kalian ini, bulan ini dan di negeri kalian ini.\""},"5279":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ قَالَ سَمِعْتُ أَبَا وَائِلٍ يُحَدِّثُ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سِبَابُ الْمُسْلِمِ فُسُوقٌ وَقِتَالُهُ كُفْرٌتَابَعَهُ غُنْدَرٌ عَنْ شُعْبَةَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Syu'bah] dari [Manshur] dia berkata; saya mendengar [Abu Wa`il] bercerita dari [Abdullah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mencela orang muslim adalah kefasikan dan membunuhnya adalah kekufuran.\" Hal ini diperkuat juga oleh riwayat [Ghundar] dari [Syu'bah].\""},"5280":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ الْحُسَيْنِ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ حَدَّثَنِي يَحْيَى بْنُ يَعْمَرَ أَنَّ أَبَا الْأَسْوَدِ الدِّيلِيَّ حَدَّثَهُ عَنْ أَبِي ذَرٍّ رَضِيَ اللَّهُ عَنْهُ أَنَّهُسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَرْمِي رَجُلٌ رَجُلًا بِالْفُسُوقِ وَلَا يَرْمِيهِ بِالْكُفْرِ إِلَّا ارْتَدَّتْ عَلَيْهِ إِنْ لَمْ يَكُنْ صَاحِبُهُ كَذَلِكَ","id":"Telah menceritakan kepada kami [Abu Ma'mar] telah menceritakan kepada kami [Abdul Warits] dari [Al Husain] dari [Abdullah bin Buraidah] telah menceritakan kepadaku [Yahya bin Ya'mar] bahwa [Abu Aswad Ad Diili] menceritakan kepadanya dari [Abu Dzar] radliallahu 'anhu bahwa dia mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Tidaklah seseorang melempar tuduhan kepada orang lain dengan kefasikan, dan tidak pula menuduh dengan kekufuran melainkan (tuduhan itu) akan kembali kepadanya, jika saudaranya tidak seperti itu.\""},"5281":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سِنَانٍ حَدَّثَنَا فُلَيْحُ بْنُ سُلَيْمَانَ حَدَّثَنَا هِلَالُ بْنُ عَلِيٍّ عَنْ أَنَسٍ قَالَلَمْ يَكُنْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاحِشًا وَلَا لَعَّانًا وَلَا سَبَّابًا كَانَ يَقُولُ عِنْدَ الْمَعْتَبَةِ مَا لَهُ تَرِبَ جَبِينُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Sinan] telah menceritakan kepada kami [Fulaih bin Sulaiman] telah menceritakan kepada kami [Hilal bin Ali] dari [Anas] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam tidak pernah berkata keji, melaknat dan mencela, apabila beliau hendak mencela, maka beliau akan berkata: \"Mengapa dahinya berdebu (dengan bahasa sindiran).\""},"5282":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا عَلِيُّ بْنُ الْمُبَارَكِ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي قِلَابَةَ أَنَّ ثَابِتَ بْنَ الضَّحَّاكِوَكَانَ مِنْ أَصْحَابِ الشَّجَرَةِ حَدَّثَهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَلَفَ عَلَى مِلَّةٍ غَيْرِ الْإِسْلَامِ فَهُوَ كَمَا قَالَ وَلَيْسَ عَلَى ابْنِ آدَمَ نَذْرٌ فِيمَا لَا يَمْلِكُ وَمَنْ قَتَلَ نَفْسَهُ بِشَيْءٍ فِي الدُّنْيَا عُذِّبَ بِهِ يَوْمَ الْقِيَامَةِ وَمَنْ لَعَنَ مُؤْمِنًا فَهُوَ كَقَتْلِهِ وَمَنْ قَذَفَ مُؤْمِنًا بِكُفْرٍ فَهُوَ كَقَتْلِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Utsman bin Umar] telah menceritakan kepada kami [Ali bin Mubarrak] dari [Yahya bin Abu Katsir] dari [Abu Qilabah] bahwa [Tsabit bin Adl Dlahak] -dan dia termasuk dari Ashabus Syajarah (ikut serta dalam baiatur ridlwan) - dia menceritakan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersumpah dengan agama selain Islam, maka dia bagaikan apa yang dia katakan, anak Adam tidak boleh bernadzar dengan sesuatu yang tidak dia miliki, barangsiapa bunuh diri dengan sesuatu di dunia, maka dia akan disiksa di akhirat dengan sesuatu yang digunakan untuk bunuh diri, barangsiapa melaknat orang mukmin maka ia seperti membunuhnya, barangsiapa menuduh seorang muslim dengan kekafiran maka ia seperti membunuhnya.\""},"5283":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ قَالَ حَدَّثَنِي عَدِيُّ بْنُ ثَابِتٍ قَالَ سَمِعْتُ سُلَيْمَانَ بْنَ صُرَدٍرَجُلًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اسْتَبَّ رَجُلَانِ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَغَضِبَ أَحَدُهُمَا فَاشْتَدَّ غَضَبُهُ حَتَّى انْتَفَخَ وَجْهُهُ وَتَغَيَّرَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَأَعْلَمُ كَلِمَةً لَوْ قَالَهَا لَذَهَبَ عَنْهُ الَّذِي يَجِدُ فَانْطَلَقَ إِلَيْهِ الرَّجُلُ فَأَخْبَرَهُ بِقَوْلِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ تَعَوَّذْ بِاللَّهِ مِنْ الشَّيْطَانِ فَقَالَ أَتُرَى بِي بَأْسٌ أَمَجْنُونٌ أَنَا اذْهَبْ","id":"Telah menceritakan kepada kami [Umar bin Hafsh] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Al A'masy] dia berkata; telah menceritakan kepadaku ['Adi bin Tsabit] dia berkata; saya mendengar [Sulaiman bin Shurd] -seorang dari sahabat nabi shallallahu 'alaihi wasallam- dia berkata; \"Dua orang laki-laki saling mencaci maki di sisi Nabi shallallahu 'alaihi wasallam. Ternyata salah seorang di antara keduanya sangat marah hingga mukanya berubah menjadi merah. Lalu Rasulullah bersabda: 'Sungguh aku mengetahui satu kalimat yang seandainya diucapkan, maka marahnya akan hilang.\" Lalu orang yang mendengar ucapan beliau beranjak pergi dan mengabarkan kepadanya sabda Nabi shallallahu 'alaihi wasallam, katanya; \"Berlindunglah kepada Allah dari Syetan.\" laki-laki yang marah tersebut berkata; 'Apakah kamu menganggap saya ada masalah, sudah gilakah saya, pergilah?\""},"5284":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ عَنْ حُمَيْدٍ قَالَ قَالَ أَنَسٌ حَدَّثَنِي عُبَادَةُ بْنُ الصَّامِتِ قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُخْبِرَ النَّاسَ بِلَيْلَةِ الْقَدْرِ فَتَلَاحَى رَجُلَانِ مِنْ الْمُسْلِمِينَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجْتُ لِأُخْبِرَكُمْ فَتَلَاحَى فُلَانٌ وَفُلَانٌ وَإِنَّهَا رُفِعَتْ وَعَسَى أَنْ يَكُونَ خَيْرًا لَكُمْ فَالْتَمِسُوهَا فِي التَّاسِعَةِ وَالسَّابِعَةِ وَالْخَامِسَةِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Bisyr bin Al Mufadlal] dari [Humaid] dia berkata; [Anas] berkata; telah menceritakan kepadaku ['Ubadah bin Ash Shamit] dia berkata; Rasulullah shallallahu 'alaihi wasallam keluar untuk mengabarkan lailatul qadar kepada orang-orang, kemudian terdapat dua orang dari kalangan muslimin yang saling berselisih. Lantas Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya aku keluar hendak mengabarkan lailatul qadar kepada kalian, namun aku mendapati perselisihan antara Fulan dan Fulan sehingga laitatul qadar diangkat kembali, bisa jadi hal itu adalah lebih baik buat kalian, maka carilah lailatul qadar pada hari kesembilan, ketujuh, dan kelima (sebelum Akhir).\""},"5285":{"ar":"حَدَّثَنِي عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ عَنْ الْمَعْرُورِ هُوَ ابْنُ سُوَيْدٍ عَنْ أَبِي ذَرٍّ قَالَرَأَيْتُ عَلَيْهِ بُرْدًا وَعَلَى غُلَامِهِ بُرْدًا فَقُلْتُ لَوْ أَخَذْتَ هَذَا فَلَبِسْتَهُ كَانَتْ حُلَّةً وَأَعْطَيْتَهُ ثَوْبًا آخَرَ فَقَالَ كَانَ بَيْنِي وَبَيْنَ رَجُلٍ كَلَامٌ وَكَانَتْ أُمُّهُ أَعْجَمِيَّةً فَنِلْتُ مِنْهَا فَذَكَرَنِي إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِي أَسَابَبْتَ فُلَانًا قُلْتُ نَعَمْ قَالَ أَفَنِلْتَ مِنْ أُمِّهِ قُلْتُ نَعَمْ قَالَ إِنَّكَ امْرُؤٌ فِيكَ جَاهِلِيَّةٌ قُلْتُ عَلَى حِينِ سَاعَتِي هَذِهِ مِنْ كِبَرِ السِّنِّ قَالَ نَعَمْ هُمْ إِخْوَانُكُمْ جَعَلَهُمْ اللَّهُ تَحْتَ أَيْدِيكُمْ فَمَنْ جَعَلَ اللَّهُ أَخَاهُ تَحْتَ يَدِهِ فَلْيُطْعِمْهُ مِمَّا يَأْكُلُ وَلْيُلْبِسْهُ مِمَّا يَلْبَسُ وَلَا يُكَلِّفُهُ مِنْ الْعَمَلِ مَا يَغْلِبُهُ فَإِنْ كَلَّفَهُ مَا يَغْلِبُهُ فَلْيُعِنْهُ عَلَيْهِ","id":"Telah menceritakan kepadaku ['Umar bin Hafsh] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Al A'masy] dari [Ma'rur yaitu Ibnu Suwaid] dari [Abu Dzar], (Ma'rur) berkata; \"Saya pernah melihat Abu Dzar memakai pakaian serupa dengan sahayanya. Maka saya berkata kepadanya; \"Sekiranya kamu mengambil kain tersebut untuk kamu kenakan kemudian kamu memberi kain lagi untuk sahayamu (itu akan lebih baik), Lalu Abu Dzar berkata; \"Bahwa dahulu aku dengan seorang laki-laki terjadi percekcokan, sementara ibu laki-laki itu adalah orang 'ajm (non Arab) lalu aku pun menghinakannya. Kemudian laki-laki itu mengadu kepada Nabi shallallahu 'alaihi wasallam, maka beliau bersabda kepadaku: \"Apakah kamu habis menjelekkan fulan?\" jawabku; \"Benar.\" Beliau bertanya lagi; \"Apakah kamu juga menghinakan ibunya?\" jawabku; \"Benar.\" Beliau bersabda: \"Sungguh dalam dirimu masih terdapat sifat jahiliyah, \" aku pun berkata; \"Apakah saya masih memiliki sifat jahiliyahan padahal aku sudah tua?\" beliau menjawab: \"Ya, benar, mereka adalah saudaramu dan paman-pamanmu yang dititipkan Allah dibawah pengurusanmu, barangsiapa memiliki saudara yang masih dalam pengurusanya, hendaklah dia diberi makan sebagaimana yang dia makan, diberi pakaian sebagaimana ia mengenakan pakaian. Dan janganlah kamu bebaninya diluar batas kemampuannya, dan jika kamu membebaninya, maka bantulah dia dalam menyelesaikan tugasnya.\""},"5286":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا يَزِيدُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا مُحَمَّدٌ عَنْ أَبِي هُرَيْرَةَصَلَّى بِنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ رَكْعَتَيْنِ ثُمَّ سَلَّمَ ثُمَّ قَامَ إِلَى خَشَبَةٍ فِي مُقَدَّمِ الْمَسْجِدِ وَوَضَعَ يَدَهُ عَلَيْهَا وَفِي الْقَوْمِ يَوْمَئِذٍ أَبُو بَكْرٍ وَعُمَرُ فَهَابَا أَنْ يُكَلِّمَاهُ وَخَرَجَ سَرَعَانُ النَّاسِ فَقَالُوا قَصُرَتْ الصَّلَاةُ وَفِي الْقَوْمِ رَجُلٌ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْعُوهُ ذَا الْيَدَيْنِ فَقَالَ يَا نَبِيَّ اللَّهِ أَنَسِيتَ أَمْ قَصُرَتْ فَقَالَ لَمْ أَنْسَ وَلَمْ تَقْصُرْ قَالُوا بَلْ نَسِيتَ يَا رَسُولَ اللَّهِ قَالَ صَدَقَ ذُو الْيَدَيْنِ فَقَامَ فَصَلَّى رَكْعَتَيْنِ ثُمَّ سَلَّمَ ثُمَّ كَبَّرَ فَسَجَدَ مِثْلَ سُجُودِهِ أَوْ أَطْوَلَ ثُمَّ رَفَعَ رَأْسَهُ وَكَبَّرَ ثُمَّ وَضَعَ مِثْلَ سُجُودِهِ أَوْ أَطْوَلَ ثُمَّ رَفَعَ رَأْسَهُ وَكَبَّرَ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Yazid bin Ibrahim] telah menceritakan kepada kami [Muhammad] dari [Abu Hurairah] \"Nabi shallallahu 'alaihi wasallam mengimami kami pada waktu shalat zhuhur hanya dua raka'at kemudian salam, lalu beliau mendekat ke sebatang kayu yang tersandar di masjid sambil meletakkan tangan beliau di atas batang kayu tersebut. Pada waktu itu di antara mereka terdapat Abu Bakar dan Umar, keduanya merasa segan untuk menegur Rasulullah shallallahu 'alaihi wasallam, dan orang-orang segera keluar masjid sambil berkata; \"Apakah shalat di Qashar (ringkas)?\" Di antara mereka juga terdapat seorang laki-laki yang biasa dipanggil oleh Nabi shallallahu 'alaihi wasallam dengan sebutan Dzul yadain, ia berkata; \"Wahai Nabiyullah, apakah engkau telah lupa atau memang shalatnya diqashar (diringkas)?\" Beliau menjawab: \"Aku tidak lupa dan shalatnya tidak pula diringkas.\" Para sahabat berkata; 'Bahkan anda telah lupa wahai Rasulullah.\" Beliau bersabda: \"kalau begitu benar apa kata Dzulyadain.\" Lalu beliau mengerjakan shalat dua raka'at kemudian salam, kemudian beliau bertakbir dan sujud sebagaimana sujudnya (waktu shalat), atau bahkan lebih lama lagi, kemudian mengangkat kepalanya dan bertakbir, kemudian beliau meletakkan (kepalanya) sebagaimana beliau sujud bahkan lebih lama lagi kemudian beliau mengangkat kepalanya dan bertakbir.\""},"5287":{"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ قَالَ سَمِعْتُ مُجَاهِدًا يُحَدِّثُ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَمَرَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى قَبْرَيْنِ فَقَالَ إِنَّهُمَا لَيُعَذَّبَانِ وَمَا يُعَذَّبَانِ فِي كَبِيرٍ أَمَّا هَذَا فَكَانَ لَا يَسْتَتِرُ مِنْ بَوْلِهِ وَأَمَّا هَذَا فَكَانَ يَمْشِي بِالنَّمِيمَةِ ثُمَّ دَعَا بِعَسِيبٍ رَطْبٍ فَشَقَّهُ بِاثْنَيْنِ فَغَرَسَ عَلَى هَذَا وَاحِدًا وَعَلَى هَذَا وَاحِدًا ثُمَّ قَالَ لَعَلَّهُ يُخَفَّفُ عَنْهُمَا مَا لَمْ يَيْبَسَا","id":"Telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Waki'] dari [Al A'masy] dia berkata; saya mendengar [Mujahid] bercerita dari [Thawus] dari [Ibnu Abbas] radliallahu 'anhuma dia berkata; Rasulullah shallallahu 'alaihi wasallam pernah melewati dua kuburan lalu beliau bersabda: \"Kedua penghuni kubur ini tengah disiksa dan keduanya disiksa bukan karena dosa besar. Yang satu ini, tidak bersuci dari kencingnya, sedangkan yang ini disiksa karena selalu mengadu domba.\" Kemudian beliau meminta sepotong pelepah kurma yang masih basah. Beliau membelahnya menjadi dua dan menancapkannya pada dua kuburan tersebut. Beliau kemudian bersabda: 'Semoga ini bisa meringankan keduanya selagi belum kering.'"},"5288":{"ar":"حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزِّنَادِ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي أُسَيْدٍ السَّاعِدِيِّ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ دُورِ الْأَنْصَارِ بَنُو النَّجَّارِ","id":"Telah menceritakan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari [Abu Az Zinnad] dari [Abu Salamah] dari [Abu Usaid As Sa'idi] dia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik pemukiman orang Anshar adalah pemukiman Bani Najjar.\""},"5289":{"ar":"حَدَّثَنَا صَدَقَةُ بْنُ الْفَضْلِ أَخْبَرَنَا ابْنُ عُيَيْنَةَ سَمِعْتُ ابْنَ الْمُنْكَدِرِ سَمِعَ عُرْوَةَ بْنَ الزُّبَيْرِ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَخْبَرَتْهُ قَالَتْاسْتَأْذَنَ رَجُلٌ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ائْذَنُوا لَهُ بِئْسَ أَخُو الْعَشِيرَةِ أَوْ ابْنُ الْعَشِيرَةِ فَلَمَّا دَخَلَ أَلَانَ لَهُ الْكَلَامَ قُلْتُ يَا رَسُولَ اللَّهِ قُلْتَ الَّذِي قُلْتَ ثُمَّ أَلَنْتَ لَهُ الْكَلَامَ قَالَ أَيْ عَائِشَةُ إِنَّ شَرَّ النَّاسِ مَنْ تَرَكَهُ النَّاسُ أَوْ وَدَعَهُ النَّاسُ اتِّقَاءَ فُحْشِهِ","id":"Telah menceritakan kepada kami [Shadaqah bin Al Fadl] telah mengabarkan kepada kami [Ibnu 'Uyainah] saya mendengar [Ibnu Al Munkadir] dia mendengar ['Urwah bin Az Zubair] bahwa [Aisyah] radliallahu 'anha pernah mengabarkan kepadanya, katanya: \"Seorang laki-laki meminta izin kepada nabi Shallalahu 'alaihi wa sallam, beliau lalu bersabda: \"Izinkanlah dia masuk, amat buruklah saudara 'Asyirah (maksudnya kabilah) ini atau amat buruklah Ibnul Asyirah (maksudnya kabilah) ini.\" Ketika orang itu duduk, beliau berbicara kepadanya dengan suara yang lembut, lalu aku bertanya; \"Wahai Rasulullah, anda berkata seperti ini dan ini, namun setelah itu anda berbicara dengannya dengan suara yang lembut, Maka beliau bersabda: \"Wahai 'A`isyah, sesungguhnya seburuk-buruk kedudukan manusia di sisi Allah pada hari kiamat adalah orang yang ditinggalkan oleh manusia karena takut akan kekejiannya.\""},"5290":{"ar":"حَدَّثَنَا ابْنُ سَلَامٍ أَخْبَرَنَا عَبِيْدَةُ بْنُ حُمَيْدٍ أَبُو عَبْدِ الرَّحْمَنِ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ قَالَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ بَعْضِ حِيطَانِ الْمَدِينَةِ فَسَمِعَ صَوْتَ إِنْسَانَيْنِ يُعَذَّبَانِ فِي قُبُورِهِمَا فَقَالَ يُعَذَّبَانِ وَمَا يُعَذَّبَانِ فِي كَبِيرٍ وَإِنَّهُ لَكَبِيرٌ كَانَ أَحَدُهُمَا لَا يَسْتَتِرُ مِنْ الْبَوْلِ وَكَانَ الْآخَرُ يَمْشِي بِالنَّمِيمَةِ ثُمَّ دَعَا بِجَرِيدَةٍ فَكَسَرَهَا بِكِسْرَتَيْنِ أَوْ ثِنْتَيْنِ فَجَعَلَ كِسْرَةً فِي قَبْرِ هَذَا وَكِسْرَةً فِي قَبْرِ هَذَا فَقَالَ لَعَلَّهُ يُخَفَّفُ عَنْهُمَا مَا لَمْ يَيْبَسَا","id":"Telah menceritakan kepada kami [Ibnu Salam] telah mengabarkan kepada kami ['Abidah bin Humaid Abu Abdurrahman] dari [Manshur] dari [Mujahid] dari [Ibnu Abbas] dia berkata; Nabi shallallahu 'alaihi wasallam pernah keluar dari salah satu kebun yang ada di Madinah, lalu beliau mendengar suara dua orang yang sedang di siksa di kuburnya, setelah itu beliau bersabda: \"Tidaklah keduanya di siksa karena dosa besar namun hal itu adalah perkara yang besar, salah satu darinya adalah tidak bersuci dari kencingnya sedangkan yang lain selalu mengadu domba.\" Kemudian beliau meminta sepotong pelepah kurma yang masih basah. Beliau membelahnya menjadi dua, sepotong beliau tancapkan di kuburan yang satu dan sepotong di kuburan yang lain. Beliau kemudian bersabda: 'Semoga ini bisa meringankan siksa keduanya selagi belum kering.'"},"5291":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ هَمَّامٍ قَالَ كُنَّا مَعَ حُذَيْفَةَفَقِيلَ لَهُ إِنَّ رَجُلًا يَرْفَعُ الْحَدِيثَ إِلَى عُثْمَانَ فَقَالَ لَهُ حُذَيْفَةُ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَدْخُلُ الْجَنَّةَ قَتَّاتٌ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Ibrahim] dari [Hammam] dia berkata; \"Kami pernah bersama [Hudzaifah], lalu di beritahukan kepadanya bahwa ada seseorang yang merafa'kan (menyandarkan) hadits kepada Utsman, lantas Hudzaifah berkata kepada orang tersebut; \"Saya mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak akan masuk surga orang yang suka mengadu domba.\""},"5292":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الْمَقْبُرِيِّ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ لَمْ يَدَعْ قَوْلَ الزُّورِ وَالْعَمَلَ بِ��ِ وَالْجَهْلَ فَلَيْسَ لِلَّهِ حَاجَةٌ أَنْ يَدَعَ طَعَامَهُ وَشَرَابَهُقَالَ أَحْمَدُ أَفْهَمَنِي رَجُلٌ إِسْنَادَهُ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Ibnu Abu Dzi`b] dari [Al Maqburi] dari [Ayahnya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Barangsiapa tidak meninggalkan perkataan kotor, melakukan hal itu dan masa bodoh, maka Allah tidak butuh (amalannya) meskipun dia meninggalkan makanan dan minumannya (puasa).\" Ahmad berkata; Seorang laki-laki memahamkanku tentang isnad hadits ini."},"5293":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا أَبُو صَالِحٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَجِدُ مِنْ شَرِّ النَّاسِ يَوْمَ الْقِيَامَةِ عِنْدَ اللَّهِ ذَا الْوَجْهَيْنِ الَّذِي يَأْتِي هَؤُلَاءِ بِوَجْهٍ وَهَؤُلَاءِ بِوَجْهٍ","id":"Telah menceritakan kepada kami [Umar bin Hafsh] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Al A'masy] telah menceritakan kepada kami [Abu Shalih] dari [Abu Hurairah] radliallahu 'anhu dia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Kamu akan mendapati orang yang paling jelek di sisi Allah pada hari Kiamat kelak adalah orang yang bermuka dua, yang datang dengan satu muka dan datang kepada orang lain dengan muka yang lain.\""},"5294":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ أَخْبَرَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ ابْنِ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَسَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِسْمَةً فَقَالَ رَجُلٌ مِنْ الْأَنْصَارِ وَاللَّهِ مَا أَرَادَ مُحَمَّدٌ بِهَذَا وَجْهَ اللَّهِ فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ فَتَمَعَّرَ وَجْهُهُ وَقَالَ رَحِمَ اللَّهُ مُوسَى لَقَدْ أُوذِيَ بِأَكْثَرَ مِنْ هَذَا فَصَبَرَ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah mengabarkan kepada kami [Sufyan] dari [Al A'masy] dari [Abu Wa`il] dari [Ibnu Mas'ud] radliallahu 'anhu dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah membagikan suatu bagian, lantas seorang laki-laki dari Anshar berkata; \"Demi Allah, dalam hal ini Muhammad tidak mengharapkan wajah Allah.\" Lalu saya langsung mendatangi Rasulullah shallallahu 'alaihi wasallam dan mengabarkan kepada beliau, tiba-tiba wajah beliau berubah menjadi merah dan bersabda: \"Semoga Allah merahmati Musa, sungguh dia lebih banyak disakiti daripada ini lalu dia bersabar.\""},"5295":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ صَبَّاحٍ حَدَّثَنَا إِسْمَاعِيلُ بْنُ زَكَرِيَّاءَ حَدَّثَنَا بُرَيْدُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي بُرْدَةَ عَنْ أَبِي بُرْدَةَ بْنِ أَبِي مُوسَى عَنْ أَبِي مُوسَى قَالَسَمِعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا يُثْنِي عَلَى رَجُلٍ وَيُطْرِيهِ فِي الْمِدْحَةِ فَقَالَ أَهْلَكْتُمْ أَوْ قَطَعْتُمْ ظَهْرَ الرَّجُلِ","id":"Telah menceritakan kepada kami [Muhammad bin Shabbah] telah menceritakan kepada kami [Isma'il bin Zakariya'] telah menceritakan kepada kami [Buraid bin Abdullah bin Abu Burdah] dari [Abu Burdah bin Abu Musa] dari [Abu Musa] dia berkata; \"Nabi Shallallahu 'alaihi wasalam pernah mendengar seseorang memuji orang lain secara berlebihan, lalu beliau bersabda: \"Kalian telah binasa-atau: Kalian telah memutuskan punggung seseorang.\""},"5296":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ عَنْ خَالِدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ عَنْ أَبِيهِأَنَّ رَجُلًا ذُكِرَ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَثْنَى عَلَيْهِ رَجُلٌ خَيْرًا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيْحَكَ قَطَعْتَ عُنُقَ صَاحِبِكَ يَقُولُهُ مِرَارًا إِنْ كَانَ أَحَدُكُمْ مَادِحًا لَا مَحَالَةَ فَلْيَقُلْ أَحْسِبُ كَذَا وَكَذَا إِنْ كَانَ يُرَى أَنَّهُ كَذَلِكَ وَحَسِيبُهُ اللَّهُ وَلَا يُزَكِّي عَلَى اللَّهِ أَحَدًاقَالَ وُهَيْبٌ عَنْ خَالِدٍ وَيْلَكَ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] dari [Khalid] dari [Abdurrahman bin Abu Bakrah] dari [Ayahnya] bahwa seorang laki-laki disebut-sebut disamping Nabi shallallahu 'alaihi wasallam, lalu laki-laki lain memuji kebaikan laki-laki tersebut, lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Celaka kamu, kamu telah memenggal leher saudaramu.\" -Beliau mengatakannya hingga berkali-kali- bila salah seorang dari kalian memuji temannya -tidak mustahil- hendaklah mengucapkan: 'Aku kira fulan seperti ini dan ini, walaupun jika diperlihatkan ia memang seperti itu, dan Allah lah yang akan menilainya, supaya ia tidak menyucikan seorang pun atas Allah.\" [Wuhaib] mengatakan dari [Khalid]; \"Wailaka (celaka kamu).\""},"5297":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ عَنْ سَالِمٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ ذَكَرَ فِي الْإِزَارِ مَا ذَكَرَ قَالَ أَبُو بَكْرٍ يَا رَسُولَ اللَّهِ إِنَّ إِزَارِي يَسْقُطُ مِنْ أَحَدِ شِقَّيْهِ قَالَ إِنَّكَ لَسْتَ مِنْهُمْ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Musa bin 'Uqbah] dari [Salim] dari [Ayahnya] bahwa ketika Rasulullah shallallahu 'alaihi wasallam menyebutkan tentang kain sarung sebagaimana yang beliau sebutkan, Abu Bakr berkata; \"Wahai Rasulullah, salah satu dari kain sarungku yang sebelah selalu terjatuh, \" beliau bersabda: \"Sesungguhnya kamu tidak termasuk dari mereka (yang menjulurkan kain sarung sampai di bawah mata kaki).\" "},"5298":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْمَكَثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَذَا وَكَذَا يُخَيَّلُ إِلَيْهِ أَنَّهُ يَأْتِي أَهْلَهُ وَلَا يَأْتِي قَالَتْ عَائِشَةُ فَقَالَ لِي ذَاتَ يَوْمٍ يَا عَائِشَةُ إِنَّ اللَّهَ أَفْتَانِي فِي أَمْرٍ اسْتَفْتَيْتُهُ فِيهِ أَتَانِي رَجُلَانِ فَجَلَسَ أَحَدُهُمَا عِنْدَ رِجْلَيَّ وَالْآخَرُ عِنْدَ رَأْسِي فَقَالَ الَّذِي عِنْدَ رِجْلَيَّ لِلَّذِي عِنْدَ رَأْسِي مَا بَالُ الرَّجُلِ قَالَ مَطْبُوبٌ يَعْنِي مَسْحُورًا قَالَ وَمَنْ طَبَّهُ قَالَ لَبِيدُ بْنُ أَعْصَمَ قَالَ وَفِيمَ قَالَ فِي جُفِّ طَلْعَةٍ ذَكَرٍ فِي مُشْطٍ وَمُشَاقَةٍ تَحْتَ رَعُوفَةٍ فِي بِئْرِ ذَرْوَانَ فَجَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هَذِهِ الْبِئْرُ الَّتِي أُرِيتُهَا كَأَنَّ رُءُوسَ نَخْلِهَا رُءُوسُ الشَّيَاطِينِ وَكَأَنَّ مَاءَهَا نُقَاعَةُ الْحِنَّاءِ فَأَمَرَ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأُخْرِجَ قَالَتْ عَائِشَةُ فَقُلْتُ يَا رَسُولَ اللَّهِ فَهَلَّا تَعْنِي تَنَشَّرْتَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا اللَّهُ فَقَدْ شَفَانِي وَأَمَّا أَنَا فَأَكْرَهُ أَنْ أُثِيرَ عَلَى النَّاسِ شَرًّا قَالَتْ وَلَبِيدُ بْنُ أَعْصَمَ رَجُلٌ مِنْ بَنِي زُرَيْقٍ حَلِيفٌ لِيَهُودَ","id":"Telah menceritakan kepada kami [Al Humaidi] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah] radliallahu 'anha dia berkata; \"Nabi shallallahu 'alaihi wasallam tetap termenung seperti ini dan ini, sehingga beliau dibuat seakan-akan telah melakukan sesuatu terhadap isterinya padahal beliau tidak melakukannya.\" Aisyah melanjutkan; \"Sampai di suatu hari beliau bersabda: \"Wahai Aisyah, apakah kamu telah merasakan bahwa Allah telah memberikan fatwa (menghukumi) dengan apa yang telah aku fatwakan (hukumi)? Dua orang laki-laki telah datang kepadaku, lalu salah seorang dari keduanya duduk di kakiku dan satunya lagi di atas kepalaku. Kemudian orang yang berada di kakiku berkata kepada orang yang berada di atas kepalaku; \"Kenapakah laki-laki ini?\" temannya menjawab; \"Dia terkena sihir.' Salah seorang darinya bertanya; \"Siapakah yang menyihirnya?\" temannya menjawab; \"Labid bin Al A'sham.\" Salah satunya bertanya; \"Dengan benda apakah dia menyihir?\" temannya menjawab; \"Dengan seladang mayang kurma dan rambut yang terjatuh ketika disisir yang diletakkan di bawah batu dalam sumur Dzarwan.\" Kemudian Nabi shallallahu 'alaihi wasallam mendatanginya, lalu bersabda: \"Inilah sumur yang diperlihatkan kepadaku, seakan-akan pohon kurmanya bagaikan kepala syetan dan seolah-olah airnya berubah bagaikan rendaman pohon inai.\" Lalu Nabi shallallahu 'alaihi wasallam memerintahkan untuk mengeluarkannya, kemudian barang tersebut pun dikeluarkan. Aisyah berkata; \"aku bertanya; \"Wahai Rasulullah, tidakkah anda menjampinya (meruqyahnya)?\" maka Nabi shallallahu 'alaihi wasallam menjawab: \"Tidak, sesungguhnya Allah telah menyembuhkanku dan aku hanya tidak suka memberikan kesan buruk kepada orang lain dari peristiwa itu.\" Aisyah berkata; \"Labid bin A'sham adalah seorang laki-laki dari Bani Zuraiq yang memiliki hubungan dengan orang-orang Yahudi.\""},"5299":{"ar":"حَدَّثَنَا بِشْرُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِيَّاكُمْ وَالظَّنَّ فَإِنَّ الظَّنَّ أَكْذَبُ الْحَدِيثِ وَلَا تَحَسَّسُوا وَلَا تَجَسَّسُوا وَلَا تَحَاسَدُوا وَلَا تَدَابَرُوا وَلَا تَبَاغَضُوا وَكُونُوا عِبَادَ اللَّهِ إِخْوَانًا","id":"Telah menceritakan kepada kami [Bisyr bin Muhammad] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Ma'mar] dari [Hammam bin Munabbih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Jauhilah prasangka buruk, karena prasangka buruk adalah ucapan yang paling dusta, janganlah kalian saling mendiamkan, janganlah suka mencari-cari isu, saling mendengki, saling membelakangi, serta saling membenci, tetapi, jadilah kalian hamba-hamba Allah yang bersaudara.\""},"5300":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي أَنَسُ بْنُ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَبَاغَضُوا وَلَا تَحَاسَدُوا وَلَا تَدَابَرُوا وَكُونُوا عِبَادَ اللَّهِ إِخْوَانًا وَلَا يَحِلُّ لِمُسْلِمٍ أَنْ يَهْجُرَ أَخَاهُ فَوْقَ ثَلَاثَةِ أَيَّامٍ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; telah menceritakan kepadaku [Anas bin Malik] radliallahu 'anhu bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian saling membenci, saling mendengki, saling membelakangi, dan jadilah kalian hamba-hamba Allah yang bersaudara, dan tidak halal seorang muslim mendiamkan saudaranya melebihi tiga hari.\""},"5301":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِيَّاكُمْ وَالظَّنَّ فَإِنَّ الظَّنَّ أَكْذَبُ الْحَدِيثِ وَلَا تَحَسَّسُوا وَلَا تَجَسَّسُوا وَلَا تَنَاجَشُوا وَلَا تَحَاسَدُوا وَلَا تَبَاغَضُوا وَلَا تَدَابَرُوا وَكُونُوا عِبَادَ اللَّهِ إِخْوَانًا","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Abu Az Zinnad] dari [Al A'raj] dari [Abu Hurairah] radliallahu 'anhu bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jauhilah prasangka buruk, karena prasangka buruk ucapan yang paling dusta, dan janganlah kalian saling mendiamkan, saling mencari kejelekan, saling menipu dalam jual beli, saling mendengki, saling memusuhi dan janganlah saling membelakangi, dan jadilah kalian semua hamba-hamba Allah yang bersaudara.\""},"5302":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَظُنُّ فُلَانًا وَفُلَانًا يَعْرِفَانِ مِنْ دِينِنَا شَيْئًاقَالَ اللَّيْثُ كَانَا رَجُلَيْنِ مِنْ الْمُنَافِقِينَ حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ بِهَذَا وَقَالَتْ دَخَلَ عَلَيَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا وَقَالَ يَا عَائِشَةُ مَا أَظُنُّ فُلَانًا وَفُلَانًا يَعْرِفَانِ دِينَنَا الَّذِي نَحْنُ عَلَيْهِ","id":"Telah menceritakan kepada kami [Sa'id bin 'Ufair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari ['Urwah] dari [Aisyah] dia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Saya tidak mengira seandainya fulan dan fulan mengetahui agama kita sedikitpun.\" Al Laits mengatakan; \"Dua orang itu adalah dari orang-orang Munafik.\" Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dengan (sanad) ini, Aisyah mengatakan; \"Pada suatu hari Nabi shallallahu 'alaihi wasallam masuk menemuiku, lalu beliau bersabda: \"Wahai Aisyah, aku menyangka ternyata fulan dan fulan tidak mengetahui perkara agama yang kita berada di atasnya.\""},"5303":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ أَخِي ابْنِ شِهَابٍ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ كُلُّ أُمَّتِي مُعَافًى إِلَّا الْمُجَاهِرِينَ وَإِنَّ مِنْ الْمُجَاهَرَةِ أَنْ يَعْمَلَ الرَّجُلُ بِاللَّيْلِ عَمَلًا ثُمَّ يُصْبِحَ وَقَدْ سَتَرَهُ اللَّهُ عَلَيْهِ فَيَقُولَ يَا فُلَانُ عَمِلْتُ الْبَارِحَةَ كَذَا وَكَذَا وَقَدْ بَاتَ يَسْتُرُهُ رَبُّهُ وَيُصْبِحُ يَكْشِفُ سِتْرَ اللَّهِ عَنْهُ","id":"Telah menceritakan kepada kami [Abdul Aziz bin Abdullah] telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Ibnu Akhi Ibnu Syihab] dari [Ibnu Syihab] dari [Salim bin Abdullah] dia berkata; saya mendengar [Abu Hurairah] berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap umatku dimaafkan (dosanya) kecuali orang-orang menampak-nampakkannya dan sesungguhnya diantara menampak-nampakkan (dosa) adalah seorang hamba yang melakukan amalan di waktu malam sementara Allah telah menutupinya kemudian di waktu pagi dia berkata: 'Wahai fulan semalam aku telah melakukan ini dan itu, ' padahal pada malam harinya (dosanya) telah ditutupi oleh Rabbnya. Ia pun bermalam dalam keadaan (dosanya) telah ditutupi oleh Rabbnya dan di pagi harinya ia menyingkap apa yang telah ditutupi oleh Allah'.\""},"5304":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ صَفْوَانَ بْنِ مُحْرِزٍ أَنَّ رَجُلًا سَأَلَ ابْنَ عُمَرَكَيْفَ سَمِعْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي النَّجْوَى قَالَ يَدْنُو أَحَدُكُمْ مِنْ رَبِّهِ حَتَّى يَضَعَ كَنَفَهُ عَلَيْهِ فَيَقُولُ عَمِلْتَ كَذَا وَكَذَا فَيَقُولُ نَعَمْ وَيَقُولُ عَمِلْتَ كَذَا وَكَذَا فَيَقُولُ نَعَمْ فَيُقَرِّرُهُ ثُمَّ يَقُولُ إِنِّي سَتَرْتُ عَلَيْكَ فِي الدُّنْيَا فَأَنَا أَغْفِرُهَا لَكَ الْيَوْمَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Shafwan bin Muhriz] bahwa seorang laki-laki pernah bertanya kepada [Ibnu Umar]; \"Bagaimana anda mendengar sabda Rasulullah shallallahu 'alaihi wasallam tentang An Najwa (bisikan di hari kiamat)?\" Ibnu Umar menjawab; \"Yaitu salah seorang dari kalian akan mendekat kepada Rabb-nya. Kemudian Dia meletakkan naungan-Nya di atasnya, (Maksudnya menutupi kesalahannya) kemudian Dia berfirman, \"Apakah kamu telah berbuat ini dan ini?\" hamba itu menjawab, \"Ya, benar.\" Dia berfirman lagi \"Apakah kamu telah melakukan ini dan ini?\". Hamba itu menjawab; \"Ya, benar.\" Dia pun mengulang-ulang pertanyannya, kemudian berfirman: \"Sesungguhnya Aku telah menutupinya (merahasiakannya) di dunia dan pada hari ini aku telah mengampuninya bagimu.\""},"5305":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ حَدَّثَنَا مَعْبَدُ بْنُ خَالِدٍ الْقَيْسِيُّ عَنْ حَارِثَةَ بْنِ وَهْبٍ الْخُزَاعِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلَا أُخْبِرُكُمْ بِأَهْلِ الْجَنَّةِ كُلُّ ضَعِيفٍ مُتَضَاعِفٍ لَوْ أَقْسَمَ عَلَى اللَّهِ لَأَبَرَّهُ أَلَا أُخْبِرُكُمْ بِأَهْلِ النَّارِ كُلُّ عُتُلٍّ جَوَّاظٍ مُسْتَكْبِرٍوَقَالَ مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا حُمَيْدٌ الطَّوِيلُ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍ قَالَإِنْ كَانَتْ الْأَمَةُ مِنْ إِمَاءِ أَهْلِ الْمَدِينَةِ لَتَأْخُذُ بِيَدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَنْطَلِقُ بِهِ حَيْثُ شَاءَتْ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] telah menceritakan kepada kami [Ma'bad bin Khalid Al Qaisi] dari [Haritsah bin Wahb Al Khuza'i] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Maukah kalian aku beritahu penduduk surga? Yaitu setiap orang yang lemah dan diperlemah. Sekiranya ia bersumpah atas nama Allah pasti Allah akan mengabulkannya, Maukah kalian aku beritahu penghuni neraka? Yaitu Setiap orang yang keras (hati), congkak dan sombong.\" [Muhammad bin Isa] berkata; telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Humaid At Thawil] telah menceritakan kepada kami [Anas bin Malik] dia berkata; \"Sekiranya ada seorang budak dari budak penduduk Madinah menggandeng tangan Rasulullah shallallahu 'alaihi wasallam, sungguh beliau akan beranjak bersamanya kemana budak itu pergi.\""},"5306":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي عَوْفُ بْنُ مَالِكِ بْنِ الطُّفَيْلِ هُوَ ابْنُ الْحَارِثِ وَهُوَ ابْنُ أَخِي عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأُمِّهَا أَنَّ عَائِشَةَ حُدِّثَتْأَنَّ عَبْدَ اللَّهِ بْنَ الزُّبَيْرِ قَالَ فِي بَيْعٍ أَوْ عَطَاءٍ أَعْطَتْهُ عَائِشَةُ وَاللَّهِ لَتَنْتَهِيَنَّ عَائِشَةُ أَوْ لَأَحْجُرَنَّ عَلَيْهَا فَقَالَتْ أَهُوَ قَالَ هَذَا قَالُوا نَعَمْ قَالَتْ هُوَ لِلَّهِ عَلَيَّ نَذْرٌ أَنْ لَا أُكَلِّمَ ابْنَ الزُّبَيْرِ أَبَدًا فَاسْتَشْفَعَ ابْنُ الزُّبَيْرِ إِلَيْهَا حِينَ طَالَتْ الْهِجْرَةُ فَقَالَتْ لَا وَاللَّهِ لَا أُشَفِّعُ فِيهِ أَبَدًا وَلَا أَتَحَنَّثُ إِلَى نَذْرِي فَلَمَّا طَالَ ذَلِكَ عَلَى ابْنِ الزُّبَيْرِ كَلَّمَ الْمِسْوَرَ بْنَ مَخْرَمَةَ وَعَبْدَ الرَّحْمَنِ بْنَ الْأَسْوَدِ بْنِ عَبْدِ يَغُوثَ وَهُمَا مِنْ بَنِي زُهْرَةَ وَقَالَ لَهُمَا أَنْشُدُكُمَا بِاللَّهِ لَمَّا أَدْخَلْتُمَانِي عَلَى عَائِشَةَ فَإِنَّهَا لَا يَحِلُّ لَهَا أَنْ تَنْذِرَ قَطِيعَتِي فَأَقْبَلَ بِهِ الْمِسْوَرُ وَعَبْدُ الرَّحْمَنِ مُشْتَمِلَيْنِ بِأَرْدِيَتِهِمَا حَتَّى اسْتَأْذَنَا عَلَى عَائِشَةَ فَقَالَا السَّلَامُ عَلَيْكِ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ أَنَدْخُلُ قَالَتْ عَائِشَةُ ادْخُلُوا قَالُوا كُلُّنَا قَالَتْ نَعَم ادْخُلُوا كُلُّكُمْ وَلَا تَعْلَمُ أَنَّ مَعَهُمَا ابْنَ الزُّبَيْرِ فَلَمَّا دَخَلُوا دَخَلَ ابْنُ الزُّبَيْرِ الْحِجَابَ فَاعْتَنَقَ عَائِشَةَ وَطَفِقَ يُنَاشِدُهَا وَيَبْكِي وَطَفِقَ الْمِسْوَرُ وَعَبْدُ الرَّحْمَنِ يُنَاشِدَانِهَا إِلَّا مَا كَلَّمَتْهُ وَقَبِلَتْ مِنْهُ وَيَقُولَانِ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَمَّا قَدْ عَلِمْتِ مِنْ الْهِجْرَةِ فَإِنَّهُ لَا يَحِلُّ لِمُسْلِمٍ أَنْ يَهْجُرَ أَخَاهُ فَوْقَ ثَلَاثِ لَيَالٍ فَلَمَّا أَكْثَرُوا عَلَى عَائِشَةَ مِنْ التَّذْكِرَةِ وَالتَّحْرِيجِ طَفِقَتْ تُذَكِّرُهُمَا نَذْرَهَا وَتَبْكِي وَتَقُولُ إِنِّي نَذَرْتُ وَالنَّذْرُ شَدِيدٌ فَلَمْ يَزَالَا بِهَا حَتَّى كَلَّمَتْ ابْنَ الزُّبَيْرِ وَأَعْتَقَتْ فِي نَذْرِهَا ذَلِكَ أَرْبَعِينَ رَقَبَةً وَكَانَتْ تَذْكُرُ نَذْرَهَا بَعْدَ ذَلِكَ فَتَبْكِي حَتَّى تَبُلَّ دُمُوعُهَا خِمَارَهَا","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; telah menceritakan kepadaku ['Auf bin Malik bin Ath Thufail] -yaitu Ibnu Al Harits ia adalah anak saudara seibu Aisyah isteri Nabi shallallahu 'alaihi wasallam- mendapatkan kabar bahwa Abdullah bin Zubair berkata tentang penjualan (rumah) atau pemberian yang di berikan Aisyah kepadanya, Kata Abdullah; \"Demi Allah, Aisyah segera membatalkan penjualan (rumah) atau aku akan menjauhi dirinya.\" Aisyah berkata; \"Apakah dia (Ibnu Zubair) mengatakan seperti itu?\" mereka berkata; \"Ya.\" [Aisyah] berkata; \"Demi Allah, saya bernadzar untuk tidak berbicara kepada Ibnu Zubair selamanya.\" Maka Ibnu Zubair pun meminta ma'af kepada Aisyah ketika Aisyah lama mendiamkannya. Namun Aisyah tetap berkata; \"Tidak, demi Allah, aku tidak akan mema'afkannya dan tidak pula menghentikan nadzarku.\" Katika hal itu dirasakan Ibnu Zubair cukup lama, maka Ibnu Zubair berkata kepada Miswar bin Makhramah dan Abdurrahman bin Al Aswad bin Abd Yaghuts keduanya dari Kabilah Zuhrah; \"Aku bersumpah atas nama Allah, ketika kalian berdua memasukkanku ke rumah Aisyah, sesungguhnya tidak halal baginya bernadzar untuk memutuskan tali silaturrahmi.\" Lantas Al Miswar dan Abdurrahman pergi menemui Aisyah dengan mengenakan mantelnya, kemudian keduanya meminta izin kepada Aisyah, katanya; \"Assalamu 'alaiki warahmatullahi wabarakutuh, apakah aku boleh masuk?\" Aisyah menjawab; \"Masuklah kalian.\" Mereka berkata; \"Kami semua.\" Aisyah menjawab; \"Ya, kalian semua.\" Aisyah tidak tahu kalau Ibnu Zubair juga ada bersama mereka berdua, ketika mereka masuk rumah, Ibnu Zubair pun masuk ke dalam ruangan Aisyah, dan langsung memeluknya. Setelah itu Ibnu Zubair pun menasihati Aisyah sambil menangis, kemudian Al Miswar dan Abdurrahman juga ikut menasihatinya. Keduanya berkata, \"Sesungguhnya Nabi shallallahu 'alaihi wasallam telah melarang untuk mendiamkan orang lain sebagaimana yang telah engkau ketahui, sesungguhnya tidak halal bagi seorang muslim mendiamkan saudaranya melebihi tiga hari.\" Ketika nasehat itu mengalir terus kepada Aisyah, Aisyah segera ingat mengenai nadzarnya dan menangis, katanya; \"Sesungguhnya aku telah bernadzar, dan nadzar tersebut sangatlah berat, dan keduanya masih saja seperti itu hingga Aisyah berkata kepada Ibnu Zubair. Setelah itu Aisyah membebaskan empat puluh budak karena nadzarnya, dan setelah Aisyah ingat nadzarnya, iapun menangis sehingga air matanya membasahi jilbabnya.\""},"5307":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَبَاغَضُوا وَلَا تَحَاسَدُوا وَلَا تَدَابَرُوا وَكُونُوا عِبَادَ اللَّهِ إِخْوَانًا وَلَا يَحِلُّ لِمُسْلِمٍ أَنْ يَهْجُرَ أَخَاهُ فَوْقَ ثَلَاثِ لَيَالٍ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Anas bin Malik] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian saling membenci, janganlah saling mendengki dan janganlah kalian saling membelakangi dan jadilah kalian hamba-hamba Allah yang bersaudara, dan tidak halal bagi seorang muslim mendiamkan saudaranya melebihi tiga malam.\""},"5308":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ أَبِي أَيُّوبَ الْأَنْصَارِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحِلُّ لِرَجُلٍ أَنْ يَهْجُرَ أَخَاهُ فَوْقَ ثَلَاثِ لَيَالٍ يَلْتَقِيَانِ فَيُعْرِضُ هَذَا وَيُعْرِضُ هَذَا وَخَيْرُهُمَا الَّذِي يَبْدَأُ بِالسَّلَامِ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari ['Atha` bin Yazid Al Laitsi] dari [Abu Ayyub Al Anshari] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal bagi seorang muslim mendiamkan saudaranya melebihi tiga malam, (jika bertemu) yang ini berpaling dan yang ini juga berpaling, dan sebaik-baik dari keduanya adalah yang memulai mengucapkan salam.\""},"5309":{"ar":"حَدَّثَنَا مُحَمَّدٌ أَخْبَرَنَا عَبْدَةُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَأَعْرِفُ غَضَبَكِ وَرِضَاكِ قَالَتْ قُلْتُ وَكَيْفَ تَعْرِفُ ذَاكَ يَا رَسُولَ اللَّهِ قَالَ إِنَّكِ إِذَا كُنْتِ رَاضِيَةً قُلْتِ بَلَى وَرَبِّ مُحَمَّدٍ وَإِذَا كُنْتِ سَاخِطَةً قُلْتِ لَا وَرَبِّ إِبْرَاهِيمَ قَالَتْ قُلْتُ أَجَلْ لَسْتُ أُهَاجِرُ إِلَّا اسْمَكَ","id":"Telah menceritakan kepada kami [Muhammad] telah mengabarkan kepada kami [Abdah] dari [Hisyam bin 'Urwah] dari [ayahnya] dari [Aisyah] radliallahu 'anha dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya aku mengetahui bila kamu ridla dan ketika kamu sedang marah.\" Aisyah berkata; \"Bagaimana Anda bisa mengetahui hal itu wahai Rasulullah?\" beliau bersabda: \"Sesungguhnya jika kamu sedang ridla maka kamu akan mengatakan; \"Tentu, demi Rabb Muhammad, \" sementara bila kamu sedang marah, maka kamu akan mengatakan; \"Tidak, demi Rabb Ibrahim.\" Aisyah berkata; lalu kataku; \"Benar, aku tidak merasa jengkel kecuali dengan namamu.\""},"5310":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامٌ عَنْ مَعْمَرٍ وَقَالَ اللَّيْثُ حَدَّثَنِي عُقَيْلٌ قَالَ ابْنُ شِهَابٍ فَأَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْلَمْ أَعْقِلْ أَبَوَيَّ إِلَّا وَهُمَا يَدِينَانِ الدِّينَ وَلَمْ يَمُرَّ عَلَيْهِمَا يَوْمٌ إِلَّا يَأْتِينَا فِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَرَفَيْ النَّهَارِ بُكْرَةً وَعَشِيَّةً فَبَيْنَمَا نَحْنُ جُلُوسٌ فِي بَيْتِ أَبِي بَكْرٍ فِي نَحْرِ الظَّهِيرَةِ قَالَ قَائِلٌ هَذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَاعَةٍ لَمْ يَكُنْ يَأْتِينَا فِيهَا قَالَ أَبُو بَكْرٍ مَا جَاءَ بِهِ فِي هَذِهِ السَّاعَةِ إِلَّا أَمْرٌ قَالَ إِنِّي قَدْ أُذِنَ لِي بِالْخُرُوجِ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] telah mengabarkan kepada kami [Hisyam] dari [Ma'mar]. [Al Laits] mengatakan; telah menceritakan kepadaku ['Uqail], [Ibnu Syihab] berkata; telah mengabarkan kepadaku ['Urwah bin Zubair] bahwa [Aisyah isteri Nabi shallallahu 'alaihi wasallam] berkata; \"Saya tidak menyadari bahwa kedua orang tuaku telah memeluk suatu agama, tidak ada hari yang kami lalui kecuali Rasulullah shallaallahu 'alaihi wa sallam pasti berkunjung ke rumah kami pada pagi maupun sore hari. Dan ketika kami tengah duduk-duduk di rumah Abu Bakr pada siang hari, tiba-tiba ada seseorang berkata; \"Ini Rasulullah shallallahu 'alaihi wasallam, datang di waktu yang belum pernah datang kepada kami pada saat seperti ini.\" Abu Bakr berkata; \"Tidaklah beliau datang pada saat seperti ini kecuali ada perkara (yang sangat penting), beliau lalu bersabda: \"Sesungguhnya aku telah di izinkan untuk keluar (berhijrah).\""},"5311":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَامٍ أَخْبَرَنَا عَبْدُ الْوَهَّابِ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَنَسِ بْنِ سِيرِينَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَارَ أَهْلَ بَيْتٍ مِنْ الْأَنْصَارِ فَطَعِمَ عِنْدَهُمْ طَعَامًا فَلَمَّا أَرَادَ أَنْ يَخْرُجَ أَمَرَ بِمَكَانٍ مِنْ الْبَيْتِ فَنُضِحَ لَهُ عَلَى بِسَاطٍ فَصَلَّى عَلَيْهِ وَدَعَا لَهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Salam] telah mengabarkan kepada kami [Abdul Wahhab] dari [Khalid Al Khaddza`] dari [Anas bin Sirin] dari [Anas bin Malik] radliallahu 'anhu bahwa Rasulullah shallallahu 'alaihi wasallam pernah mengunjungi rumah milik orang Anshar, lalu beliau makan bersama mereka, ketika beliau hendak keluar, beliau diminta supaya tetap tinggal di rumah tersebut, lalu beliau memercikkan air di atas tikar setelah itu beliau shalat dan mengajak mereka shalat (berjama'ah).\""},"5312":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ الصَّمَدِ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي يَحْيَى بْنُ أَبِي إِسْحَاقَ قَالَ قَالَ لِي سَالِمُ بْنُ عَبْدِ اللَّهِ مَا الْإِسْتَبْرَقُ قُلْتُ مَا غَلُظَ مِنْ الدِّيبَاجِ وَخَشُنَ مِنْهُ قَالَ سَمِعْتُ عَبْدَ اللَّهِ يَقُولُرَأَى عُمَرُ عَلَى رَجُلٍ حُلَّةً مِنْ إِسْتَبْرَقٍ فَأَتَى بِهَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ اشْتَرِ هَذِهِ فَالْبَسْهَا لِوَفْدِ النَّاسِ إِذَا قَدِمُوا عَلَيْكَ فَقَالَ إِنَّمَا يَلْبَسُ الْحَرِيرَ مَنْ لَا خَلَاقَ لَهُ فَمَضَى مِنْ ذَلِكَ مَا مَضَى ثُمَّ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ إِلَيْهِ بِحُلَّةٍ فَأَتَى بِهَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ بَعَثْتَ إِلَيَّ بِهَذِهِ وَقَدْ قُلْتَ فِي مِثْلِهَا مَا قُلْتَ قَالَ إِنَّمَا بَعَثْتُ إِلَيْكَ لِتُصِيبَ بِهَا مَالًافَكَانَ ابْنُ عُمَرَ يَكْرَهُ الْعَلَمَ فِي الثَّوْبِ لِهَذَا الْحَدِيثِ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] telah menceritakan kepada kami [Abdush Shamad] dia berkata; telah menceritakan kepadaku [Ayahku] dia berkata; telah menceritakan kepadaku [Yahya bin Abu Ishaq] dia berkata; [Salim bin Abdullah] berkata kepadaku; \"Apakah istabraq itu?\" aku menjawab; \"yaitu kain sutera yang agak tebal dan kasar.\" Salim berkata; saya mendengar [Abdullah] berkata; \"Umar pernah melihat seorang laki-laki mengenakan baju sutera dari istabraq (sutera tebal), lalu dia datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; \"Wahai Rasulullah, Alangkah bagusnya jika Anda membelinya untuk Anda pakai saat menerima para utusan yang datang kepada Anda.\" Maka beliau menjawab: 'Yang memakai sutera ini hanyalah orang yang tidak mendapat bagian di akhirat. Tidak berapa lama dari peristiwa itu, Nabi shallallahu 'alaihi wasallam mengutus seseorang untuk memberi kain sutera tersebut kepada Umar, lalu Umar mendatangi Nabi shallallahu 'alaihi wasallam dengan membawa kain tersebut sambil berkata; \"\"Ya Rasulullah! Bagaimana anda mengutus seseorang untuk memberiku kain sutera ini, padahal Anda telah berkata kepadaku tentang baju ini?\" beliau menjawab: 'Aku tidak mengirimkannya kepadamu kecuali supaya kamu mendapatkan hasil (menjualnya).\" Sedangkan Ibnu Umar sangat membenci corak yang terdapat dalam baju karena hadits ini.\""},"5313":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ حُمَيْدٍ عَنْ أَنَسٍ قَالَلَمَّا قَدِمَ عَلَيْنَا عَبْدُ الرَّحْمَنِ فَآخَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَهُ وَبَيْنَ سَعْدِ بْنِ الرَّبِيعِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْلِمْ وَلَوْ بِشَاةٍ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Humaid] dari [Anas] dia berkata; Abdurrahman datang kepada kami, lalu Nabi shallallahu 'alaihi wasallam mempersaudarakan antara dia dengan Sa'd bin Ar Rabi'. Lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Adakanlah walimah walau dengan seekor domba.\""},"5314":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ صَبَّاحٍ حَدَّثَنَا إِسْمَاعِيلُ بْنُ زَكَرِيَّاءَ حَدَّثَنَا عَاصِمٌ قَالَ قُلْتُ لِأَنَسِ بْنِ مَالِكٍأَبَلَغَكَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا حِلْفَ فِي الْإِسْلَامِ فَقَالَ قَدْ حَالَفَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ قُرَيْشٍ وَالْأَنْصَارِ فِي دَارِي","id":"Telah menceritakan kepada kami [Muhammad bin Shabbah] telah menceritakan kepada kami [Isma'il bin Zakariya`] telah menceritakan kepada kami ['Ashim] dia berkata; saya bertanya kepada [Anas bin Malik]; \"Apakah telah sampai kepadamu bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak ada perjanjian menjalin persahabatan dalam Islam?\" Anas menjawab; \"Sungguh Nabi shallallahu 'alaihi wasallam pernah menjalin persahabatan antara orang Quraisy dan orang-orang Anshar di rumahku.\""},"5315":{"ar":"حَدَّثَنَا حِبَّانُ بْنُ مُوسَى أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رِفَاعَةَ الْقُرَظِيَّ طَلَّقَ امْرَأَتَهُ فَبَتَّ طَلَاقَهَا فَتَزَوَّجَهَا بَعْدَهُ عَبْدُ الرَّحْمَنِ بْنُ الزَّبِيرِ فَجَاءَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّهَا كَانَتْ عِنْدَ رِفَاعَةَ فَطَلَّقَهَا آخِرَ ثَلَاثِ تَطْلِيقَاتٍ فَتَزَوَّجَهَا بَعْدَهُ عَبْدُ الرَّحْمَنِ بْنُ الزَّبِيرِ وَإِنَّهُ وَاللَّهِ مَا مَعَهُ يَا رَسُولَ اللَّهِ إِلَّا مِثْلُ هَذِهِ الْهُدْبَةِ لِهُدْبَةٍ أَخَذَتْهَا مِنْ جِلْبَابِهَا قَالَ وَأَبُو بَكْرٍ جَالِسٌ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَابْنُ سَعِيدِ بْنِ الْعَاصِ جَالِسٌ بِبَابِ الْحُجْرَةِ لِيُؤْذَنَ لَهُ فَطَفِقَ خَالِدٌ يُنَادِي أَبَا بَكْرٍ يَا أَبَا بَكْرٍ أَلَا تَزْجُرُ هَذِهِ عَمَّا تَجْهَرُ بِهِ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا يَزِيدُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى التَّبَسُّمِ ثُمَّ قَالَ لَعَلَّكِ تُرِيدِينَ أَنْ تَرْجِعِي إِلَى رِفَاعَةَ لَا حَتَّى تَذُوقِي عُسَيْلَتَهُ وَيَذُوقَ عُسَيْلَتَكِ","id":"Telah menceritakan kepada kami [Hibban bin Musa] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Urwah] dari [Aisyah] radliallahu 'anha bahwa Rifa'ah Al Qaradli telah menceraikan isterinya setelah perceraiannya berlalu, Abdurrahman bin Zubair menikahi isterinya Rifa'ah. Lalu isterinya Rifa'ah datang kepada Nabi shallaallahu'alaihi wa sallam, Aisyah melanjutkan; \"Wahai Rasulullah! Sesungguhnya wanita tersebut adalah isterinya Rifa'ah, Rifa'ah menceraikannya hingga jatuh talak tiga. Setelah itu, isterinya Rifa'ah menikah dengan Abdurrahman bin Az Zubair. Dan dia, demi Allah wahai Raulullah, tidaklah bersamanya melainkan seperti ujung kain yang ini.\" -sambil mengambil ujung jilbabnya- Urwah melanjutkan; \"waktu itu Abu Bakar duduk di sisi Nabi shallaallahu 'alaihi wa sallam sementara Khalid bin Sa'id duduk di depan pintu kamar, supaya ia diizinkan masuk, segera ia memanggil Abu Bakar dan berkata; \"Wahai Abu Bakar, apakah kamu tidak menghardik apa yang telah ia katakan dengan lancang di sisi Rasulullah shallallahu 'alaihi wasallam?\" Rasulullah shallaallahu'alaihi wa sallam tersenyum seraya bersabda: \"Sepertinya engkau hendak kembali kepada Rifa'ah. Tidak, hingga engkau merasakan madunya Abdurrahman bin Az Zubair dan dia merasakan madumu.\""},"5316":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا إِبْرَاهِيمُ عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ الْحَمِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ زَيْدِ بْنِ الْخَطَّابِ عَنْ مُحَمَّدِ بْنِ سَعْدٍ عَنْ أَبِيهِ قَالَاسْتَأْذَنَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدَهُ نِسْوَةٌ مِنْ قُرَيْشٍ يَسْأَلْنَهُ وَيَسْتَكْثِرْنَهُ عَالِيَةً أَصْوَاتُهُنَّ عَلَى صَوْتِهِ فَلَمَّا اسْتَأْذَنَ عُمَرُ تَبَادَرْنَ الْحِجَابَ فَأَذِنَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَخَلَ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَضْحَكُ فَقَالَ أَضْحَكَ اللَّهُ سِنَّكَ يَا رَسُولَ اللَّهِ بِأَبِي أَنْتَ وَأُمِّي فَقَالَ عَجِبْتُ مِنْ هَؤُلَاءِ اللَّاتِي كُنَّ عِنْدِي لَمَّا سَمِعْنَ صَوْتَكَ تَبَادَرْنَ الْحِجَابَ فَقَالَ أَنْتَ أَحَقُّ أَنْ يَهَبْنَ يَا رَسُولَ اللَّهِ ثُمَّ أَقْبَلَ عَلَيْهِنَّ فَقَالَ يَا عَدُوَّاتِ أَنْفُسِهِنَّ أَتَهَبْنَنِي وَلَمْ تَهَبْنَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْنَ إِنَّكَ أَفَظُّ وَأَغْلَظُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِيهٍ يَا ابْنَ الْخَطَّابِ وَالَّذِي نَفْسِي بِيَدِهِ مَا لَقِيَكَ الشَّيْطَانُ سَالِكًا فَجًّا إِلَّا سَلَكَ فَجًّا غَيْرَ فَجِّكَ","id":"Telah menceritakan kepada kami [Isma'il] telah menceritakan kepada kami [Ibrahim] dari [Shalih bin Kaisan] dari [Ibnu Syihab] dari [Abdul Hamid bin Abdurrahman bin Zaid bin Al Khatthab] dari [Muhammad bin Sa'd] dari [Ayahnya] dia berkata; \"Umar bin Khatthab radliallahu 'anhu pernah meminta izin kepada Rasulullah shallallahu 'alaihi wasallam, (saat itu) di dekat beliau ada beberapa wanita Quraisy yang sedang berbicara panjang lebar dan bertanya kepada beliau dengan suara yang lantang. Ketika Umar meminta izin kepada beliau, mereka segera berhijab (bersembunyi di balik tabir), lalu Nabi shallallahu 'alaihi wasallam mempersilahkan Umar untuk masuk. Ketika Umar masuk Rasulullah shallallahu 'alaihi wasallam tertawa sehingga Umar berkata; \"Demi ayah dan ibuku, apa yang membuat anda tertawa wahai Rasulullah?\" Beliau bersabda; \"Aku heran dengan mereka yang ada di sisiku, ketika mendengar suaramu mereka segera berhijab.\" Umar berkata; \"Anda adalah orang yang lebih patut untuk disegani wahai Rasulullah!. Kemudian Umar menghadapkan ke arah wanita tersebut dan berkata; \"Wahai para wanita yang menjadi musuh bagi hawa nafsunya sendiri, apakah kalian segan denganku sementara kalian tidak segan kepada Rasulullah shallallahu 'alaihi wasallam?\" Kami pun menjawab; \"Karena kamu adalah orang yang lebih keras dan lebih kaku dari Rasulullah shallallahu 'alaihi wasallam.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Biarlah wahai Ibnul Khatthab, demi Dzat yang jiwaku ada di tangan-Nya, selamanya syetan tidak akan bertemu denganmu di satu jalan yang kamu lewati melainkan syetan akan melewati jalan selain jalanmu.\""},"5317":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ أَبِي الْعَبَّاسِ عَنْ ابْنِ عُمَرَ قَالَلَمَّا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالطَّائِفِ قَالَ إِنَّا قَافِلُونَ غَدًا إِنْ شَاءَ اللَّهُ فَقَالَ نَاسٌ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا نَبْرَحُ أَوْ نَفْتَحَهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاغْدُوا عَلَى الْقِتَالِ قَالَ فَغَدَوْا فَقَاتَلُوهُمْ قِتَالًا شَدِيدًا وَكَثُرَ فِيهِمْ الْجِرَاحَاتُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّا قَافِلُونَ غَدًا إِنْ شَاءَ اللَّهُ قَالَ فَسَكَتُوا فَضَحِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ بِالْخَبَرِ كُلِّهِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Sufyan] dari ['Amru] dari [Abu 'Abbas] dari [Ibnu Umar] dia berkata; \"Ketika Rasulullah shallallahu 'alaihi wasallam berada di Tha`if (mengepung penduduk Tha`if), beliau bersabda: \"Insya Allah besok kita akan kembali pulang.\" Para sahabat bertanya; \"Kami tidak akan berhenti (mengepung) atau kita akan menaklukkannya?\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Kalau begitu, pergilah kalian besok pagi untuk memerangi mereka.\" Keesokan harinya mereka berangkat dan berperang dengan peperangan yang dahsyat sehingga mereka banyak yang terluka. Lantas Rasulullah shallallahu 'alaihi wasallam bersabda: \"Besok kita akan kembali pulang.\" Abdullah bin 'Amru berkata; \"Merekapun diam dan Rasulullah shallallahu 'alaihi wasallam tertawa.\" [Al Humaidi] berkata; telah menceritakan kepada kami [Sufyan] dengan semua cerita hadits tersebut.\""},"5318":{"ar":"حَدَّثَنَا مُوسَى حَدَّثَنَا إِبْرَاهِيمُ أَخْبَرَنَا ابْنُ شِهَابٍ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَأَتَى رَجُلٌ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هَلَكْتُ وَقَعْتُ عَلَى أَهْلِي فِي رَمَضَانَ قَالَ أَعْتِقْ رَقَبَةً قَالَ لَيْسَ لِي قَالَ فَصُمْ شَهْرَيْنِ مُتَتَابِعَيْنِ قَالَ لَا أَسْتَطِيعُ قَالَ فَأَطْعِمْ سِتِّينَ مِسْكِينًا قَالَ لَا أَجِدُ فَأُتِيَ بِعَرَقٍ فِيهِ تَمْرٌ قَالَ إِبْرَاهِيمُ الْعَرَقُ الْمِكْتَلُ فَقَالَ أَيْنَ السَّائِلُ تَصَدَّقْ بِهَا قَالَ عَلَى أَفْقَرَ مِنِّي وَاللَّهِ مَا بَيْنَ لَابَتَيْهَا أَهْلُ بَيْتٍ أَفْقَرُ مِنَّا فَضَحِكَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى بَدَتْ نَوَاجِذُهُ قَالَ فَأَنْتُمْ إِذًا","id":"Telah menceritakan kepada kami [Musa] telah menceritakan kepada kami [Ibrahim] telah mengabarkan kepada kami [Ibnu Syihab] dari [Humaid bin Abdurrahman] bahwa [Abu Hurairah] radliallahu 'anhu dia berkata; \"Seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam sambil berkata; \"Celaka aku, aku telah menyetubuhi isteriku di (siang) bulan Ramadhan.\" Beliau lalu bersabda: \"Merdekakanlah seorang budak.\" Laki-laki itu berkata; \"Aku tidak mampu untuk itu.\" Beliau bersabda: \"Berpuasalah dua bulan berturut-turut.\" Ia berkata, \"Aku tidak sanggup, \" beliau bersabda: \"Berilah makan enam puluh orang miskin.\" Ia berkata, \"Aku tidak mampu, \" lalu beliau memberinya keranjang yang berisi kurma.\" -Ibrahim berkata; Al Araq adalah al Miktal (sebanding antara lima belas hingga dua puluh sha') - Beliau lalu bersabda: \"Dimanakah laki-laki yang bertanya tadi? Pergi dan bersedekahlah dengan ini.\" Ia menjawab, \"Demi Allah, antara dua lembah ini tidak ada keluarga yang lebih membutuhkan ini kecuali kami.\" Lalu Nabi shallallahu 'alaihi wasallam tersenyum hingga kelihatan gigi gerahamnya, beliau lalu bersabda: \"Kalau begitu, berilah makan kepada keluargamu.\""},"5319":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ الْأُوَيْسِيُّ حَدَّثَنَا مَالِكٌ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكُنْتُ أَمْشِي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْهِ بُرْدٌ نَجْرَانِيٌّ غَلِيظُ الْحَاشِيَةِ فَأَدْرَكَهُ أَعْرَابِيٌّ فَجَبَذَ بِرِدَائِهِ جَبْذَةً شَدِيدَةً قَالَ أَنَسٌ فَنَظَرْتُ إِلَى صَفْحَةِ عَاتِقِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ أَثَّرَتْ بِهَا حَاشِيَةُ الرِّدَاءِ مِنْ شِدَّةِ جَبْذَتِهِ ثُمَّ قَالَ يَا مُحَمَّدُ مُرْ لِي مِنْ مَالِ اللَّهِ الَّذِي عِنْدَكَ فَالْتَفَتَ إِلَيْهِ فَضَحِكَ ثُمَّ أَمَرَ لَهُ بِعَطَاءٍ","id":"Telah menceritakan kepada kami [Abdul Aziz bin Abdullah Al Uwaisi] telah menceritakan kepada kami [Malik] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik] dia berkata; \"Saya berjalan bersama Rasulullah Shallallahu'alaihi wa Sallam, ketika itu beliau mengenakan kain (selimut) Najran yang tebal ujungnya, lalu ada seorang Arab badui (dusun) yang menemui beliau. Langsung ditariknya Rasulullah dengan kuat, Anas melanjutkan; \"Hingga saya melihat permukaan bahu beliau membekas lantaran ujung selimut akibat tarikan Arab badui yang kasar. Arab badui tersebut berkata; \"Wahai Muhammad berikan kepadaku dari harta yang diberikan Allah padamu\", maka beliau menoleh kepadanya diiringi senyum serta menyuruh salah seorang sahabat untuk memberikan sesuatu kepadanya.\""},"5320":{"ar":"حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا ابْنُ إِدْرِيسَ عَنْ إِسْمَاعِيلَ عَنْ قَيْسٍ عَنْ جَرِيرٍ قَالَمَا حَجَبَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُنْذُ أَسْلَمْتُ وَلَا رَآنِي إِلَّا تَبَسَّمَ فِي وَجْهِي وَلَقَدْ شَكَوْتُ إِلَيْهِ أَنِّي لَا أَثْبُتُ عَلَى الْخَيْلِ فَضَرَبَ بِيَدِهِ فِي صَدْرِي وَقَالَ اللَّهُمَّ ثَبِّتْهُ وَاجْعَلْهُ هَادِيًا مَهْدِيًّا","id":"Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Ibnu Idris] dari [Isma'il] dari [Qais] dari [Jarir] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam tidak pernah menghalangiku semenjak aku memeluk Islam dan tidaklah dia melihatku kecuali tersenyum. Aku telah mengadukan kepadanya, bahwa aku tidak kokoh berada di atas kuda, maka beliau menepukkan tangannya ke dadaku seraya berdoa: \"Ya Allah, kokohkan dia dan jadikanlah dia petunjuk lagi pemberi petunjuk.\""},"5321":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى عَنْ هِشَامٍ قَالَ أَخْبَرَنِي أَبِي عَنْ زَيْنَبَ بِنْتِ أُمِّ سَلَمَةَ عَنْ أُمِّ سَلَمَةَأَنَّ أُمَّ سُلَيْمٍ قَالَتْ يَا رَسُولَ اللَّهِ إِنَّ اللَّهَ لَا يَسْتَحِي مِنْ الْحَقِّ هَلْ عَلَى الْمَرْأَةِ غُسْلٌ إِذَا احْتَلَمَتْ قَالَ نَعَمْ إِذَا رَأَتْ الْمَاءَ فَضَحِكَتْ أُمُّ سَلَمَةَ فَقَالَتْ أَتَحْتَلِمُ الْمَرْأَةُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبِمَ شَبَهُ الْوَلَدِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Yahya] dari [Hisyam] dia berkata; telah mengabarkan kepadaku [Ayahku] dari [Zainab binti Ummu Salamah] dari [Ummu Salamah] bahwa Ummu Sulaim berkata; \"Wahai Rasulullah, sesungguhnya Allah tidak malu sedikitpun dari kebenaran, apakah seorang wanita wajib mandi jika ia ihtilam (mimpi basah atau bersenggama)?\" beliau menjawab: \"Ya, jika ia melihat cairan (keluar).\" Maka Ummu Salamah tersenyum dan berkata; \"Apakah wanita juga ihtilam (mimpi basah)?\" Nabi shallallahu 'alaihi wasallam pun bersabda: \"Darimanakah seorang anak itu mirip (dengan orang tuanya)?\""},"5322":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سُلَيْمَانَ قَالَ حَدَّثَنِي ابْنُ وَهْبٍ أَخْبَرَنَا عَمْرٌو أَنَّ أَبَا النَّضْرِ حَدَّثَهُ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْمَا رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُسْتَجْمِعًا قَطُّ ضَاحِكًا حَتَّى أَرَى مِنْهُ لَهَوَاتِهِ إِنَّمَا كَانَ يَتَبَسَّمُ","id":"Telah menceritakan kepada kami [Yahya bin Sulaiman] dia berkata; telah menceritakan kepadaku [Ibnu Wahb] telah mengabarkan kepada kami ['Amru] bahwa [Abu Nadlr] telah menceritakan kepadanya, dari [Sulaiman bin Yasar] dari [Aisyah] radliallahu 'anha dia berkata; \"Saya tidak pernah melihat Rasulullah shallallahu 'alaihi wasallam tertawa terbahak-bahak hingga terlihat langit-langit dalam mulutnya, beliau hanya biasa tersenyum.\""},"5323":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَحْبُوبٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍ ح و قَالَ لِي خَلِيفَةُ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُأَنَّ رَجُلًا جَاءَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْجُمُعَةِ وَهُوَ يَخْطُبُ بِالْمَدِينَةِ فَقَالَ قَحَطَ الْمَطَرُ فَاسْتَسْقِ رَبَّكَ فَنَظَرَ إِلَى السَّمَاءِ وَمَا نَرَى مِنْ سَحَابٍ فَاسْتَسْقَى فَنَشَأَ السَّحَابُ بَعْضُهُ إِلَى بَعْضٍ ثُمَّ مُطِرُوا حَتَّى سَالَتْ مَثَاعِبُ الْمَدِينَةِ فَمَا زَالَتْ إِلَى الْجُمُعَةِ الْمُقْبِلَةِ مَا تُقْلِعُ ثُمَّ قَامَ ذَلِكَ الرَّجُلُ أَوْ غَيْرُهُ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ فَقَالَ غَرِقْنَا فَادْعُ رَبَّكَ يَحْبِسْهَا عَنَّا فَضَحِكَ ثُمَّ قَالَ اللَّهُمَّ حَوَالَيْنَا وَلَا عَلَيْنَا مَرَّتَيْنِ أَوْ ثَلَاثًا فَجَعَلَ السَّحَابُ يَتَصَدَّعُ عَنْ الْمَدِينَةِ يَمِينًا وَشِمَالًا يُمْطَرُ مَا حَوَالَيْنَا وَلَا يُمْطِرُ مِنْهَا شَيْءٌ يُرِيهِمْ اللَّهُ كَرَامَةَ نَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِجَابَةَ دَعْوَتِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Mahbub] telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Anas]. Dan di riwayatkan dari jalur lain, [Khalifah] pernah berkata kepadaku; telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Anas] radliallahu 'anhu bahwa seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam, ketika beliau tengah berkhutbah Jum'at di Madinah, laki-laki itu berkata; \"Sudah sekian lama hujan tidak turun, maka mintalah hujan kepada Rabbmu!\" lalu Nabi Shallallahu'alaihi wasallam melihat ke langit, dan tidak terlihat banyak awan. Lalu beliau beristisqa' (meminta hujan turun), tiba-tiba awan bermunculan dan saling menyatu antara satu dengan yang lain, hingga hujan pun turun dan mengalirlah aliran-aliran air di Madinah. Hal ini berlangsung sampai Jumat berikutnya dan tidak terhenti. Kemudian laki-laki tersebut atau yang lainnya berdiri saat Nabi shallallahu 'alaihi wasallam tengah berkhutbah, katanya; \"Kami semua telah kebanjiran, maka berdo'alah kepada Rabbmu supaya menahan hujan dari kami\". Beliaupun tersenyum kemudian berdo'a: \"Ya Allah, turunkanlah (hujan) di sekitar kami dan bukan pada kami\". Hingga dua atau tiga kali, maka awan-awan pun bergeser dari Madinah ke arah kanan dan kiri, menghujani di sekitarnya dan tidak turun di Madinah sedikitpun, ternyata Allah hendak memperlihatkan karomah kepada Nabi-Nya shallallahu 'alaihi wasallam dan mengabulkan do'anya.\""},"5324":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الصِّدْقَ يَهْدِي إِلَى الْبِرِّ وَإِنَّ الْبِرَّ يَهْدِي إِلَى الْجَنَّةِ وَإِنَّ الرَّجُلَ لَيَصْدُقُ حَتَّى يَكُونَ صِدِّيقًا وَإِنَّ الْكَذِبَ يَهْدِي إِلَى الْفُجُورِ وَإِنَّ الْفُجُورَ يَهْدِي إِلَى النَّارِ وَإِنَّ الرَّجُلَ لَيَكْذِبُ حَتَّى يُكْتَبَ عِنْدَ اللَّهِ كَذَّابًا","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Abu Wa`il] dari [Abdullah] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Sesungguhnya kejujuran akan membimbing pada kebaikan, dan kebaikan itu akan membimbing ke surga, sesungguhnya jika seseorang yang senantiasa berlaku jujur hingga ia akan dicatat sebagai orang yang jujur. Dan sesungguhnya kedustaan itu akan mengantarkan pada kejahatan, dan sesungguhnya kejahatan itu akan menggiring ke neraka. Dan sesungguhnya jika seseorang yang selalu berdusta sehingga akan dicatat baginya sebagai seorang pendusta.\""},"5325":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ سَلَامٍ حَدَّثَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ عَنْ أَبِي سُهَيْلٍ نَافِعِ بْنِ مَالِكِ بْنِ أَبِي عَامِرٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ آيَةُ الْمُنَافِقِ ثَلَاثٌ إِذَا حَدَّثَ كَذَبَ وَإِذَا وَعَدَ أَخْلَفَ وَإِذَا اؤْتُمِنَ خَانَ","id":"Telah menceritakan kepadaku [Muhammad bin Salam] telah menceritakan kepada kami [Isma'il bin Ja'far] dari [Abu Suhail Nafi' bin Malik bin Abu 'Amir] dari [Ayahnya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tanda-tanda orang munafik itu ada tiga, yaitu; jika berbicara berdusta, jika berjanji mengingkari dan jika dipercaya berkhianat.\""},"5326":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا جَرِيرٌ حَدَّثَنَا أَبُو رَجَاءٍ عَنْ سَمُرَةَ بْنِ جُنْدُبٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَيْتُ اللَّيْلَةَ رَجُلَيْنِ أَتَيَانِي قَالَا الَّذِي رَأَيْتَهُ يُشَقُّ شِدْقُهُ فَكَذَّابٌ يَكْذِبُ بِالْكَذْبَةِ تُحْمَلُ عَنْهُ حَتَّى تَبْلُغَ الْآفَاقَ فَيُصْنَعُ بِهِ إِلَى يَوْمِ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Jarir] telah menceritakan kepada kami [Abu Raja`] dari [Samurah bin Jundab] radliallahu 'anhu dia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Aku tadi malam bermimpi ada dua orang yang membawaku, keduanya berkata; \"Dan yang kamu lihat seseorang yang dirobek-robek mulutnya adalah seorang pendusta yang selalu berbicara dengan kedustaannya hingga dibawanya sampai ke ufuk (cakrawala) sana, dan ia selalu seperti itu hingga datang hari Kiamat.\""},"5327":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ قَالَ قُلْتُ لِأَبِي أُسَامَةَ أَحَدَّثَكُمْ الْأَعْمَشُ سَمِعْتُ شَقِيقًا قَالَ سَمِعْتُ حُذَيْفَةَ يَقُولُإِنَّ أَشْبَهَ النَّاسِ دَلًّا وَسَمْتًا وَهَدْيًا بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَابْنُ أُمِّ عَبْدٍ مِنْ حِينِ يَخْرُجُ مِنْ بَيْتِهِ إِلَى أَنْ يَرْجِعَ إِلَيْهِ لَا نَدْرِي مَا يَصْنَعُ فِي أَهْلِهِ إِذَا خَلَا","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] dia berkata; saya berkata kepada [Abu Usamah]; Apakah [Al A'masy] pernah menceritakan kepada kalian? Yaitu; saya mendengar [Syaqiq] dia berkata; saya mendengar [Hudzaifah] berkata; \"Orang yang paling mirip Rasulullah shallallahu 'alaihi wasallam dari perilaku dan sifatnya adalah Ibnu Ummi 'Abd (Ibnu Mas'ud), semenjak dia keluar dari rumahnya sampai dia kembali (ke rumahnya) hingga kami tidak mengetahui apa yang diperbuat bersama isterinya.\""},"5328":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ مُخَارِقٍ سَمِعْتُ طَارِقًا قَالَ قَالَ عَبْدُ اللَّهِإِنَّ أَحْسَنَ الْحَدِيثِ كِتَابُ اللَّهِ وَأَحْسَنَ الْهَدْيِ هَدْيُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari [Muhariq] saya mendengar [Thariq] berkata; [Abdullah] berkata; \"Sesungguhnya sebaik-baik ucapan adalah kitabullah, dan sebaik-baik petunjuk adalah petunjuk Muhammad shallallahu 'alaihi wasallam.\""},"5329":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سُفْيَانَ قَالَ حَدَّثَنِي الْأَعْمَشُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ عَنْ أَبِي مُوسَى رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ أَحَدٌ أَوْ لَيْسَ شَيْءٌ أَصْبَرَ عَلَى أَذًى سَمِعَهُ مِنْ اللَّهِ إِنَّهُمْ لَيَدْعُونَ لَهُ وَلَدًا وَإِنَّهُ لَيُعَافِيهِمْ وَيَرْزُقُهُمْ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sufyan] dia berkata; telah menceritakan kepadaku [Al A'masy] dari [Sa'id bin Jubair] dari [Abu Abdurrahman As Sulami] dari [Abu Musa] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Tidak ada siapa pun atau tidak ada sesuatu pun yang lebih bersabar atas gangguan yang ia dengar melebihi Allah, Sesungguhnya mereka menganggap Dia punya anak namun Dia memaafkan dan memberi mereka rizki.\""},"5330":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ قَالَ سَمِعْتُ شَقِيقًا يَقُولُ قَالَ عَبْدُ اللَّهِقَسَمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِسْمَةً كَبَعْضِ مَا كَانَ يَقْسِمُ فَقَالَ رَجُلٌ مِنْ الْأَنْصَارِ وَاللَّهِ إِنَّهَا لَقِسْمَةٌ مَا أُرِيدَ بِهَا وَجْهُ اللَّهِ قُلْتُ أَمَّا أَنَا لَأَقُولَنَّ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَيْتُهُ وَهُوَ فِي أَصْحَابِهِ فَسَارَرْتُهُ فَشَقَّ ذَلِكَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَتَغَيَّرَ وَجْهُهُ وَغَضِبَ حَتَّى وَدِدْتُ أَنِّي لَمْ أَكُنْ أَخْبَرْتُهُ ثُمَّ قَالَ قَدْ أُوذِيَ مُوسَى بِأَكْثَرَ مِنْ ذَلِكَ فَصَبَرَ","id":"Telah menceritakan kepada kami [Umar bin Hafsh] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Al A'masy] dia berkata; saya mendengar [Syaqiq] berkata; [Abdullah] berkata; \"Nabi shallallahu 'alaihi wasallam pernah membagikan sesuatu sebagaimana sebagian (mendapatkan) pembagian dari beliau, tiba-tiba seorang laki-laki dari Anshar berkata; \"Demi Allah, sepertinya pembagian ini tidak untuk mencari ridla Allah.\" maka aku pun berkata (dalam hati); \"Sungguh aku akan melaporkannya kepada Nabi shallallahu 'alaihi wasallam, lalu aku mendatangi beliau ketika beliau berada bersama para sahabatnya, kemudian aku mengatakannya dengan suara pelan, Nabi shallallahu 'alaihi wasallam pun merasa berat hati hingga wajahnya berubah karena marah, sampai aku berharap jika tadi aku tidak jadi memberitahukan kepada beliau, kemudian belaiu bersabda: \"Sungguh Musa juga pernah disakiti lebih daripada ini namun dia tetap bersabar.\""},"5331":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا مُسْلِمٌ عَنْ مَسْرُوقٍ قَالَتْ عَائِشَةُصَنَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا فَرَخَّصَ فِيهِ فَتَنَزَّهَ عَنْهُ قَوْمٌ فَبَلَغَ ذَلِكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَطَبَ فَحَمِدَ اللَّهَ ثُمَّ قَالَ مَا بَالُ أَقْوَامٍ يَتَنَزَّهُونَ عَنْ الشَّيْءِ أَصْنَعُهُ فَوَاللَّهِ إِنِّي لَأَعْلَمُهُمْ بِاللَّهِ وَأَشَدُّهُمْ لَهُ خَشْيَةً","id":"Telah menceritakan kepada kami [Umar bin Hafsh] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Al A'masy] telah menceritakan kepada kami [Muslim] dari [Masruq], [Aisyah] berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah membuat sesuatu yang diperbolehkan bagi beliau, namun anehnya ada beberapa orang sahabat yang mengingkarinya (tidak mau menerimanya). Ketika berita itu sampai kepada Nabi shallallahu 'alaihi wasallam, Maka beliau berkhutbah, setelah memuji Allah beliau bersabda: \"Apa alasan mereka itu mengingkari sesuatu yang aku buat, demi Allah, aku adalah manusia yang paling mengenal Allah dan paling takut kepada-Nya.\""},"5332":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا شُعْبَةُ عَنْ قَتَادَةَ سَمِعْتُ عَبْدَ اللَّهِ هُوَ ابْنُ أَبِي عُتْبَةَ مَوْلَى أَنَسٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَشَدَّ حَيَاءً مِنْ الْعَذْرَاءِ فِي خِدْرِهَا فَإِذَا رَأَى شَيْئًا يَكْرَهُهُ عَرَفْنَاهُ فِي وَجْهِهِ","id":"Telah menceritakan kepada kami [Abdan] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Syu'bah] dari [Qatadah] saya mendengar [Abdullah yaitu Ibnu Abu 'Utbah] bekas budak Anas, dari [Abu Sa'id Al Khudri] dia berkata; Nabi shallallahu 'alaihi wasallam adalah sosok yang lebih pemalu daripada seorang gadis yang dipingit dalam rumah, apabila beliau melihat sesuatu yang tidak disukainya, maka kami akan mengetahui dari raut muka beliau.\""},"5333":{"ar":"حَدَّثَنَا مُحَمَّدٌ وَأَحْمَدُ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا عَلِيُّ بْنُ الْمُبَارَكِ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قَالَ الرَّجُلُ لِأَخِيهِ يَا كَافِرُ فَقَدْ بَاءَ بِهِ أَحَدُهُمَاوَقَالَ عِكْرِمَةُ بْنُ عَمَّارٍ عَنْ يَحْيَى عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ سَمِعَ أَبَا سَلَمَةَ سَمِعَ أَبَا هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad] dan [Ahmad bin Sa'id] keduanya berkata; telah mengabarkan kepada kami [Utsman bin Umar] telah mengabarkan kepada kami [Ali bin Mubarrak] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Abu Hurairah] radliallahu 'anhu bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila seseorang berkata kepada saudaranya; \"Wahai kafir\" maka bisa jadi akan kembali kepada salah satu dari keduanya.\" [Ikrimah bin 'Ammar] berkata; dari [Yahya] dari [Abdullah bin Yazid] dia mendengar [Abu Salamah] mendengar [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam.\""},"5334":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيُّمَا رَجُلٍ قَالَ لِأَخِيهِ يَا كَافِرُ فَقَدْ بَاءَ بِهَا أَحَدُهُمَا","id":"Telah menceritakan kepada kami [Ismail] katanya; telah menceritakan kepadaku [Malik] dari [Abdullah bin Dinar] dari [Abdullah bin Umar] radliallahu 'anhuma bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa saja yang berkata kepada saudaranya; \"Wahai Kafir\" maka bisa jadi akan kembali kepada salah satu dari keduanya.\""},"5335":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ عَنْ ثَابِتِ بْنِ الضَّحَّاكِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَلَفَ بِمِلَّةٍ غَيْرِ الْإِسْلَامِ كَاذِبًا فَهُوَ كَمَا قَالَ وَمَنْ قَتَلَ نَفْسَهُ بِشَيْءٍ عُذِّبَ بِهِ فِي نَارِ جَهَنَّمَ وَلَعْنُ الْمُؤْمِنِ كَقَتْلِهِ وَمَنْ رَمَى مُؤْمِنًا بِكُفْرٍ فَهُوَ كَقَتْلِهِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Ayyub] dari [Abu Qilabah] dari [Tsabit bin Adl Dlahak] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Barangsiapa bersumpah dengan selain agama Islam secara dusta, maka dia seperti apa yang dia katakan, barangsiapa bunuh diri dengan sesuatu di dunia, maka dia akan disiksa di neraka Jahannam dengan sesuatu yang ia pergunakan untuk bunuh diri, barangsiapa melaknat seorang muslim maka ia seperti membunuhnya dan barangsiapa menuduh seorang muslim dengan kekafiran maka ia seperti membunuhnya.\""},"5336":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبَادَةَ أَخْبَرَنَا يَزِيدُ أَخْبَرَنَا سَلِيمٌ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ حَدَّثَنَا جَابِرُ بْنُ عَبْدِ اللَّهِأَنَّ مُعَاذَ بْنَ جَبَلٍ رَضِيَ اللَّهُ عَنْهُ كَانَ يُصَلِّي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ يَأْتِي قَوْمَهُ فَيُصَلِّي بِهِمْ الصَّلَاةَ فَقَرَأَ بِهِمْ الْبَقَرَةَ قَالَ فَتَجَوَّزَ رَجُلٌ فَصَلَّى صَلَاةً خَفِيفَةً فَبَلَغَ ذَلِكَ مُعَاذًا فَقَالَ إِنَّهُ مُنَافِقٌ فَبَلَغَ ذَلِكَ الرَّجُلَ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّا قَوْمٌ نَعْمَلُ بِأَيْدِينَا وَنَسْقِي بِنَوَاضِحِنَا وَإِنَّ مُعَاذًا صَلَّى بِنَا الْبَارِحَةَ فَقَرَأَ الْبَقَرَةَ فَتَجَوَّزْتُ فَزَعَمَ أَنِّي مُنَافِقٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا مُعَاذُ أَفَتَّانٌ أَنْتَ ثَلَاثًا اقْرَأْ وَالشَّمْسِ وَضُحَاهَا وَسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَنَحْوَهَا","id":"Telah menceritakan kepada kami [Muhammad bin Abdah] telah mengabarkan kepada kami [Yazid] telah mengabarkan kepada kami [Salim] telah menceritakan kepada kami ['Amru bin Dinar] telah menceritakan kepada kami [Jabir bin Abdullah] bahwa Mu'adz bin Jabal radliallahu 'anhu pernah shalat (dibelakang) Rasulullah shallallahu 'alaihi wasallam, kemudian dia kembali ke kaumnya untuk mengimami shalat bersama mereka dengan membaca surat Al Baqarah, Jabir melanjutkan; \"Maka seorang laki-laki pun keluar (dari shaf) lalu ia shalat dengan shalat yang agak ringan, ternyata hal itu sampai kepada Mu'adz, ia pun berkata; \"Sesungguhnya dia adalah seorang munafik.\" Ketika ucapan Mu'adz sampai ke laki-laki tersebut, laki-laki itu langsung mendatangi Nabi shallallahu 'alaihi wasallam sambil berkata; \"Wahai Rasulullah, sesungguhnya kami adalah kaum yang memiliki pekerjaan untuk menyiram ladang, sementara semalam Mu'adz shalat mengimami kami dengan membaca surat Al Baqarah, hingga saya keluar dari shaf, lalu dia mengiraku seorang munafik.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Wahai Mu'adz, apakah kamu hendak membuat fitnah.\" -Beliau mengucapkannya hingga tiga kali- bacalah Was syamsi wadluhaaha dan wasabbih bismirabbikal a'la atau yang serupa dengannya.\""},"5337":{"ar":"حَدَّثَنِي إِسْحَاقُ أَخْبَرَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنَا الزُّهْرِيُّ عَنْ حُمَيْدٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ مِنْكُمْ فَقَالَ فِي حَلِفِهِ بِاللَّاتِ وَالْعُزَّى فَلْيَقُلْ لَا إِلَهَ إِلَّا اللَّهُ وَمَنْ قَالَ لِصَاحِبهِ تَعَالَ أُقَامِرْكَ فَلْيَتَصَدَّقْ","id":"Telah menceritakan kepadaku [Ishaq] telah mengabarkan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Al Auza'i] telah menceritakan kepada kami [Az Zuhri] dari [Humaid] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa salah seorang dari kalian bersumpah, dan dalam sumpahnya berkata demi Lata dan Uzza, hendaknya ia segera mengatakan; \"Laa ilaaha illallah (tiada ilah yang berhak di sembah kecuali Allah), dan barangsiapa berkata kepada saudaranya; \"kemarilah kita main judi\" hendaknya ia segera bersedekah.\""},"5338":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا لَيْثٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّهُ أَدْرَكَ عُمَرَ بْنَ الْخَطَّابِ فِي رَكْبٍ وَهُوَ يَحْلِفُ بِأَبِيهِ فَنَادَاهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا إِنَّ اللَّهَ يَنْهَاكُمْ أَنْ تَحْلِفُوا بِآبَائِكُمْ فَمَنْ كَانَ حَالِفًا فَلْيَحْلِفْ بِاللَّهِ وَإِلَّا فَلْيَصْمُتْ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Laits] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhuma bahwa dia pernah mendapati Umar ketika di atas tunggangannya bersumpah dengan nenek moyangnya, lalu Rasulullah shallallahu 'alaihi wasallam menyeru kepada orang-orang: \"Sesungguhnya Allah melarang kalian bersumpah dengan bapak-bapak kalian, barangsiapa bersumpah hendaknya ia bersumpah dengan nama Allah atau kalau tidak, lebih baik ia diam.\""},"5339":{"ar":"حَدَّثَنَا يَسَرَةُ بْنُ صَفْوَانَ حَدَّثَنَا إِبْرَاهِيمُ عَنْ الزُّهْرِيِّ عَنْ الْقَاسِمِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْدَخَلَ عَلَيَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفِي الْبَيْتِ قِرَامٌ فِيهِ صُوَرٌ فَتَلَوَّنَ وَجْهُهُ ثُمَّ تَنَاوَلَ السِّتْرَ فَهَتَكَهُ وَقَالَتْ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ أَشَدِّ النَّاسِ عَذَابًا يَوْمَ الْقِيَامَةِ الَّذِينَ يُصَوِّرُونَ هَذِهِ الصُّوَرَ","id":"Telah menceritakan kepada kami [Yasrah bin Shafwan] telah menceritakan kepada kami [Ibrahim] dari [Az Zuhri] dari [Al Qasim] dari [Aisyah] radliallahu 'anha dia berkata; Nabi shallallahu 'alaihi wasallam masuk menemuiku, sementara di dalam rumah terdapat kain pembatas (satir) yang bergambar, maka rona wajah beliau berubah, beliau langsung mengambil satir tersebut dan memotongnya.\" Aisyah melanjutkan; \"Lalu beliau bersabda: \"Sesungguhnya orang-orang yang paling keras siksaannya pada hari Kiamat adalah orang yang menggambar gambar seperti ini.\""},"5340":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ إِسْمَاعِيلَ بْنِ أَبِي خَالِدٍ حَدَّثَنَا قَيْسُ بْنُ أَبِي حَازِمٍ عَنْ أَبِي مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُ قَالَأَتَى رَجُلٌ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي لَأَتَأَخَّرُ عَنْ صَلَاةِ الْغَدَاةِ مِنْ أَجْلِ فُلَانٍ مِمَّا يُطِيلُ بِنَا قَالَ فَمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَطُّ أَشَدَّ غَضَبًا فِي مَوْعِظَةٍ مِنْهُ يَوْمَئِذٍ قَالَ فَقَالَ يَا أَيُّهَا النَّاسُ إِنَّ مِنْكُمْ مُنَفِّرِينَ فَأَيُّكُمْ مَا صَلَّى بِالنَّاسِ فَلْيَتَجَوَّزْ فَإِنَّ فِيهِمْ الْمَرِيضَ وَالْكَبِيرَ وَذَا الْحَاجَةِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Isma'il bin Abu Khalid] telah menceritakan kepada kami [Qais bin Abu Hazim] dari [Abu Mas'ud] radliallahu 'anhu dia berkata; \"Seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam sambil berkata; \"Sesungguhnya aku akan mengakhirkan shalat shubuh karena fulan yang memanjangkan (bacaannya).\" Abu Mas'ud berkata; \"Maka aku tidak pernah melihat Rasulullah shallallahu 'alaihi wasallam sangat marah dalam menyampaikan nasihatnya melebihi marahnya beliau pada hari itu, Abu Mas'ud melanjutkan; \"Lalu beliau bersbada: \"Wahai sekalian manusia, sesungguhnya di antara kalian ada yang menjadikan orang-orang lari (dari keta'atan), barangsiapa di antara kalian shalat dengan orang banyak, hendaklah ia memperingan shalatnya, sebab di antara mereka ada orang yang lemah, orang yang sudah lanjut usia dan orang yang mempunyai keperluan.\""},"5341":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا جُوَيْرِيَةُ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَبَيْنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي رَأَى فِي قِبْلَةِ الْمَسْجِدِ نُخَامَةً فَحَكَّهَا بِيَدِهِ فَتَغَيَّظَ ثُمَّ قَالَ إِنَّ أَحَدَكُمْ إِذَا كَانَ فِي الصَّلَاةِ فَإِنَّ اللَّهَ حِيَالَ وَجْهِهِ فَلَا يَتَنَخَّمَنَّ حِيَالَ وَجْهِهِ فِي الصَّلَاةِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Juwairiyah] dari [Nafi'] dari [Abdullah] radliallahu 'anhu dia berkata; \"Ketika Nabi shallallahu 'alaihi wasallam shalat, beliau melihat ludah di arah Qiblat Masjid, kemudian beliau mengeruknya dan menutupinya, lalu beliau bersabda: \"Apabila salah seorang dari kalian sedang shalat, maka sesungguhnya Allah berada di hadapannya, karena itu janganlah ia meludah ke hadapannya ketika mengerjakan shalat.\""},"5342":{"ar":"حَدَّثَنَا مُحَمَّدٌ حَدَّثَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ أَخْبَرَنَا رَبِيعَةُ بْنُ أَبِي عَبْدِ الرَّحْمَنِ عَنْ يَزِيدَ مَوْلَى الْمُنْبَعِثِ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّأَنَّ رَجُلًا سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ اللُّقَطَةِ فَقَالَ عَرِّفْهَا سَنَةً ثُمَّ اعْرِفْ وِكَاءَهَا وَعِفَاصَهَا ثُمَّ اسْتَنْفِقْ بِهَا فَإِنْ جَاءَ رَبُّهَا فَأَدِّهَا إِلَيْهِ قَالَ يَا رَسُولَ اللَّهِ فَضَالَّةُ الْغَنَمِ قَالَ خُذْهَا فَإِنَّمَا هِيَ لَكَ أَوْ لِأَخِيكَ أَوْ لِلذِّئْبِ قَالَ يَا رَسُولَ اللَّهِ فَضَالَّةُ الْإِبِلِ قَالَ فَغَضِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى احْمَرَّتْ وَجْنَتَاهُ أَوْ احْمَرَّ وَجْهُهُ ثُمَّ قَالَ مَا لَكَ وَلَهَا مَعَهَا حِذَاؤُهَا وَسِقَاؤُهَا حَتَّى يَلْقَاهَا رَبُّهَا","id":"Telah menceritakan kepada kami [Muhammad] telah menceritakan kepada kami [Isma'il bin Ja'far] telah mengabarkan kepada kami [Rabi'ah bin Abu Abdurrahman] dari [Yazid] bekas budak Al Munba'its, dari [Zaid bin Khalid Al Juhani] bahwa seseorang bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang barang temuan, beliau menjawab: \"Umumkanlah selama setahun, lalu kenalilah wadah dan talinya, (sementara waktu) kamu boleh memanfa'atkannya, apabila pemiliknya datang, maka berikanlah barang tersebut kepadanya.\" Orang itu bertanya lagi; \"Wahai Rasulullah, bagaimana dengan kambing yang hilang?\". Beliau menjawab; \"Ambillah, mungkin ia dapat menjadi milikmu atau milik saudaramu atau bahkan menjadi milik serigala.\" Dia bertanya lagi; \"Wahai Rasulullah, bagaimana dengan temuan unta?\" Zaid bin Khalid berkata; \"Maka Rasulullah shallallahu 'alaihi wasallam marah hingga wajahnya memerah atau rona wajahnya menjadi merah, kemudian beliau bersabda: \"Apa urusanmu dengan unta yang hilang?, biarkanlah ia, karena ia telah membawa sepatu dan wadah airnya sendiri hingga bertemu pemiliknya.\""},"5343":{"ar":"وَقَالَ الْمَكِّيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ ح و حَدَّثَنِي مُحَمَّدُ بْنُ زِيَادٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنِي سَالِمٌ أَبُو النَّضْرِ مَوْلَى عُمَرَ بْنِ عُبَيْدِ اللَّهِ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ زَيْدِ بْنِ ثَابِتٍ رَضِيَ اللَّهُ عَنْهُ قَالَاحْتَجَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُجَيْرَةً مُخَصَّفَةً أَوْ حَصِيرًا فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِيهَا فَتَتَبَّعَ إِلَيْهِ رِجَالٌ وَجَاءُوا يُصَلُّونَ بِصَلَاتِهِ ثُمَّ جَاءُوا لَيْلَةً فَحَضَرُوا وَأَبْطَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْهُمْ فَلَمْ يَخْرُجْ إِلَيْهِمْ فَرَفَعُوا أَصْوَاتَهُمْ وَحَصَبُوا الْبَابَ فَخَرَجَ إِلَيْهِمْ مُغْضَبًا فَقَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا زَالَ بِكُمْ صَنِيعُكُمْ حَتَّى ظَنَنْتُ أَنَّهُ سَيُكْتَبُ عَلَيْكُمْ فَعَلَيْكُمْ بِالصَّلَاةِ فِي بُيُوتِكُمْ فَإِنَّ خَيْرَ صَلَاةِ الْمَرْءِ فِي بَيْتِهِ إِلَّا الصَّلَاةَ الْمَكْتُوبَةَ","id":"Dan berkata [Al Makki]; telah menceritakan kepada kami [Abdullah bin Sa'id]. diriwayatkan dari jalur lain, telah menceritakan kepadaku [Muhammad bin Ziyad] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Abdullah bin Sa'id] dia berkata; telah menceritakan kepadaku [Salim bin Abu An Nadlr] bekas budak Umar bin 'Ubaidullah, dari [Busr bin Sa'id] dari [Zaid bin Tsabit] radliallahu 'anhu dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah membuat ruangan yang dibatasi dengan sehelai kain atau tikar di masjid, lalu Rasulullah shallallahu 'alaihi wasallam keluar dan melakukan shalat. kemudian orang-orang pun ikut melakukan shalat bersama beliau. Di malam berikutnya merekapun datang, namun Rasulullah shallallahu 'alaihi wasallam tidak kunjung keluar, sambil mengeraskan suara, mereka melempar pintu beliau dengan kerikil. Tidak lama kemudian Rasulullah shallallahu 'alaihi wasallam keluar menemui mereka dalam keadaan marah seraya bersabda: \"Masih saja kalian mengerjakannya (dengan berjama'ah), hingga aku mengira shalat tersebut akan diwajibkan atas kalian, hendaknya kalian melakukan shalat di rumah kalian, sesungguhnya sebaik-baik shalat seseorang adalah dirumahnya kecuali shalat wajib.\""},"5344":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ الشَّدِيدُ بِالصُّرَعَةِ إِنَّمَا الشَّدِيدُ الَّذِي يَمْلِكُ نَفْسَهُ عِنْدَ الْغَضَبِ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Sa'id bin Musayyib] dari [Abu Hurairah] radliallahu 'anhu bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah orang yang kuat adalah orang yang pandai bergulat, tapi orang yang kuat adalah orang yang dapat menahan nafsunya ketika ia marah.\""},"5345":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ عَدِيِّ بْنِ ثَابِتٍ حَدَّثَنَا سُلَيْمَانُ بْنُ صُرَدٍ قَالَاسْتَبَّ رَجُلَانِ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ عِنْدَهُ جُلُوسٌ وَأَحَدُهُمَا يَسُبُّ صَاحِبَهُ مُغْضَبًا قَدْ احْمَرَّ وَجْهُهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَأَعْلَمُ كَلِمَةً لَوْ قَالَهَا لَذَهَبَ عَنْهُ مَا يَجِدُ لَوْ قَالَ أَعُوذُ بِاللَّهِ مِنْ الشَّيْطَانِ الرَّجِيمِ فَقَالُوا لِلرَّجُلِ أَلَا تَسْمَعُ مَا يَقُولُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنِّي لَسْتُ بِمَجْنُونٍ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Adi bin Tsabit] telah menceritakan kepada kami [Sulaiman bin Shurd] dia berkata; \"Ada dua orang yang saling mencerca di samping Nabi shallallahu 'alaihi wasallam, sementara kami duduk-duduk di samping beliau, salah seorang darinya mencerca temannya sambil marah, hingga wajahnya memerah, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya saya mengetahui suatu kalimat yang apabila ia membacanya, niscaya kemarahannya akan hilang, sekiranya ia mengatakan; \"A'uudzubillahi minasy syaithaanir rajiim.\" Lalu orang-orang berkata kepada laki-laki itu; \"Apakah kamu tidak mendengar apa yang di katakan oleh Nabi shallallahu 'alaihi wasallam? Justru laki-laki itu menimpali; \"Sesungguhnya aku tidaklah gila.\""},"5346":{"ar":"حَدَّثَنِي يَحْيَى بْنُ يُوسُفَ أَخْبَرَنَا أَبُو بَكْرٍ هُوَ ابْنُ عَيَّاشٍ عَنْ أَبِي حَصِينٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَجُلًا قَالَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْصِنِي قَالَ لَا تَغْضَبْ فَرَدَّدَ مِرَارًا قَالَ لَا تَغْضَبْ","id":"Telah menceritakan kepadaku [Yahya bin Yusuf] telah mengabarkan kepada kami [Abu Bakr yaitu Ibnu Ayyasy] dari [Abu Hashin] dari [Abu Shalih] dari [Abu Hurairah] radliallahu 'anhu bahwa seorang laki-laki berkata kepada Nabi shallallahu 'alaihi wasallam; \"Berilah aku wasiat?\" beliau bersabda: \"Janganlah kamu marah.\" Laki-laki itu mengulangi kata-katanya, beliau tetap bersabda: \"Janganlah kamu marah.\""},"5347":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَبِي السَّوَّارِ الْعَدَوِيِّ قَالَ سَمِعْتُ عِمْرَانَ بْنَ حُصَيْنٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْحَيَاءُ لَا يَأْتِي إِلَّا بِخَيْرٍفَقَالَ بُشَيْرُ بْنُ كَعْبٍ مَكْتُوبٌ فِي الْحِكْمَةِ إِنَّ مِنْ الْحَيَاءِ وَقَارًا وَإِنَّ مِنْ الْحَيَاءِ سَكِينَةً فَقَالَ لَهُ عِمْرَانُ أُحَدِّثُكَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَتُحَدِّثُنِي عَنْ صَحِيفَتِكَ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Abu As Sawwar Al 'Adawi] dia berkata; saya mendengar ['Imran bin Hushain] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Sifat malu itu tidak datang kecuali dengan kebaikan.\" Maka Busyair bin Ka'b berkata; \"Telah tertulis dalam hikmah, sesungguhnya dari sifat malu itu terdapat ketenangan, sesungguhnya dari sifat malu itu terdapat ketentraman.\" Maka Imran berkata kepadanya; \"Aku menceritakan kepadamu dari Rasulullah shallallahu 'alaihi wasallam, sementara kamu menceritakan kepadaku dari catatanmu.\""},"5348":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي سَلَمَةَ حَدَّثَنَا ابْنُ شِهَابٍ عَنْ سَالِمٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَامَرَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى رَجُلٍ وَهُوَ يُعَاتِبُ أَخَاهُ فِي الْحَيَاءِ يَقُولُ إِنَّكَ لَتَسْتَحْيِي حَتَّى كَأَنَّهُ يَقُولُ قَدْ أَضَرَّ بِكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعْهُ فَإِنَّ الْحَيَاءَ مِنْ الْإِيمَانِ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Abdul Aziz bin Abu Salamah] telah menceritakan kepada kami [Ibnu Syihab] dari [Salim] dari [Abdullah bin Umar] radliallahu 'anhuma; \"Nabi shallallahu 'alaihi wasallam pernah melewati seorang laki-laki yang tengah mencela saudaranya karena malu, kata laki-laki itu; \"Sesungguhnya kamu selalu malu hingga hal itu akan membahayakan bagimu.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Biarkanlah ia, karena sesungguhnya sifat malu itu termasuk dari iman.\""},"5349":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْجَعْدِ أَخْبَرَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ مَوْلَى أَنَسٍ قَالَ أَبُو عَبْد اللَّهِ اسْمُهُ عَبْدُ اللَّهِ بْنُ أَبِي عُتْبَةَ سَمِعْتُ أَبَا سَعِيدٍ يَقُولُكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَشَدَّ حَيَاءً مِنْ الْعَذْرَاءِ فِي خِدْرِهَا","id":"Telah menceritakan kepada kami [Ali bin Al Ja'ad] telah mengabarkan kepada kami [Syu'bah] dari [Qatadah] dari [Bekas budak Anas], Abu Abdullah berkata; namanya adalah Abdullah bin Abu 'Utbah dia berkata; saya mendengar [Abu Sa'id] berkata; Nabi shallallahu 'alaihi wasallam lebih pemalu daripada seorang gadis pingitan yang dipingit di kamarnya.\""},"5350":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا مَنْصُورٌ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ حَدَّثَنَا أَبُو مَسْعُودٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِمَّا أَدْرَكَ النَّاسُ مِنْ كَلَامِ النُّبُوَّةِ الْأُولَى إِذَا لَمْ تَسْتَحْيِ فَاصْنَعْ مَا شِئْتَ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Manshur] dari [Rib'i bin Hirasy] telah menceritakan kepada kami [Abu Mas'ud] dia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya yang diperoleh manusia dari ucapan kenabian yang pertama adalah jika kamu tidak mempunyai rasa malu, maka berbuatlah sesukamu.\""},"5351":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ زَيْنَبَ بِنْتِ أَبِي سَلَمَةَ عَنْ أُمِّ سَلَمَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْجَاءَتْ أُمُّ سُلَيْمٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ اللَّهَ لَا يَسْتَحِي مِنْ الْحَقِّ فَهَلْ عَلَى الْمَرْأَةِ غُسْلٌ إِذَا احْتَلَمَتْ فَقَالَ نَعَمْ إِذَا رَأَتْ الْمَاءَ","id":"Telah menceritakan kepada kami [Isma'il] dia berkata; telah menceritakan kepadaku [Malik] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari [Zainab binti Abu Salamah] dari [Ummu Salamah] radliallahu 'anha dia berkata; \"Ummu Sulaim datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata; \"Wahai Rasulullah, sesungguhnya Allah tidak malu dari kebenaran, apakah seorang wanita wajib mandi jika ia ihtilam (mimpi basah)? Beliau bersabda: \"Ya, jika ia melihat air.\""},"5352":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا مُحَارِبُ بْنُ دِثَارٍ قَالَ سَمِعْتُ ابْنَ عُمَرَ يَقُولُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثَلُ الْمُؤْمِنِ كَمَثَلِ شَجَرَةٍ خَضْرَاءَ لَا يَسْقُطُ وَرَقُهَا وَلَا يَتَحَاتُّ فَقَالَ الْقَوْمُ هِيَ شَجَرَةُ كَذَا هِيَ شَجَرَةُ كَذَا فَأَرَدْتُ أَنْ أَقُولَ هِيَ النَّخْلَةُ وَأَنَا غُلَامٌ شَابٌّ فَاسْتَحْيَيْتُ فَقَالَ هِيَ النَّخْلَةُوَعَنْ شُعْبَةَ حَدَّثَنَا خُبَيْبُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ حَفْصِ بْنِ عَاصِمٍ عَنْ ابْنِ عُمَرَ مِثْلَهُ وَزَادَ فَحَدَّثْتُ بِهِ عُمَرَ فَقَالَ لَوْ كُنْتَ قُلْتَهَا لَكَانَ أَحَبَّ إِلَيَّ مِنْ كَذَا وَكَذَا","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Muharib bin Ditsar] dia berkata; saya mendengar [Ibnu Umar] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Perumpamaan seorang muslim bagaikan pohon hijau, daunnya tidak pernah berjatuhan dan berguguran.\" orang-orang pun menjawab; \"Ia adalah pohon ini, ia adalah pohon ini.\" Dan aku hendak menjawab; \"Itu adalah pohon kurma, karena waktu itu aku masih sangat muda, maka akupun malu menjawabnya.\" Kemudian beliau bersabda: \"Ia adalah pohon kurma.\" Dan dari [Syu'bah] telah menceritakan kepada kami [Khubaib bin Abdurrahman] dari [Hafsh bin 'Ashim] dari [Ibnu Umar] seperti hadits di atas, dia menambahkan; \"Lalu aku sampaikan kepada Umar (ayahnya), Umar pun berkata; \"Sekiranya kamu mengatakan hal itu, niscaya lebih aku sukai dari pada ini dan ini.\""},"5353":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا مَرْحُومٌ سَمِعْتُ ثَابِتًا أَنَّهُ سَمِعَ أَنَسًا رَضِيَ اللَّهُ عَنْهُ يَقُولُجَاءَتْ امْرَأَةٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَعْرِضُ عَلَيْهِ نَفْسَهَا فَقَالَتْ هَلْ لَكَ حَاجَةٌ فِيَّ فَقَالَتْ ابْنَتُهُ مَا أَقَلَّ حَيَاءَهَا فَقَالَ هِيَ خَيْرٌ مِنْكِ عَرَضَتْ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَفْسَهَا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Marhum] saya mendengar [Tsabit] bahwa dia mendengar [Anas] radliallahu 'anhu berkata; \"Seorang wanita datang kepada Nabi shallallahu 'alaihi wasallam menawarkan dirinya, katanya; \"Apakah engkau membutuhkanku?\" maka anak perempuan (Anas bin Malik) berkata; \"Alangkah sedikit malunya perempuan itu.\" Anas bin Malik berkata; \"Ia lebih baik darimu, dia tawarkan dirinya kepada Rasulullah shallallahu 'alaihi wasallam.\""},"5354":{"ar":"حَدَّثَنِي إِسْحَاقُ حَدَّثَنَا النَّضْرُ أَخْبَرَنَا شُعْبَةُ عَنْ سَعِيدِ بْنِ أَبِي بُرْدَةَ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَلَمَّا بَعَثَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمُعَاذَ بْنَ جَبَلٍ قَالَ لَهُمَا يَسِّرَا وَلَا تُعَسِّرَا وَبَشِّرَا وَلَا تُنَفِّرَا وَتَطَاوَعَا قَالَ أَبُو مُوسَى يَا رَسُولَ اللَّهِ إِنَّا بِأَرْضٍ يُصْنَعُ فِيهَا شَرَابٌ مِنْ الْعَسَلِ يُقَالُ لَهُ الْبِتْعُ وَشَرَابٌ مِنْ الشَّعِيرِ يُقَالُ لَهُ الْمِزْرُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ مُسْكِرٍ حَرَامٌ","id":"Telah menceritakan kepadaku [Ishaq] telah menceritakan kepada kami [An Nadlr] telah mengabarkan kepada kami [Syu'bah] dari [Sa'id bin Abu Burdah] dari [Ayahnya] dari [Kakeknya] dia berkata; \"Ketika beliau mengutusnya bersama Mu'adz bin Jabal, beliau bersabda kepada keduanya: \"Mudahkanlah setiap urusan dan janganlah kamu mempersulit, berilah kabar gembira dan jangan kamu membuatnya lari, dan bersatu padulah! Lantas Abu Musa berkata; \"Wahai Rasulullah, di daerah kami sering dibuat minuman dari rendaman madu yang biasa di sebut dengan Al Bit'u dan minuman dari rendaman gandum yang biasa di seut Al Mizru. Maka Rasulullah shallallahu 'alaihi wasallam menjawab: \"Setiap yang memabukkan adalah haram.\""},"5355":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي التَّيَّاحِ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسِّرُوا وَلَا تُعَسِّرُوا وَسَكِّنُوا وَلَا تُنَفِّرُوا","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] dari [Abu At Tayyah] dia berkata; saya mendengar [Anas bin Malik] radliallahu 'anhu berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Mudahkanlah setiap urusan dan janganlah kalian mempersulitnya, buatlah mereka tenang dan jangan membuat mereka lari.\""},"5356":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَنَّهَا قَالَتْمَا خُيِّرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ أَمْرَيْنِ قَطُّ إِلَّا أَخَذَ أَيْسَرَهُمَا مَا لَمْ يَكُنْ إِثْمًا فَإِنْ كَانَ إِثْمًا كَانَ أَبْعَدَ النَّاسِ مِنْهُ وَمَا انْتَقَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِنَفْسِهِ فِي شَيْءٍ قَطُّ إِلَّا أَنْ تُنْتَهَكَ حُرْمَةُ اللَّهِ فَيَنْتَقِمَ بِهَا لِلَّهِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Ibnu Syihab] dari [Urwah] dari [Aisyah] radliallahu 'anha bahwa dia berkata; \"Tidaklah Rasulullah shallallahu 'alaihi wasallam merasa bingung terhadap dua pilihan melainkan beliau akan memilih perkara yang lebih mudah (ringan) selama hal itu tidak mengandung dosa. Jika perkara itu mengandung dosa, maka beliau adalah orang yang paling menjauhkan diri dari padanya. Dan tidaklah Rasulullah shallallahu 'alaihi wasallam marah terhadap suatu perkara, melainkan bila beliau melihat larangan Allah dilanggar, maka beliau akan marah karena Allah.\""},"5357":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ الْأَزْرَقِ بْنِ قَيْسٍ قَالَكُنَّا عَلَى شَاطِئِ نَهَرٍ بِالْأَهْوَازِ قَدْ نَضَبَ عَنْهُ الْمَاءُ فَجَاءَ أَبُو بَرْزَةَ الْأَسْلَمِيُّ عَلَى فَرَسٍ فَصَلَّى وَخَلَّى فَرَسَهُ فَانْطَلَقَتْ الْفَرَسُ فَتَرَكَ صَلَاتَهُ وَتَبِعَهَا حَتَّى أَدْرَكَهَا فَأَخَذَهَا ثُمَّ جَاءَ فَقَضَى صَلَاتَهُ وَفِينَا رَجُلٌ لَهُ رَأْيٌ فَأَقْبَلَ يَقُولُ انْظُرُوا إِلَى هَذَا الشَّيْخِ تَرَكَ صَلَ��تَهُ مِنْ أَجْلِ فَرَسٍ فَأَقْبَلَ فَقَالَ مَا عَنَّفَنِي أَحَدٌ مُنْذُ فَارَقْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ إِنَّ مَنْزِلِي مُتَرَاخٍ فَلَوْ صَلَّيْتُ وَتَرَكْتُهُ لَمْ آتِ أَهْلِي إِلَى اللَّيْلِ وَذَكَرَ أَنَّهُ قَدْ صَحِبَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَأَى مِنْ تَيْسِيرِهِ","id":"Telah menceritakan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] dari [Al Azraq bin Qais] dia berkata; \"Kami pernah berada di tepi sungai di Ahwaz yang airnya sedikit mengering, tiba-tiba [Abu Barzah Al Aslami] datang dengan mengendarai kuda, lalu dia mengerjakan shalat dengan membiarkan kudanya, tiba-tiba kudanya kabur, dia pun membatalkan shalatnya untuk mengejar kudanya yang kabur hingga ia dapat menangkapnya lagi, kemudian dia kembali untuk mengqadla' shalatnya. Ternyata di antara kami ada seorang laki-laki yang memiliki pikiran (lain), ia lalu menghadap dan berkata; \"Lihatlah orang tua ini, ia meninggalkan (membatalkan) shalatnya karena seekor kuda.\" Setelah itu Abu Barzah menemuinya dan berkata; \"Tidak ada seorang pun yang sangat mencelaku semenjak saya berpisah dengan Rasulullah shallallahu 'alaihi wasallam, \" katanya selanjutnya; \"Sesungguhnya tempat tinggalku sangatlah jauh, sekiranya aku shalat dan membiarkan kudaku, niscaya aku pulang ke keluarga sampai larut malam.\" Dan Al Azraq menyebutkan bahwa dia telah menemani Rasulullah shallallahu 'alaihi wasallam dan ikut berperang bersama beliau.\""},"5358":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ وَقَالَ اللَّيْثُ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّ أَبَا هُرَيْرَةَ أَخْبَرَهُأَنَّ أَعْرَابِيًّا بَالَ فِي الْمَسْجِدِ فَثَارَ إِلَيْهِ النَّاسُ ليَقَعُوا بِهِ فَقَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعُوهُ وَأَهْرِيقُوا عَلَى بَوْلِهِ ذَنُوبًا مِنْ مَاءٍ أَوْ سَجْلًا مِنْ مَاءٍ فَإِنَّمَا بُعِثْتُمْ مُيَسِّرِينَ وَلَمْ تُبْعَثُوا مُعَسِّرِينَ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri], [Al Laits] berkata; telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab] telah mengabarkan kepadaku ['Ubaidullah bin Abdullah bin 'Utbah] bahwa [Abu Hurairah] telah mengabarkan kepadanya; Seorang Arab badui kencing di Masjid, maka orang-orang pun segera menuju kepadanya dan menghardiknya, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda kepada mereka: \"Biarkanlah dia, dan guyurlah air kencingnya dengan seember air, hanyasanya kalian diutus untuk memudahkan bukan untuk mempersulit.\""},"5359":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا أَبُو التَّيَّاحِ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ يَقُولُإِنْ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيُخَالِطُنَا حَتَّى يَقُولَ لِأَخٍ لِي صَغِيرٍ يَا أَبَا عُمَيْرٍ مَا فَعَلَ النُّغَيْرُ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Abu At Tayyah] dia berkata; saya mendengar [Anas bin Malik] radliallahu 'anhu berkata; \"Nabi shallallahu 'alaihi wasallam biasa bergaul dengan kami, hingga beliau bersabda kepada saudaraku yang kecil: \"Wahai Abu Umair, apa yang dilakukan oleh Nughair (nama burung)?\""},"5360":{"ar":"حَدَّثَنَا مُحَمَّدٌ أَخْبَرَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكُنْتُ أَلْعَبُ بِالْبَنَاتِ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ لِي صَوَاحِبُ يَلْعَبْنَ مَعِي فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلَ يَتَقَمَّعْنَ مِنْهُ فَيُسَرِّبُهُنَّ إِلَيَّ فَيَلْعَبْنَ مَعِي","id":"Telah menceritakan kepada kami [Muhammad] telah mengabarkan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Hisyam] dari [Ayahnya] dari [Aisyah] radliallahu 'anha dia berkata; \"Aku pernah bermain bersama anak-anak perempuan di dekat Nabi shallallahu 'alaihi wasallam, dan aku juga mempunyai teman-teman yang biasa bermain denganku, apabila Rasulullah shallaallahu'alaihi wa sallam masuk, mereka bersembunyi dari beliau. Sehingga beliau memanggil mereka supaya bermain bersamaku.\""},"5361":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ الْمُنْكَدِرِ حَدَّثَهُ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ أَنَّ عَائِشَةَ أَخْبَرَتْهُأَنَّهُ اسْتَأْذَنَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ فَقَالَ ائْذَنُوا لَهُ فَبِئْسَ ابْنُ الْعَشِيرَةِ أَوْ بِئْسَ أَخُو الْعَشِيرَةِ فَلَمَّا دَخَلَ أَلَانَ لَهُ الْكَلَامَ فَقُلْتُ لَهُ يَا رَسُولَ اللَّهِ قُلْتَ مَا قُلْتَ ثُمَّ أَلَنْتَ لَهُ فِي الْقَوْلِ فَقَالَ أَيْ عَائِشَةُ إِنَّ شَرَّ النَّاسِ مَنْزِلَةً عِنْدَ اللَّهِ مَنْ تَرَكَهُ أَوْ وَدَعَهُ النَّاسُ اتِّقَاءَ فُحْشِهِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Sufyan] dari [Ibnu Al Munkadir] dia menceritakan dari ['Urwah bin Zubair] bahwa [Aisyah] telah mengabarkan kepadanya, bahwa seorang laki-laki meminta izin kepada Nabi Shallalahu 'alaihi wa sallam, beliau lalu bersabda: \"Izinkanlah dia masuk, amat buruklah Ibnu 'Asyirah (maksudnya kabilah) atau amat buruklah Suadara 'Asyirah (maksudnya kabilah).\" Ketika orang itu masuk, beliau berbicara kepadanya dengan suara yang lembut, lalu aku bertanya; \"Wahai Rasulullah, anda berkata seperti ini dan ini, namun setelah itu anda berbicara dengannya dengan suara yang lembut, Maka beliau bersabda: \"Wahai 'A`isyah, sesungguhnya seburuk-buruk kedudukan manusia di sisi Allah pada hari kiamat adalah orang yang ditinggalkan oleh manusia karena takut akan kejahatannya.\""},"5362":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الْوَهَّابِ أَخْبَرَنَا ابْنُ عُلَيَّةَ أَخْبَرَنَا أَيُّوبُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي مُلَيْكَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُهْدِيَتْ لَهُ أَقْبِيَةٌ مِنْ دِيبَاجٍ مُزَرَّرَةٌ بِالذَّهَبِ فَقَسَمَهَا فِي نَاسٍ مِنْ أَصْحَابِهِ وَعَزَلَ مِنْهَا وَاحِدًا لِمَخْرَمَةَ فَلَمَّا جَاءَ قَالَ قَدْ خَبَأْتُ هَذَا لَكَقَالَ أَيُّوبُ بِثَوْبِهِ وَأَنَّهُ يُرِيهِ إِيَّاهُ وَكَانَ فِي خُلُقِهِ شَيْءٌ رَوَاهُ حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ وَقَالَ حَاتِمُ بْنُ وَرْدَانَ حَدَّثَنَا أَيُّوبُ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ الْمِسْوَرِ قَدِمَتْ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْبِيَةٌ","id":"Telah menceritakan kepada kami [Abdullah bin Abdul Wahhab] telah mengabarkan kepada kami [Ibnu 'Ulayyah] telah mengabarkan kepada kami [Ayyub] dari [Abdullah bin Abu Mulaikah] bahwa Nabi shallallahu 'alaihi wasallam pernah diberi hadiah beberapa potong baju yang terbuat dari sutera dan berkancing emas lalu beliau membagi-bagikannya kepada para shahabat dan menyisakan satu potong untuk Makhramah. Ketika Makhramah datang beliau bersabda: \"Aku telah menyimpannya untukmu.\" Lalu Ayyub memperagakan bagaimana beliau memberikan kain tersebut kepada Makhramah, sedangkan dalam perangainya tersebut ada suatu (pelajaran).\" Hadits ini juga di riwayatkan [Hammad bin Zaid] dari [Ayyub]. Dan [Hatim bin Wardan] berkata; telah menceritakan kepada kami [Ayyub] dari [Ibnu Abu Mulaikah] dari [Miswar] bahwa Nabi shallallahu 'alaihi wasallam pernah di beri aqbiyah (sejenis mantel)...\""},"5363":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ الزُّهْرِيِّ عَنْ ابْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لَا يُلْدَغُ الْمُؤْمِنُ مِنْ جُحْرٍ وَاحِدٍ مَرَّتَيْنِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Az Zuhri] dari [Ibnu Al Musayyib] dari [Abu Hurairah] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam bahwa beliau bersabda: \"Orang mukmin tidak akan terperosok dua kali pada satu lobang.\""},"5364":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ مَنْصُورٍ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا حُسَيْنٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَلَمْ أُخْبَرْ أَنَّكَ تَقُومُ اللَّيْلَ وَتَصُومُ النَّهَارَ قُلْتُ بَلَى قَالَ فَلَا تَفْعَلْ قُمْ وَنَمْ وَصُمْ وَأَفْطِرْ فَإِنَّ لِجَسَدِكَ عَلَيْكَ حَقًّا وَإِنَّ لِعَيْنِكَ عَلَيْكَ حَقًّا وَإِنَّ لِزَوْرِكَ عَلَيْكَ حَقًّا وَإِنَّ لِزَوْجِكَ عَلَيْكَ حَقًّا وَإِنَّكَ عَسَى أَنْ يَطُولَ بِكَ عُمُرٌ وَإِنَّ مِنْ حَسْبِكَ أَنْ تَصُومَ مِنْ كُلِّ شَهْرٍ ثَلَاثَةَ أَيَّامٍ فَإِنَّ بِكُلِّ حَسَنَةٍ عَشْرَ أَمْثَالِهَا فَذَلِكَ الدَّهْرُ كُلُّهُ قَالَ فَشَدَّدْتُ فَشُدِّدَ عَلَيَّ فَقُلْتُ فَإِنِّي أُطِيقُ غَيْرَ ذَلِكَ قَالَ فَصُمْ مِنْ كُلِّ جُمُعَةٍ ثَلَاثَةَ أَيَّامٍ قَالَ فَشَدَّدْتُ فَشُدِّدَ عَلَيَّ قُلْتُ أُطِيقُ غَيْرَ ذَلِكَ قَالَ فَصُمْ صَوْمَ نَبِيِّ اللَّهِ دَاوُدَ قُلْتُ وَمَا صَوْمُ نَبِيِّ اللَّهِ دَاوُدَ قَالَ نِصْفُ الدَّهْرِ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] telah menceritakan kepada kami [Rauh bin 'Ubadah] telah menceritakan kepada kami [Husain] dari [Yahya bin Abu Katsir] dari [Abu Salamah bin Abdurrahman] dari [Abdullah bin 'Amru] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam menemuiku, lalu beliau bersabda: \"Aku memperoleh berita bahwa kamu bangun di malam hari dan berpuasa di siang hari, benarkah itu?\" Aku menjawab; \"Benar.\" Beliau bersabda: \"Jangan kamu lakukannya; namun tidur dan bangunlah, berpuasa dan berbukalah. Karena tubuhmu memiliki hak atas dirimu, kedua matamu memiliki hak atas dirimu, tamumu memiliki hak atas dirimu, istrimu memiliki hak atas dirimu. Sungguh, semoga panjang umur dan cukup bagimu berpuasa tiga hari dalam setiap bulan, dan suatu kebaikan akan dibalas dengan sepuluh kali lipatnya, itulah puasa Dahr.\" Abdullah bin 'Amru berkata; \"Aku bersikap keras dan beliau pun bersikap keras kepadaku, lalu kataku; \"Sungguh aku masih kuat melakukan lebih dari itu?\". Beliau bersabda: \"Berpuasalah tiga hari setiap Jum'at.\" Abdullah bin 'Amru berkata; \"Aku bersikap keras dan beliau pun bersikap keras kepadaku, lalu kataku; \"Sungguh aku masih kuat melakukan lebih dari itu?\" Beliau bersabda: \"Kalau begitu, berpuasalah seperti puasanya Nabiyullah Daud.\" Aku bertanya; \"Bagaimana puasa Nabiyullah Daud?\" Beliau bersabda: \"Yaitu puasa setengah zaman (sehari puasa sehari berbuka).\""},"5365":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي شُرَيْحٍ الْكَعْبِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيُكْرِمْ ضَيْفَهُ جَائِزَتُهُ يَوْمٌ وَلَيْلَةٌ وَالضِّيَافَةُ ثَلَاثَةُ أَيَّامٍ فَمَا بَعْدَ ذَلِكَ فَهُوَ صَدَقَةٌ وَلَا يَحِلُّ لَهُ أَنْ يَثْوِيَ عِنْدَهُ حَتَّى يُحْرِجَهُحَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ مِثْلَهُ وَزَادَ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيَقُلْ خَيْر��ا أَوْ لِيَصْمُتْ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Sa'id bin Abu Sa'id Al Maqburi] dari [Abu Suraih Al Ka'bi] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa beriman kepada Allah dan hari Akhir, hendaknya ia memuliakan tamunya dan menjamunya siang dan malam, dan bertamu itu tiga hari, lebih dari itu adalah sedekah baginya, tidak halal bagi tamu tinggal (bermalam) hingga (ahli bait) mengeluarkannya.\" Telah menceritakan kepada kami [Isma'il] dia berkata; telah menceritakan kepadaku [Malik] seperti hadits di atas, dia menambahkan; \"Barangsiapa beriman kepada Allah dan hari Akhir, hendaknya berkata baik atau diam.\""},"5366":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا ابْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي حَصِينٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلَا يُؤْذِ جَارَهُ وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيُكْرِمْ ضَيْفَهُ وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيَقُلْ خَيْرًا أَوْ لِيَصْمُتْ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] telah menceritakan kepada kami [Ibnu Mahdi] telah menceritakan kepada kami [Sufyan] dari [Abu Hashin] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Barangsiapa beriman kepada Allah dan hari Akhir, janganlah ia menyakiti tetangganya, barangsiapa beriman kepada Allah dan hari Akhir, hendaknya ia memuliakan tamunya, dan barangsiapa beriman kepada Allah dan hari Akhir, hendaknya ia berkata baik atau diam.\""},"5367":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ عُقْبَةَ بْنِ عَامِرٍ رَضِيَ اللَّهُ عَنْهُ أَنَّهُ قَالَقُلْنَا يَا رَسُولَ اللَّهِ إِنَّكَ تَبْعَثُنَا فَنَنْزِلُ بِقَوْمٍ فَلَا يَقْرُونَنَا فَمَا تَرَى فَقَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ نَزَلْتُمْ بِقَوْمٍ فَأَمَرُوا لَكُمْ بِمَا يَنْبَغِي لِلضَّيْفِ فَاقْبَلُوا فَإِنْ لَمْ يَفْعَلُوا فَخُذُوا مِنْهُمْ حَقَّ الضَّيْفِ الَّذِي يَنْبَغِي لَهُمْ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari [Abu Al Khair] dari ['Uqbah bin 'Amir] radliallahu 'anhu bahwa dia berkata; \"Kami bertanya; \"Wahai Rasulullah, sesungguhnya anda mengutus kami, lalu kami singgah di suatu kaum, namun mereka tidak melayani kami, bagaimana menurut anda?\" maka Rasulullah shallallahu 'alaihi wasallam bersabda kepada kami: \"Jika kalian singgah di suatu kaum, lalu mereka melayani kalian sebagaimana layaknya seorang tamu, maka terimalah layanan mereka. Jika mereka tidak melayani kalian, maka kalian boleh mengambil dari mereka hak tamu yang pantas mereka berikan.\""},"5368":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا هِشَامٌ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيُكْرِمْ ضَيْفَهُ وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيَصِلْ رَحِمَهُ وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيَقُلْ خَيْرًا أَوْ لِيَصْمُتْ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] telah menceritakan kepada kami [Hisyam] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Barangsiapa beriman kepada Allah dan hari Akhir, hendaknya ia memuliakan tamunya, dan barangsiapa beriman kepada Allah dan hari Akhir, hendaknya ia menyambung tali silaturrahmi, dan barangsiapa beriman kepada Allah dan hari Akhir, hendaknya ia berkata baik atau diam.\""},"5369":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ حَدَّثَنَا أَبُو الْعُمَيْسِ عَنْ عَوْنِ بْنِ أَبِي جُحَيْفَةَ عَنْ أَبِيهِ قَالَآخَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ سَلْمَانَ وَأَبِي الدَّرْدَاءِ فَزَارَ سَلْمَانُ أَبَا الدَّرْدَاءِ فَرَأَى أُمَّ الدَّرْدَاءِ مُتَبَذِّلَةً فَقَالَ لَهَا مَا شَأْنُكِ قَالَتْ أَخُوكَ أَبُو الدَّرْدَاءِ لَيْسَ لَهُ حَاجَةٌ فِي الدُّنْيَا فَجَاءَ أَبُو الدَّرْدَاءِ فَصَنَعَ لَهُ طَعَامًا فَقَالَ كُلْ فَإِنِّي صَائِمٌ قَالَ مَا أَنَا بِآكِلٍ حَتَّى تَأْكُلَ فَأَكَلَ فَلَمَّا كَانَ اللَّيْلُ ذَهَبَ أَبُو الدَّرْدَاءِ يَقُومُ فَقَالَ نَمْ فَنَامَ ثُمَّ ذَهَبَ يَقُومُ فَقَالَ نَمْ فَلَمَّا كَانَ آخِرُ اللَّيْلِ قَالَ سَلْمَانُ قُمْ الْآنَ قَالَ فَصَلَّيَا فَقَالَ لَهُ سَلْمَانُ إِنَّ لِرَبِّكَ عَلَيْكَ حَقًّا وَلِنَفْسِكَ عَلَيْكَ حَقًّا وَلِأَهْلِكَ عَلَيْكَ حَقًّا فَأَعْطِ كُلَّ ذِي حَقٍّ حَقَّهُ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ ذَلِكَ لَهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَقَ سَلْمَانُأَبُو جُحَيْفَةَ وَهْبٌ السُّوَائِيُّ يُقَالُ وَهْبُ الْخَيْرِ","id":"Telah menceritakan kepadaku [Muhammad bin Basyar] telah menceritakan kepada kami [Ja'far bin Aun] telah menceritakan kepada kami [Abu Al 'Umais] dari ['Aun bin Abu Juhaifah] dari [Ayahnya] dia berkata; Nabi shallallahu 'alaihi wasallam mempersaudarakan antara Salman dengan Abu Darda`, lalu Salman mengunjungi Abu Darda` dan melihat Ummu Darda' berpenampilan kusam, Salman pun bertanya; \"Kenapa denganmu?\" Ummu Darda` menjawab; \"Sesungguhnya saudaramu yaitu Abu Darda' tidak membutuhkan terhadap dunia sedikitpun, \" Ketika Abu Darda` tiba, dia membuatkan makanan untuk Salman lalu berkata; \"Makanlah karena aku sedang berpuasa.\" Salman menjawab; \"Saya tidak ingin makan hingga kamu ikut makan.\" Akhirnya Abu Darda' pun makan. Ketika tiba waktu malam, Abu Darda' beranjak untuk melaksanakan shalat namun Salman berkata kepadanya; \"Tidurlah.\" Abu Darda` pun tidur, tidak berapa lama kemudian dia beranjak untuk mengerjakan shalat, namun Salman tetap berkata; \"Tidurlah.\" akhirnya dia tidur.\" Ketika di akhir malam, Salman berkata kepadanya; \"Sekarang bangunlah, \" Abu Juhaifah berkata; \"Keduanya pun bangun dan melaksanakan shalat, setelah itu Salman berkata; \"Sesungguhnya Rabbmu memiliki hak atas dirimu, dan badanmu memiliki hak atas dirimu, isterimu memiliki hak atas dirimu, maka berikanlah haknya setiap yang memiliki hak.\" Selang beberapa saat Nabi shallallahu 'alaihi wasallam datang, lalu hal itu diberitahukan kepada beliau, Nabi shallallahu 'alaihi wasallam bersabda: \"Salman benar.\" Abu Juhaifah Wahb As Suwa`i biasa di sebut dengan Wahb Al Khair."},"5370":{"ar":"حَدَّثَنَا عَيَّاشُ بْنُ الْوَلِيدِ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا سَعِيدٌ الْجُرَيْرِيُّ عَنْ أَبِي عُثْمَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ أَبَا بَكْرٍ تَضَيَّفَ رَهْطًا فَقَالَ لِعَبْدِ الرَّحْمَنِ دُونَكَ أَضْيَافَكَ فَإِنِّي مُنْطَلِقٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَافْرُغْ مِنْ قِرَاهُمْ قَبْلَ أَنْ أَجِيءَ فَانْطَلَقَ عَبْدُ الرَّحْمَنِ فَأَتَاهُمْ بِمَا عِنْدَهُ فَقَالَ اطْعَمُوا فَقَالُوا أَيْنَ رَبُّ مَنْزِلِنَا قَالَ اطْعَمُوا قَالُوا مَا نَحْنُ بِآكِلِينَ حَتَّى يَجِيءَ رَبُّ مَنْزِلِنَا قَالَ اقْبَلُوا عَنَّا قِرَاكُمْ فَإِنَّهُ إِنْ جَاءَ وَلَمْ تَطْعَمُوا لَنَلْقَيَنَّ مِنْهُ فَأَبَوْا فَعَرَفْتُ أَنَّهُ يَجِدُ عَلَيَّ فَلَمَّا جَاءَ تَنَحَّيْتُ عَنْهُ فَقَالَ مَا صَنَعْتُمْ فَأَخْبَرُوهُ فَقَالَ يَا عَبْدَ الرَّحْمَنِ فَسَكَتُّ ثُمَّ قَالَ يَا عَبْدَ الرَّحْمَنِ فَسَكَتُّ فَقَالَ يَا غُنْثَرُ أَقْسَمْتُ عَلَيْكَ إِنْ كُنْتَ تَسْمَعُ صَوْتِي لَمَّا جِئْتَ فَخَرَجْتُ فَقُلْتُ سَلْ أَضْيَافَكَ فَقَالُوا صَدَقَ أَتَانَا بِهِ قَالَ فَإِنَّمَا انْتَظَرْتُمُونِي وَاللَّهِ لَا أَطْعَمُهُ اللَّيْلَةَ فَقَالَ الْآخَرُونَ وَاللَّهِ لَا نَطْعَمُهُ حَتَّى تَطْعَمَهُ قَالَ لَمْ أَرَ فِي الشَّرِّ كَاللَّيْلَةِ وَيْلَكُمْ مَا أَنْتُمْ لِمَ لَا تَقْبَلُونَ عَنَّا قِرَاكُمْ هَاتِ طَعَامَكَ فَجَاءَهُ فَوَضَعَ يَدَهُ فَقَالَ بِاسْمِ اللَّهِ الْأُولَى لِلشَّيْطَانِ فَأَكَلَ وَأَكَلُوا","id":"Telah menceritakan kepada kami [Ayyasy bin Al Walid] telah menceritakan kepada kami [Abdul A'la] telah menceritakan kepada kami [Sa'id Al Jurairi] dari [Abu Utsman] dari [Abdurrahman bin Abu Bakr] radliallahu 'anhuma bahwa Abu Bakar kedatangan tamu beberapa orang, lalu dia berkata kepada Abdurrahman; \"Layani tamu-tamumu dengan baik, karena aku hendak menemui Nabi shallallahu 'alaihi wasallam, pergilah untuk menjamu mereka sebelum aku kembali.\" Lantas Abdurrahman beranjak dan menjamu apa yang dia miliki kepada mereka, lalu dia berkata; \"Silahkan makan.\" Namun mereka berkata; \"Kemanakah tuan rumah?\" Abdurrahman berkata; \"Makanlah.\" Mereka tetap berkata; \"Kami tidak akan menyantap makanan sampai tuan rumah datang.\" Abdurrahman berkata; \"Terimalah jamuan kalian ini, karena bila ia datang, sedangkan kalian belum memakannya, dia akan membuangnya.\" Namun mereka tetap menolaknya, maka akupun tahu kalau Abu Bakr akan memarahiku, ketika dia datang, aku langsung menghidar darinya, Abu Bakr berkata; \"Apakah kalian telah memakannya?\" maka mereka mengabarinya (bahwa mereka belum menjamahnya), maka Abu Bakr menyeru; \"Wahai Abdurrahman?\" aku pun terdiam, kemudian dia berkata lagi; \"Wahai Abdurrahman?\" aku tetap diam, lalu dia berkata; \"Wahai Ghuntsar (sebutan untuk Abdurrahman), aku bersumpah kepadamu, jika kamu mendengar suaraku.\" Ketika aku datang dan keluar, aku langsung berkata; \"Tanyalah kepada para tamumu.\" Mereka pun menjawab; \"Dia benar, dia telah menyodorkannya kepada kami.\" Abu Bakr berkata; \"Apakah kalian menungguku?, demi Allah aku tidak akan makan malam ini.\" Dan yang lain pun menimpali; \"Demi Allah, kami tidak akan memakannya hingga kamu memakannya lebih dulu.\" Abu Bakr berkata; \"Aku sama sekali tidak pernah melihat keburukan seperti yang terjadi malam ini.' Celakalah kalian kenapa kalian tidak mau menerima hidangan kami? Berikanlah makananmu kepadaku, \" lalu disodorkanlah makanan tersebut kepadanya kemudian dia meletakkan di tangannya dan berkata; \"Dengan nama Allah, (sumpah) yang pertama adalah untuk syetan.\" Lalu Abu Bakr memakannya dan mereka pun ikut makan.\""},"5371":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ سُلَيْمَانَ عَنْ أَبِي عُثْمَانَ قَالَ عَبْدُ الرَّحْمَنِ بْنُ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُمَاجَاءَ أَبُو بَكْرٍ بِضَيْفٍ لَهُ أَوْ بِأَضْيَافٍ لَهُ فَأَمْسَى عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا جَاءَ قَالَتْ لَهُ أُمِّي احْتَبَسْتَ عَنْ ضَيْفِكَ أَوْ عَنْ أَضْيَافِكَ اللَّيْلَةَ قَالَ مَا عَشَّيْتِهِمْ فَقَالَتْ عَرَضْنَا عَلَيْهِ أَوْ عَلَيْهِمْ فَأَبَوْا أَوْ فَأَبَى فَغَضِبَ أَبُو بَكْرٍ فَسَبَّ وَجَدَّعَ وَحَلَفَ لَا يَطْعَمُهُ فَاخْتَبَأْتُ أَنَا فَقَالَ يَا غُنْثَرُ فَحَلَفَتْ الْمَرْأَةُ لَا تَطْعَمُهُ حَتَّى يَطْعَمَهُ فَحَلَفَ الضَّيْفُ أَوْ الْأَضْيَافُ أَنْ لَا يَطْعَمَهُ أَوْ يَطْعَمُوهُ حَتَّى يَطْعَمَهُ فَقَالَ أَبُو بَكْرٍ كَأَنَّ هَذِهِ مِنْ الشَّيْطَانِ فَدَعَا بِالطَّعَامِ فَأَكَلَ وَأَكَلُوا فَجَعَلُوا لَا يَرْفَعُونَ لُقْمَةً إِلَّا رَبَا مِنْ أَسْفَلِهَا أَكْثَرُ مِنْهَا فَقَالَ يَا أُخْتَ بَنِي فِرَاسٍ مَا هَذَا فَقَالَتْ وَقُرَّةِ عَيْنِي إِنَّهَا الْآنَ لَأَكْثَرُ قَبْلَ أَنْ نَأْكُلَ فَأَكَلُوا وَبَعَثَ بِهَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ أَنَّهُ أَكَلَ مِنْهَا","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Sulaiman] dari [Abu Utsman]. [Abdurrahman bin Abu Bakr] radliallahu 'anhu berkata; \"Abu Bakr kedatangan tamu atau kedatangan para tamu, sementara dia bersama Nabi shallallahu 'alaihi wasallam hingga larut malam, ketika dia kembali pulang, ibuku berkata kepadanya; \"Apa yang menghalangimu tidak menemui tamumu atau para tamumu semalam?\" dia berkata; \"Apakah kamu telah menjamu mereka?\" ibuku menjawab; \"Aku telah berusaha menjamunya atau menjamu mereka, namun mereka tetap menolaknya atau dia menolaknya.\" Abu Bakr pun marah, mencela dan mencaci serta bersumpah untuk tidak memberinya makan.\" Lalu aku pergi dan bersembunyi, dia berkata; \"Wahai Ghuntsar!\" maka isterinya pun bersumpah untuk tidak memakannya begitu juga dengan tamu atau para tamu yang bersumpah untuk tidak memakannya.\" Maka Abu Bakr berkata; \"Seakan-akan hal ini dari syetan.\" Abu Bakr pun meminta diambilkan makanan, lalu dia memakannya dan mereka juga ikut menyantapnya, anehnya tidaklah mereka mengambil sesuap (makanan) melainkan dari bawah makanan tersebut bertambah semakin banyak, maka Abu Bakr berkata; \"Wahai saudari Bani Firas, ada apa dengan ini?\" isterinya menjawab; \"Sungguh menjadi kesejukan pada hatiku, bahwa makanan tersebut sekarang lebih banyak sebelum kita memakannya.\" Maka para tamu pun ikut menyantapnya dan sebagiannya di kirimkan kepada Nabi shallallahu 'alaihi wasallam, dan Abdurrahman menyebutkan bahwa beliau juga ikut memakannya.\""},"5372":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادٌ هُوَ ابْنُ زَيْدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ بُشَيْرِ بْنِ يَسَارٍ مَوْلَى الْأَنْصَارِ عَنْ رَافِعِ بْنِ خَدِيجٍ وَسَهْلِ بْنِ أَبِي حَثْمَةَ أَنَّهُمَا حَدَّثَاهُأَنَّ عَبْدَ اللَّهِ بْنَ سَهْلٍ وَمُحَيِّصَةَ بْنَ مَسْعُودٍ أَتَيَا خَيْبَرَ فَتَفَرَّقَا فِي النَّخْلِ فَقُتِلَ عَبْدُ اللَّهِ بْنُ سَهْلٍ فَجَاءَ عَبْدُ الرَّحْمَنِ بْنُ سَهْلٍ وَحُوَيِّصَةُ وَمُحَيِّصَةُ ابْنَا مَسْعُودٍ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَكَلَّمُوا فِي أَمْرِ صَاحِبِهِمْ فَبَدَأَ عَبْدُ الرَّحْمَنِ وَكَانَ أَصْغَرَ الْقَوْمِ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَبِّرْ الْكُبْرَ قَالَ يَحْيَى يَعْنِي لِيَلِيَ الْكَلَامَ الْأَكْبَرُ فَتَكَلَّمُوا فِي أَمْرِ صَاحِبِهِمْ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَسْتَحِقُّونَ قَتِيلَكُمْ أَوْ قَالَ صَاحِبَكُمْ بِأَيْمَانِ خَمْسِينَ مِنْكُمْ قَالُوا يَا رَسُولَ اللَّهِ أَمْرٌ لَمْ نَرَهُ قَالَ فَتُبْرِئُكُمْ يَهُودُ فِي أَيْمَانِ خَمْسِينَ مِنْهُمْ قَالُوا يَا رَسُولَ اللَّهِ قَوْمٌ كُفَّارٌ فَوَدَاهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ قِبَلِهِ قَالَ سَهْلٌ فَأَدْرَكْتُ نَاقَةً مِنْ تِلْكَ الْإِبِلِ فَدَخَلَتْ مِرْبَدًا لَهُمْ فَرَكَضَتْنِي بِرِجْلِهَاقَالَ اللَّيْثُ حَدَّثَنِي يَحْيَى عَنْ بُشَيْرٍ عَنْ سَهْلٍ قَالَ يَحْيَى حَسِبْتُ أَنَّهُ قَالَ مَعَ رَافِعِ بْنِ خَدِيجٍ وَقَالَ ابْنُ عُيَيْنَةَ حَدَّثَنَا يَحْيَى عَنْ بُشَيْرٍ عَنْ سَهْلٍ وَحْدَهُ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad] yaitu Ibnu Zaid dari [Yahya bin Sa'id] dari [Busyair bin Yasar] bekas budak Anshar, dari [Rafi' bin Khadij] dan [Sahal bin Abu Hatsmah] bahwa keduanya menceritakan kepadanya bahwa Abdullah bin Sahal dan Muhayishah bin Mas'ud pergi ke Khaibar, kemudian keduanya berpisah di suatu kebun kurma, tiba-tiba Abdullah bin Sahal terbunuh, lantas Abdurrahman bin Sahl Huwayishah dan Muhayishah bin Mas'ud pergi menemui Nabi shallallahu 'alaihi wasallam untuk melapor mengenai perkara saudaranya, Abdurrahman angkat bicara padahal dia adalah orang yang paling muda di antara mereka, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Yang lebih tua, yang lebih tua.\" Yahya berkata; \"Maksudnya hendaknya yang paling tua yang lebih dulu angkat bicara.\" Lalu mereka melaporkan mengenai perkara saudaranya, lantas Nabi shallallahu 'alaihi wasallam bersabda: \"Hendaknya lima puluh orang dari kalian bersumpah atas satu orang dari mereka (Yahudi), maka kalian berhak menuntut darah sahabatmu.\" Mereka berkata; \"Perkara ini sama sekali belum pernah kami alami, bagaimana kami akan bersumpah?\" beliau bersabda: \"Jika demikian, orang-orang Yahudi telah terbebas dari tuduhanmu, dengan lima puluh orang dari mereka yang bersumpah.\" Mereka berkata; \"Wahai Rasulullah, mereka adalah orang-orang kafir.\" Kemudian Rasulullah shallallahu 'alaihi wasallam membayar diyat dari diri beliau sendiri kepada mereka.\" Sahal berkata; \"Maka saya dapati seekor unta dari unta-unta tersebut, lalu saya masukkan ke kandang unta mereka, tiba-tiba saya di tendang oleh kaki unta itu.\" [Laits] berkata; Telah menceritakan kepadaku [Yahya] dari [Busyair] dari [Sahal]. Yahya berkata; Aku mengira dia berkata bersama dengan Rafi' bin Khadij. [Ibnu 'Uyainah] berkata; Telah menceritakan kepada kami [Yahya] dari [Busyair] dari [Sahal] saja."},"5373":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبِرُونِي بِشَجَرَةٍ مَثَلُهَا مَثَلُ الْمُسْلِمِ تُؤْتِي أُكُلَهَا كُلَّ حِينٍ بِإِذْنِ رَبِّهَا وَلَا تَحُتُّ وَرَقَهَا فَوَقَعَ فِي نَفْسِي أَنَّهَا النَّخْلَةُ فَكَرِهْتُ أَنْ أَتَكَلَّمَ وَثَمَّ أَبُو بَكْرٍ وَعُمَرُ فَلَمَّا لَمْ يَتَكَلَّمَا قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هِيَ النَّخْلَةُ فَلَمَّا خَرَجْتُ مَعَ أَبِي قُلْتُ يَا أَبَتَاهُ وَقَعَ فِي نَفْسِي أَنَّهَا النَّخْلَةُ قَالَ مَا مَنَعَكَ أَنْ تَقُولَهَا لَوْ كُنْتَ قُلْتَهَا كَانَ أَحَبَّ إِلَيَّ مِنْ كَذَا وَكَذَا قَالَ مَا مَنَعَنِي إِلَّا أَنِّي لَمْ أَرَكَ وَلَا أَبَا بَكْرٍ تَكَلَّمْتُمَا فَكَرِهْتُ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] telah menceritakan kepadaku [Nafi'] dari [Ibnu Umar] radliallahu 'anhuma dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Beritahukanlah kepadaku suatu pohon yang perumpamaannya mirip seorang muslim, berbuah setiap saat dengan izin pemiliknya dan daunnya pun tidak pernah berguguran.\" Hatiku mengatakan bahwa pohon itu adalah pohon kurma, namun aku tidak berani mengatakannya apalagi disana terdapat Abu Bakr dan Umar, ketika keduanya tidak angkat bicara, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pohon itu adalah pohon kurma.\" Ketika aku keluar bersama ayahku, aku berkata; \"Wahai ayahku, tadi dalam hatiku mengatakan bahwa pohon itu adalah pohon kurma.\" Ayahku berkata; \"Kenapa kamu tidak menjawabnya! Sekiranya kamu menjawabnya, maka hal itu lebih aku sukai daripada ini dan ini.\" Abdullah berkata; \"Sebenarnya tidak ada yang mencegahku untuk menjawabnya melainkan aku melihatmu dan Abu Bakr tidak juga angkat bicara, maka aku tidak suka (mendahulinya).\""},"5374":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي أَبُو بَكْرِ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ مَرْوَانَ بْنَ الْحَكَمِ أَخْبَرَهُ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ الْأَسْوَدِ بْنِ عَبْدِ يَغُوثَ أَخْبَرَهُ أَنَّ أُبَيَّ بْنَ كَعْبٍ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ مِنْ الشِّعْرِ حِكْمَةً","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku [Abu Bakr bin Abdurrahman] bahwa [Marwan bin Hakam] telah mengabarkan kepadanya bahwa [Abdurrahman bin Al Aswad bin Abdu Yaghuts] telah mengabarkan kepadanya, bahwa [Ubay bin Ka'b] telah mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya dalam sya'ir itu terkandung hikmah.\""},"5375":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ الْأَسْوَدِ بْنِ قَيْسٍ سَمِعْتُ جُنْدَبًا يَقُولُبَيْنَمَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْشِي إِذْ أَصَابَهُ حَجَرٌ فَعَثَرَ فَدَمِيَتْ إِصْبَعُهُ فَقَالَ هَلْ أَنْتِ إِلَّا إِصْبَعٌ دَمِيتِوَفِي سَبِيلِ اللَّهِ مَا لَقِيتِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Al Aswad bin Qais] saya mendengar [Jundub] berkata; \"Tatkala Nabi shallallahu 'alaihi wasallam berjalan, tiba-tiba beliau tersandung batu kemudian beliau terjatuh hingga menyebabkan jari (kakinya) berdarah, lalu beliau bersabda: \"Bukankah engkau hanya sebatang jari yang berdarah? Dan ini terjadi ketika engkau ikut berjihad fi sabilillah.\""},"5376":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الْمَلِكِ حَدَّثَنَا أَبُو سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصْدَقُ كَلِمَةٍ قَالَهَا الشَّاعِرُ كَلِمَةُ لَبِيدٍ أَلَا كُلُّ شَيْءٍ مَا خَلَا اللَّهَ بَاطِلُوَكَادَ أُمَيَّةُ بْنُ أَبِي الصَّلْتِ أَنْ يُسْلِمَ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Ibnu Mahdi] telah menceritakan kepada kami [Sufyan] dari [Abdul Malik] telah menceritakan kepada kami [Abu Salamah] dari [Abu Hurairah] radliallahu 'anhu dia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Kalimat sya'ir paling benar yang pernah diucapkan oleh seorang penya'ir adalah kalimat Labid: Alaa, kullu syaiin maa khalallaha bathil (Ketahuilah, segala sesuatu selain Allah itu pasti binasa). Dan hampir saja Umayyah bin Abu Shalt masuk Islam.\""},"5377":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَاعِيلَ عَنْ يَزِيدَ بْنِ أَبِي عُبَيْدٍ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى خَيْبَرَ فَسِرْنَا لَيْلًا فَقَالَ رَجُلٌ مِنْ الْقَوْمِ لِعَامِرِ بْنِ الْأَكْوَعِ أَلَا تُسْمِعُنَا مِنْ هُنَيْهَاتِكَ قَالَ وَكَانَ عَامِرٌ رَجُلًا شَاعِرًا فَنَزَلَ يَحْدُو بِالْقَوْمِ يَقُولُ اللَّهُمَّ لَوْلَا أَنْتَ مَا اهْتَدَيْنَاوَلَا تَصَدَّقْنَا وَلَا صَلَّيْنَافَاغْفِرْ فِدَاءٌ لَكَ مَا اقْتَفَيْنَاوَثَبِّتْ الْأَقْدَامَ إِنْ لَاقَيْنَاوَأَلْقِيَنْ سَكِينَةً عَلَيْنَاإِنَّا إِذَا صِيحَ بِنَا أَتَيْنَاوَبِالصِّيَاحِ عَوَّلُوا عَلَيْنَافَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ هَذَا السَّائِقُ قَالُوا عَامِرُ بْنُ الْأَكْوَعِ فَقَالَ يَرْحَمُهُ اللَّهُ فَقَالَ رَجُلٌ مِنْ الْقَوْمِ وَجَبَتْ يَا نَبِيَّ اللَّهِ لَوْلَا أَمْتَعْتَنَا بِهِ قَالَ فَأَتَيْنَا خَيْبَرَ فَحَاصَرْنَاهُمْ حَتَّى أَصَابَتْنَا مَخْمَصَةٌ شَدِيدَةٌ ثُمَّ إِنَّ اللَّهَ فَتَحَهَا عَلَيْهِمْ فَلَمَّا أَمْسَى النَّاسُ الْيَوْمَ الَّذِي فُتِحَتْ عَلَيْهِمْ أَوْقَدُوا نِيرَانًا كَثِيرَةً فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا هَذِهِ النِّيرَانُ عَلَى أَيِّ شَيْءٍ تُوقِدُونَ قَالُوا عَلَى لَحْمٍ قَالَ عَلَى أَيِّ لَحْمٍ قَالُوا عَلَى لَحْمِ حُمُرٍ إِنْسِيَّةٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَهْرِقُوهَا وَاكْسِرُوهَا فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَوْ نُهَرِيقُهَا وَنَغْسِلُهَا قَالَ أَوْ ذَاكَ فَلَمَّا تَصَافَّ الْقَوْمُ كَانَ سَيْفُ عَامِرٍ فِيهِ قِصَرٌ فَتَنَاوَلَ بِهِ يَهُودِيًّا لِيَضْرِبَهُ وَيَرْجِعُ ذُبَابُ سَيْفِهِ فَأَصَابَ رُكْبَةَ عَامِرٍ فَمَاتَ مِنْهُ فَلَمَّا قَفَلُوا قَالَ سَلَمَةُ رَآنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَاحِبًا فَقَالَ لِي مَا لَكَ فَقُلْتُ فِدًى لَكَ أَبِي وَأُمِّي زَعَمُوا أَنَّ عَامِرًا حَبِطَ عَمَلُهُ قَالَ مَنْ قَالَهُ قُلْتُ قَالَهُ فُلَانٌ وَفُلَانٌ وَفُلَانٌ وَأُسَيْدُ بْنُ الْحُضَيْرِ الْأَنْصَارِيُّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَذَبَ مَنْ قَالَهُ إِنَّ لَهُ لَأَجْرَيْنِ وَجَمَعَ بَيْنَ إِصْبَعَيْهِ إِنَّهُ لَجَاهِدٌ مُجَاهِدٌ قَلَّ عَرَبِيٌّ نَشَأَ بِهَا مِثْلَهُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Hatim bin Isma'il] dari [Yazid bin Abu 'Ubaid] dari [Salamah bin Al Akwa'] dia berkata; \"Aku pernah keluar bersama Rasulullah shallallahu 'alaihi wasallam menuju Khaibar, maka kami mengadakan perjalanan di malam hari, seorang anggota pasukan dari suatu Kaum berkata kepada 'Amir bin Al Akwa'; \"Tidakkah kamu mau memperdengarkan kepada kami sajak-sajakmu? Salamah berkata; 'Amir memang seorang penyair, kemudian dia turun sambil menghalau unta dan berkata; \"Ya Allah, kalau bukan karena (Hidayah-Mu) maka tidaklah kami akan mendapat petunjuk, kami tidak akan bersedekah, dan tidak akan mendirikan shalat. Oleh karena itu, ampunilah kami, sebagai tebusan Engkau atas kesalahan kami. Dan teguhkanlah pendirian kami jika bertemu dengan musuh. Tanamkanlah ketenangan di hati kami, apabila di teriaki kami kan datang. Dan dengan teriakan, mereka kan menangis kepada kami.\" Maka Rasulullah shallallahu 'alaihi wasallam bertanya: \"Siapakah orang yang menghalau unta sambil bersyair itu?\" mereka menjawab; \"Amir bin Al Akwa'.\" Beliau bersabda: \"Semoga Allah merahmatinya.\" Lalu seorang anggota pasukan bertanya; \"Betulkah begitu ya Rasulullah?, alangkah baiknya sekiranya anda menyuruhnya supaya menghibur kami terus.\" Salamah berkata; \"Kiranya saat itu kami telah sampai di Khaibar, kemudian kami mengepung penduduknya, sehingga perut kami terasa sangat lapar, kemudian Allah menaklukkan negeri itu atas mereka (kaum Muslimin).\" Setelah hari mulai petang di hari penaklukan Khaibar, mereka mulai menyalakan api, maka Rasulullah shallallahu 'alaihi wasallam bertanya: \"Nyala api apakah itu? Dan untuk apakah mereka menyalakan api?\" mereka menjawab; \"Untuk memasak daging.\" Beliau bertanya: \"Daging apa?\" mereka menjawab; \"Daging keledai jinak.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tumpahkanlah dan pecahkanlah.\" Lantas ada seorang laki-laki berkata; \"Wahai Rasulullah, atau tumpahkan kemudian di cuci.\" Beliau menjawab: \"atau seperti itu.\" Tatkala dua pasukan saling berhadapan, ternyata 'Amir hanya mempunyai pedang pendek. Dengan pedang itu maka ia menikamnya di betis orang Yahudi, tetapi malang baginya, ujung pedang itu terus meluncur hingga berbalik mengenai lutut 'Amir, dan 'Amir pun gugur karenanya.\" Setelah mereka kembali pulang, Salamah mengatakan; \"Rasulullah shallallahu 'alaihi wasallam melihatku murung, lalu beliau bersabda kepadaku: \"Kenapa denganmu?\" Aku menjawab; \"Ayah dan ibuku menjadi tebusan anda, orang-orang menganggap pahala 'Amir telah terhapus.\" Beliau bertanya; \"Siapa yang mengatakannya?\" jawabku; \"Fulan, fulan, fulan dan Usaid bin Hudlair Al Anshari.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dusta orang yang mengatakannya, sesungguhnya dia memperoleh pahala ganda -sambil beliau menggabungkan kedua jemarinya- dialah pejuang sesungguhnya, dan sedikit sekali orang Arab yang pergi berperang seperti dia.\""},"5378":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَأَتَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى بَعْضِ نِسَائِهِ وَمَعَهُنَّ أُمُّ سُلَيْمٍ فَقَالَ وَيْحَكَ يَا أَنْجَشَةُ رُوَيْدَكَ سَوْقًا بِالْقَوَارِيرِ قَالَ أَبُو قِلَابَةَ فَتَكَلَّمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِكَلِمَةٍ لَوْ تَكَلَّمَ بِهَا بَعْضُكُمْ لَعِبْتُمُوهَا عَلَيْهِ قَوْلُهُ سَوْقَكَ بِالْقَوَارِيرِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Isma'il] telah menceritakan kepada kami [Ayyub] dari [Abu Qilabah] dari [Anas bin Malik] radliallahu 'anhu dia berkata; Nabi shallallahu 'alaihi wasallam menemui sebagian isterinya, sementara Ummu Sulaim bersama mereka, maka beliau bersabda: 'Hati-hati wahai Anjasyah, pelan-pelanlah jika mengawal sesuatu yang diibaratkan dengan barang yang mudah pecah (maksudnya para wanita). Abu Qilabah berkata; \"Nabi shallallahu 'alaihi wasallam berbicara dengan kalimat yang seandainya sebagian dari kalian mengucapkannya, niscaya kalian akan mempermainkan orang yang mengucapkannya.' (karena jarang yang melakukannya). Yaitu sabda beliau; \"Kamu mengawal sesuatu yang diibaratkan dengan barang yang mudah pecah (maksudnya adalah para wanita).\""},"5379":{"ar":"حَدَّثَنَا مُحَمَّدٌ حَدَّثَنَا عَبْدَةُ أَخْبَرَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْاسْتَأْذَنَ حَسَّانُ بْنُ ثَابِتٍ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هِجَاءِ الْمُشْرِكِينَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَيْفَ بِنَسَبِي فَقَالَ حَسَّانُ لَأَسُلَّنَّكَ مِنْهُمْ كَمَا تُسَلُّ الشَّعَرَةُ مِنْ الْعَجِينِ وَعَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ قَالَ ذَهَبْتُ أَسُبُّ حَسَّانَ عِنْدَ عَائِشَةَ فَقَالَتْ لَا تَسُبُّهُ فَإِنَّهُ كَانَ يُنَافِحُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad] telah menceritakan kepada kami ['Abdah] telah mengabarkan kepada kami [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah] radliallahu 'anha dia berkata; \"Hasan bin Tsabit pernah meminta izin kepada Rasulullah shallallahu 'alaihi wasallam untuk mengejek kaum Musyrikin (Quraisy), lalu beliau bersabda: \"Tapi bagaimana dengan nasab (keturunan) ku?\" Hasan berkata; \"Aku pasti akan mengeluarkan (menyelamatkan) tuan dari mereka sebagaimana rambut dikeluarkan dari adonan tepung.\" Dan dari Hisyam bin 'Urwah dari Ayahnya dia berkata; \"Aku pernah pergi untuk mencela Hasan di hadapan Aisyah, maka dia berkata; \"Jangan kamu mencelanya, karena dia pernah menyelamatkan (melindungi) Nabi shallallahu 'alaihi wasallam.\""},"5380":{"ar":"حَدَّثَنَا أَصْبَغُ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَنَّ الْهَيْثَمَ بْنَ أَبِي سِنَانٍ أَخْبَرَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَفِي قَصَصِهِ يَذْكُرُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ أَخًا لَكُمْ لَا يَقُولُ الرَّفَثَ يَعْنِي بِذَاكَ ابْنَ رَوَاحَةَ قَالَ وَفِينَا رَسُولُ اللَّهِ يَتْلُو كِتَابَهُإِذَا انْشَقَّ مَعْرُوفٌ مِنْ الْفَجْرِ سَاطِعُأَرَانَا الْهُدَى بَعْدَ الْعَمَى فَقُلُوبُنَابِهِ مُوقِنَاتٌ أَنَّ مَا قَالَ وَاقِعُيَبِيتُ يُجَافِي جَنْبَهُ عَنْ فِرَاشِهِإِذَا اسْتَثْقَلَتْ بِالْكَافِرِينَ الْمَضَاجِعُتَابَعَهُ عُقَيْلٌ عَنْ الزُّهْرِيِّ وَقَالَ الزُّبَيْدِيُّ عَنْ الزُّهْرِيِّ عَنْ سَعِيدٍ وَالْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ","id":"Telah menceritakan kepada kami [Asbagh] dia berkata; telah mengabarkan kepadaku [Abdullah bin Wahb] dia berkata; telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] bahwa [Al Haitsam bin Abu Sinan] telah mengabarkan kepadanya, bahwa dia pernah mendengar [Abu Hurairah] dalam kisahnya menyebutkan bahwa Nabi shallallahu 'alaihi wasallam bersabda: bahwa saudara kalian (maksudnya Ibnu Rawahah) pernah mengucapkan perkataan jelek, bahkan dia mengatakan; \"Di antara kita ada Rasulullah shallallahu 'alaihi wasallam yang membaca kitabnya, saat fajar merekah terang. Beliau memperlihatkan petunjuk kepada kita. Yang karenanya hati kita menjadi yakin, setelah nyata apa yang diucapkannya musti terjadi. Beliau bermalam dengan menjauhkan punggungnya dari tempat tidurnya, saat tempat tidur terasa berat bagi orang-orang kafir.\" Hadits ini juga diperkuat ['Uqail] dari [Az Zuhri], [Az Zubuaidi] mengatakan dari [Az Zuhri] dari [Sa'id], dan [Al A'raj] dari [Abu Hurairah].\""},"5381":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ ح و حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي أَخِي عَنْ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ أَبِي عَتِيقٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ أَنَّهُ سَمِعَ حَسَّانَ بْنَ ثَابِتٍ الْأَنْصَارِيَّ يَسْتَشْهِدُ أَبَا هُرَيْرَةَ فَيَقُولُيَا أَبَا هُرَيْرَةَ نَشَدْتُكَ بِاللَّهِ هَلْ سَمِعْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَا حَسَّانُ أَجِبْ عَنْ رَسُولِ اللَّهِ اللَّهُمَّ أَيِّدْهُ بِرُوحِ الْقُدُسِ قَالَ أَبُو هُرَيْرَةَ نَعَمْ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri]. Dan diriwayatkan dari jalur lain, telah menceritakan kepada kami [Isma'il] dia berkata; telah menceritakan kepadaku [Saudaraku] dari [Sulaiman] dari [Muhammad bin Abu 'Atiq] dari [Ibnu Syihab] dari [Abu Salamah bin Abdurrahman bin Auf] bahwa dia mendengar [Hasan bin Tsabit Al Anshari] meminta persaksian kepada [Abu Hurairah], seraya berkata; \"Saya bersumpah kepadamu dengan nama Allah wahai Abu Hurairah, pernahkah kamu mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Hasan, balaslah (sya'ir orang-orang kafir itu) untuk membela Rasulullah! Ya Allah, dukunglah Hasan dengan ruhul Quds (Jibril).\" Abu Hurairah menjawab; \"Ya, pernah.\""},"5382":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ الْبَرَاءِ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِحَسَّانَ اهْجُهُمْ أَوْ قَالَ هَاجِهِمْ وَجِبْرِيلُ مَعَكَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Syu'bah] dari ['Adi bin Tsabit] dari [Al Barra`] radliallahu 'anhu bahwa Nabi shallallahu 'alaihi wasallam bersabda kepada Hasan: \"Seranglah mereka atau beliau bersabda balaslah serangan mereka dan Jibril bersamamu.\""},"5383":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى أَخْبَرَنَا حَنْظَلَةُ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَأَنْ يَمْتَلِئَ جَوْفُ أَحَدِكُمْ قَيْحًا خَيْرٌ لَهُ مِنْ أَنْ يَمْتَلِئَ شِعْرًا","id":"Telah menceritakan kepada kami ['Ubaidullah bin Musa] telah mengabarkan kepada kami [Hanzhalah] dari [Salim] dari [Ibnu Umar] radliallahu 'anhuma dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Perut salah seorang dari kalian penuh dengan nanah itu lebih baik daripada penuh dengan bait-bait sya'ir.\""},"5384":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ قَالَ سَمِعْتُ أَبَا صَالِحٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَنْ يَمْتَلِئَ جَوْفُ رَجُلٍ قَيْحًا يَرِيهِ خَيْرٌ مِنْ أَنْ يَمْتَلِئَ شِعْرًا","id":"Telah menceritakan kepada kami [Umar bin Hafsh] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Al A'masy] dia berkata; saya mendengar [Abu Shalih] dari [Abu Hurairah] radliallahu 'anhu dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perut seseorang penuh dengan nanah yang berbau busuk itu lebih daripada penuh dengan bait-bait sya'ir.\""},"5385":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْإِنَّ أَفْلَحَ أَخَا أَبِي الْقُعَيْسِ اسْتَأْذَنَ عَلَيَّ بَعْدَ مَا نَزَلَ الْحِجَابُ فَقُلْتُ وَاللَّهِ لَا آذَنُ لَهُ حَتَّى أَسْتَأْذِنَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنَّ أَخَا أَبِي الْقُعَيْسِ لَيْسَ هُوَ أَرْضَعَنِي وَلَكِنْ أَرْضَعَتْنِي امْرَأَةُ أَبِي الْقُعَيْسِ فَدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ الرَّجُلَ لَيْسَ هُوَ أَرْضَعَنِي وَلَكِنْ أَرْضَعَتْنِي امْرَأَتُهُ قَالَ ائْذَنِي لَهُ فَإِنَّهُ عَمُّكِ تَرِبَتْ يَمِينُكِقَالَ عُرْوَةُ فَبِذَلِكَ كَانَتْ عَائِشَةُ تَقُولُ حَرِّمُوا مِنْ الرَّضَاعَةِ مَا يَحْرُمُ مِنْ النَّسَبِ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari ['Urwah] dari [Aisyah] sesungguhnya Aflah saudara Abu Al Qu'ais pernah meminta izin untuk menemuiku setelah turun (ayat) hijab, maka aku berkata; \"Demi Allah, aku tidak akan mengizinkannya (masuk) sebelum aku meminta izin kepada Rasulullah shallallahu 'alaihi wasallam, karena saudara Abu Al Qu'ais bukanlah orang yang menyusuiku, akan tetapi yang menyusuiku adalah isterinya.\" Beberapa saat kemudian Rasulullah shallallahu 'alaihi wasallam datang, lalu aku berkata; \"Wahai Rasulullah, sesungguhnya laki-laki itu bukanlah orang yang menyusuiku, akan tetapi yang menyusuiku adalah isterinya, beliau bersabda: \"Izinkanlah ia (masuk) karena dia adalah pamanmu, semoga kamu beruntung!.\""},"5386":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا الْحَكَمُ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْأَرَادَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَنْفِرَ فَرَأَى صَفِيَّةَ عَلَى بَابِ خِبَائِهَا كَئِيبَةً حَزِينَةً لِأَنَّهَا حَاضَتْ فَقَالَ عَقْرَى حَلْقَى لُغَةٌ لِقُرَيْشٍ إِنَّكِ لَحَابِسَتُنَا ثُمَّ قَالَ أَكُنْتِ أَفَضْتِ يَوْمَ النَّحْرِ يَعْنِي الطَّوَافَ قَالَتْ نَعَمْ قَالَ فَانْفِرِي إِذًا","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Al Hakam] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] radliallahu 'anha dia berkata; Nabi shallallahu 'alaihi wasallam hendak bepergian, tiba-tiba beliau melihat Shafiyyah berdiri di depan pintu tendanya dengan penuh kesedihan karena dirinya sedang haidl. Beliau pun bersabda padanya: \"Oo…(dengan bahasa Quraisy), sesungguhnya kamu benar-benar menyebabkan kami tertahan.\" Kemudian beliau bersabda: \"Apakah kamu telah melaksanakan ifadlah di hari Nahr (kurban)? Maksudnya adalah thawaf.\" Shafiyah menjawab; \"Ya.\" Beliau bersabda: \"Kalau begitu, berangkatlah.\""},"5387":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ أَبِي النَّضْرِ مَوْلَى عُمَرَ بْنِ عُبَيْدِ اللَّهِ أَنَّ أَبَا مُرَّةَ مَوْلَى أُمِّ هَانِئٍ بِنْتِ أَبِي طَالِبٍ أَخْبَرَهُ أَنَّهُ سَمِعَ أُمَّ هَانِئٍ بِنْتَ أَبِي طَالِبٍ تَقُولُذَهَبْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الْفَتْحِ فَوَجَدْتُهُ يَغْتَسِلُ وَفَاطِمَةُ ابْنَتُهُ تَسْتُرُهُ فَسَلَّمْتُ عَلَيْهِ فَقَالَ مَنْ هَذِهِ فَقُلْتُ أَنَا أُمُّ هَانِئٍ بِنْتُ أَبِي طَالِبٍ فَقَالَ مَرْحَبًا بِأُمِّ هَانِئٍ فَلَمَّا فَرَغَ مِنْ غُسْلِهِ قَامَ فَصَلَّى ثَمَانِيَ رَكَعَاتٍ مُلْتَحِفًا فِي ثَوْبٍ وَاحِدٍ فَلَمَّا انْصَرَفَ قُلْتُ يَا رَسُولَ اللَّهِ زَعَمَ ابْنُ أُمِّي أَنَّهُ قَاتِلٌ رَجُلًا قَدْ أَجَرْتُهُ فُلَانُ بْنُ هُبَيْرَةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَجَرْنَا مَنْ أَجَرْتِ يَا أُمَّ هَانِئٍ قَالَتْ أُمُّ هَانِئٍ وَذَاكَ ضُحًى","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Abu An Nadlr] bekas budak Umar bin 'Ubaidullah, bahwa [Abu Murrah] bekas budak Ummu Hani` binti Abu Thalib telah mengabarkan kepadanya bahwa dia mendengar [Ummu Hani` binti Abu Thalib] berkata; \"Aku pernah pergi menemui Rasulullah shallallahu 'alaihi wasallam pada waktu Fathu Makkah, Saya mendapati beliau sedang mandi sedangkan Fathimah, anak perempuannya, menutupinya dengan selembar kain. Lalu saya mengucapkan salam kepadanya.\" Beliau bertanya: \"Siapa itu?\" saya menjawab; \"Saya Ummu Hani` binti Abu Thalib\" beliau bersabda: \"Selamat datang, Ummu Hani`.\" Seusai mandi, beliau berdiri dan shalat delapan rakaat dengan memakai sehelai baju. Saat beliau selesai, saya menuturkan; \"Wahai Rasulullah! saudaraku Ali hendak membunuh seorang laki-laki yang telah saya beri perlindungan, dia adalah fulan bin Hubairah.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kami telah memberi perlindungan terhadap orang yang telah kamu lindungi, wahai Ummu Hani`.\" Ummu Hani` berkata; \"Demikian itu terjadi pada waktu dluha.\""},"5388":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَجُلًا يَسُوقُ بَدَنَةً فَقَالَ ارْكَبْهَا قَالَ إِنَّهَا بَدَنَةٌ قَالَ ارْكَبْهَا قَالَ إِنَّهَا بَدَنَةٌ قَالَ ارْكَبْهَا وَيْلَكَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Anas] radliallahu 'anhu bahwa Nabi shallallahu 'alaihi wasallam melihat seorang laki-laki yang menuntun unta, lalu beliau bersabda: \"Naikilah\" laki-laki tersebut menjawab; \"Ia hanya seekor unta?\" beliau bersabda: \"Naikilah.\" Laki-laki itu tetap berkata; \"Sesungguhnya ia hanya seekor unta.\" Beliau bersabda: \"Naikilah, celaka kamu.\""},"5389":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَجُلًا يَسُوقُ بَدَنَةً فَقَالَ لَهُ ارْكَبْهَا قَالَ يَا رَسُولَ اللَّهِ إِنَّهَا بَدَنَةٌ قَالَ ارْكَبْهَا وَيْلَكَ فِي الثَّانِيَةِ أَوْ فِي الثَّالِثَةِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] radliallahu 'anhu bahwa Rasulullah shallallahu 'alaihi wasallam melihat seorang laki-laki yang menuntun unta, lalu beliau bersabda: \"Naikilah.\" Laki-laki itu berkata; \"Wahai Rasulullah, sesungguhnya ia hanya seekor unta.\" Beliau bersabda: \"Naikilah, celaka kamu, \" beliau mengucapkan itu di kali yang kedua atau ketiga\""},"5390":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ وَأَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ وَكَانَ مَعَهُ غُلَامٌ لَهُ أَسْوَدُ يُقَالُ لَهُ أَنْجَشَةُ يَحْدُو فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيْحَكَ يَا أَنْجَشَةُ رُوَيْدَكَ بِالْقَوَارِيرِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Hammad] dari [Tsabit Al Bunani] dari [Anas bin Malik], sedangkan [Ayyub] dari [Abu Qilabah] dari [Anas bin Malik] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah dalam suatu perjalanan, sementara bersama beliau ada seorang budak laki-laki hitam yang bernama Anjasyah sebagai pengawal, maka Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Celaka kamu wahai Anjsyah, hati-hatilah kamu jika mengawal sesuatu yang mudah pecah (maksudnya adalah wanita karena lemahnya).\""},"5391":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا وُهَيْبٌ عَنْ خَالِدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ عَنْ أَبِيهِ قَالَأَثْنَى رَجُلٌ عَلَى رَجُلٍ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ وَيْلَكَ قَطَعْتَ عُنُقَ أَخِيكَ ثَلَاثًا مَنْ كَانَ مِنْكُمْ مَادِحًا لَا مَحَالَةَ فَلْيَقُلْ أَحْسِبُ فُلَانًا وَاللَّهُ حَسِيبُهُ وَلَا أُزَكِّي عَلَى اللَّهِ أَحَدًا إِنْ كَانَ يَعْلَمُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Wuhaib] dari [Khalid] dari [Abdurrahman bin Abu Bakrah] dari [Ayahnya] dia berkata; \"Ada seorang laki-laki yang menyanjung kebaikan laki-laki lain di depan Nabi shallallahu 'alaihi wasallam, maka beliau bersabda: \"Celaka kamu, kamu telah memenggal leher saudaramu.\" -Beliau mengatakannya hingga tiga kali- bila salah seorang dari kalian memuji temannya -tidak mustahil- hendaklah mengucapkan: 'Aku kira fulan seperti ini dan ini, dan Allah lah yang akan menilainya, dan aku tidak menyucikan seorang pun atas Allah walaupun Dia mengetahuinya.\""},"5392":{"ar":"حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ حَدَّثَنَا الْوَلِيدُ عَنْ الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ وَالضَّحَّاكِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَبَيْنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْسِمُ ذَاتَ يَوْمٍ قِسْمًا فَقَالَ ذُو الْخُوَيْصِرَةِ رَجُلٌ مِنْ بَنِي تَمِيمٍ يَا رَسُولَ اللَّهِ اعْدِلْ قَالَ وَيْلَكَ مَنْ يَعْدِلُ إِذَا لَمْ أَعْدِلْ فَقَالَ عُمَرُ ائْذَنْ لِي فَلْأَضْرِبْ عُنُقَهُ قَالَ لَا إِنَّ لَهُ أَصْحَابًا يَحْقِرُ أَحَدُكُمْ صَلَاتَهُ مَعَ صَلَاتِهِمْ وَصِيَامَهُ مَعَ صِيَامِهِمْ يَمْرُقُونَ مِنْ الدِّينِ كَمُرُوقِ السَّهْمِ مِنْ الرَّمِيَّةِ يُنْظَرُ إِلَى نَصْلِهِ فَلَا يُوجَدُ فِيهِ شَيْءٌ ثُمَّ يُنْظَرُ إِلَى رِصَافِهِ فَلَا يُوجَدُ فِيهِ شَيْءٌ ثُمَّ يُنْظَرُ إِلَى نَضِيِّهِ فَلَا يُوجَدُ فِيهِ شَيْءٌ ثُمَّ يُنْظَرُ إِلَى قُذَذِهِ فَلَا يُوجَدُ فِيهِ شَيْءٌ قَدْ سَبَقَ الْفَرْثَ وَالدَّمَ يَخْرُجُونَ عَلَى حِينِ فُرْقَةٍ مِنْ النَّاسِ آيَتُهُمْ رَجُلٌ إِحْدَى يَدَيْهِ مِثْلُ ثَدْيِ الْمَرْأَةِ أَوْ مِثْلُ الْبَضْعَةِ تَدَرْدَرُ قَالَ أَبُو سَعِيدٍ أَشْهَدُ لَسَمِعْتُهُ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَشْهَدُ أَنِّي كُنْتُ مَعَ عَلِيٍّ حِينَ قَاتَلَهُمْ فَالْتُمِسَ فِي الْقَتْلَى فَأُتِيَ بِهِ عَلَى النَّعْتِ الَّذِي نَعَتَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepadaku [Abdurrahman bin Ibrahim] telah menceritakan kepada kami [Al Walid] dari [Al Auza'i] dari [Az Zuhri] dari [Abu Salamah] dan [Adl Dlahak] dari [Abu Sa'id Al Khudri] dia berkata; Pada suatu hari, Nabi shallallahu 'alaihi wasallam membagi pembagian, tiba-tiba Dzul Huwaishirah seorang laki-laki dari Bani Tamim berkata; \"Wahai Rasulullah, hendaknya engkau berbuat adil! Spontan beliau menjawab: \"Siapa lagi bisa berbuat adil jika aku tak bisa berbuat adil? 'Umar kemudian mengatakan 'Izinkanlah aku yang memenggal lehernya! Beliau menjawab: 'Biarkan saja dia, sesungguhnya dia mempunyai beberapa kawan yang salah seorang diantara kalian meremehkan shalatnya sekalipun dia shalat, dan meremehkan puasanya sekalipun dia puasa, mereka keluar dari agama sebagaimana anak panah keluar dari busur, ia melihat mata panahnya namun tak ada apa-apa, kemudian memperhatikan kain panahnya namun tidak ditemukan apa-apa, kemudian melihat anak panahnya namun tidak didapatkan apa-apa, kemudian melihat pada bulu anak panahnya namun tidak didapatkan apa-apa, rupanya telah didahulu oleh kotoran dan darah. Mereka muncul ketika manusia mengalami perpecahan. Ciri mereka adalah seorang laki-laki yang salah satu diantara kedua tangannya seperti dada kaum perempuan atau ia seperti daging yang bergerak-gerak.\" Abu Sa'id mengatakan; \"Aku bersaksi bahwa aku mendengar dari Nabi shallallahu 'alaihi wasallam, dan aku bersaksi bahwa 'Ali membunuh mereka dan aku bersamanya ketika didatangkan seseorang yang cirinya seperti yang dicirikan Nabi shallallahu 'alaihi wasallam.\""},"5393":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَبُو الْحَسَنِ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي ابْنُ شِهَابٍ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَجُلًا أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ هَلَكْتُ قَالَ وَيْحَكَ قَالَ وَقَعْتُ عَلَى أَهْلِي فِي رَمَضَانَ قَالَ أَعْتِقْ رَقَبَةً قَالَ مَا أَجِدُهَا قَالَ فَصُمْ شَهْرَيْنِ مُتَتَابِعَيْنِ قَالَ لَا أَسْتَطِيعُ قَالَ فَأَطْعِمْ سِتِّينَ مِسْكِينًا قَالَ مَا أَجِدُ فَأُتِيَ بِعَرَقٍ فَقَالَ خُذْهُ فَتَصَدَّقْ بِهِ فَقَالَ يَا رَسُولَ اللَّهِ أَعَلَى غَيْرِ أَهْلِي فَوَالَّذِي نَفْسِي بِيَدِهِ مَا بَيْنَ طُنُبَيْ الْمَدِينَةِ أَحْوَجُ مِنِّي فَضَحِكَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى بَدَتْ أَنْيَابُهُ قَالَ خُذْهُتَابَعَهُ يُونُسُ عَنْ الزُّهْرِيِّ وَقَالَ عَبْدُ الرَّحْمَنِ بْنُ خَالِدٍ عَنْ الزُّهْرِيِّ وَيْلَكَ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil Abu Al Hasan] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Al Auza'i] dia berkata; telah menceritakan kepadaku [Ibnu Syihab] dari [Humaid bin Abdurrahman] dari [Abu Hurairah] radliallahu 'anhu bahwa seorang laki-laki datang kepada Rasulullah shallallahu 'alaihi wasallam seraya berkata; \"Wahai Rasulullah, celaka aku!.\" Beliau menanggapi: \"Ada apa denganmu?\" laki-laki itu berkata; \"Aku telah menggauli isteri di (siang) bulan Ramadhan.\" Beliau bersabda: \"Kalau begitu, bebaskanlah budak.\" Laki-laki itu berkata; \"Aku tidak mampu.\" Beliau bersabda: \"Berpuasalah dua bulan berturut-turut.\" Laki-laki itu berkata; \"Aku tidak mampu.\" Beliau bersabda: \"Berilah makan enam puluh orang miskin.\" Laki-laki itu berkata; \"Aku tidak mampu.\" Lalu beliau memberinya segantang makanan, dan bersabda: \"Ambillah dan bersedekahlah dengannya.\" Laki-laki itu berkata; \"Wahai Rasulullah, apakah ini untuk selain keluargaku? Demi dzat yang jiwaku berada di tangan-Nya, tidak ada seorang pun di antara dua lembah ini (maksudnya Madinah) yang lebih membutuhkan daripada (keluargaku).\" Maka Nabi shallallahu 'alaihi wasallam tersenyum hingga terlihat giginya, lalu beliau bersabda: \"Kalau begitu ambilah untukmu.\" Hadits ini juga di perkuat oleh [Yunus] dari [Az Zuhri]. [Abdurrahman bin Khalid] berkata; dari [Az Zuhri] dengan redaksi \"wailaka (celaka kamu).\""},"5394":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنَا الْوَلِيدُ حَدَّثَنَا أَبُو عَمْرٍو الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي ابْنُ شِهَابٍ الزُّهْرِيُّ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُأَنَّ أَعْرَابِيًّا قَالَ يَا رَسُولَ اللَّهِ أَخْبِرْنِي عَنْ الْهِجْرَةِ فَقَالَ وَيْحَكَ إِنَّ شَأْنَ الْهِجْرَةِ شَدِيدٌ فَهَلْ لَكَ مِنْ إِبِلٍ قَالَ نَعَمْ قَالَ فَهَلْ تُؤَدِّي صَدَقَتَهَا قَالَ نَعَمْ قَالَ فَاعْمَلْ مِنْ وَرَاءِ الْبِحَارِ فَإِنَّ اللَّهَ لَنْ يَتِرَكَ مِنْ عَمَلِكَ شَيْئًا","id":"Telah menceritakan kepada kami [Sulaiman bin Abdurrahman] telah menceritakan kepada kami [Al Walid] telah menceritakan kepada kami [Abu 'Amru Al Auza'i] dia berkata; telah menceritakan kepadaku [Ibnu Syihab Az Zuhri] dari ['Atha` bin Yazid Al Laitsi] dari [Abu Sa'id Al Khudri] radliallahu 'anhu bahwa seorang Arab Badui berkata; \"Wahai Rasulullah, beritahukanlah kepadaku tentang Hijrah!.\" Beliau bersabda: \"Sayang sekali, hijrah itu sangat berat. Apakah kamu mempunyai unta?\" Jawab orang itu; \"Ada!\" beliau bertanya: \"Sudahkah kamu membayar zakatnya?\" dia menjawab; \"Ya!\" beliau bersabda: \"Kalau begitu beramallah di negerimu, sesungguhnya Allah Ta'ala tidak akan menyia-nyiakan pahala amalmu sedikitpun juga.\""},"5395":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الْوَهَّابِ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا شُعْبَةُ عَنْ وَاقِدِ بْنِ مُحَمَّدِ بْنِ زَيْدٍ سَمِعْتُ أَبِي عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَيْلَكُمْ أَوْ وَيْحَكُمْ قَالَ شُعْبَةُ شَكَّ هُوَ لَا تَرْجِعُوا بَعْدِي كُفَّارًا يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍوَقَالَ النَّضْرُ عَنْ شُعْبَةَ وَيْحَكُمْ وَقَالَ عُمَرُ بْنُ مُحَمَّدٍ عَنْ أَبِيهِ وَيْلَكُمْ أَوْ وَيْحَكُمْ","id":"Telah menceritakan kepada kami [Abdullah bin Abdul Wahhab] telah menceritakan kepada kami [Khalid bin Al Harits] telah menceritakan kepada kami [Syu'bah] dari [Waqid bin Muhammad bin Zaid] saya mendengar [Ayahku] dari [Ibnu Umar] radliallahu 'anhuma dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Celakalah kalian -atau binasalah kalian-Syu'bah mengatakan; \"Ada keraguan pada Waqid\"- janganlah kalian kembali kepada kekufuran sepeninggalku yaitu dengan saling berperang di antara kalian.\" dan berkata [An Nadlar] dari [Syu'bah] dengan lafadz waihakum (celakalah kalian), dan [Umar bin Muhammad] berkata dari [ayahnya] dengan lafadz wailakum atau waihakum (celakalah kalian)."},"5396":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَاصِمٍ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ رَجُلًا مِنْ أَهْلِ الْبَادِيَةِ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ مَتَى السَّاعَةُ قَائِمَةٌ قَالَ وَيْلَكَ وَمَا أَعْدَدْتَ لَهَا قَالَ مَا أَعْدَدْتُ لَهَا إِلَّا أَنِّي أُحِبُّ اللَّهَ وَرَسُولَهُ قَالَ إِنَّكَ مَعَ مَنْ أَحْبَبْتَ فَقُلْنَا وَنَحْنُ كَذَلِكَ قَالَ نَعَمْ فَفَرِحْنَا يَوْمَئِذٍ فَرَحًا شَدِيدًا فَمَرَّ غُلَامٌ لِلْمُغِيرَةِ وَكَانَ مِنْ أَقْرَانِي فَقَالَ إِنْ أُخِّرَ هَذَا فَلَنْ يُدْرِكَهُ الْهَرَمُ حَتَّى تَقُومَ السَّاعَةُوَاخْتَصَرَهُ شُعْبَةُ عَنْ قَتَادَةَ سَمِعْتُ أَنَسًا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Amru bin 'Ashim] telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Anas] bahwa seorang laki-laki dari penduduk kampung datang kepada Nabi shallallahu 'alaihi wasallam seraya berkata; \"Wahai Rasulullah, kapankah hari Kiamat akan terjadi?\" beliau menjawab: \"Celaka kamu, apa yang telah kau persiapkan?\" laki-laki itu berkata; \"Aku belum mempersiapkan bekal kecuali aku hanya mencintai Allah dan Rasul-Nya.\" Beliau bersabda: \"Kalau begitu, kamu bersama dengan orang yang kamu cintai.\" Maka kami pun berkata; \"Apakah kami juga seperti itu?\" beliau menjawab: \"Ya.\" Maka pada hari itu kami sangat bahagia, tiba-tiba pelayan Mughirah lewat -sedangkan dia termasuk dari teman dekatku- beliau lalu bersabda: \"Jika (ajalnya) ini diakhirkan, pasti dia tidak akan mendapati penyakit tua sampai kiamat tiba.\" [Syu'bah] meringkasnya, dari [Qatadah] saya mendengar [Anas] dari Nabi shallallahu 'alaihi wasallam."},"5397":{"ar":"حَدَّثَنَا بِشْرُ بْنُ خَالِدٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ الْمَرْءُ مَعَ مَنْ أَحَبَّ","id":"Telah menceritakan kepada kami [Bisyr bin Khalid] telah menceritakan kepada kami [Muhammad bin Ja'far] dari [Syu'bah] dari [Sulaiman] dari [Abu Wa`il] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam bahwa beliau bersabda: \"Seseorang akan bersama dengan orang yang dicintainya.\""},"5398":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ قَالَ قَالَ عَبْدُ اللَّهِ بْنُ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُجَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ كَيْفَ تَقُولُ فِي رَجُلٍ أَحَبَّ قَوْمًا وَلَمْ يَلْحَقْ بِهِمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَرْءُ مَعَ مَنْ أَحَبَّتَابَعَهُ جَرِيرُ بْنُ حَازِمٍ وَسُلَيْمَانُ بْنُ قَرْمٍ وَأَبُو عَوَانَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Wa`il] dia berkata; [Abdullah bin Mas'ud] radliallahu 'anhu berkata; \"Seorang laki-laki datang kepada Rasulullah shallallahu 'alaihi wasallam seraya bertanya; \"Wahai Rasulullah, bagaimana anda mengatakan mengenai seseorang yang mencintai suatu kaum, namun dia sendiri belum pernah bertemu dengan kaum tersebut?\" maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seseorang akan bersama dengan yang di cintainya.\" Hadits ini juga diperkuat oleh [Jarir bin Hazim] dan [Sulaiman bin Qarm] serta [Abu 'Awanah] dari [Al A'masy] dari [Abu Wa`il] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam."},"5399":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي وَائِلٍ عَنْ أَبِي مُوسَى قَالَقِيلَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الرَّجُلُ يُحِبُّ الْقَوْمَ وَلَمَّا يَلْحَقْ بِهِمْ قَالَ الْمَرْءُ مَعَ مَنْ أَحَبَّتَابَعَهُ أَبُو مُعَاوِيَةَ وَمُحَمَّدُ بْنُ عُبَيْدٍ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Al A'masy] dari [Abu Wa'il] dari [Abu Musa] dia berkata; diberitahukan kepada Nabi shallallahu 'alaihi wasallam bahwa ada seseorang yang mencintai suatu kaum, namun dia sendiri belum pernah berjumpa dengan kaum tersebut, beliau bersabda: \"Seseorang akan bersama dengan orang yang di cintainya.\" Hadits ini di perkuat juga oleh [Abu Mu'awiyah] dan [Muhammad bin 'Ubaid]."},"5400":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا أَبِي عَنْ شُعْبَةَ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَجُلًا سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَتَى السَّاعَةُ يَا رَسُولَ اللَّهِ قَالَ مَا أَعْدَدْتَ لَهَا قَالَ مَا أَعْدَدْتُ لَهَا مِنْ كَثِيرِ صَلَاةٍ وَلَا صَوْمٍ وَلَا صَدَقَةٍ وَلَكِنِّي أُحِبُّ اللَّهَ وَرَسُولَهُ قَالَ أَنْتَ مَعَ مَنْ أَحْبَبْتَ","id":"Telah menceritakan kepada kami ['Abdan] telah mengabarkan kepada kami [Ayahku] dari [Syu'bah] dari ['Amru bin Murrah] dari [Salim bin Abu Al Ja'd] dari [Anas bin Malik] bahwa seorang laki-laki bertanya kepada Nabi shallallahu 'alaihi wasallam; \"Kapankah hari Kiamat terjadi wahai Rasulullah?\" beliau menjawab: \"Apa yang telah kau persiapkan untuknya?\" laki-laki itu menjawab; \"Aku belum mempersiapkan banyak, baik itu shalat, puasa ataupun sedekah, namun aku hanya mencintai Allah dan Rasul-Nya.\" Belaiu bersabda: \"Kamu akan bersama dengan orang yang kamu cintai.\""},"5401":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا سَلْمُ بْنُ زَرِيرٍ سَمِعْتُ أَبَا رَجَاءٍ سَمِعْتُ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِابْنِ صَائِدٍ قَدْ خَبَأْتُ لَكَ خَبِيئًا فَمَا هُوَ قَالَ الدُّخُّ قَالَ اخْسَأْ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Salm bin Zarir] saya mendengar [Abu Roja'] saya mendengar [Ibnu Abbas] radliallahu 'anhuma berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepada Ibnu Sha`id: \"Sungguh aku meminta kepadamu agar mengira (apa yang aku sembunyikan dalam hatiku) \". Ibnu Shayyad berkata; \"Aku kira asap\". Nabi bersabda: \"Celaka kamu.\""},"5402":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ أَخْبَرَهُأَنَّ عُمَرَ بْنَ الْخَطَّابِ انْطَلَقَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَهْطٍ مِنْ أَصْحَابِهِ قِبَلَ ابْنِ صَيَّادٍ حَتَّى وَجَدَهُ يَلْعَبُ مَعَ الْغِلْمَانِ فِي أُطُمِ بَنِي مَغَالَةَ وَقَدْ قَارَبَ ابْنُ صَيَّادٍ يَوْمَئِذٍ الْحُلُمَ فَلَمْ يَشْعُرْ حَتَّى ضَرَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ظَهْرَهُ بِيَدِهِ ثُمَّ قَالَ أَتَشْهَدُ أَنِّي رَسُولُ اللَّهِ فَنَظَرَ إِلَيْهِ فَقَالَ أَشْهَدُ أَنَّكَ رَسُولُ الْأُمِّيِّينَ ثُمَّ قَالَ ابْنُ صَيَّادٍ أَتَشْهَدُ أَنِّي رَسُولُ اللَّهِ فَرَضَّهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ آمَنْتُ بِاللَّهِ وَرُسُلِهِ ثُمَّ قَالَ لِابْنِ صَيَّادٍ مَاذَا تَرَى قَالَ يَأْتِينِي صَادِقٌ وَكَاذِبٌ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُلِّطَ عَلَيْكَ الْأَمْرُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي خَبَأْتُ لَكَ خَبِيئًا قَالَ هُوَ الدُّخُّ قَالَ اخْسَأْ فَلَنْ تَعْدُوَ قَدْرَكَ قَالَ عُمَرُ يَا رَسُولَ اللَّهِ أَتَأْذَنُ لِي فِيهِ أَضْرِبْ عُنُقَهُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ يَكُنْ هُوَ لَا تُسَلَّطُ عَلَيْهِ وَإِنْ لَمْ يَكُنْ هُوَ فَلَا خَيْرَ لَكَ فِي قَتْلِهِ قَالَ سَالِمٌ فَسَمِعْتُ عَبْدَ اللَّهِ بْنَ عُمَرَ يَقُولُ انْطَلَقَ بَعْدَ ذَلِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأُبَيُّ بْنُ كَعْبٍ الْأَنْصَارِيُّ يَؤُمَّانِ النَّخْلَ الَّتِي فِيهَا ابْنُ صَيَّادٍ حَتَّى إِذَا دَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَفِقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَّقِي بِجُذُوعِ النَّخْلِ وَهُوَ يَخْتِلُ أَنْ يَسْمَعَ مِنْ ابْنِ صَيَّادٍ شَيْئًا قَبْلَ أَنْ يَرَاهُ وَابْنُ صَيَّادٍ مُضْطَجِعٌ عَلَى فِرَاشِهِ فِي قَطِيفَةٍ لَهُ فِيهَا رَمْرَمَةٌ أَوْ زَمْزَمَةٌ فَرَأَتْ أُمُّ ابْنِ صَيَّادٍ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَتَّقِي بِجُذُوعِ النَّخْلِ فَقَالَتْ لِابْنِ صَيَّادٍ أَيْ صَافِ وَهُوَ اسْمُهُ هَذَا مُحَمَّدٌ فَتَنَاهَى ابْنُ صَيَّادٍ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ تَرَكَتْهُ بَيَّنَقَالَ سَالِمٌ قَالَ عَبْدُ اللَّهِ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي النَّاسِ فَأَثْنَى عَلَى اللَّهِ بِمَا هُوَ أَهْلُهُ ثُمَّ ذَكَرَ الدَّجَّالَ فَقَالَ إِنِّي أُنْذِرُكُمُوهُ وَمَا مِنْ نَبِيٍّ إِلَّا وَقَدْ أَنْذَرَهُ قَوْمَهُ لَقَدْ أَنْذَرَهُ نُوحٌ قَوْمَهُ وَلَكِنِّي سَأَقُولُ لَكُمْ فِيهِ قَوْلًا لَمْ يَقُلْهُ نَبِيٌّ لِقَوْمِهِ تَعْلَمُونَ أَنَّهُ أَعْوَرُ وَأَنَّ اللَّهَ لَيْسَ بِأَعْوَرَ قَالَ أَبُو عَبْد اللَّهِ خَسَأْتُ الْكَلْبَ بَعَّدْتُهُ{ خَاسِئِينَ }مُبْعَدِينَ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku [Salim bin Abdullah] bahwa [Abdullah bin Umar] telah mengabarkan kepadanya, bahwa Umar bin Khatthab pernah pergi bersama Rasulullah shallallahu 'alaihi wasallam dengan beberapa orang dari para sahabat beliau untuk menemui Ibnu Shayyad. Beliau mendapatinya tengah bermain bersama dua anak kecil di dekat benteng Bani Maghalah. Ibnu Shayyad waktu itu sudah hampir baligh namun dia tidak menyadari sesuatupun (kedatangan rombongan) hingga Nabi shallallahu 'alaihi wasallam memukul punggungnya dengan tangan beliau, kemudian beliau bersabda: \"Apakah kamu bersaksi bahwa aku ini utusan Allah?\". Maka Ibnu Shayyad memandang beliau lalu berkata; \"Aku bersaksi bahwa engkau utusan bagi ummat yang ummiy\" (khusus bangsa 'Arab). Kemudian Ibnu Shayyad berkata; \"Apakah kamu bersaksi bahwa aku ini utusan Allah?\" Nabi shallallahu 'alaihi wasallam pun menolaknya sambil bersabda: \"Aku beriman kepada Allah dan Rasul-rasul-Nya.\" Setelah itu beliau bersabda kepada Ibnu Shayyad: \"Bagaimana pendapatmu?\". Ibnu Shayyad menjawab; \"Telah datang kepadaku orang yang jujur dan pendusta\". Rasulullah shallallahu 'alaihi wasallam bersabda: \"Urusanmu kacau balau.\" Rasulullah shallallahu 'alaihi wasallam juga bersabda: \"Sungguh aku meminta kepadamu agar mengira (apa yang aku sembunyikan dalam hatiku) \". Ibnu Shayyad berkata; \"Aku kira asap.\" Beliau bersabda: \"Celaka kamu. Kamu tidak akan mempunyai kemampuan (untuk mengetahuinya) \". Spontanitas Umar berkata; \"Wahai Rasulullah, biarkanlah aku memenggal lehernya\". Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika dia benar (Dajjal), maka kamu tidak akan dapat menguasainya dan jika dia bukan (Dajjal) maka tidak ada kebaikannya membunuhnya\". Salim berkata; \"Aku mendengar Abdullah bin Umar berkata; \"Setelah itu Rasulullah shallallahu 'alaihi wasallam beranjak meninggalkannya, Salim berkata: Aku mendengar Abdullah bin Umar bekata: \"Setelah itu Rasulullah shallallahu 'alaihi wasallam dan Ubai bin Ka'ab Al Anshari pergi menuju kebun kurma dimana Ibnu Shayyad berada, dan ketika Rasulullah shallallahu 'alaihi wasallam memasuki kebun, Rasulullah shallallahu 'alaihi wasallam segera menjaga dirinya dengan pelepah kurma agar tidak mendengar apa pun yang dikatakan Ibnu Shayyad sebelum ia melihat beliau. Sementara Ibnu Shayyad tengah berbaring di atas hamparan kain beludru miliknya, yang terdengar suara tikar bila diduduki. Ketika Ibu Ibnu Shayyad melihat Nabi shallallahu 'alaihi wasallam tengah menjaga diri dengan pelepah kurma, maka ibunya berkata pada Ibnu Shayyad: Hai Shaf -nama Ibnu Shayyad- ini Muhammad.\" Ibnu Shayyad langsung terbangun, lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Andai dia (ibu Ibnu Shayyad) membiarkannya maka akan tampak jelas olehnya.\" Salim berkata: Abdullah bin Umar berkata: Rasulullah shallallahu 'alaihi wasallam berdiri ditengah orang-orang, beliau memuja dan memuji dengan pujian yang layak baginya, setelah itu beliau menyebut Dajjal, beliau bersabda: \"Sesungguhnya aku mengingatkan kalian darinya. Dan tidak ada seorang nabi pun melainkan ia akan mengingatkan kaumnya dari Dajjal. Nuh telah mengingatkan kaumnya, namun aku akan menyebutkan suatu hal pada kalian yang belum pernah dikemukakan oleh seorang nabi pun kepada kaumnya, ketahuilah oleh kalian bahwa ia (Dajjal) buta sebelah matanya sedangkan Allah tidak buta sebelah mata-Nya.\" Abu Abdullah mengatakan; \"Aku menghalau anjing maksudnya menjauhkannya, sedangkan kata \"Khasi`iin\" QS Al Baqarah; 65, maknanya adalah terusirlah dengan hina."},"5403":{"ar":"حَدَّثَنَا عِمْرَانُ بْنُ مَيْسَرَةَ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا أَبُو التَّيَّاحِ عَنْ أَبِي جَمْرَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَمَّا قَدِمَ وَفْدُ عَبْدِ الْقَيْسِ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَرْحَبًا بِالْوَفْدِ الَّذِينَ جَاءُوا غَيْرَ خَزَايَا وَلَا نَدَامَى فَقَالُوا يَا رَسُولَ اللَّهِ إِنَّا حَيٌّ مِنْ رَبِيعَةَ وَبَيْنَنَا وَبَيْنَكَ مُضَرُ وَإِنَّا لَا نَصِلُ إِلَيْكَ إِلَّا فِي الشَّهْرِ الْحَرَامِ فَمُرْنَا بِأَمْرٍ فَصْلٍ نَدْخُلُ بِهِ الْجَنَّةَ وَنَدْعُو بِهِ مَنْ وَرَاءَنَا فَقَالَ أَرْبَعٌ وَأَرْبَعٌ أَقِيمُوا الصَّلَاةَ وَآتُوا الزَّكَاةَ وَصُومُوا رَمَضَانَ وَأَعْطُوا خُمُسَ مَا غَنِمْتُمْ وَلَا تَشْرَبُوا فِي الدُّبَّاءِ وَالْحَنْتَمِ وَالنَّقِيرِ وَالْمُزَفَّتِ","id":"Telah menceritakan kepada kami [Imran bin Maisarah] telah menceritakan kepada kami [Abdul Warits] telah menceritakan kepada kami [Abu At Tayyah] dari [Abu Jamrah] dari [Ibnu Abbas] radliallahu 'anhuma dia berkata; \"Ketika utusan Abdul Qais datang kepada nabi shallallahu 'alaihi wasallam, lalu beliau bersabda: \"Selamat datang wahai utusan yang datang dengan tanpa kehinaan dan penyesalan.\" Mereka berkata; \"Wahai Rasulullah, sesungguhnya kami tinggal di perkampungan Rabi'ah, sedangkan antara kami dengan anda terdapat kabilah Mudlar, hingga kami tidak dapat menjumpai anda kecuali pada Bulan Haram, oleh karena itu perintahkanlah kepada kami suatu amalan yang ringkas yang dapat memasukkan kami ke dalam surga. dan dapat kami tinggalkan untuk orang-orang setelah kami.\" Maka beliau bersabda: \"(Aku perintahkan) empat perkara dan (aku melarang dari) empat perkara, yaitu; tegakkanlah shalat, bayarlah zakat, berpuasalah pada bulan Ramadhan serta tunaikanlah kepadaku seperlima dari rampasan perang yang kalian dapatkan, dan janganlah kalian minum dari duba` (labu yang dilubangi dan dijadikan untuk merendam buah hingga menjadi khamr), hantam (bejana yang dibuat dari tanah, rambut dan darah), Naqir (bejana yang terbuat dari batang pohon yang dilubangi) dan Muzaffat (bejana yang dilapisi dengan ter atau aspal).\""},"5404":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْغَادِرَ يُرْفَعُ لَهُ لِوَاءٌ يَوْمَ الْقِيَامَةِ يُقَالُ هَذِهِ غَدْرَةُ فُلَانِ بْنِ فُلَانٍ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhuma dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Sesungguhnya akan di kibarkan bendera untuk para penghianat pada hari Kiamat kelak, dan dikatakan; \"Ini adalah bendera penghianatan fulan bin fulan.\""},"5405":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْغَادِرَ يُنْصَبُ لَهُ لِوَاءٌ يَوْمَ الْقِيَامَةِ فَيُقَالُ هَذِهِ غَدْرَةُ فُلَانِ بْنِ فُلَانٍ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Abdullah bin Dinar] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya akan dikibarkan bendera untuk para penghianat pada hari Kiamat kelak, maka akan dikatakan; Ini adalah bendera penghiantan fulan bin fulan.\""},"5406":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَقُولَنَّ أَحَدُكُمْ خَبُثَتْ نَفْسِي وَلَكِنْ لِيَقُلْ لَقِسَتْ نَفْسِي","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Hisyam] dari [Ayahnya] dari [Aisyah] radliallahu 'anha dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"janganlah salah seorang dari kalian mengatakan; \"Khabutsat nafsi (diriku sangat buruk), akan tetapi hendaknya ia mengatakan \"laqishat nafsi (diriku ada kekurangan).\""},"5407":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلٍ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَقُولَنَّ أَحَدُكُمْ خَبُثَتْ نَفْسِي وَلَكِنْ لِيَقُلْ لَقِسَتْ نَفْسِيتَابَعَهُ عُقَيْلٌ","id":"Telah menceritakan kepada kami ['Abdan] telah mengabarkan kepada kami [Abdullah] dari [Yunus] dari [Az Zuhri] dari [Abu Umamah bin Sahl] dari [Ayahnya] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: “Jangan sekali-kali kalian mengatakan'Khabutsat nafsi' (diriku sangat buruk), akan tetapi hendaknya ia mengatakan 'laqishat nafsi (diriku ada kekurangan)'.\" Hadits ini juga diperkuat oleh ['Uqail]."},"5408":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ ح��دَّثَنَا اللَّيْثُ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي أَبُو سَلَمَةَ قَالَ قَالَ أَبُو هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُ يَسُبُّ بَنُو آدَمَ الدَّهْرَ وَأَنَا الدَّهْرُ بِيَدِي اللَّيْلُ وَالنَّهَارُ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Yunus] dari [Ibnu Syihab] telah mengabarkan kepadaku [Abu Salamah] dia berkata; [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah berfirman; \"Anak Adam mencela masa, padahal Aku adalah masa, di tangan-Ku lah siang dan malam berada.\""},"5409":{"ar":"حَدَّثَنَا عَيَّاشُ بْنُ الْوَلِيدِ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُسَمُّوا الْعِنَبَ الْكَرْمَ وَلَا تَقُولُوا خَيْبَةَ الدَّهْرِ فَإِنَّ اللَّهَ هُوَ الدَّهْرُ","id":"Telah menceritakan kepada kami ['Ayyasy bin Al Walid] telah menceritakan kepada kami [Abdul A'la] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Janganlah kalian menamakan 'inab (anggur) sebagai karam (kemuliaan), dan janganlah kalian mengatakan \"alangkah sialnya masa\" karena sesungguhnya Allah adalah masa.\""},"5410":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيَقُولُونَ الْكَرْمُ إِنَّمَا الْكَرْمُ قَلْبُ الْمُؤْمِنِ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] radliallahu 'anhu dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang-orang banyak menyebut (anggur) \"al karmu (kemuliaan) \" padahal alkarmu (kemuliaan) adalah hatinya orang mukmin.\""},"5411":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ حَدَّثَنِي سَعْدُ بْنُ إِبْرَاهِيمَ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادٍ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَمَا سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُفَدِّي أَحَدًا غَيْرَ سَعْدٍ سَمِعْتُهُ يَقُولُ ارْمِ فَدَاكَ أَبِي وَأُمِّي أَظُنُّهُ يَوْمَ أُحُدٍ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Sufyan] telah menceritakan kepadaku [Sa'd bin Ibrahim] dari [Abdullah bin Syaddad] dari [Ali] radliallahu 'anhu dia berkata; \"Saya belum pernah mendengar Rasulullah shallallahu 'alaihi wasallam menjadikan tebusan kepada salah seorang pun melainkan kepada Sa'd, beliau bersabda: \"Lemparlah, demi ayah dan ibuku sebagai tebusanmu.\" Aku mengira peristiwa itu terjadi pada waktu perang Uhud."},"5412":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ حَدَّثَنَا يَحْيَى بْنُ أَبِي إِسْحَاقَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّهُ أَقْبَلَ هُوَ وَأَبُو طَلْحَةَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَفِيَّةُ مُرْدِفُهَا عَلَى رَاحِلَتِهِ فَلَمَّا كَانُوا بِبَعْضِ الطَّرِيقِ عَثَرَتْ النَّاقَةُ فَصُرِعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْمَرْأَةُ وَأَنَّ أَبَا طَلْحَةَ قَالَ أَحْسِبُ اقْتَحَمَ عَنْ بَعِيرِهِ فَأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا نَبِيَّ اللَّهِ جَعَلَنِي اللَّهُ فِدَاكَ هَلْ أَصَابَكَ مِنْ شَيْءٍ قَالَ لَا وَلَكِنْ عَلَيْكَ بِالْمَرْأَةِ فَأَلْقَى أَبُو طَلْحَةَ ثَوْبَهُ عَلَى وَجْهِهِ فَقَصَدَ قَصْدَهَا فَأَلْقَى ثَوْبَهُ عَلَيْهَا فَقَامَتْ الْمَرْأَةُ فَشَدَّ لَهُمَا عَلَى رَاحِلَتِهِمَا فَرَكِبَا فَسَارُوا حَتَّى إِذَا كَانُوا بِظَهْرِ الْمَدِينَةِ أَوْ قَالَ أَشْرَفُوا عَلَى الْمَدِينَةِ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ آيِبُونَ تَائِبُونَ عَابِدُونَ لِرَبِّنَا حَامِدُونَ فَلَمْ يَزَلْ يَقُولُهَا حَتَّى دَخَلَ الْمَدِينَةَ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Bisyr bin Al Mufadlal] telah menceritakan kepada kami [Yahya bin Abu Ishaq] dari [Anas bin Malik] bahwa dia dan Abu Thalhah pernah kembali bersama Nabi shallallahu 'alaihi wasallam, sedangkan Shafiyah membonceng Nabi shallallahu 'alaihi wasallam di atas hewan tunggangannya, ketika berada di tengah jalan, hewan tunggangan beliau terjatuh, hingga menyebabkan Nabi shallallahu 'alaihi wasallam dan wanita (Shafiyah) jatuh tersungkur, -Saya kira Yahya berkata; Bahwa Abu Thalhah segera lompat dari untanya dan langsung mendatangi Rasulullah shallallahu 'alaihi wasallam, dia berkata; \"Wahai Nabiyullah, biarkanlah Allah menjadikanku sebagai tebusan anda, apakah anda terkena sesuatu?\" beliau bersabda: \"Tidak, tetapi coba kamu tolong wanita (Shafiyah) itu\". Maka Abu Thalhah menutup wajahnya dengan selembar kainnya karena dia mengerti apa yang dikehendaki Shafiyah, maka dia melempar kainnya untuk Shafiyah, lalu wanita itu (Shafiyah) berdiri. Setelah itu Abu Thalhah memperbaiki pelana hewan tungangan beliau hingga keduanya dapat mengendarai kembali. Mereka pun melanjutkan perjalanan hingga ketika kota Madinah telah nampak -atau (perawi) berkata- sudah hampir mendekati kota Madinah, Beliau berdo'a: \"AAYIBUUNA TAA'IBUUNA 'AABIDUUNA LI RABBINAA HAAMIDUUNA. (Kita kembali sebagai hamba yang bertaubat, ber'ibadah kepada Rabb kita dan memuji-Nya\"). Beliau terus saja membaca do'a itu hingga memasuki kota Madinah."},"5413":{"ar":"حَدَّثَنَا صَدَقَةُ بْنُ الْفَضْلِ أَخْبَرَنَا ابْنُ عُيَيْنَةَ حَدَّثَنَا ابْنُ الْمُنْكَ��ِرِ عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُقَالَ وُلِدَ لِرَجُلٍ مِنَّا غُلَامٌ فَسَمَّاهُ الْقَاسِمَ فَقُلْنَا لَا نَكْنِيكَ أَبَا الْقَاسِمِ وَلَا كَرَامَةَ فَأَخْبَرَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ سَمِّ ابْنَكَ عَبْدَ الرَّحْمَنِ","id":"Telah menceritakan kepada kami [Shadaqah bin Al Fadl] telah mengabarkan kepada kami [Ibnu 'Uyainah] telah menceritakan kepada kami [Ibnu Al Munkadir] dari [Jabir] radliallahu 'anhu dia berkata; \"Seorang laki-laki di antara kami ada yang memiliki anak, kemudian dia memberi nama \"Al Qasim.\" Maka kami berkata; \"Kami tidak akan menjuluki kamu dengan Abu Al Qasim dan kami tidak akan memuliakannya. Lalu orang tersebut memberitahukan kepada Nabi shallallahu 'alaihi wasallam. Maka beliau bersabda: \"Berilah anakmu nama Abdurrahman.\""},"5414":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا خَالِدٌ حَدَّثَنَا حُصَيْنٌ عَنْ سَالِمٍ عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُ قَالَوُلِدَ لِرَجُلٍ مِنَّا غُلَامٌ فَسَمَّاهُ الْقَاسِمَ فَقَالُوا لَا نَكْنِيهِ حَتَّى نَسْأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ سَمُّوا بِاسْمِي وَلَا تَكْتَنُوا بِكُنْيَتِي","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Khalid] telah menceritakan kepada kami [Hushain] dari [Salim] dari [Jabir] radliallahu 'anhu dia berkata; \"Seorang laki-laki di antara kami ada yang memiliki anak, kemudian dia memberi nama \"Al Qasim.\" Maka orang-orang berkata; \"Kami tidak akan menjulukinya hingga kami bertanya kepada Nabi shallallahu 'alaihi wasallam. Maka beliau bersabda: \"Berilah nama dengan namaku dan janganlah kalian memberi julukan dengan julukanku.\""},"5415":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ أَيُّوبَ عَنْ ابْنِ سِيرِينَ سَمِعْتُ أَبَا هُرَيْرَةَقَالَ أَبُو الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمُّوا بِاسْمِي وَلَا تَكْتَنُوا بِكُنْيَتِي","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] dari [Ayyub] dari [Ibnu Sirin] saya mendengar [Abu Hurairah] bahwa Abu Al Qasim shallallahu 'alaihi wasallam bersabda; \"Berilah nama dengan namaku dan jangan kalian menjuluki dengan julukanku.\""},"5416":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا سُفْيَانُ قَالَ سَمِعْتُ ابْنَ الْمُنْكَدِرِ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَاوُلِدَ لِرَجُلٍ مِنَّا غُلَامٌ فَسَمَّاهُ الْقَاسِمَ فَقَالُوا لَا نَكْنِيكَ بِأَبِي الْقَاسِمِ وَلَا نُنْعِمُكَ عَيْنًا فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ ذَلِكَ لَهُ فَقَالَ أَسْمِ ابْنَكَ عَبْدَ الرَّحْمَنِ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] telah menceritakan kepada kami [Sufyan] dia berkata; saya mendengar [Ibnu Al Munkadir] berkata; saya mendengar [Jabir bin Abdullah] radliallahu 'anhuma bahwa seorang laki-laki dari kami memiliki seorang anak, lalu dia memberi nama Al Qasim, maka orang-orang berkata; \"Kami tidak akan menjulukinya dengan \"Abu Qasim\" dan kami tidak akan memuliakanmu dengan itu sedikitpun, lalu orang itu datang kepada Nabi shallallahu 'alaihi wasallam dan memberitahukan tentang hal itu, maka beliau bersabda: \"Namailah anakmu dengan Abdurrahman.\""},"5417":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ نَصْرٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ ابْنِ الْمُسَيَّبِ عَنْ أَبِيهِ أَنَّ أَبَاهُجَاءَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا اسْمُكَ قَالَ حَزْنٌ قَالَ أَنْتَ سَهْلٌ قَالَ لَا أُغَيِّرُ اسْمًا سَمَّانِيهِ أَبِيقَالَ ابْنُ الْمُسَيَّبِ فَمَا زَالَتْ الْحُزُونَةُ فِينَا بَعْدُ حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ وَمَحْمُودٌ هُوَ ابْنُ غَيْلَانَ قَالَا حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ ابْنِ الْمُسَيَّبِ عَنْ أَبِيهِ عَنْ جَدِّهِ بِهَذَا","id":"Telah menceritakan kepada kami [Ishaq bin Nashr] telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ibnu Musayyib] dari [Ayahnya] bahwa ayahnya pernah datang kepada Nabi shallallahu 'alaihi wasallam, lalu beliau bertanya: \"Siapakah namamu?\" ayahku menjawab; \"(namaku) Hazn (sedih).\" Beliau bersabda: \"(namamu) adalah Sahl (mudah).\" Ayahku berkata; \"Tidak, aku tidak akan merubah nama yang pernah diberikan oleh ayahku.\" Ibnu Musayyib berkata; \"Maka ia masih saja terlihat sedih ketika bersama kami, setelah peristiwa itu.\" Telah menceritakan kepada kami [Ali bin Abdullah] dan [Mahmud] yaitu Ibnu Ghailan keduanya berkata; telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ibnu Musayyab] dari [Ayahnya] dari [Kakeknya] dengan hadits ini.\""},"5418":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ حَدَّثَنَا أَبُو غَسَّانَ قَالَ حَدَّثَنِي أَبُو حَازِمٍ عَنْ سَهْلٍ قَالَأُتِيَ بِالْمُنْذِرِ بْنِ أَبِي أُسَيْدٍ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ وُلِدَ فَوَضَعَهُ عَلَى فَخِذِهِ وَأَبُو أُسَيْدٍ جَالِسٌ فَلَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشَيْءٍ بَيْنَ يَدَيْهِ فَأَمَرَ أَبُو أُسَيْدٍ بِابْنِهِ فَاحْتُمِلَ مِنْ فَخِذِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَفَاقَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَيْنَ الصَّبِيُّ فَقَالَ أَبُو أُسَيْدٍ قَلَبْنَاهُ يَا رَسُولَ اللَّهِ قَالَ مَا اسْمُهُ قَالَ فُلَانٌ قَالَ وَلَكِنْ أَسْمِهِ الْمُنْذِرَ فَسَمَّاهُ يَوْمَئِذٍ الْمُنْذِرَ","id":"Telah menceritakan kepada kami [Sa'id bin Abu Maryam] telah menceritakan kepada kami [Abu Ghassan] dia berkata; telah menceritakan kepada kami [Abu Hazim] dari [Sahl] dia berkata; \"Al Mundzir bin Abu Usaid di bawa ke hadapan Nabi shallallahu 'alaihi wasallam ketika ia baru dilahirkan, lalu beliau meletakkannya di pangkuan beliau, sementara Abu Usaid duduk di dekat beliau, tampaknya perhatian Nabi shallallahu 'alaihi wasallam tercurah penuh kepada sesuatu yang berada di hadapannya. Kemudian Abu Usaid menyuruh seorang untuk mengangkat anaknya dari atas paha nabi shallallahu 'alaihi wasallam dan memindahkannya. Ketika Nabi shallallahu 'alaihi wasallam selesai dari urusannya, beliau bertanya: 'Mana bayi itu? 'Abu Usaid menjawab; 'Kami telah memulangkannya, wahai Rasulullah.' Beliau bertanya: 'Siapa namanya? ' Abu Usaid menjawab; 'Fulan.' Lalu beliau bersabda: 'Tidak, tetapi namanya adalah Al Mundzir! ' Dengan demikian, beliau telah memberinya nama Al Mundzir pada hari itu.\""},"5419":{"ar":"حَدَّثَنَا صَدَقَةُ بْنُ الْفَضْلِ أَخْبَرَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ عَطَاءِ بْنِ أَبِي مَيْمُونَةَ عَنْ أَبِي رَافِعٍ عَنْ أَبِي هُرَيْرَةَأَنَّ زَيْنَبَ كَانَ اسْمُهَا بَرَّةَ فَقِيلَ تُزَكِّي نَفْسَهَا فَسَمَّاهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَيْنَبَ","id":"Telah menceritakan kepada kami [Shadaqah bin Al Fadl] telah mengabarkan kepada kami [Muhammad bin Ja'far] dari [Syu'bah] dari ['Atha` bin Abu Maimunah] dari [Abu Rafi'] dari [Abu Hurairah] bahwa Zainab nama (aslinya) adalah Barrah, maka dikatakan kepadanya; \"Apakah kamu hendak mensucikankan dirinya?\" setelah itu Rasulullah shallallahu 'alaihi wasallam menamainya Zainab.\""},"5420":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى حَدَّثَنَا هِشَامٌ أَنَّ ابْنَ جُرَيْجٍ أَخْبَرَهُمْ قَالَ أَخْبَرَنِي عَبْدُ الْحَمِيدِ بْنُ جُبَيْرِ بْنِ شَيْبَةَ قَالَ جَلَسْتُ إِلَى سَعِيدِ بْنِ الْمُسَيَّبِفَحَدَّثَنِي أَنَّ جَدَّهُ حَزْنًا قَدِمَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا اسْمُكَ قَالَ اسْمِي حَزْنٌ قَالَ بَلْ أَنْتَ سَهْلٌ قَالَ مَا أَنَا بِمُغَيِّرٍ اسْمًا سَمَّانِيهِ أَبِيقَالَ ابْنُ الْمُسَيَّبِ فَمَا زَالَتْ فِينَا الْحُزُونَةُ بَعْدُ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] telah menceritakan kepada kami [Hisyam] bahwa [Ibnu Juraij] telah mengabarkan kepada orang-orang, katanya; telah mengabarkan kepadaku [Abdul Hamid bin Jubair bin Syaibah] dia berkata; saya duduk di hadapan [Sa'id bin Musayyab] maka dia menceritakan kepadaku, bahwa kakeknya datang kepada Nabi shallallahu 'alaihi wasallam dalam keadaan sedih, lalu beliau bertanya; \"Siapakah namamu?\" dia menjawab; \"Namaku Hazn (sedih), \" beliau bersabda: \"Bahkan namamu adalah Sahl.\" Namun dia berkata; \"Tidak, aku tidak akan merubah nama yang pernah di berikan oleh ayahku.\" Ibnu Musayyib berkata; \"Maka dia masih saja terlihat sedih setelah peristiwa itu.\""},"5421":{"ar":"حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا إِسْمَاعِيلُ قُلْتُ لِابْنِ أَبِي أَوْفَىرَأَيْتَ إِبْرَاهِيمَ ابْنَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَاتَ صَغِيرًا وَلَوْ قُضِيَ أَنْ يَكُونَ بَعْدَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَبِيٌّ عَاشَ ابْنُهُ وَلَكِنْ لَا نَبِيَّ بَعْدَهُ","id":"Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Muhammad bin Bisyr] telah menceritakan kepada kami [Isma'il] saya berkata kepada [Ibnu Abu Aufa]; \"Apakah kamu mengetahui Ibrahim putra Nabi shallallahu 'alaihi wasallam? Ibnu Abu Aufa menjawab; \"Ibrahim meninggal ketika masih kecil, sekiranya ia ditetapkan sebagai Nabi setelah Muhammad shallallahu 'alaihi wasallam, maka ia akan tetap hidup, namun tidak ada Nabi setelah beliau.\""},"5422":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ أَخْبَرَنَا شُعْبَةُ عَنْ عَدِيِّ بْنِ ثَابِتٍ قَالَ سَمِعْتُ الْبَرَاءَ قَالَلَمَّا مَاتَ إِبْرَاهِيمُ عَلَيْهِ السَّلَام قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لَهُ مُرْضِعًا فِي الْجَنَّةِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah mengabarkan kepada kami [Syu'bah] dari ['Adi bin Tsabit] dia berkata; saya mendengar [Al Barra`] berkata; \"Ketika Ibrahim 'alaihis salam meninggal dunia, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya akan ada orang yang menyusuinya di surga.\""},"5423":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ عَنْ حُصَيْنِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ الْأَنْصَارِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمُّوا بِاسْمِي وَلَا تَكْتَنُوا بِكُنْيَتِي فَإِنَّمَا أَنَا قَاسِمٌ أَقْسِمُ بَيْنَكُمْوَرَوَاهُ أَنَسٌ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] dari [Hushain bin Abdurrahman] dari [Salim bin Abu Al Ja'd] dari [Jabir bin Abdullah Al Anshari] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Namailah dengan namaku dan janganlah kalian memberikan julukan dengan julukanku, sesungguhnya aku adalah Qasim, yang akan membagi-bagikan (rahmat Allah) di antara kalian.\""},"5424":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو عَوَانَةَ حَدَّثَنَا أَبُو حَصِينٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَمُّوا بِاسْمِي وَلَا تَكْتَنُوا بِكُنْيَتِي وَمَنْ رَآنِي فِي الْمَنَامِ فَقَدْ رَآنِي فَإِنَّ الشَّيْطَانَ لَا يَتَمَثَّلُ فِي صُورَتِي وَمَنْ كَذَبَ عَلَيَّ مُتَعَمِّدًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Abu 'Awanah] telah menceritakan kepada kami [Abu Hashin] dari [Abu Shalih] dari [Abu Hurairah] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Namailah dengan namaku dan jangan kalian menjuluki dengan julukanku, barangsiapa melihatku dalam mimpi, maka sesungguhnya ia telah melihatku, karena syetan tidak dapat menyerupaiku, dan barangsiapa berdusta atas namaku dengan sengaja, hendaknya ia mempersiapkan tempatnya di neraka.\""},"5425":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي بُرْدَةَ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَوُلِدَ لِي غُلَامٌ فَأَتَيْتُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَمَّاهُ إِبْرَاهِيمَ فَحَنَّكَهُ بِتَمْرَةٍ وَدَعَا لَهُ بِالْبَرَكَةِ وَدَفَعَهُ إِلَيَّ وَكَانَ أَكْبَرَ وَلَدِ أَبِي مُوسَى","id":"Telah menceritakan kepada kami [Muhammad bin Al Ala`] telah menceritakan kepada kami [Abu Usamah] dari [Buraid bin Abdullah bin Abu Burdah] dari [Abu Burdah] dari [Abu Musa] dia berkata; \"Aku pernah memliki seorang anak yang baru lahir, lalu aku serahkan kepada Nabi shallallahu 'alaihi wasallam, kemudian beliau memberinya nama Ibrahim dan mentahniknya (mengunyahkan kurma kemudian menyuapkan ke mulut bayi) dengan kurma, setelah itu beliau mendo'akannya dengan keberkahan, lalu beliau mengembalikannya kepadaku.\" Dan dia (anak tersebut) adalah anak yang paling besar dari anaknya Abu Musa.\""},"5426":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا زَائِدَةُ حَدَّثَنَا زِيَادُ بْنُ عِلَاقَةَ سَمِعْتُ الْمُغِيرَةَ بْنَ شُعْبَةَ قَالَانْكَسَفَتْ الشَّمْسُ يَوْمَ مَاتَ إِبْرَاهِيمُرَوَاهُ أَبُو بَكْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Al walid] telah menceritakan kepada kami [Za`idah] telah menceritakan kepada kami [Ziyad bin 'Ilaqah] saya mendengar [Al Mughirah bin Syu'bah] berkata; \"Terjadi gerhana pada hari meninggalnya Ibrahim.\" Di riwayatkan oleh Abu Bakrah dari Nabi shallallahu 'alaihi wasallam."},"5427":{"ar":"أَخْبَرَنَا أَبُو نُعَيْمٍ الْفَضْلُ بْنُ دُكَيْنٍ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ قَالَلَمَّا رَفَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأْسَهُ مِنْ الرَّكْعَةِ قَالَ اللَّهُمَّ أَنْجِ الْوَلِيدَ بْنَ الْوَلِيدِ وَسَلَمَةَ بْنَ هِشَامٍ وَعَيَّاشَ بْنَ أَبِي رَبِيعَةَ وَالْمُسْتَضْعَفِينَ بِمَكَّةَ اللَّهُمَّ اشْدُدْ وَطْأَتَكَ عَلَى مُضَرَ اللَّهُمَّ اجْعَلْهَا عَلَيْهِمْ سِنِينَ كَسِنِي يُوسُفَ","id":"Telah mengabarkan kepada kami [Abu Nu'aim Fadl bin Dukain] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Az Zuhri] dari [Sa'id] dari [Abu Hurairah] dia berkata; \"Tatkala Nabi shallallahu 'alaihi wasallam mengangkat kepala dari ruku', beliau berdo'a: \"Ya Allah, selamatkanlah Al Walid bin Al Walid dan Salamah bin Hisyam serta 'Ayyasy bin Abu Rabi'ah dan golongan yang lemah di Makkah. Ya Allah, timpakanlah kerasnya siksa-Mu kepada Mudlar dan jadikanlah siksa-Mu untuk mereka berupa paceklik seperti paceklik yang terjadi pada zaman Nabi Yusuf.\""},"5428":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَائِشَ هَذَا جِبْرِيلُ يُقْرِئُكِ السَّلَامَ قُلْتُ وَعَلَيْهِ السَّلَامُ وَرَحْمَةُ اللَّهِ قَالَتْ وَهُوَ يَرَى مَا لَا نَرَى","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; telah menceritakan kepadaku [Abu Salamah bin Abdurrahman] bahwa [Aisyah] radliallahu 'anha isteri Nabi shallallahu 'alaihi wasallam berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai 'Aisy (sebutan untuk Aisyah), Ini adalah Jibril, ia menitipkan salam untukmu.\" Lalu aku menjawab; \"Wa'alaihis salam warahmatullah.\" Aisyah berkata; \"Dia (Jibril) melihat sesuatu yang tidak kami lihat.\""},"5429":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَتْ أُمُّ سُلَيْمٍ فِي الثَّقَلِ وَأَنْجَشَةُ غُلَامُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسُوقُ بِهِنَّ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَنْجَشُ رُوَيْدَكَ سَوْقَكَ بِالْقَوَارِيرِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Ayyub] dari [Abu Qilabah] dari [Anas] radliallahu 'anhu dia berkata; \"Ummu Sulaim pernah sakit, sementara Anjasyah yaitu hamba sahaya Nabi shallallahu 'alaihi wasallam mengawalnya, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Wahai Anjasy, pelan-pelanlah kamu kalau mengawal sesuatu yang mudah pecah (maksudnya wanita).\""},"5430":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ أَبِي التَّيَّاحِ عَنْ أَنَسٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحْسَنَ النَّاسِ خُلُقًا وَكَانَ لِي أَخٌ يُقَالُ لَهُ أَبُو عُمَيْرٍ قَالَ أَحْسِبُهُ فَطِيمًا وَكَانَ إِذَا جَاءَ قَالَ يَا أَبَا عُمَيْرٍ مَا فَعَلَ النُّغَيْرُ نُغَرٌ كَانَ يَلْعَبُ بِهِ فَرُبَّمَا حَضَرَ الصَّلَاةَ وَهُوَ فِي بَيْتِنَا فَيَأْمُرُ بِالْبِسَاطِ الَّذِي تَحْتَهُ فَيُكْنَسُ وَيُنْضَحُ ثُمَّ يَقُومُ وَنَقُومُ خَلْفَهُ فَيُصَلِّي بِنَا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abdul Warits] dari [Abu At Tayyah] dari [Anas] dia berkata; \"Nabi shallallahu 'alaihi wasallam adalah sosok yang paling mulia akhlaknya, aku memiliki saudara yang bernama Abu 'Umair -Perawi mengatakan; aku mengira Anas juga berkata; 'Kala itu ia habis disapih.\"- Dan apabila beliau datang, maka beliau akan bertanya: 'Hai Abu Umar, bagaimana kabar si nughair (burung pipitnya). Abu Umair memang senang bermain dengannya, dan ketika waktu shalat telah tiba, sedangkan beliau masih berada di rumah kami, maka beliau meminta dihamparkan tikar dengan menyapu bawahnya dan memercikinya, lalu kami berdiri di belakang beliau, dan beliau pun shalat mengimami kami.\""},"5431":{"ar":"حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا سُلَيْمَانُ قَالَ حَدَّثَنِي أَبُو حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَإِنْ كَانَتْ أَحَبَّ أَسْمَاءِ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ إِلَيْهِ لَأَبُو تُرَابٍ وَإِنْ كَانَ لَيَفْرَحُ أَنْ يُدْعَى بِهَا وَمَا سَمَّاهُ أَبُو تُرَابٍ إِلَّا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَاضَبَ يَوْمًا فَاطِمَةَ فَخَرَجَ فَاضْطَجَعَ إِلَى الْجِدَارِ إِلَى الْمَسْجِدِ فَجَاءَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتْبَعُهُ فَقَالَ هُوَ ذَا مُضْطَجِعٌ فِي الْجِدَارِ فَجَاءَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَامْتَلَأَ ظَهْرُهُ تُرَابًا فَجَعَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْسَحُ التُّرَابَ عَنْ ظَهْرِهِ وَيَقُولُ اجْلِسْ يَا أَبَا تُرَابٍ","id":"Telah menceritakan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Sulaiman] dia berkata; telah menceritakan kepadaku [Abu Hazim] dari [Sahl bin Sa'd] dia berkata; \"Bahwa di antara nama-nama yang paling disukai oleh Ali adalah Abu Turab, dan dia lebih suka apabila dipanggil dengan sebutan Abu Turab. Dan tidaklah ia dijuluki Abu Turab melainkan suatu hari Nabi shallallahu 'alaihi wasallam (mengetahui) bahwa antara dia dengan Fathimah ada sedikit permasalahan, lalu dia keluar dan tidur di masjid, ternyata Nabi shallallahu 'alaihi wasallam membuntutinya dan hendak menemuinya, lalu beliau bersabda: \"ini dia sedang berbaring di masjid.\" Kemudian Nabi shallallahu 'alaihi wasallam menemuinya sementara dirinya tengah berbaring hingga banyak debu menempel di punggungnya, maka Nabi shallallahu 'alaihi wasallam membersihkan debu dari punggungnya dan bersabda: \"Duduklah wahai Abu Turab.\""},"5432":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْنَى الْأَسْمَاءِ يَوْمَ الْقِيَامَةِ عِنْدَ اللَّهِ رَجُلٌ تَسَمَّى مَلِكَ الْأَمْلَاكِ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] telah menceritakan kepada kami [Abu Az Zinnad] dari [Al A'raj] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sehina-hinanya nama di sisi Allah pada hari Kiamat kelak adalah seseorang yang bernama Malikil Amlak (raja diraja).\""},"5433":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رِوَايَةً قَالَ أَخْنَعُ اسْمٍ عِنْدَ اللَّهِ وَقَالَ سُفْيَانُ غَيْرَ مَرَّةٍأَخْنَعُ الْأَسْمَاءِ عِنْدَ اللَّهِ رَجُلٌ تَسَمَّى بِمَلِكِ الْأَمْلَاكِقَالَ سُفْيَانُ يَقُولُ غَيْرُهُ تَفْسِيرُهُ شَاهَانْ شَاهْ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] dari [Abu Az Zinnad] dari [Al A'raj] dari [Abu Hurairah] secara periwayatan, dia berkata; \"Sehina-hinanya nama di sisi Allah -Sufyan mengatakan tidak cuma sekali- sehina-hinanya nama di sisi Allah adalah seseorang yang bernama Malikil Amalak (raja diraja).\" Sufyan berkata; yang lain mengatakan; sedangkan tafsirnya adalah syahan syah (sebutan untuk raja dari segala raja)."},"5434":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ ح حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي أَخِي عَنْ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ أَبِي عَتِيقٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ أَنَّ أُسَامَةَ بْنَ زَيْدٍ رَضِيَ اللَّهُ عَنْهُمَا أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكِبَ عَلَى حِمَارٍ عَلَيْهِ قَطِيفَةٌ فَدَكِيَّةٌ وَأُسَامَةُ وَرَاءَهُ يَعُودُ سَعْدَ بْنَ عُبَادَةَ فِي بَنِي حَارِثِ بْنِ الْخَزْرَجِ قَبْلَ وَقْعَةِ بَدْرٍ فَسَارَا حَتَّى مَرَّا بِمَجْلِسٍ فِيهِ عَبْدُ اللَّهِ بْنُ أُبَيٍّ ابْنُ سَلُولَ وَذَلِكَ قَبْلَ أَنْ يُسْلِمَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ فَإِذَا فِي الْمَجْلِسِ أَخْلَاطٌ مِنْ الْمُسْلِمِينَ وَالْمُشْرِكِينَ عَبَدَةِ الْأَوْثَانِ وَالْيَهُودِ وَفِي الْمُسْلِمِينَ عَبْدُ اللَّهِ بْنُ رَوَاحَةَ فَلَمَّا غَشِيَتْ الْمَجْلِسَ عَجَاجَةُ الدَّابَّةِ خَمَّرَ ابْنُ أُبَيٍّ أَنْفَهُ بِرِدَائِهِ وَقَالَ لَا تُغَبِّرُوا عَلَيْنَا فَسَلَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْهِمْ ثُمَّ وَقَفَ فَنَزَلَ فَدَعَاهُمْ إِلَى اللَّهِ وَقَرَأَ عَلَيْهِمْ الْقُرْآنَ فَقَالَ لَهُ عَبْدُ اللَّهِ بْنُ أُبَيٍّ ابْنُ سَلُولَ أَيُّهَا الْمَرْءُ لَا أَحْسَنَ مِمَّا تَقُولُ إِنْ كَانَ حَقًّا فَلَا تُؤْذِنَا بِهِ فِي مَجَالِسِنَا فَمَنْ جَاءَكَ فَاقْصُصْ عَلَيْهِ قَالَ عَبْدُ اللَّهِ بْنُ رَوَاحَةَ بَلَى يَا رَسُولَ اللَّهِ فَاغْشَنَا فِي مَجَالِسِنَا فَإِنَّا نُحِبُّ ذَلِكَ فَاسْتَبَّ الْمُسْلِمُونَ وَالْمُشْرِكُونَ وَالْيَهُودُ حَتَّى كَادُوا يَتَثَاوَرُونَ فَلَمْ يَزَلْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُخَفِّضُهُمْ حَتَّى سَكَتُوا ثُمَّ رَكِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَابَّتَهُ فَسَارَ حَتَّى دَخَلَ عَلَى سَعْدِ بْنِ عُبَادَةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيْ سَعْدُ أَلَمْ تَسْمَعْ مَا قَالَ أَبُو حُبَابٍ يُرِيدُ عَبْدَ اللَّهِ بْنَ أُبَيٍّ قَالَ كَذَا وَكَذَا فَقَالَ سَعْدُ بْنُ عُبَادَةَ أَيْ رَسُولَ اللَّهِ بِأَبِي أَنْتَ اعْفُ عَنْهُ وَاصْفَحْ فَوَالَّذِي أَنْزَلَ عَلَيْكَ الْكِتَابَ لَقَدْ جَاءَ اللَّهُ بِالْحَقِّ الَّذِي أَنْزَلَ عَلَيْكَ وَلَقَدْ اصْطَلَحَ أَهْلُ هَذِهِ الْبَحْرَةِ عَلَى أَنْ يُتَوِّجُوهُ وَيُعَصِّبُوهُ بِالْعِصَابَةِ فَلَمَّا رَدَّ اللَّهُ ذَلِكَ بِالْحَقِّ الَّذِي أَعْطَاكَ شَرِقَ بِذَلِكَ فَذَلِكَ فَعَلَ بِهِ مَا رَأَيْتَ فَعَفَا عَنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ يَعْفُونَ عَنْ الْمُشْرِكِينَ وَأَهْلِ الْكِتَابِ كَمَا أَمَرَهُمْ اللَّهُ وَيَصْبِرُونَ عَلَى الْأَذَى قَالَ اللَّهُ تَعَالَى{ وَلَتَسْمَعُنَّ مِنْ الَّذِينَ أُوتُوا الْكِتَابَ }الْآيَةَ وَقَالَ{ وَدَّ كَثِيرٌ مِنْ أَهْلِ الْكِتَابِ }فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَأَوَّلُ فِي الْعَفْوِ عَنْهُمْ مَا أَمَرَهُ اللَّهُ بِهِ حَتَّى أَذِنَ لَهُ فِيهِمْ فَلَمَّا غَزَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَدْرًا فَقَتَلَ اللَّهُ بِهَا مَنْ قَتَلَ مِنْ صَنَادِيدِ الْكُفَّارِ وَسَادَةِ قُرَيْشٍ فَقَفَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ مَنْصُورِينَ غَانِمِينَ مَعَهُمْ أُسَارَى مِنْ صَنَادِيدِ الْكُفَّارِ وَسَادَةِ قُرَيْشٍ قَالَ ابْنُ أُبَيٍّ ابْنُ سَلُولَ وَمَنْ مَعَهُ مِنْ الْمُشْرِكِينَ عَبَدَةِ الْأَوْثَانِ هَذَا أَمْرٌ قَدْ تَوَجَّهَ فَبَايِعُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْإِسْلَامِ فَأَسْلَمُوا","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri]. Dan diriwayatkan dari jalur lain, telah menceritakan kepada kami [Isma'il] dia berkata; telah menceritakan kepadaku [Saudaraku] dari [Sulaiman] dari [Muhammad bin Abu 'Atiq] dari [Ibnu Syihab] dari ['Urwah bin Az Zubair] bahwa [Usamah bin Zaid] radliallahu 'anhuma telah mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam pernah mengendarai seekor keledai, dilengkapi dengan pelana yang terbuat dari kain Fadak, sementara Usamah berada di belakang beliau. Beliau pergi untuk menjenguk Sa'ad bin 'Ubadah di Bani Al Harits bin Al Khazraj; kejadian ini berlangsung sebelum perang Badar. Kemudian beliau berangkat hingga melewati suatu majlis, yang di dalamnya terdapat 'Abdullah bin 'Ubay bin Salul. Itu terjadi sebelum 'Abdullah bin 'Ubay masuk Islam. Di dalam majlis itu berkumpul pula orang-orang dari kaum Muslimin, orang-orang Musyrik, para penyembah berhala, dan orang-orang Yahudi. Di kalangan kaum Muslimin terdapat 'Abdullah bin Rawahah. Ketika majlis tersebut di kepuli oleh debu yang ditimbulkan dari hewan tunggangan, 'Abdullah bin 'Ubay langsung menutup hidungnya sambil berkata; \"Hei, jangan kamu kepuli kami dengan debu.\" Rasulullah shallallahu 'alaihi wasallam mengucapkan salam kepada mereka, lalu beliau berhenti, turun dan mengajak mereka kepada Allah (memeluk agama Islam) dan membacakan kepada mereka Al Qur'an. Mendengar hal itu 'Abdullah bin 'Ubay berkata; 'Hei..! apa tak ada yang lebih baik dari yang engkau ucapkan! jika itu benar, jangan ganggu di pertemuan kami. Kembalilah! Dan bacakan saja kepada orang-orang yang datang kepadamu! ' Mendengar itu 'Abdullah bin Rawahah berkata; 'Ya Rasulullah! sampaikan saja kepada kami dalam pertemuan ini, karena kami menyukai hal itu.' Maka Kaum Muslimin, orang-orang kafir, dan Yahudi saling mencaci-maki satu sama lain hingga hampir saja mereka berkelahi. Nabi shallallahu 'alaihi wasallam tidak henti-hentinya menenangkan mereka hingga mereka semua kembali tenang. Setelah itu Rasulullah shallallahu 'alaihi wasallam menaiki kembali keledainya dan melanjutkan perjalanan hingga sampai di kediaman Sa'ad bin 'Ubadah. Lalu Rasulullah shallallahu 'alaihi wasallam berkata kepada Sa'ad: 'Wahai Sa'd, tidakkah engkau mendengar apa yang diucapkan Abu Hubab? ' -yang beliau maksudkan adalah 'Abdullah bin 'Ubay- 'Dia telah berkata ini dan itu.' Mendengar itu Sa'ad bin 'Ubadah berkata; Demi ayahku, maafkan dia wahai Rasulullah dan berlapang dadalah kepadanya. Demi dzat yang menurunkan kitab kepada anda, Allah telah datang dengan kebenaran yang diturunkan kepada anda. (dahulu) Penduduk telaga ini (penduduk Madinah -red) bersepakat untuk memilihnya dan mengangkatnya, namun karena kebenaran yang diberikan kepada anda itu muncul, sehingga menghalanginya (Abdullah bin Ubay) menjabat sebagai pemimpin, maka seperti itulah perbuatannya sebagaimana yang anda lihat.\" Akhirnya Rasulullah shallallahu 'alaihi wasallam memaafkannya, karena itu Rasulullah shallallahu 'alaihi wasallam dan para sahabatnya memaafkan orang-orang kafir dan para Ahli Kitab sebagaimana yang diperintahkan Allah, dan mereka bersabar terhadap gangguan mereka. Allah Ta'ala berfirman: (…kamu sungguh-sungguh akan mendengar dari orang-orang yang diberi Kitab…) QS Ali Imran; 186. dan firman Allah (…Sebahagian besar ahli Kitab menginginkan agar mereka dapat mengembalikan kamu…) QS Al Baqarah; 109. Dan Nabi shallallahu 'alaihi wasallam menafsirkan (ayat di atas) suatu prinsip memberikan ampunan kepada mereka selama Allah memerintahkannya demikian hingga Allah memberikan izin untuk memerangi mereka. Maka ketika Rasulullah shallallahu 'alaihi wasallam memerangi mereka dalam Perang Badar dan Allah membinasakan orang-orang terkemuka Quraisy, maka Rasulullah shallallahu 'alaihi wasallam dan para sahabatnya pun kembali dengan membawa kemenangan, baik harta ghanimah maupun para tawanan dari pembesar-pembesar Qurasy, Abdullah bin Ubay bin Salul dan orang-orang kafir dari para penyembah berhala yang bersamanya berkata; 'Perkara ini (Islam) telah muncul.' Lalu mereka berbaiat atas Islam kepada Rasulullah shallallahu 'alaihi wasallam, akhirnya mereka masuk Islam."},"5435":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو عَوَانَةَ حَدَّثَنَا عَبْدُ الْمَلِكِ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ بْنِ نَوْفَلٍ عَنْ عَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِ قَالَيَا رَسُولَ اللَّهِ هَلْ نَفَعْتَ أَبَا طَالِبٍ بِشَيْءٍ فَإِنَّهُ كَانَ يَحُوطُكَ وَيَغْضَبُ لَكَ قَالَ نَعَمْ هُوَ فِي ضَحْضَاحٍ مِنْ نَارٍ لَوْلَا أَنَا لَكَانَ فِي الدَّرَكِ الْأَسْفَلِ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Abu 'Awanah] telah menceritakan kepada kami [Abdul Malik] dari [Abdullah bin Al Harits bin Naufal] dari [Abbas bin Abdul Mutthalib] dia berkata; \"Wahai Rasulullah, apakah anda dapat memberi manfa'at kepada Abu Thalib, karena dia telah mengasuhmu dan terkadang marah (untuk memberikan pembelaan) kepadamu.\" Beliau menjawab; \"Ya. ia berada di bagian neraka yang dangkal, dan kalaulah bukan karena diriku, niscaya berada di dasar neraka.\""},"5436":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَسِيرٍ لَهُ فَحَدَا الْحَادِي فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ارْفُقْ يَا أَنْجَشَةُ وَيْحَكَ بِالْقَوَارِيرِ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] dari [Tsabit Al Bunani] dari [Anas bin Malik] dia berkata; Nabi shallallahu 'alaihi wasallam pernah dalam berada di suatu perjalanan, dan di kawal oleh seorang pengawal, lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Pelan-pelanlah wahai Anjasyah jika mengawal para wanita.\""},"5437":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ عَنْ أَنَسٍ وَأَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ فِي سَفَرٍ وَكَانَ غُلَامٌ يَحْدُو بِهِنَّ يُقَالُ لَهُ أَنْجَشَةُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رُوَيْدَكَ يَا أَنْجَشَةُ سَوْقَكَ بِالْقَوَارِيرِقَالَ أَبُو قِلَابَةَ يَعْنِي النِّسَاءَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad] dari [Tsabit] dari [Anas] dan [Ayyub] dari [Abu Qilabah] dari [Anas] radliallahu 'anhu bahwa Nabi shallallahu 'alaihi wasallam pernah dalam suatu perjalanan, sementara seorang hamba sahayanya bernama Anjasyah mengawal para wanita, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Pelan-pelanlah wahai Anjasyah, karena kamu tengah mengawal sesuatu yang mudah pecah.\" Abu Qilabah mengatakan; maksudnya adalah (mengawal) para wanita.\""},"5438":{"ar":"حَدَّثَنَا إِسْحَاقُ أَخْبَرَنَا حَبَّانُ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍ قَالَكَانَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَادٍ يُقَالُ لَهُ أَنْجَشَةُ وَكَانَ حَسَنَ الصَّوْتِ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رُوَيْدَكَ يَا أَنْجَشَةُ لَا تَكْسِرْ الْقَوَارِيرَقَالَ قَتَادَةُ يَعْنِي ضَعَفَةَ النِّسَاءِ","id":"Telah menceritakan kepada kami [Ishaq] telah mengabarkan kepada kami [Habban] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] telah menceritakan kepada kami [Anas bin Malik] dia berkata; \"Nabi shallallahu 'alaihi wasallam memiliki seorang pengawal yang bernama Anjasyah, dan beliau adalah sosok yang suaranya merdu, maka Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Pelan-pelanlah wahai Anjasyah, janganlah kamu memecahkan sesuatu yang mudah pecah (wanita).\" Qatadah mengatakan; Maksudnya adalah wanita, karena lemahnya diri mereka.\""},"5439":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ قَالَ حَدَّثَنِي قَتَادَةُ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ بِالْمَدِينَةِ فَزَعٌ فَرَكِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَسًا لِأَبِي طَلْحَةَ فَقَالَ مَا رَأَيْنَا مِنْ شَيْءٍ وَإِنْ وَجَدْنَاهُ لَبَحْرًا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Syu'bah] dia berkata; telah menceritakan kepadaku [Qatadah] dari [Anas bin Malik] dia berkata; \"Suatu ketika di Madinah dikejutkan oleh suatu suara, maka Rasulullah shallallahu 'alaihi wasallam langsung naik kuda milik Abu Thalhah, lalu beliau bersabda: \"Kami tidak melihat suatu yang mengejutkan, yang kami dapati hanya seekor kuda yang berlari kencang.\""},"5440":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَامٍ أَخْبَرَنَا مَخْلَدُ بْنُ يَزِيدَ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ ابْنُ شِهَابٍ أَخْبَرَنِي يَحْيَى بْنُ عُرْوَةَ أَنَّهُ سَمِعَ عُرْوَةَ يَقُولُ قَالَتْ عَائِشَةُسَأَلَ أُنَاسٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْكُهَّانِ فَقَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسُوا بِشَيْءٍ قَالُوا يَا رَسُولَ اللَّهِ فَإِنَّهُمْ يُحَدِّثُونَ أَحْيَانًا بِالشَّيْءِ يَكُونُ حَقًّا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تِلْكَ الْكَلِمَةُ مِنْ الْحَقِّ يَخْطَفُهَا الْجِنِّيُّ فَيَقُرُّهَا فِي أُذُنِ وَلِيِّهِ قَرَّ الدَّجَاجَةِ فَيَخْلِطُونَ فِيهَا أَكْثَرَ مِنْ مِائَةِ كَذْبَةٍ","id":"Telah menceritakan kepada kami [Muhammad bin Salam] telah mengabarkan kepada kami [Makhlad bin Yazid] telah mengabarkan kepada kami [Ibnu Juraij], [Ibnu Syihab] berkata; telah mengabarkan kepadaku [Yahya bin 'Urwah] bahwa dia mendengar [Urwah] berkata; [Aisyah] berkata; \"Orang-orang bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai paranormal (dukun), maka beliau bersabda kepada mereka: \"Sesungguhnya mereka tidak (mengetahui) apa-apa.\" Mereka berkata; \"Wahai Rasulullah, terkadang pembicaraan mereka benar.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ucapan yang benar itu adalah hasil curian jin, kemudian ia perdengarkan ke telinga para wali-walinya sebagaimana ayam betina bersuara, kemudian mereka menambah-nambahi dengan seratus kebohongan.\""},"5441":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ قَالَ سَمِعْتُ أَبَا سَلَمَةَ بْنَ عَبْدِ الرَّحْمَنِ يَقُولُ أَخْبَرَنِي جَابِرُ بْنُ عَبْدِ اللَّهِ أَنَّهُسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ ثُمَّ فَتَرَ عَنِّي الْوَحْيُ فَبَيْنَا أَنَا أَمْشِي سَمِعْتُ صَوْتًا مِنْ السَّمَاءِ فَرَفَعْتُ بَصَرِي إِلَى السَّمَاءِ فَإِذَا الْمَلَكُ الَّذِي جَاءَنِي بِحِرَاءٍ قَاعِدٌ عَلَى كُرْسِيٍّ بَيْنَ السَّمَاءِ وَالْأَرْضِ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dia berkata; saya mendengar [Abu Salamah bin Abdurrahman] berkata; telah mengabarkan kepadaku [Jabir bin Abdullah] bahwa dia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kemudian wahyu terhenti dariku, ketika aku berjalan, tiba-tiba aku mendengar suara dari langit, aku langsung memandang ke arah langit, ternyata malaikat yang datang kepadaku ketika di go'a hira' tengah duduk di atas kursi antara langit dan bumi.\""},"5442":{"ar":"حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ أَخْبَرَنِي شَرِيكٌ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَبِتُّ فِي بَيْتِ مَيْمُونَةَ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَهَا فَلَمَّا كَانَ ثُلُثُ اللَّيْلِ الْآخِرُ أَوْ بَعْضُهُ قَعَدَ فَنَظَرَ إِلَى السَّمَاءِ فَقَرَأَ{ إِنَّ فِي خَلْقِ السَّمَوَاتِ وَالْأَرْضِ وَاخْتِلَافِ اللَّيْلِ وَالنَّهَارِ لَآيَاتٍ لِأُولِي الْأَلْبَابِ }","id":"Telah menceritakan kepada kami [Ibnu Abu Maryam] telah menceritakan kepada kami [Muhammad bin Ja'far] dia berkata; telah mengabarkan kepadaku [Syarik] dari [Kuraib] dari [Ibnu Abbas] radliallahu 'anhuma dia berkata; \"Aku pernah bermalam di rumah Maimunah, sedangkan Nabi shallallahu 'alaihi wasallam berada di sisinya, tatkala di sepertiga malam terakhir atau sebagian malam, beliau duduk dan memandang ke arah langit sambil membaca: \"Sesungguhnya dalam penciptaan langit dan bumi, dan silih bergantinya malam dan siang terdapat tanda-tanda bagi orang-orang yang berakal.\" QS Ali Imran; 190."},"5443":{"ar":"حَدَّثَنَا مُسَدَّدٌ ��َدَّثَنَا يَحْيَى عَنْ عُثْمَانَ بْنِ غِيَاثٍ حَدَّثَنَا أَبُو عُثْمَانَ عَنْ أَبِي مُوسَىأَنَّهُ كَانَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَائِطٍ مِنْ حِيطَانِ الْمَدِينَةِ وَفِي يَدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عُودٌ يَضْرِبُ بِهِ بَيْنَ الْمَاءِ وَالطِّينِ فَجَاءَ رَجُلٌ يَسْتَفْتِحُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ افْتَحْ لَهُ وَبَشِّرْهُ بِالْجَنَّةِ فَذَهَبْتُ فَإِذَا أَبُو بَكْرٍ فَفَتَحْتُ لَهُ وَبَشَّرْتُهُ بِالْجَنَّةِ ثُمَّ اسْتَفْتَحَ رَجُلٌ آخَرُ فَقَالَ افْتَحْ لَهُ وَبَشِّرْهُ بِالْجَنَّةِ فَإِذَا عُمَرُ فَفَتَحْتُ لَهُ وَبَشَّرْتُهُ بِالْجَنَّةِ ثُمَّ اسْتَفْتَحَ رَجُلٌ آخَرُ وَكَانَ مُتَّكِئًا فَجَلَسَ فَقَالَ افْتَحْ لَهُ وَبَشِّرْهُ بِالْجَنَّةِ عَلَى بَلْوَى تُصِيبُهُ أَوْ تَكُونُ فَذَهَبْتُ فَإِذَا عُثْمَانُ فَقُمْتُ فَفَتَحْتُ لَهُ وَبَشَّرْتُهُ بِالْجَنَّةِ فَأَخْبَرْتُهُ بِالَّذِي قَالَ قَالَ اللَّهُ الْمُسْتَعَانُ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Utsman bin Ghiyats] telah menceritakan kepada kami [Abu Utsman] dari [Abu Musa] bahwa dia pernah bersama Nabi shallallahu 'alaihi wasallam berada di suatu kebun di antara kebun-kebun yang ada di Madinah, ketika itu beliau tengah membawa dahan dan memukul-mukulkan antara air dan tanah, tiba-tiba datang seorang laki-laki meminta izin, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Bukakanlah dan berilah kabar gembira kepadanya dengan surga\". Maka aku pergi, ternyata laki-laki itu adalah Abu Bakr, lalu aku pun membukakan pintu untuknya dan kusampaikan kabar gembira dengan surga. Kemudian datang lagi laki-laki lain meminta dibukakan pintu, maka beliau bersabda: \"Bukakanlah dan sampaikan kabar gembira kepadanya dengan surga.\" Ternyata dia adalah Umar, maka aku membukakan pintu dan aku sampaikan kabar gembira dengan surga. Kemudian datang lagi laki-laki lain meminta dibukakan pintu, ketika itu beliau tengah berbaring, kemudian beliau duduk dan bersabda: \"Bukakanlah dan sampaikan kabar gembira kepadanya dengan surga atas ujian yang menimpanya atau yang akan menimpanya.\" Lalu aku beranjak pergi, ternyata laki-laki itu adalah 'Utsman lalu aku berdiri dan membukakan pintu untuknya, dan menyampaikan kepadanya kabar gembira dengan surga serta memberitahukan sebagaimana yang di sabdakan beliau. 'Utsman lalu berkata; \"Allah sajalah dzat yang dimintai pertolongan-Nya.\""},"5444":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ وَمَنْصُورٍ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي جَنَازَةٍ فَجَعَلَ يَنْكُتُ الْأَرْضَ بِعُودٍ فَقَالَ لَيْسَ مِنْكُمْ مِنْ أَحَدٍ إِلَّا وَقَدْ فُرِغَ مِنْ مَقْعَدِهِ مِنْ الْجَنَّةِ وَالنَّارِ فَقَالُوا أَفَلَا نَتَّكِلُ قَالَ اعْمَلُوا فَكُلٌّ مُيَسَّرٌ{ فَأَمَّا مَنْ أَعْطَى وَاتَّقَى }الْآيَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Syu'bah] dari [Sulaiman] dan [Manshur] dari [Sa'd bin 'Ubaidah] dari [Abu Abdurrahman As Sulami] dari [Ali] radliallahu 'anhu dia berkata; \"Kami pernah pergi bersama Nabi shallallahu 'alaihi wasallam di suatu Jenazah, kemudian beliau mengambil ranting yang ada di atas tanah dan bersabda: \"Tidaklah seorangpun di antara kalian kecuali telah ditulis tempatnya, di neraka atau di syurga.\" Mereka berkata; \"Wahai Rasulullah, kalau begitu kita bertawakkal saja.\" Beliau bersabda: \"Beramallah! Karena semuanya akan dimudahkan. (Adapun orang yang memberikan (hartanya di jalan Allah) dan bertakwa).\" QS Al Lail; 5."},"5445":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ حَدَّثَتْنِي هِنْدُ بِنْتُ الْحَارِثِ أَنَّ أُمَّ سَلَمَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْاسْتَيْقَظَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ سُبْحَانَ اللَّهِ مَاذَا أُنْزِلَ مِنْ الْخَزَائِنِ وَمَاذَا أُنْزِلَ مِنْ الْفِتَنِ مَنْ يُوقِظُ صَوَاحِبَ الْحُجَرِ يُرِيدُ بِهِ أَزْوَاجَهُ حَتَّى يُصَلِّينَ رُبَّ كَاسِيَةٍ فِي الدُّنْيَا عَارِيَةٌ فِي الْآخِرَةِوَقَالَ ابْنُ أَبِي ثَوْرٍ عَنْ ابْنِ عَبَّاسٍ عَنْ عُمَرَ قَالَ قُلْتُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَلَّقْتَ نِسَاءَكَ قَالَ لَا قُلْتُ اللَّهُ أَكْبَرُ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] telah menceritakan kepadaku [Hindun binti Al Harits] bahwa [Ummu Salamah] radliallahu 'anha berkata; \"Tiba-tiba Nabi shallallahu 'alaihi wasallam terbangun, lalu beliau mengucapkan: \"Subhanallah, perbendaharaan apa lagi yang Allah turunkan? Dan fitnah apa lagi yang Allah turunkan? Siapa yang mau membangunkan penghuni kamar-kamar -maksudnya isterinya- untuk menegakkan shalat? Betapa banyak orang berpakaian di dunia namun di akherat telanjang.\" Ibnu Abu Tsaur berkata; dari Ibnu Abbas dari Umar dia berkata; saya bertanya kepada Nabi shallallahu 'alaihi wasallam; \"Apakah anda mentalak isteri anda?\" beliau menjawab: \"Tidak.\" Maka saya berkata; \"Allahu Akbar.\""},"5446":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ ح و حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي أَخِي عَنْ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ أَبِي عَتِيقٍ عَنْ ابْنِ شِهَابٍ عَنْ عَلِيِّ بْنِ الْحُسَيْنِ أَنَّ صَفِيَّةَ بِنْتَ حُيَيٍّ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَتْهُأَنَّهَا جَاءَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَزُورُهُ وَهُوَ مُعْتَكِفٌ فِي الْمَسْجِدِ فِي الْعَشْرِ الْغَوَابِرِ مِنْ رَمَضَانَ فَتَحَدَّثَتْ عِنْدَهُ سَاعَةً مِنْ الْعِشَاءِ ثُمَّ قَامَتْ تَنْقَلِبُ فَقَامَ مَعَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْلِبُهَا حَتَّى إِذَا بَلَغَتْ بَابَ الْمَسْجِدِ الَّذِي عِنْدَ مَسْكَنِ أُمِّ سَلَمَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِهِمَا رَجُلَانِ مِنْ الْأَنْصَارِ فَسَلَّمَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ نَفَذَا فَقَالَ لَهُمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى رِسْلِكُمَا إِنَّمَا هِيَ صَفِيَّةُ بِنْتُ حُيَيٍّ قَالَا سُبْحَانَ اللَّهِ يَا رَسُولَ اللَّهِ وَكَبُرَ عَلَيْهِمَا مَا قَالَ إِنَّ الشَّيْطَانَ يَجْرِي مِنْ ابْنِ آدَمَ مَبْلَغَ الدَّمِ وَإِنِّي خَشِيتُ أَنْ يَقْذِفَ فِي قُلُوبِكُمَا","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dan diriwayatkan dari jalur lain, telah menceritakan kepada kami [Isma'il] dia berkata; telah menceritakan kepadaku [Saudaraku] dari [Sulaiman] dari [Muhammad bin Abu 'Atiq] dari [Ibnu Syihab] dari [Ali bin Al Hasan] bahwa [Shafiyah binti Huyay isteri Nabi] shallallahu 'alaihi wasallam telah mengabarkan kepadanya, bahwa dia pernah datang mengunjungi Rasulullah shallallahu 'alaihi wasallam saat beliau tengah beri'tikaf di Masjid pada sepuluh hari terakhir bulan Ramadlan. Lalu dia berbincang-bincang dengan Nabi hingga menjelang Isya', setelah itu dia beranjak untuk kembali pulang, maka Nabi shallallahu 'alaihi wasallam ikut pergi bersamanya hingga ketika sampai agak jauh dari pintu masjid dan dekat rumah Ummu Salamah, istri Nabi shallallahu 'alaihi wasallam, dua orang laki-laki kaum Anshar lewat dan keduanya memberi salam kepada Rasulullah shallallahu 'alaihi wasallam, kemudian bergegas pergi. Maka Rasulullah shallallahu 'alaihi wasallam bersabda kepada keduanya: \"Kenapa terburu-buru? sesungguhnya dia adalah Shafiyah binti Huyay.\" Kedua orang itu berkata; \"Maha suci Allah, wahai Rasulullah.\" Maka dengan ucapan dua orang tersebut, beliau jadi tercengang. (sabdanya): \"Sesungguhnya syetan masuk kepada manusia lewat aliran darah dan aku khawatir bila syetan telah membisikkan sesuatu dalam hati kalian berdua.\""},"5447":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ قَالَ سَمِعْتُ عُقْبَةَ بْنَ صُهْبَانَ الْأَزْدِيَّ يُحَدِّثُ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ الْمُزَنِيِّ قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْخَذْفِ وَقَالَ إِنَّهُ لَا يَقْتُلُ الصَّيْدَ وَلَا يَنْكَأُ الْعَدُوَّ وَإِنَّهُ يَفْقَأُ الْعَيْنَ وَيَكْسِرُ السِّنَّ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dia berkata; saya mendengar ['Uqbah bin Shahban Al Azdi] bercerita dari [Abdullah bin Mughaffal Al Muzanni] dia berkata; Nabi shallallahu 'alaihi wasallam melarang melempar (berburu binatang dengan melempar batu). Lalu beliau bersabda: \"Karena hal itu tidak akan mematikan buruan dan tidak pula mengalahkan musuh, akan tetapi hal itu hanya bisa mematahkan gigi dan membutakan mata.\""},"5448":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا سُلَيْمَانُ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَعَطَسَ رَجُلَانِ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَشَمَّتَ أَحَدَهُمَا وَلَمْ يُشَمِّتْ الْآخَرَ فَقِيلَ لَهُ فَقَالَ هَذَا حَمِدَ اللَّهَ وَهَذَا لَمْ يَحْمَدْ اللَّهَ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Sulaiman] dari [Anas bin Malik] radliallahu 'anhu dia berkata; \"Dua orang laki-laki tengah bersin di dekat Nabi shallallahu 'alaihi wasallam, lalu beliau mendo'akan yang satu dan membiarkan yang lain, maka ditanyakan kepada beliau, beliau pun menjawab: \"Orang ini memuji Allah, (maka aku mendo'akannya) dan yang ini tidak memuji Allah.\""},"5449":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ الْأَشْعَثِ بْنِ سُلَيْمٍ قَالَ سَمِعْتُ مُعَاوِيَةَ بْنَ سُوَيْدِ بْنِ مُقَرِّنٍ عَنْ الْبَرَاءِ رَضِيَ اللَّهُ عَنْهُ قَالَأَمَرَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِسَبْعٍ وَنَهَانَا عَنْ سَبْعٍ أَمَرَنَا بِعِيَادَةِ الْمَرِيضِ وَاتِّبَاعِ الْجِنَازَةِ وَتَشْمِيتِ الْعَاطِسِ وَإِجَابَةِ الدَّاعِي وَرَدِّ السَّلَامِ وَنَصْرِ الْمَظْلُومِ وَإِبْرَارِ الْمُقْسِمِ وَنَهَانَا عَنْ سَبْعٍ عَنْ خَاتَمِ الذَّهَبِ أَوْ قَالَ حَلْقَةِ الذَّهَبِ وَعَنْ لُبْسِ الْحَرِيرِ وَالدِّيبَاجِ وَالسُّنْدُسِ وَالْمَيَاثِرِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Syu'bah] dari [Al Asy'ats bin Sulaim] dia berkata; saya mendengar [Mu'awiyah bin Suwaid bin Muqarrin] dari [Al Barra`] radliallahu 'anhu dia berkata; \"Nabi shallallahu 'alaihi wasallam memerintahkan kami tujuh perkara dan melarang tujuh perkara, beliau memerintahkan menjenguk orang sakit, mengiringi jenazah, mendo'akan orang yang bersin, memenuhi undangan, menjawab salam dan menolong orang yang terzhalimi serta melaksanakan sumpah, dan beliau melarang tujuh perkara, yaitu; mengenakan cincin emas, atau bersabda; kalung emas, mengenakan sutera, dibaj (sejenis sutera), Sundus (kain yang terbuat dari sutera) dan mayasir (mantel yang bertutup kepala yang terbuat dari sutera).\""},"5450":{"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ حَدَّثَنَا سَعِيدٌ الْمَقْبُرِيُّ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ يُحِبُّ الْعُطَاسَ وَيَكْرَهُ التَّثَاؤُبَ فَإِذَا عَطَسَ فَحَمِدَ اللَّهَ فَحَقٌّ عَلَى كُلِّ مُسْلِمٍ سَمِعَهُ أَنْ يُشَمِّتَهُ وَأَمَّا التَّثَاؤُبُ فَإِنَّمَا هُوَ مِنْ الشَّيْطَانِ فَلْيَرُدَّهُ مَا اسْتَطَاعَ فَإِذَا قَالَ هَا ضَحِكَ مِنْهُ الشَّيْطَانُ","id":"Telah menceritakan kepada kami [Adam bin Iyas] telah menceritakan kepada kami [Ibnu Abu Dzi`b] telah menceritakan kepada kami [Sa'id Al Maqburi] dari [Ayahnya] dari [Abu Hurairah] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam: \"Sesungguhnya Allah menyukai bersin, dan membenci menguap, apabila salah seorang dari kalian bersin, hendaklah ia memuji Allah, dan kewajiban seorang muslim yang mendengarnya untuk mendo'akan, sedangkan menguap datangnya dari syetan, hendaknya ia menahan semampunya, jika ia sampai mengucapkan haaah, maka syetan akan tertawa karenanya.\""},"5451":{"ar":"حَدَّثَنَا مَالِكُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي سَلَمَةَ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ دِينَارٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا عَطَسَ أَحَدُكُمْ فَلْيَقُلْ الْحَمْدُ لِلَّهِ وَلْيَقُلْ لَهُ أَخُوهُ أَوْ صَاحِبُهُ يَرْحَمُكَ اللَّهُ فَإِذَا قَالَ لَهُ يَرْحَمُكَ اللَّهُ فَلْيَقُلْ يَهْدِيكُمُ اللَّهُ وَيُصْلِحُ بَالَكُمْ","id":"Telah menceritakan kepada kami [Malik bin Isma'il] telah menceritakan kepada kami [Abdul Aziz bin Abu Salamah] telah mengabarkan kepada kami [Abdullah bin Dinar] dari [Abu Shalih] dari [Abu Hurairah] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Ababila salah seorang dari kalian bersin, hendaknya ia mengucapkan \"Al Hamdulillah\" sedangkan saudaranya atau temannya hendaklah mengucapkan \"Yarhamukallah (semoga Allah merahmatimu), dan hendaknya ia membalas; \"Yahdikumullah wa yushlih baalakum (semoga Allah memberimu petunjuk dan memperbaiki hatimu).\""},"5452":{"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا سُلَيْمَانُ التَّيْمِيُّ قَالَ سَمِعْتُ أَنَسًا رَضِيَ اللَّهُ عَنْهُ يَقُولُعَطَسَ رَجُلَانِ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَشَمَّتَ أَحَدَهُمَا وَلَمْ يُشَمِّتْ الْآخَرَ فَقَالَ الرَّجُلُ يَا رَسُولَ اللَّهِ شَمَّتَّ هَذَا وَلَمْ تُشَمِّتْنِي قَالَ إِنَّ هَذَا حَمِدَ اللَّهَ وَلَمْ تَحْمَدْ اللَّهَ","id":"Telah menceritakan kepada kami [Adam bin Abu Iyasy] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Sulaiman At Taimi] dia berkata; saya mendengar [Anas] radliallahu 'anhu berkata; \"Dua orang laki-laki sedang bersin di dekat Nabi shallallahu 'alaihi wasallam, lalu beliau mendo'akan yang satu dan membiarkan yang lain, maka laki-laki (yang tidak dido'akan) berkata; \"Wahai Rasulullah, kenapa anda mendo'akan yang ini, namun tidak mendo'akanku?\" beliau menjawab: \"Sesungguhnya orang ini memuji Allah, sedangkan kamu tidak memujinya (ketika bersin).\""},"5453":{"ar":"حَدَّثَنَا عَاصِمُ بْنُ عَلِيٍّ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ يُحِبُّ الْعُطَاسَ وَيَكْرَهُ التَّثَاؤُبَ فَإِذَا عَطَسَ أَحَدُكُمْ وَحَمِدَ اللَّهَ كَانَ حَقًّا عَلَى كُلِّ مُسْلِمٍ سَمِعَهُ أَنْ يَقُولَ لَهُ يَرْحَمُكَ اللَّهُ وَأَمَّا التَّثَاؤُبُ فَإِنَّمَا هُوَ مِنْ الشَّيْطَانِ فَإِذَا تَثَاءَبَ أَحَدُكُمْ فَلْيَرُدَّهُ مَا اسْتَطَاعَ فَإِنَّ أَحَدَكُمْ إِذَا تَثَاءَبَ ضَحِكَ مِنْهُ الشَّيْطَانُ","id":"Telah menceritakan kepada kami ['Ashim bin Ali] telah menceritakan kepada kami [Ibnu Abu Dzi`b] dari [Sa'id Al Maqburi] dari [Ayahnya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Sesungguhnya Allah menyukai bersin dan membenci menguap, apabila salah seorang dari kalian bersin, lalu memuji Allah, maka kewajiban setiap muslim yang mendengarnya untuk mengucapkan; \"Yarhamukallah (semoga Allah merahmatimu), sedangkan menguap datangnya dari syetan, dan apabila salah seorang dari kalian menguap, hendaknya ia menahan semampunya, karena jika salah seorang menguap, maka syetan tertawa karenanya.\""},"5454":{"ar":"حَدَّثَنَا يَحْيَى بْنُ جَعْفَرٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ هَمَّامٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَلَقَ اللَّهُ آدَمَ عَلَى صُورَتِهِ طُولُهُ سِتُّونَ ذِرَاعًا فَلَمَّا خَلَقَهُ قَالَ اذْهَبْ فَسَلِّمْ عَلَى أُولَئِكَ النَّفَرِ مِنْ الْمَلَائِكَةِ جُلُوسٌ فَاسْتَمِعْ مَا يُحَيُّونَكَ فَإِنَّهَا تَحِيَّتُكَ وَتَحِيَّةُ ذُرِّيَّتِكَ فَقَالَ السَّلَامُ عَلَيْكُمْ فَقَالُوا السَّلَامُ عَلَيْكَ وَرَحْمَةُ اللَّهِ فَزَادُوهُ وَرَحْمَةُ اللَّهِ فَكُلُّ مَنْ يَدْخُلُ الْجَنَّةَ عَلَى صُورَةِ آدَمَ فَلَمْ يَزَلْ الْخَلْقُ يَنْقُصُ بَعْدُ حَتَّى الْآنَ","id":"Telah menceritakan kepada kami [Yahya bin Ja'far] telah menceritakan kepada kami [Abdurrazzaq] dari [Ma'mar] dari [Hammam] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Telah Allah cipta Adam dengan semua ciri fisiknya, tingginya enam puluh hasta. Selesai Allah menciptanya, Allah berfirman \"Sana pergi, dan ucapkanlah salam kepada malaikat yang duduk itu, dan dengarkan baik-baik bacaan salam mereka kepadamu, sebab itu sebagai salam penghormatanmu dan juga anak cucu keturunanmu.\" Adam mengucapkan \"Assalamu'alaikum\". Para malaikat menjawab \"Assalamu'alaika warohmatullah.\" Dan mereka menambahnya lagi dengan \"Wabarokaatuh.\" Maka siapapun yang masuk surga, ciri fisiknya seperti Adam (tingginya enam puluh hasta), namun manusia semenjak jaman Adam, tingginya semakin berkurang hingga sekarang."},"5455":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سُلَيْمَانُ بْنُ يَسَارٍ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَأَرْدَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْفَضْلَ بْنَ عَبَّاسٍ يَوْمَ النَّحْرِ خَلْفَهُ عَلَى عَجُزِ رَاحِلَتِهِ وَكَانَ الْفَضْلُ رَجُلًا وَضِيئًا فَوَقَفَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلنَّاسِ يُفْتِيهِمْ وَأَقْبَلَتْ امْرَأَةٌ مِنْ خَثْعَمَ وَضِيئَةٌ تَسْتَفْتِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَطَفِقَ الْفَضْلُ يَنْظُرُ إِلَيْهَا وَأَعْجَبَهُ حُسْنُهَا فَالْتَفَتَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْفَضْلُ يَنْظُرُ إِلَيْهَا فَأَخْلَفَ بِيَدِهِ فَأَخَذَ بِذَقَنِ الْفَضْلِ فَعَدَلَ وَجْهَهُ عَنْ النَّظَرِ إِلَيْهَا فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ فَرِيضَةَ اللَّهِ فِي الْحَجِّ عَلَى عِبَادِهِ أَدْرَكَتْ أَبِي شَيْخًا كَبِيرًا لَا يَسْتَطِيعُ أَنْ يَسْتَوِيَ عَلَى الرَّاحِلَةِ فَهَلْ ��َقْضِي عَنْهُ أَنْ أَحُجَّ عَنْهُ قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku [Sulaiman bin Yasar] telah mengabarkan kepadaku [Abdullah bin Abbas] radliallahu 'anhuma dia berkata; \"Pada hari Iedul Kurban, Al Fadlu bin Abbas pernah membonceng Rasulullah shallallahu 'alaihi wasallam dibelakang hewan tunggangannya, Al Fadl adalah orang yang cakap wajahnya, lalu Nabi shallallahu 'alaihi wasallam berhenti sejenak untuk memberi fatwa di hadapan orang-orang, ternyata ada seorang wanita berwajah cantik dari Kaitsam datang kepada Rasulullah shallallahu 'alaihi wasallam untuk meminta fatwa, segera Al Fadlu memandang wanita tersebut, ia merasa heran dengan kecantikannya, ketika Nabi shallallahu 'alaihi wasallam menoleh ke arah Al Fadl, dia masih saja memandangi wanita tersebut, akhirnya beliau memutar tangan ke arah belakang dan memegang dagu Al Fadl serta memalingkan wajahnya ke arah lain. Wanita tersebut bertanya; \"Wahai Rasulullah, sesungguhnya Allah telah mewajibkan ibadah haji kepada para hamba-Nya, sementara ayahku baru mampu melaksanakan haji saat dia telah lanjut usia hingga menyebabkan ia tidak mampu naik kendaraan. Apakah saya boleh berhaji untuknya?\" beliau menjawab; \"Ya.\""},"5456":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ أَخْبَرَنَا أَبُو عَامِرٍ حَدَّثَنَا زُهَيْرٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِيَّاكُمْ وَالْجُلُوسَ بِالطُّرُقَاتِ فَقَالُوا يَا رَسُولَ اللَّهِ مَا لَنَا مِنْ مَجَالِسِنَا بُدٌّ نَتَحَدَّثُ فِيهَا فَقَالَ إِذْ أَبَيْتُمْ إِلَّا الْمَجْلِسَ فَأَعْطُوا الطَّرِيقَ حَقَّهُ قَالُوا وَمَا حَقُّ الطَّرِيقِ يَا رَسُولَ اللَّهِ قَالَ غَضُّ الْبَصَرِ وَكَفُّ الْأَذَى وَرَدُّ السَّلَامِ وَالْأَمْرُ بِالْمَعْرُوفِ وَالنَّهْيُ عَنْ الْمُنْكَرِ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] telah mengabarkan kepada kami [Abu 'Amir] telah menceritakan kepada kami [Zuhair] dari [Zaid bin Aslam] dari ['Atha` bin Yasar] dari [Abu Sa'id Al Khudri] radliallahu 'anhu bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian duduk-duduk di pinggir jalan.\" Mereka (para sahabat) berkata; \"Wahai Rasulullah, Itu kebiasaan kami yang sudah biasa kami lakukan karena itu menjadi majelis tempat kami untuk bercakap-cakap.\" Beliau bersabda: \"Jika kalian tidak mau meninggalkan majelis seperti itu maka tunaikanlah hak jalan tersebut.\" Mereka bertanya: \"Apa hak jalan itu?\" Beliau menjawab: \"Menundukkan pandangan, menyingkirkan halangan, menjawab salam dan amar ma'ruf nahi munkar.\""},"5457":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ قَالَ حَدَّثَنِي شَقِيقٌ عَنْ عَبْدِ اللَّهِ قَالَكُنَّا إِذَا صَلَّيْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْنَا السَّلَامُ عَلَى اللَّهِ قَبْلَ عِبَادِهِ السَّلَامُ عَلَى جِبْرِيلَ السَّلَامُ عَلَى مِيكَائِيلَ السَّلَامُ عَلَى فُلَانٍ وَفُلَانٍ فَلَمَّا انْصَرَفَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْبَلَ عَلَيْنَا بِوَجْهِهِ فَقَالَ إِنَّ اللَّهَ هُوَ السَّلَامُ فَإِذَا جَلَسَ أَحَدُكُمْ فِي الصَّلَاةِ فَلْيَقُلْ التَّحِيَّاتُ لِلَّهِ وَالصَّلَوَاتُ وَالطَّيِّبَاتُ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ فَإِنَّهُ إِذَا قَالَ ذَلِكَ أَصَابَ كُلَّ عَبْدٍ صَالِحٍ فِي السَّمَاءِ وَالْأَرْضِ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ ثُمَّ يَتَخَيَّرْ بَعْدُ مِنْ الْكَلَامِ مَا شَاءَ","id":"Telah menceritakan kepada kami [Umar bin Hafsh] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Al A'masy] dia berkata; telah menceritakan kepadaku [Syaqiq] dari [Abdullah] dia berkata; \"Ketika kami membaca shalawat di belakang Nabi shallallahu 'alaihi wasallam, maka kami mengucapkan: \"ASSALAAMU 'ALALLAHI QABLA 'IBAADIHI, ASSALAAMU 'ALAA JIBRIIL, ASSSALAAMU 'ALAA MIKAA`IIL, ASSALAAMU 'ALAA FULAAN WA FULAAN (Semoga keselamatan terlimpahkan kepada Allah, semoga keselamatan terlimpah kepada Jibril, Mika'il, kepada fulan dan fulan).\" Ketika Nabi shallallahu 'alaihi wasallam selesai melaksanakan shalat, beliau menghadapkan wajahnya kepada kami dan bersabda: \"Sesungguhnya Allah adalah As salam, apabila salah seorang dari kalian duduk dalam shalat (tahiyyat), hendaknya mengucapkan; \"AT-TAHIYYATUT LILLAHI WASH-SHALAWAATU WATH-THAYYIBAATU, ASSALAAMU 'ALAIKA AYYUHAN-NABIYYU WA RAHMATULLAHI WA BARAKAATUH, ASSALAAMU 'ALAINAA WA 'ALA 'IBAADILLAAHISH SHAALIHIIN, (penghormatan, rahmat dan kebaikan hanya milik Allah. Semoga keselamatan, rahmat, dan keberkahan tetap ada pada engkau wahai Nabi. Keselamatan juga semoga ada pada hamba-hamba Allah yang shalih. Sesungguhnya jika ia mengucapkannya, maka hal itu sudah mencakup seluruh hamba-hamba yang shalih baik di langit maupun di bumi, lalu melanjutkan; \"ASYHADU ALLAA ILAAHA ILLALLAH WA ASYHADU ANNA MUHAMMADAN 'ABDUHU WA RASUULUH (Aku bersaksi bahwa tiada Dzat yang berhak disembah selain Allah, dan Muhammad adalah hamba dan utusan-Nya).\" Setelah itu ia boleh memilih do'a yang ia kehendaki.\""},"5458":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَبُو الْحَسَنِ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُسَلِّمُ الصَّغِيرُ عَلَى الْكَبِيرِ وَالْمَارُّ عَلَى الْقَاعِدِ وَالْقَلِيلُ عَلَى الْكَثِيرِ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil Abu Al Hasan] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Ma'mar] dari [Hammam bin Munabbih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Hendaknya yang muda memberi salam kepada yang tua, yang berjalan kepada yang duduk, dan (rombongan) yang sedikit kepada (rombongan) yang banyak.\""},"5459":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ سَلَامٍ أَخْبَرَنَا مَخْلَدٌ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي زِيَادٌ أَنَّهُ سَمِعَ ثَابِتًا مَوْلَى عَبْدِ الرَّحْمَنِ بْنِ زَيْدٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُسَلِّمُ الرَّاكِبُ عَلَى الْمَاشِي وَالْمَاشِي عَلَى الْقَاعِدِ وَالْقَلِيلُ عَلَى الْكَثِيرِ","id":"Telah menceritakan kepadaku [Muhammad bin Salam] telah mengabarkan kepada kami [Makhlad] telah mengabarkan kepada kami [Ibnu Juraij] dia berkata; telah mengabarkan kepadaku [Ziyad] bahwa dia mendengar [Tsabit] bekas budak Abdurrahman bin Zaid, bahwa dia mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaknya orang yang berkendara memberi salam kepada yang berjalan, dan yang berjalan memberi salam kepada yang duduk dan (rombongan) yang sedikit kepada (rombongan) yang banyak.\""},"5460":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي زِيَادٌ أَنَّ ثَابِتًا أَخْبَرَهُ وَهُوَ مَوْلَى عَبْدِ الرَّحْمَنِ بْنِ زَيْدٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ يُسَلِّمُ الرَّاكِبُ عَلَى الْمَاشِي وَالْمَاشِي عَلَى الْقَاعِدِ وَالْقَلِيلُ عَلَى الْكَثِيرِ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Rauh bin 'Ubadah] telah menceritakan kepada kami [Ibnu Juraij] dia berkata; telah mengabarkan kepadaku [Ziyad] bahwa [Tsabit] telah mengabarkan kepadanya -dia adalah bekas budak Abdurrahman bin Zaid- dari [Abu Hurairah] radliallahu 'anhu dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Hendaknya orang yang berkendaraan memberi salam kepada yang berjalan, dan yang berjalan kepada yang duduk dan (rombongan) yang sedikit kepada (rombongan) yang banyak.\""},"5461":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا جَرِيرٌ عَنْ الشَّيْبَانِيِّ عَنْ أَشْعَثَ بْنِ أَبِي الشَّعْثَاءِ عَنْ مُعَاوِيَةَ بْنِ سُوَيْدِ بْنِ مُقَرِّنٍ عَنْ الْبَرَاءِ بْنِ عَازِبٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِسَبْعٍ بِعِيَادَةِ الْمَرِيضِ وَاتِّبَاعِ الْجَنَائِزِ وَتَشْمِيتِ الْعَاطِسِ وَنَصْرِ الضَّعِيفِ وَعَوْنِ الْمَظْلُومِ وَإِفْشَاءِ السَّلَامِ وَإِبْرَارِ الْمُقْسِمِ وَنَهَى عَنْ الشُّرْبِ فِي الْفِضَّةِ وَنَهَانَا عَنْ تَخَتُّمِ الذَّهَبِ وَعَنْ رُكُوبِ الْمَيَاثِرِ وَعَنْ لُبْسِ الْحَرِيرِ وَالدِّيبَاجِ وَالْقَسِّيِّ وَالْإِسْتَبْرَقِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Jarir] dari [Asy Syaibani] dari [Asy'ats bin Abu Asy Sya'tsa'] dari [Mu'awiyah bin Suwaid bin Muqarrin] dari [Al Barra` bin 'Azib] radliallahu 'anhuma dia berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkan kami tujuh perkara yaitu; menjenguk orang yang sakit, mengiringi jenazah, mendo'akan orang yang bersin, menolong yang lemah, menolong orang yang terzhalimi, menebarkan salam dan menunaikan sumpah, dan beliau juga melarang minum dari bejana yang terbuat dari perak, mengenakan cincin emas, menaiki sekedup yang ditutupi dengan kain sutera, mengenakan kain sutera, dibaj, Qasiy dan Istabraq (sejenis kain sutera).\""},"5462":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ قَالَ حَدَّثَنِي يَزِيدُ عَنْ أَبِي الْخَيْرِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ رَجُلًا سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ الْإِسْلَامِ خَيْرٌ قَالَ تُطْعِمُ الطَّعَامَ وَتَقْرَأُ السَّلَامَ عَلَى مَنْ عَرَفْتَ وَعَلَى مَنْ لَمْ تَعْرِفْ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah menceritakan kepada kami [Al Laits] dia berkata; telah menceritakan kepadaku [Yazid] dari [Abu Al Khair] dari [Abdullah bin 'Amru] bahwa seorang laki-laki bertanya kepada Nabi shallallahu 'alaihi wasallam; \"Islam bagaimanakah yang baik?\" beliau menjawab: \"Kamu memberi makan, menebarkan salam baik terhadap orang yang kamu kenal maupun terhadap orang yang tidak kamu kenal.\""},"5463":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ أَبِي أَيُّوبَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحِلُّ لِمُسْلِمٍ أَنْ يَهْجُرَ أَخَاهُ فَوْقَ ثَلَاثٍ يَلْتَقِيَانِ فَيَصُدُّ هَذَا وَيَصُدُّ هَذَا وَخَيْرُهُمَا الَّذِي يَبْدَأُ بِالسَّلَامِوَذَكَرَ سُفْيَانُ أَنَّهُ سَمِعَهُ مِنْهُ ثَلَاثَ مَرَّاتٍ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari ['Atha`bin Yazid Al Laitsi] dari [Abu Ayyub] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Tidak halal seorang muslim mendiamkan saudaranya lebih dari tiga hari, jika bertemu saling menjauhkan, dan yang paling baik di antara keduanya adalah yang memulai salam.\" Sufyan menyebutkan, bahwa dia mendengar Zuhri hingga tiga kali.\""},"5464":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سُلَيْمَانَ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي أَنَسُ بْنُ مَالِكٍأَنَّهُ كَانَ ابْنَ عَشْرِ سِنِينَ مَقْدَمَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ فَخَدَمْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَشْرًا حَيَاتَهُ وَكُنْتُ أَعْلَمَ النَّاسِ بِشَأْنِ الْحِجَابِ حِينَ أُنْزِلَ وَقَدْ كَانَ أُبَيُّ بْنُ كَعْبٍ يَسْأَلُنِي عَنْهُ وَكَانَ أَوَّلَ مَا نَزَلَ فِي مُبْتَنَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِزَيْنَبَ بِنْتِ جَحْشٍ أَصْبَحَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَا عَرُوسًا فَدَعَا الْقَوْمَ فَأَصَابُوا مِنْ الطَّعَامِ ثُمَّ خَرَجُوا وَبَقِيَ مِنْهُمْ رَهْطٌ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَطَالُوا الْمُكْثَ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَرَجَ وَخَرَجْتُ مَعَهُ كَيْ يَخْرُجُوا فَمَشَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَشَيْتُ مَعَهُ حَتَّى جَاءَ عَتَبَةَ ��ُجْرَةِ عَائِشَةَ ثُمَّ ظَنَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُمْ خَرَجُوا فَرَجَعَ وَرَجَعْتُ مَعَهُ حَتَّى دَخَلَ عَلَى زَيْنَبَ فَإِذَا هُمْ جُلُوسٌ لَمْ يَتَفَرَّقُوا فَرَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَجَعْتُ مَعَهُ حَتَّى بَلَغَ عَتَبَةَ حُجْرَةِ عَائِشَةَ فَظَنَّ أَنْ قَدْ خَرَجُوا فَرَجَعَ وَرَجَعْتُ مَعَهُ فَإِذَا هُمْ قَدْ خَرَجُوا فَأُنْزِلَ آيَةُ الْحِجَابِ فَضَرَبَ بَيْنِي وَبَيْنَهُ سِتْرًا","id":"Telah menceritakan kepada kami [Yahya bin Sulaiman] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dia berkata; telah mengabarkan kepadaku [Anas bin Malik] bahwa ketika Rasulullah shallallahu 'alaihi wasallam tiba di Madinah ia masih berusia sepuluh tahun. (Ia mengkisahkan); Maka aku menjadi pelayan Rasulullah shallallahu 'alaihi wasallam selama sepuluh tahun semasa hayat beliau. Dan akulah orang yang paling mengerti tentang hijab ketika perintah itu diturunkan, Ubay bin Ka'b juga pernah bertanya kepadaku tentang hal itu. Perintah itu pertama kali turun di waktu pernikahan Rasulullah shallallahu 'alaihi wasallam dengan Zainab binti Jahsyi. Saat itu Rasulullah shallallahu 'alaihi wasallam tengah mengadakan pesta walimah, beliau mengundang orang-orang dan mereka pun menikmati makanan yang dihidangkan. Setelah itu, mereka pun keluar pergi, kecuali beberapa orang yang masih tetap berada di sisi Rasulullah shallallahu 'alaihi wasallam, mereka sengaja memperlama duduk di situ. Maka Rasulullah shallallahu 'alaihi wasallam pun beranjak dan keluar, lalu aku pun ikut keluar bersama beliau agar orang-orang itu juga ikut keluar. Kemudian Rasulullah shallallahu 'alaihi wasallam berjalan, dan aku juga ikut berjalan hingga sampai di ambang pintu rumah Aisyah. Lalu Rasulullah shallallahu 'alaihi wasallam mengira, bahwa mereka yang duduk tadi telah keluar, maka beliau kembali lagi dan aku juga ikut kembali hingga beliau sampai di tempat Zainab, ternyata orang-orang itu masih ada di tempat semula dan belum beranjak pergi. Akhirnya Rasulullah shallallahu 'alaihi wasallam pun kembali lagi dan aku juga ikut kembali bersamanya, ketika sampai di ambang pintu Aisyah, beliau menduga bahwa mereka pasti sudah pergi, maka beliau kembali lagi dan aku juga ikut kembali bersama beliau, ternyata orang-orang itu telah beranjak pergi, lalu turunlah ayat hijab hingga beliau meletakkan pembatas antara aku dan beliau.\""},"5465":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا مُعْتَمِرٌ قَالَ أَبِي حَدَّثَنَا أَبُو مِجْلَزٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا تَزَوَّجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَيْنَبَ دَخَلَ الْقَوْمُ فَطَعِمُوا ثُمَّ جَلَسُوا يَتَحَدَّثُونَ فَأَخَذَ كَأَنَّهُ يَتَهَيَّأُ لِلْقِيَامِ فَلَمْ يَقُومُوا فَلَمَّا رَأَى ذَلِكَ قَامَ فَلَمَّا قَامَ قَامَ مَنْ قَامَ مِنْ الْقَوْمِ وَقَعَدَ بَقِيَّةُ الْقَوْمِ وَإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَ لِيَدْخُلَ فَإِذَا الْقَوْمُ جُلُوسٌ ثُمَّ إِنَّهُمْ قَامُوا فَانْطَلَقُوا فَأَخْبَرْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ حَتَّى دَخَلَ فَذَهَبْتُ أَدْخُلُ فَأَلْقَى الْحِجَابَ بَيْنِي وَبَيْنَهُ وَأَنْزَلَ اللَّهُ تَعَالَى{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَدْخُلُوا بُيُوتَ النَّبِيِّ }الْآيَةَقَالَ أَبُو عَبْد اللَّهِ فِيهِ مِنْ الْفِقْهِ أَنَّهُ لَمْ يَسْتَأْذِنْهُمْ حِينَ قَامَ وَخَرَجَ وَفِيهِ أَنَّهُ تَهَيَّأَ لِلْقِيَامِ وَهُوَ يُرِيدُ أَنْ يَقُومُوا","id":"Telah menceritakan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Mu'tamar], [Ayahku] berkata; telah menceritakan kepada kami [Abu Mijlaz] dari [Anas] radliallahu 'anhu dia berkata; \"Ketika Nabi shallallahu 'alaihi wasallam menikah dengan Zainab, orang-orang (tamu undangan) pun berdatangan dan menikmati hindangan, kemudian mereka duduk dan berbincang-bincang. Lalu beliau merubah posisi seakan-akan ingin berdiri, namun orang-orang tidak juga berdiri, tatkala beliau mengetahui hal itu, maka beliau berdiri dan orang-orang pun ikut berdiri. Tinggal beberapa orang yang masih tetap, sesungguhnya Nabi shallallahu 'alaihi wasallam datang dan hendak masuk ke kamar Zainab, namun orang-orang masih tetap duduk-duduk, setelah itu mereka berdiri dan beranjak pergi, lalu saya mengabarkan hal itu kepada Nabi shallallahu 'alaihi wasallam. Kemudian beliau masuk dan saya mengikuti beliau masuk, lalu beliau menurunkan kain tirainya antara saya dengan beliau. Ternyata Allah Ta'ala menurunkan (ayat) Wahai orang-orang yang beriman, janganlah kalian masuk ke rumah Nabi…QS Al Ahzab; 53 Abu Abdullah mengatakan; \"Dalam perintah tersebut terdapat hukum fikih, bahwa beliau tidak mengizinkan mereka (para sahabat) ketika beliau berdiri dan keluar, dan juga ketika beliau merubah posisi seakan-akan hendak berdiri, menandakan bahwa beliau menghendaki mereka (para sahabat) keluar.\""},"5466":{"ar":"حَدَّثَنَا إِسْحَاقُ أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْكَانَ عُمَرُ بْنُ الْخَطَّابِ يَقُولُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْجُبْ نِسَاءَكَ قَالَتْ فَلَمْ يَفْعَلْ وَكَانَ أَزْوَاجُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْرُجْنَ لَيْلًا إِلَى لَيْلٍ قِبَلَ الْمَنَاصِعِ فَخَرَجَتْ سَوْدَةُ بِنْتُ زَمْعَةَ وَكَانَتْ امْرَأَةً طَوِيلَةً فَرَآهَا عُمَرُ بْنُ الْخَطَّابِ وَهُوَ فِي الْمَجْلِسِ فَقَالَ عَرَفْتُكِ يَا سَوْدَةُ حِرْصًا عَلَى أَنْ يُنْزَلَ الْحِجَابُ قَالَتْ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ آيَةَ الْحِجَابِ","id":"Telah menceritakan kepada kami [Ishaq] telah mengabarkan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [Ayahku] dari [Shalih] dari [Ibnu Syihab] dia berkata; telah mengabarkan kepadaku [Urwah bin Az Zubair] bahwa [Aisyah] radliallahu 'anha isteri Nabi shallallahu 'alaihi wasallam berkata; \"Umar bin Khatthab pernah berkata kepada Nabi shallallahu 'alaihi wasallam; \"Tolong, perintahkanlah para isteri anda untuk berhijab.\" Aisyah melanjutkan; \"Namun beliau tidak melakukannya, sedangkan isteri-isteri Nabi shallallahu 'alaihi wasallam juga biasa keluar pada malam hari ke tempat untuk buang hajat. Maka isteri beliau, Saudah binti Zam'ah keluar, ia adalah wanita yang berpostur tinggi, lalu 'Umar bin Khatthab melihatnya ketika ia berada di Majlis, katanya; 'Hai Saudah! Kami mengenalimu! ' 'Sesungguhnya 'Umar menegurnya hanya karena dia ingin semoga ayat hijab segera turun. Kata 'Aisyah; 'Memang, tidak lama kemudian Allah 'azza wajalla menurunkan ayat hijab.'"},"5467":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ الزُّهْرِيُّ حَفِظْتُهُ كَمَا أَنَّكَ هَا هُنَا عَنْ سَهْلِ بْنِ سَعْدٍ قَالَاطَّلَعَ رَجُلٌ مِنْ جُحْرٍ فِي حُجَرِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِدْرًى يَحُكُّ بِهِ رَأْسَهُ فَقَالَ لَوْ أَعْلَمُ أَنَّكَ تَنْظُرُ لَطَعَنْتُ بِهِ فِي عَيْنِكَ إِنَّمَا جُعِلَ الِاسْتِئْذَانُ مِنْ أَجْلِ الْبَصَرِ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan], [Az Zuhri] berkata; \"Aku telah menghafalnya sebagaimana dirimu di sini, dari [Sahl bin Sa'd] dia berkata; \"Seorang laki-laki pernah melongokkan kepalanya ke salah satu kamar Nabi shallallahu 'alaihi wasallam, waktu itu Nabi shallallahu 'alaihi wasallam tengah membawa sisir untuk menyisir rambutnya, lalu beliau bersabda: \"Sekiranya aku tahu kamu mengintip, sungguh aku akan mencolok kedua matamu, sesungguhnya meminta izin itu di berlakukan karena pandangan.\""},"5468":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَجُلًا اطَّلَعَ مِنْ بَعْضِ حُجَرِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ إِلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِشْقَصٍ أَوْ بِمَشَاقِصَ فَكَأَنِّي أَنْظُرُ إِلَيْهِ يَخْتِلُ الرَّجُلَ لِيَطْعُنَهُ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Hammad bin Zaid] dari ['Ubaidullah bin Abu Bakr] dari [Anas bin Malik] bahwa seorang laki-laki melongokkan kepalanya ke salah satu kamar Nabi shallallahu 'alaihi wasallam, lantas Nabi shallallahu 'alaihi wasallam berdiri menemuinya dengan membawa sisir, dan seolah-olah aku melihat beliau menakut-nakuti hendak mencolok laki-laki itu.\""},"5469":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَ لَمْ أَرَ شَيْئًا أَشْبَهَ بِاللَّمَمِ مِنْ قَوْلِ أَبِي هُرَيْرَةَ ح حَدَّثَنِي مَحْمُودٌ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَمَا رَأَيْتُ شَيْئًا أَشْبَهَ بِاللَّمَمِ مِمَّا قَالَ أَبُو هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ كَتَبَ عَلَى ابْنِ آدَمَ حَظَّهُ مِنْ الزِّنَا أَدْرَكَ ذَلِكَ لَا مَحَالَةَ فَزِنَا الْعَيْنِ النَّظَرُ وَزِنَا اللِّسَانِ الْمَنْطِقُ وَالنَّفْسُ تَمَنَّى وَتَشْتَهِي وَالْفَرْجُ يُصَدِّقُ ذَلِكَ كُلَّهُ وَيُكَذِّبُهُ","id":"Telah menceritakan kepada kami [Al Humaidi] telah menceritakan kepada kami [Sufyan] dari [Ibnu Thawus] dari [Ayahnya] dari [Ibnu Abbas] radliallahu 'anhuma dia berkata; \"Saya tidak berpendapat dengan sesuatu yang menyerupai makna lamam (dosa kecil) selain perkataan [Abu Hurairah]. Dan di riwayatkan dari jalur lain, telah menceritakan kepadaku [Mahmud] telah mengabarkan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Ibnu Thawus] dari [Ayahnya] dari [Ibnu Abbas] dia berkata; \"Saya tidak berpendapat tentang sesuatu yang paling dekat dengan makna Al lamam (dosa-dosa kecil) selain dari apa yang telah dikatakan oleh [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam: \"Sesungguhnya Allah telah menetapkan pada setiap anak cucu Adam bagiannya dari perbuatan zina yang pasti terjadi dan tidak mungkin dihindari, maka zinanya mata adalah melihat sedangkan zinanya lisan adalah ucapan, zinanya nafsu keinginan dan berangan-angan, dan kemaluanlah sebagai pembenar semuanya atau tidak.\""},"5470":{"ar":"حَدَّثَنَا إِسْحَاقُ أَخْبَرَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُثَنَّى حَدَّثَنَا ثُمَامَةُ بْنُ عَبْدِ اللَّهِ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا سَلَّمَ سَلَّمَ ثَلَاثًا وَإِذَا تَكَلَّمَ بِكَلِمَةٍ أَعَادَهَا ثَلَاثًا","id":"Telah menceritakan kepada kami [Ishaq] telah mengabarkan kepada kami [Abdush Shamad] telah menceritakan kepada kami [Abdullah bin Al Mutsanna] telah menceritakan kepada kami [Tsumamah bin Abdullah] dari [Anas] radliallahu 'anhu bahwa; \"Apabila Rasulullah shallallahu 'alaihi wasallam memberi salam, beliau memberi salam hingga tiga kali, dan apabila berbicara biasanya beliau mengulanginya hingga tiga kali.\""},"5471":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا يَزِيدُ بْنُ خُصَيْفَةَ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَكُنْتُ فِي مَجْلِسٍ مِنْ مَجَالِسِ الْأَنْصَارِ إِذْ جَاءَ أَبُو مُوسَى كَأَنَّهُ مَذْعُورٌ فَقَالَ اسْتَأْذَنْتُ عَلَى عُمَرَ ثَلَاثًا فَلَمْ يُؤْذَنْ لِي فَرَجَعْتُ فَقَالَ مَا مَنَعَكَ قُلْتُ اسْتَأْذَنْتُ ثَلَاثًا فَلَمْ يُؤْذَنْ لِي فَرَجَعْتُ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اسْتَأْذَنَ أَحَدُكُمْ ثَلَاثًا فَلَمْ يُؤْذَنْ لَهُ فَلْيَرْجِعْ فَقَالَ وَاللَّهِ لَتُقِيمَنَّ عَلَيْهِ بِبَيِّنَةٍ أَمِنْكُمْ أَحَدٌ سَمِعَهُ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أُبَيُّ بْنُ كَعْبٍ وَاللَّهِ لَا يَقُومُ مَعَكَ إِلَّا أَصْغَرُ الْقَوْمِ فَكُنْتُ أَصْغَرَ الْقَوْمِ فَقُمْتُ مَعَهُ فَأَخْبَرْتُ عُمَرَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ذَلِكَوَقَالَ ابْنُ الْمُبَارَكِ أَخْبَرَنِي ابْنُ عُيَيْنَةَ حَدَّثَنِي يَزِيدُ بْنُ خُصَيْفَةَ عَنْ بُسْرِ بْنِ سَعِيدٍ سَمِعْتُ أَبَا سَعِيدٍ بِهَذَا","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Yazid bin Khushaifah] dari [Busr bin Sa'id] dari [Abu Sa'id Al Khudri] dia berkata; \"Saya pernah berada di majlis dari majlisnya orang-orang Anshar, tiba-tiba [Abu Musa] datang dalam keadaan kalut, lalu dia berkata; \"Aku (tadi) meminta izin kepada Umar hingga tiga kali, namun ia tidak memberiku izin, maka aku hendak kembali pulang, lalu Umar bertanya; \"Apa yang membuatmu hendak kembali pulang?\" jawabku; \"Aku (tadi) meminta izin hingga tiga kali, namun aku tidak diberi izin, maka aku hendak kembali pulang, karena Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian meminta izin, namun tidak diberi izin, hendaknya ia kembali pulang.\" Maka Umar pun berkata; \"Demi Allah, sungguh kamu harus memberiku satu bukti yang jelas, \" (kata Abu Musa) \"Apakah di antara kalian ada yang pernah mendengarnya dari Nabi shallallahu 'alaihi wasallam?\" lalu Ubay bin Ka'ab angkat bicara; \"Demi Allah, tidaklah ada orang yang akan bersamamu melainkan orang yang paling muda di antara mereka, sedangkan akulah orang yang paling muda.\" Lalu aku pergi bersamanya menemui Umar, dan aku pun memberitahukan kepada Umar bahwa Nabi shallallahu 'alaihi wasallam berkata seperti itu.\" Dan [Ibnu Mubarak] berkata; telah mengabarkan kepadaku [Ibnu Uyainah] telah menceritakan kepadaku [Yazid bin Khushaifah] dari [Busr bin Sa'id] saya mendengar [Abu Sa'id] seperti ini."},"5472":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا عُمَرُ بْنُ ذَرٍّ و حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا عُمَرُ بْنُ ذَرٍّ أَخْبَرَنَا مُجَاهِدٌ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَدَخَلْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَجَدَ لَبَنًا فِي قَدَحٍ فَقَالَ أَبَا هِرٍّ الْحَقْ أَهْلَ الصُّفَّةِ فَادْعُهُمْ إِلَيَّ قَالَ فَأَتَيْتُهُمْ فَدَعَوْتُهُمْ فَأَقْبَلُوا فَاسْتَأْذَنُوا فَأُذِنَ لَهُمْ فَدَخَلُوا","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami ['Umar bin Dzar], dan telah menceritakan kepada kami [Muhammad bin Muqatil] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Umar bin Dzar] telah mengabarkan kepada kami [Mujahid] dari [Abu Hurairah] radliallahu 'anhu dia berkata; \"Aku pernah masuk bersama Rasulullah shallallahu 'alaihi wasallam, lalu kami mendapatkan semangkok susu, beliau bersabda: \"Wahai Abu Hurairah, temuilah ahli Shuffah dan panggilah mereka kemari.\" Abu Hurairah berkata; \"Lantas aku menemui mereka dan memanggilnya, setelah itu mereka memenuhi panggilan beliau dan meminta izin masuk, setelah mereka di izinkan masuk, barulah mereka masuk.\""},"5473":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْجَعْدِ أَخْبَرَنَا شُعْبَةُ عَنْ سَيَّارٍ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّهُ مَرَّ عَلَى صِبْيَانٍ فَسَلَّمَ عَلَيْهِمْ وَقَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْعَلُهُ","id":"Telah menceritakan kepada kami [Ali bin Al Ja'd] telah mengabarkan kepada kami [Syu'bah] dari [Sayyar] dari [Tsabit Al Bunani] dari [Anas bin Malik] radliallahu 'anhu bahwa dia pernah melewati anak-anak kecil, lalu ia memberi salam kepada mereka dan berkata; \"Nabi shallallahu 'alaihi wasallam juga biasa melakukan hal ini.\""},"5474":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا ابْنُ أَبِي حَازِمٍ عَنْ أَبِيهِ عَنْ سَهْلٍ قَالَكُنَّا نَفْرَحُ يَوْمَ الْجُمُعَةِ قُلْتُ وَلِمَ قَالَ كَانَتْ لَنَا عَجُوزٌ تُرْسِلُ إِلَى بُضَاعَةَ قَالَ ابْنُ مَسْلَمَةَ نَخْلٍ بِالْمَدِينَةِ فَتَأْخُذُ مِنْ أُصُولِ السِّلْقِ فَتَطْرَحُهُ فِي قِدْرٍ وَتُكَرْكِرُ حَبَّاتٍ مِنْ شَعِيرٍ فَإِذَا صَلَّيْنَا الْجُمُعَةَ انْصَرَفْنَا وَنُسَلِّمُ عَلَيْهَا فَتُقَدِّمُهُ إِلَيْنَا فَنَفْرَحُ مِنْ أَجْلِهِ وَمَا كُنَّا نَقِيلُ وَلَا نَتَغَدَّى إِلَّا بَعْدَ الْجُمُعَةِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] telah menceritakan kepada kami [Ibnu Abu Hazim] dari [Ayahnya] dari [Sahl] dia berkata; \"(Dahulu) Kami merasa gembira ketika tiba hari Jum'at, aku (Abu Hazm) bertanya; \"Kenapa?\" Sahl menjawab; \"Kami memiliki seorang nenek yang telah tua. Biasanya ia pergi ke Budla'ah -Ibnu Maslamah berkata; yaitu sebuah kebun kurma di Madinah- lalu ia mengambil ubi lalu meletakkannya di dalam periuk miliknya dan menumbuk biji-bijian dari gandum. Setelah shalat Jum'at kami pergi menemuinya, kami memberi salam kepadanya, lalu sang nenek pun menyuguhkannya kepada kami. Karena itu, hari Jum'at adalah hari yang sangat menyenangkan bagi kami. Kami tidak pernah menyantap makan siang dan tidak pula qailulah (tidur siang sebelum dluhur), kecuali setelah Jum'at.\""},"5475":{"ar":"حَدَّثَنَا ابْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَائِشَةُ هَذَا جِبْرِيلُ يَقْرَأُ عَلَيْكِ السَّلَامَ قَالَتْ قُلْتُ وَعَلَيْهِ السَّلَامُ وَرَحْمَةُ اللَّهِ تَرَى مَا لَا نَرَى تُرِيدُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَتَابَعَهُ شُعَيْبٌ وَقَالَ يُونُسُ وَالنُّعْمَانُ عَنْ الزُّهْرِيِّ وَبَرَكَاتُهُ","id":"Telah menceritakan kepada kami [Ibnu Muqatil] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abu Salamah bin Abdurrahman] dari [Aisyah] radliallahu 'anha dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Aisyah, ini Jibril menyampaikan salam untukmu!.\" Aisyah berkata; \"Jawabku; \"Wa'alihis salam warahmatullahi, anda melihat apa yang tidak kami lihat.\" Maksud Aisyah adalah Rasulullah shallallahu 'alaihi wasallam.\" Hadits ini juga di perkuat oleh riwayat [Syu'aib], [Yunus] dan [An Nu'man] mengatakan dari [Az Zuhri] ia menambahkan; \"Wabarakatuh.\""},"5476":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ هِشَامُ بْنُ عَبْدِ الْمَلِكِ حَدَّثَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي دَيْنٍ كَانَ عَلَى أَبِي فَدَقَقْتُ الْبَابَ فَقَالَ مَنْ ذَا فَقُلْتُ أَنَا فَقَالَ أَنَا أَنَا كَأَنَّهُ كَرِهَهَا","id":"Telah menceritakan kepada kami [Abu Al Walid Hisyam bin Abdul Malik] telah menceritakan kepada kami [Syu'bah] dari [Muhammad bin Al Munkadir] dia berkata; saya mendengar [Jabir bin Abdullah] radliallahu 'anhuma berkata; \"Aku menemui Nabi shallallahu 'alaihi wasallam karena hutang ayahku, lalu aku mengetuk pintu rumah beliau, beliau bertanya;: \"Siapakah itu?\" aku menjawab; \"Saya.\" Beliau bersabda: \"Saya, saya!.\" Seolah-olah beliau membencinya.\""},"5477":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ مَنْصُورٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَجُلًا دَخَلَ الْمَسْجِدَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسٌ فِي نَاحِيَةِ الْمَسْجِدِ فَصَلَّى ثُمَّ جَاءَ فَسَلَّمَ عَلَيْهِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْكَ السَّلَامُ ارْجِعْ فَصَلِّ فَإِنَّكَ لَمْ تُصَلِّ فَرَجَعَ فَصَلَّى ثُمَّ جَاءَ فَسَلَّمَ فَقَالَ وَعَلَيْكَ السَّلَامُ فَارْجِعْ فَصَلِّ فَإِنَّكَ لَمْ تُصَلِّ فَقَالَ فِي الثَّانِيَةِ أَوْ فِي الَّتِي بَعْدَهَا عَلِّمْنِي يَا رَسُولَ اللَّهِ فَقَالَ إِذَا قُمْتَ إِلَى الصَّلَاةِ فَأَسْبِغْ الْوُضُوءَ ثُمَّ اسْتَقْبِلْ الْقِبْلَةَ فَكَبِّرْ ثُمَّ اقْرَأْ بِمَا تَيَسَّرَ مَعَكَ مِنْ الْقُرْآنِ ثُمَّ ارْكَعْ حَتَّى تَطْمَئِنَّ رَاكِعًا ثُمَّ ارْفَعْ حَتَّى تَسْتَوِيَ قَائِمًا ثُمَّ اسْجُدْ حَتَّى تَطْمَئِنَّ سَاجِدًا ثُمَّ ارْفَعْ حَتَّى تَطْمَئِنَّ جَالِسًا ثُمَّ اسْجُدْ حَتَّى تَطْمَئِنَّ سَاجِدًا ثُمَّ ارْفَعْ حَتَّى تَطْمَئِنَّ جَالِسًا ثُمَّ افْعَلْ ذَلِكَ فِي صَلَاتِكَ كُلِّهَاوَقَالَ أَبُو أُسَامَةَ فِي الْأَخِيرِ حَتَّى تَسْتَوِيَ قَائِمًا حَدَّثَنَا ابْنُ بَشَّارٍ قَالَ حَدَّثَنِي يَحْيَى عَنْ عُبَيْدِ اللَّهِ حَدَّثَنِي سَعِيدٌ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ ارْفَعْ حَتَّى تَطْمَئِنَّ جَالِسًا","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] telah mengabarkan kepada kami [Abdullah bin Numair] telah menceritakan kepada kami ['Ubaidullah] dari [Sa'id bin Abu Sa'id Al Maqbury] dari [Abu Hurairah] radliallahu 'anhu bahwa seorang laki-laki memasuki masjid, sementara Rasulullah shallallahu 'alaihi wasallam tengah duduk di pojok masjid, kemudian laki-laki itu mengerjakan shalat. Seusai shalat ia datang menemui beliau sambil mengucapkan salam, dan Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Wa'alikas salam, Kembalilah dan ulangi shalatmu karena kamu belum mengerjakan shalat! ' lalu ia kembali lagi dan mengulangi shalatnya. Seusai shalat ia datang lagi sambil mengucapkan salam dan beliau bersabda: \"Wa'alaikas-salam. Kembali dan ulangi lagi shalatmu karena kamu belum mengerjakan shalat! ' Lalu orang tersebut berkata ketika disuruh mengulangi yang kedua kali atau setelahnya; \"Ajarilah aku wahai Rasulullah!\" Selanjutnya beliau bersabda: 'Jika kamu hendak mengerjakan shalat, maka sempurnakanlah wudlu', lalu menghadap ke arah Kiblat, setelah itu bertakbirlah, kemudian bacalah Al Qur'an yang mudah bagimu. Kemudian ruku'lah hingga kamu benar-benar ruku' dan bangkitlah dari ruku' hingga kamu berdiri tegak. Lalu sujudlah kamu hingga kamu benar-benar sujud, dan bangkitlah hingga kamu benar-benar duduk, setelah itu sujudlah hingga kamu benar-benar sujud, lalu bangkitlah hingga kamu benar-benar duduk, dan Kerjakanlah semua hal tersebut pada setiap shalatmu.\" [Abu Usamah] mengatakan di akhir haditsnya; \"Sehingga kamu benar-benar berdiri.\" Telah menceritakan kepada kami [Ibnu Basyar] dia berkata; telah menceritakan kepadaku [Yahya] dari ['Ubaidullah] telah menceritakan kepadaku [Sa'id] dari [Ayahnya] dari [Abu Hurairah] dia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Kemudian bangkitlah (dari sujud) hingga kamu benar-benar duduk.\""},"5478":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زَكَرِيَّاءُ قَالَ سَمِعْتُ عَامِرًا يَقُولُ حَدَّثَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا حَدَّثَتْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهَا إِنَّ جِبْرِيلَ يُقْرِئُكِ السَّلَامَ قَالَتْ وَعَلَيْهِ السَّلَامُ وَرَحْمَةُ اللَّهِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Zakariya`] dia berkata; saya mendengar ['Amir] berkata; telah menceritakan kepadaku [Abu Salamah bin Abdurrahman] bahwa [Aisyah] radliallahu 'anha pernah menceritakan kepadanya bahwa Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Sesungguhnya Jibril menyampaikan salam kepadamu.\" Aisyah menjawab; \"Wa'alaihis salam warahmatullahi.\""},"5479":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامٌ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ قَالَ أَخْبَرَنِي أُسَامَةُ بْنُ زَيْدٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكِبَ حِمَارًا عَلَيْهِ إِكَافٌ تَحْتَهُ قَطِيفَةٌ فَدَكِيَّةٌ وَأَرْدَفَ وَرَاءَهُ أُسَامَةَ بْنَ زَيْدٍ وَهُوَ يَعُودُ سَعْدَ بْنَ عُبَادَةَ فِي بَنِي الْحَارِثِ بْنِ الْخَزْرَجِ وَذَلِكَ قَبْلَ وَقْعَةِ بَدْرٍ حَتَّى مَرَّ فِي مَجْلِسٍ فِيهِ أَخْلَاطٌ مِنْ الْمُسْلِمِينَ وَالْمُشْرِكِينَ عَبَدَةِ الْأَوْثَانِ وَالْيَهُودِ وَفِيهِمْ عَبْدُ اللَّهِ بْنُ أُبَيٍّ ابْنُ سَلُولَ وَفِي الْمَجْلِسِ عَبْدُ اللَّهِ بْنُ رَوَاحَةَ فَلَمَّا غَشِيَتْ الْمَجْلِسَ عَجَاجَةُ الدَّابَّةِ خَمَّرَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ أَنْفَهُ بِرِدَائِهِ ثُمَّ قَالَ لَا تُغَبِّرُوا عَلَيْنَا فَسَلَّمَ عَلَيْهِمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ وَقَفَ فَنَزَلَ فَدَعَاهُمْ إِلَى اللَّهِ وَقَرَأَ عَلَيْهِمْ الْقُرْآنَ فَقَالَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ ابْنُ سَلُولَ أَيُّهَا الْمَرْءُ لَا أَحْسَنَ مِنْ هَذَا إِنْ كَانَ مَا تَقُولُ حَقًّا فَلَا تُؤْذِنَا فِي مَجَالِسِنَا وَارْجِعْ إِلَى رَحْلِكَ فَمَنْ جَاءَكَ مِنَّا فَاقْص��صْ عَلَيْهِ قَالَ عَبْدُ اللَّهِ بْنُ رَوَاحَةَ اغْشَنَا فِي مَجَالِسِنَا فَإِنَّا نُحِبُّ ذَلِكَ فَاسْتَبَّ الْمُسْلِمُونَ وَالْمُشْرِكُونَ وَالْيَهُودُ حَتَّى هَمُّوا أَنْ يَتَوَاثَبُوا فَلَمْ يَزَلْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُخَفِّضُهُمْ ثُمَّ رَكِبَ دَابَّتَهُ حَتَّى دَخَلَ عَلَى سَعْدِ بْنِ عُبَادَةَ فَقَالَ أَيْ سَعْدُ أَلَمْ تَسْمَعْ إِلَى مَا قَالَ أَبُو حُبَابٍ يُرِيدُ عَبْدَ اللَّهِ بْنَ أُبَيٍّ قَالَ كَذَا وَكَذَا قَالَ اعْفُ عَنْهُ يَا رَسُولَ اللَّهِ وَاصْفَحْ فَوَاللَّهِ لَقَدْ أَعْطَاكَ اللَّهُ الَّذِي أَعْطَاكَ وَلَقَدْ اصْطَلَحَ أَهْلُ هَذِهِ الْبَحْرَةِ عَلَى أَنْ يُتَوِّجُوهُ فَيُعَصِّبُونَهُ بِالْعِصَابَةِ فَلَمَّا رَدَّ اللَّهُ ذَلِكَ بِالْحَقِّ الَّذِي أَعْطَاكَ شَرِقَ بِذَلِكَ فَذَلِكَ فَعَلَ بِهِ مَا رَأَيْتَ فَعَفَا عَنْهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] telah mengabarkan kepada kami [Hisyam] dari [Ma'mar] dari [Az Zuhri] dari ['Urwah bin Zubair] dia berkata; telah mengabarkan kepadaku [Usamah bin Zaid] bahwa Nabi shallallahu 'alaihi wasallam mengendarai keledai milik beliau, di atasnya ada pelana bersulam beludru Fadaki, sementara Usamah bin Zaid membonceng di belakang beliau ketika hendak menjenguk Sa'ad bin 'Ubadah di Bani Al Harits Al Khazraj, peristiwa itu tersjadi sebelum perang Badar, lalu beliau berjalan hingga melewati suatu majlis yang di majlis tersebut bercampur antara kaum Muslimin, orang-orang musyrik, para penyembah patung, dan orang-orang Yahudi, dan dalam majlis tersebut terdapat pula Abdullah bin Ubay bin Salul dan Abdullah bin Rawahah, saat majlis itu dipenuhi kepulan debu hewan kendaraan, 'Abdullah bin Ubai menutupi hidungnya dengan selendang sambil berkata: \"Jangan mengepuli kami dengan debu, \" kemudian Nabi shallallahu 'alaihi wasallam mengucapkan salam pada mereka lalu berhenti dan turun, Nabi shallallahu 'alaihi wasallam mengajak mereka menuju Allah sambil membacakan al-Qur'an kepada mereka. 'Abdullah bin Ubay bin Salul berkata kepada beliau: \"Wahai saudara! Sesungguhnya apa yang kamu katakan tidak ada kebaikannya sedikit pun, bila apa yang kau katakan itu benar, maka janganlah kamu mengganggu kami di majlis ini, silahkan kembali ke kendaraan anda, lalu siapa saja dari kami mendatangi anda, silahkan anda bercerita padanya.\" Abdullah bin Rawahah berkata; \"Wahai Rasulullah, bergabunglah dengan kami di majlis ini karena kami menyukai hal itu.\" Maka Kaum muslimin, orang-orang musyrik dan orang-orang Yahudi pun saling mencaci hingga mereka hendak saling menyerang, Nabi shallallahu 'alaihi wasallam terus menenangkan mereka hingga mereka semuanya diam, kemudian beliau naik kendaraan hingga masuk ke kediaman Sa'd bin 'Ubadah, lalu beliau bersabda: \"Hai Sa'd! Apa kau tidak mendengar ucapan Abu Hubab?\" maksud beliau tentang ucapan 'Abdullah bin Ubay. Beliau bersabda: \"Dia telah mengatakan ini dan ini.\" Sa'ad berkata; \"Maafkan dia wahai Rasulullah dan berlapang dadalah kepadanya, demi Allah, Allah telah memberi anda apa yang telah diberikan pada anda. (dahulu) Penduduk telaga ini (penduduk Madinah -red) bersepakat untuk memilihnya dan mengangkatnya, namun karena kebenaran yang diberikan kepada anda itu muncul, sehingga menghalanginya (Abdullah bin Ubay) menjabat sebagai pemimpin, maka seperti itulah perbuatannya sebagaimana yang anda lihat.\" Akhirnya beliau pun mema'afkannya."},"5480":{"ar":"حَدَّثَنَا ابْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ كَعْبٍ أَنَّ عَبْدَ اللَّهِ بْنَ كَعْبٍ قَالَ سَمِعْتُ كَعْبَ بْنَ مَالِكٍ يُحَدِّثُحِينَ تَخَلَّفَ عَنْ تَبُوكَ وَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ كَلَامِنَا وَآتِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأُسَلِّمُ عَلَيْهِ فَأَقُولُ فِي نَفْسِي هَلْ حَرَّكَ شَفَتَيْهِ بِرَدِّ السَّلَامِ أَمْ لَا حَتَّى كَمَلَتْ خَمْسُونَ لَيْلَةً وَآذَنَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِتَوْبَةِ اللَّهِ عَلَيْنَا حِينَ صَلَّى الْفَجْرَ","id":"Telah menceritakan kepada kami [Abu Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari [Abdurrahman bin Abdullah bin Ka'b] bahwa [Abdullah bin Ka'b] berkata; saya medengar [Ka'b bin Malik] bercerita ketika dia tidak mengikuti perang tabuk (tanpa udzur), Rasulullah shallallahu 'alaihi wasallam melarang berbicara kepada kami, kemudian aku medatangi Rasulullah shallallahu 'alaihi wasallam, aku memberi salam kepadanya, dalam hatiku berkata; \"Apakah beliau menggerak-gerakkan bibirnya untuk menjawab salam ataukah tidak, hingga hal itu berlangsung genap lima puluh malam, setelah itu barulah Nabi shallallahu 'alaihi wasallam mengumumkan penerimaan Allah atas taubat kami setelah shalat shubuh.\""},"5481":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْدَخَلَ رَهْطٌ مِنْ الْيَهُودِ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا السَّامُ عَلَيْكَ فَفَهِمْتُهَا فَقُلْتُ عَلَيْكُمْ السَّامُ وَاللَّعْنَةُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَهْلًا يَا عَائِشَةُ فَإِنَّ اللَّهَ يُحِبُّ الرِّفْقَ فِي الْأَمْرِ كُلِّهِ فَقُلْتُ يَا رَسُولَ اللَّهِ أَوَلَمْ تَسْمَعْ مَا قَالُوا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَدْ قُلْتُ وَعَلَيْكُمْ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku ['Urwah] bahwa [Aisyah] radliallahu 'anha berkata; \"Beberapa orang dari kaum Yahudi menemui Rasulullah shallallahu 'alaihi wasallam, mereka berkata; \"Assaamu 'alaika (kebinasaan atasmu).\" Maka aku pun memahami ucapan mereka, spontan aku menjawab; \"'Alaikumus saam walla'nah (semoga atas kalian kebinasaan dan juga laknat).\" maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tenanglah wahai Aisyah, sesungguhnya Allah mencintai kelembutan disetiap perkara.\" Aku berkata; \"Wahai Rasulullah, apakah anda tidak mendengar apa yang diucapkan mereka?\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku telah menjawabnya; \"wa'alaikum (dan atas kalian juga).\""},"5482":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا سَلَّمَ عَلَيْكُمْ الْيَهُودُ فَإِنَّمَا يَقُولُ أَحَدُهُمْ السَّامُ عَلَيْكَ فَقُلْ وَعَلَيْكَ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Abdullah bin Dinar] dari [Abdullah bin Umar] radliallahu 'anhuma bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila orang-orang Yahudi menyalami kalian, bahwa salah seorang dari mereka mengatakan; \"As saamu 'alaika (kebinasaan keatasmu), maka jawablah; \"wa'alaika (dan keatasmu juga).\""},"5483":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ أَبِي بَكْرِ بْنِ أَنَسٍ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَلَّمَ عَلَيْكُمْ أَهْلُ الْكِتَابِ فَقُولُوا وَعَلَيْكُمْ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami ['Ubaidullah bin Abu Bakr bin Anas] telah menceritakan kepada kami [Anas bin Malik] radliallahu 'anhu dia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila ahli kitab menyampaikan salam kepada kalian, maka jawablah; 'wa 'alaikum (dan keatasmu).\""},"5484":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ بُهْلُولٍ حَدَّثَنَا ابْنُ إِدْرِيسَ قَالَ حَدَّثَنِي حُصَيْنُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُقَالَ بَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالزُّبَيْرَ بْنَ الْعَوَّامِ وَأَبَا مَرْثَدٍ الْغَنَوِيَّ وَكُلُّنَا فَارِسٌ فَقَالَ انْطَلِقُوا حَتَّى تَأْتُوا رَوْضَةَ خَاخٍ فَإِنَّ بِهَا امْرَأَةً مِنْ الْمُشْرِكِينَ مَعَهَا صَحِيفَةٌ مِنْ حَاطِبِ بْنِ أَبِي بَلْتَعَةَ إِلَى الْمُشْرِكِينَ قَالَ فَأَدْرَكْنَاهَا تَسِيرُ عَلَى جَمَلٍ لَهَا حَيْثُ قَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قُلْنَا أَيْنَ الْكِتَابُ الَّذِي مَعَكِ قَالَتْ مَا مَعِي كِتَابٌ فَأَنَخْنَا بِهَا فَابْتَغَيْنَا فِي رَحْلِهَا فَمَا وَجَدْنَا شَيْئًا قَالَ صَاحِبَايَ مَا نَرَى كِتَابًا قَالَ قُلْتُ لَقَدْ عَلِمْتُ مَا كَذَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي يُحْلَفُ بِهِ لَتُخْرِجِنَّ الْكِتَابَ أَوْ لَأُجَرِّدَنَّكِ قَالَ فَلَمَّا رَأَتْ الْجِدَّ مِنِّي أَهْوَتْ بِيَدِهَا إِلَى حُجْزَتِهَا وَهِيَ مُحْتَجِزَةٌ بِكِسَاءٍ فَأَخْرَجَتْ الْكِتَابَ قَالَ فَانْطَلَقْنَا بِهِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا حَمَلَكَ يَا حَاطِبُ عَلَى مَا صَنَعْتَ قَالَ مَا بِي إِلَّا أَنْ أَكُونَ مُؤْمِنًا بِاللَّهِ وَرَسُولِهِ وَمَا غَيَّرْتُ وَلَا بَدَّلْتُ أَرَدْتُ أَنْ تَكُونَ لِي عِنْدَ الْقَوْمِ يَدٌ يَدْفَعُ اللَّهُ بِهَا عَنْ أَهْلِي وَمَالِي وَلَيْسَ مِنْ أَصْحَابِكَ هُنَاكَ إِلَّا وَلَهُ مَنْ يَدْفَعُ اللَّهُ بِهِ عَنْ أَهْلِهِ وَمَالِهِ قَالَ صَدَقَ فَلَا تَقُولُوا لَهُ إِلَّا خَيْرًا قَالَ فَقَالَ عُمَرُ بْنُ الْخَطَّابِ إِنَّهُ قَدْ خَانَ اللَّهَ وَرَسُولَهُ وَالْمُؤْمِنِينَ فَدَعْنِي فَأَضْرِبَ عُنُقَهُ قَالَ فَقَالَ يَا عُمَرُ وَمَا يُدْرِيكَ لَعَلَّ اللَّهَ قَدْ اطَّلَعَ عَلَى أَهْلِ بَدْرٍ فَقَالَ اعْمَلُوا مَا شِئْتُمْ فَقَدْ وَجَبَتْ لَكُمْ الْجَنَّةُ قَالَ فَدَمَعَتْ عَيْنَا عُمَرَ وَقَالَ اللَّهُ وَرَسُولُهُ أَعْلَمُ","id":"Telah menceritakan kepada kami [Yusuf bin Buhlul] telah menceritakan kepada kami [Ibnu Idris] dia berkata; telah menceritakan kepadaku [Husain bin Abdurrahman] dari [Sa'd bin 'Ubaidah] dari [Abu Abdurrahman bin As Sulami] dari [Ali] radliallahu 'anhu dia berkata; \"Rasulullah shallallahu 'alaihi wasallam mengutusku, Zubair serta Abu Martsad Al Ghanawi, sedangkan kami semua adalah para penunggang kuda, lalu beliau bersabda; \"Berangkatlah kalian hingga tiba di Raudlah Khakh, karena di sana ada seorang wanita musyrik yang membawa surat dari Hatib Bin Abi Balta'ah untuk orang-orang Musyrik, lalu bawalah surat itu kepadaku, \" Ali berkata; \"Akhirnya kami menjumpai wanita itu tengah mengendarai untanya sebagaimana yang disabdakan oleh Rasulullah shallallahu 'alaihi wasallam, Ali berkata; \"Lantas kami langsung bertanya kepadanya; \"Di mana surat yang ada pada kamu?\" dia menjawab; \"Saya tidak membawa surat.\" Kemudian kami menderumkan untanya dan menggeledah kendaraannya, namun kami tidak menemukan sesuatu, kedua sahabatku berkata; \"Kita tidak menemukan suratnya.\" Ali melanjutkan; \"Akupun menjawab; \"Saya yakin bahwa Rasulullah shallallahu 'alaihi wasallam tidak mungkin berdusta, demi Dzat yang aku bersumpah dengan-Nya, jika kamu tidak mau mengeluarkan surat tersebut, maka kami akan menelanjangimu!\" Ali melanjutkan; \"Ketika ia melihat kesungguhanku, dia langsung menggapai ikat pinggangnya -karena ia memakai ikat pinggang dengan secarik kain- dan mengeluarkan surat itu.\" Ali melanjutkan; \"Setelah itu kami membawa surat itu kepada Rasulullah shallallahu 'alaihi wasallam. Beliau lalu berabda: \"Wahai Hatib, apa yang menyebabkanmu berbuat demikian?\" Hatib menjawab; \"Tidaklah aku melakukan seperti ini melainkan aku ingin beriman kepada Allah dan Rasul-Nya, aku tidak akan merubahnya dan tidak pula hendak menggantinya, akan tetapi aku ingin memiliki tangan (orang yang menolong -red) di tengah-tengah suatu kaum, yang dengannya Allah akan membela keluarga dan hartaku, sementara tidak seorangpun dari sahabatmu di sana melainkan ada kaum yang dengannya Allah membela keluarga dan hartanya.\" Beliau menjawab; \"Kamu benar, maka kalian jangan berkata kepadanya kecuali kebaikan.\" Ali melanjutkan; \"Kemudian Umar berkata; \"Wahai Rasulullah, sesungguhnya dia telah berkhianat kepada Allah dan Rasul-Nya dan kaum mukminin, izinkanlah saya memenggal lehernya.\" Ali melanjutkan; \"Maka beliau menjawab; \"Wahai Umar, apa yang kamu ketahui?, padahal Allah telah melihat amalan ahli Badar dan berfirman; 'lakukan apa yang kalian kehendaki sesungguhnya kalian telah di jamin masuk syurga.\" Mendengar itu berlinanglah kedua mata Umar sambil berkata; \"Allah dan Rasul-Nya lebih mengetahui.\""},"5485":{"ar":"حَدّ��ثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَبُو الْحَسَنِ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّ ابْنَ عَبَّاسٍ أَخْبَرَهُ أَنَّ أَبَا سُفْيَانَ بْنَ حَرْبٍ أَخْبَرَهُأَنَّ هِرَقْلَ أَرْسَلَ إِلَيْهِ فِي نَفَرٍ مِنْ قُرَيْشٍ وَكَانُوا تِجَارًا بِالشَّأْمِ فَأَتَوْهُ فَذَكَرَ الْحَدِيثَ قَالَ ثُمَّ دَعَا بِكِتَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُرِئَ فَإِذَا فِيهِ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ مِنْ مُحَمَّدٍ عَبْدِ اللَّهِ وَرَسُولِهِ إِلَى هِرَقْلَ عَظِيمِ الرُّومِ السَّلَامُ عَلَى مَنْ اتَّبَعَ الْهُدَى أَمَّا بَعْدُ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil Abu Al Hasan] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Yunus] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku ['Ubaidullah bin Abdullah bin 'Utbah] bahwa [Ibnu Abbas] telah mengabarkan kepadanya bahwa [Abu Sufyan bin Harb] telah mengabarkan kepadanya bahwa Heraklius (raja Ramawi) pernah mengutusnya kepada sekelompok orang orang Quraisy yaitu para pedagang di Syam, setelah itu para pedagang tersebut menemuinya -lalu perawi menyebutkan riawayat hadits, dia berkata; \"Kemudian Heraklius meminta surat Rasulullah shallallahu 'alaihi wasallam, ketika dibaca ternyata di dalamnya tertulis \"BISMILLAHIR RAHMAANIR RAHIIM (dengan nama Allah yang maha pengasih lagi maha penyayang), dari Muhammad hamba Allah dan Rasul-Nya kepada Hiraklius raja Ramawi, salam kesejahteraan bagi yang mengikuti petunjuk, amma ba'du.\""},"5486":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلِ بْنِ حُنَيْفٍ عَنْ أَبِي سَعِيدٍأَنَّ أَهْلَ قُرَيْظَةَ نَزَلُوا عَلَى حُكْمِ سَعْدٍ فَأَرْسَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيْهِ فَجَاءَ فَقَالَ قُومُوا إِلَى سَيِّدِكُمْ أَوْ قَالَ خَيْرِكُمْ فَقَعَدَ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هَؤُلَاءِ نَزَلُوا عَلَى حُكْمِكَ قَالَ فَإِنِّي أَحْكُمُ أَنْ تُقْتَلَ مُقَاتِلَتُهُمْ وَتُسْبَى ذَرَارِيُّهُمْ فَقَالَ لَقَدْ حَكَمْتَ بِمَا حَكَمَ بِهِ الْمَلِكُقَالَ أَبُو عَبْد اللَّهِ أَفْهَمَنِي بَعْضُ أَصْحَابِي عَنْ أَبِي الْوَلِيدِ مِنْ قَوْلِ أَبِي سَعِيدٍ إِلَى حُكْمِكَ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari [Sa'd bin Ibrahim] dari [Abu Umamah bin Sahl bin Hunaif] dari [Abu Sa'id] bahwa penduduk Bani Quraidlah telah menetapkan hukum yang akan diputuskan oleh Sa'ad. Maka Nabi shallallahu 'alaihi wasallam mengutus seseorang untuk memanggilnya, ketika dia datang beliau bersabda: \"Berdirilah kalian untuk menghormati orang terbaik kalian -atau beliau bersabda- pemimpin kalian.\" Lalu Sa'd duduk di dekat Nabi shallallahu 'alaihi wasallam, setelah itu beliau melanjutkan: \"Sesungguhnya mereka telah setuju dengan keputusan yang akan kamu tetapkan.\" Sa'ad berkata; \"Aku akan memutuskan kepada mereka agar para tentara perang mereka dibunuh dan anak-anak serta wanita mereka dijadikan tawanan.\" Maka beliau bersabda: \"Sungguh kamu telah memutuskan hukum kepada mereka dengan hukum Allah (Raja diraja).\" Abu Abdullah berkata; \"Sebagian sahabatku telah memahamkanku dari Al Walid dari perkataannya Abu Sa'id hingga perkataan \"…dengan keputusan yang kamu putuskan.\""},"5487":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَاصِمٍ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ قَالَ قُلْتُ لِأَنَسٍأَكَانَتْ الْمُصَافَحَةُ فِي أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ","id":"Telah menceritakan kepada kami ['Amru bin 'Ashim] telah menceritakan kepada kami [Hammam] dari [Qatadah] dia berkata; aku bertanya kepada [Anas]; \"Apakah diantara para sahabat Nabi shallallahu 'alaihi wasallam sering berjabat tangan?\" dia menjawab; \"Ya.\""},"5488":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سُلَيْمَانَ قَالَ حَدَّثَنِي ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي حَيْوَةُ قَالَ حَدَّثَنِي أَبُو عَقِيلٍ زُهْرَةُ بْنُ مَعْبَدٍ سَمِعَ جَدَّهُ عَبْدَ اللَّهِ بْنَ هِشَامٍ قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ آخِذٌ بِيَدِ عُمَرَ بْنِ الْخَطَّابِ","id":"Telah menceritakan kepada kami [Yahya bin Sulaiman] dia berkata; telah menceritakan kepadaku [Ibnu Wahb] dia berkata; telah mengabarkan kepadaku [Haiwah] dia berkata; telah menceritakan kepadaku [Abu 'Aqil Zuhrah bin Ma'bad] dia mendengar kakeknya [Abdullah bin Hisyam] dia berkata; \"Kami bersama nabi shallallahu 'alaihi wasallam ketika itu beliau tengah menggandeng tangan Umar bin Khatthab.\""},"5489":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سَيْفٌ قَالَ سَمِعْتُ مُجَاهِدًا يَقُولُ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ سَخْبَرَةَ أَبُو مَعْمَرٍ قَالَ سَمِعْتُ ابْنَ مَسْعُودٍ يَقُولُعَلَّمَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَفِّي بَيْنَ كَفَّيْهِ التَّشَهُّدَ كَمَا يُعَلِّمُنِي السُّورَةَ مِنْ الْقُرْآنِ التَّحِيَّاتُ لِلَّهِ وَالصَّلَوَاتُ وَالطَّيِّبَاتُ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ وَهُوَ بَيْنَ ظَهْرَانَيْنَا فَلَمَّا قُبِضَ قُلْنَا السَّلَامُ يَعْنِي عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Saif] dia berkata; saya mendengar [Mujahid] berkata; telah menceritakan kepadaku [Abdullah bin Sahbarah Abu Ma'mar] dia berkata; saya mendengar [Ibnu Mas'ud] berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah mengajariku tasyahud -sambil menghamparkan kedua telapak tangannya- sebagaimana beliau mengajariku surat Al Qur'an, yaitu; \"AT-TAHIYYATUT LILLAHI WASH-SHALAWAATU WATH-THAYYIBAATU, ASSALAAMU 'ALAIKA AYYUHAN-NABIYYU WA RAHMATULLAHI WA BARAKAATUH, ASSALAAMU 'ALAINAA WA 'ALA 'IBAADILLAAHISH-SHAALIHIIN, ASYHADU ALLAA ILAAHA ILLALLAAH WA ASYHADU ANNA MUHAMMADAN ABDUHU WA RASUULUH (penghormatan, rahmat dan kebaikan hanya untuk Allah. Semoga keselamatan, rahmat, dan keberkahan tetap ada pada engkau wahai Nabi. Keselamatan juga semoga ada pada hamba-hamba Allah yang shalih. Aku bersaksi bahwa tiada Dzat yang berhak disembah kecuali Allah, dan Muhammad adalah hamba dan utusan-Nya). Yaitu ketika beliau masih hidup bersama kami, namun ketika beliau telah meninggal, kami mengucapkan; \"Assalaamu maksudnya atas Nabi shallallahu 'alaihi wasallam.\""},"5490":{"ar":"حَدَّثَنَا إِسْحَاقُ أَخْبَرَنَا بِشْرُ بْنُ شُعَيْبٍ حَدَّثَنِي أَبِي عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ كَعْبٍ أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ أَخْبَرَهُ أَنَّ عَلِيًّا يَعْنِي ابْنَ أَبِي طَالِبٍ خَرَجَ مِنْ عِنْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَنْبَسَةُ حَدَّثَنَا يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ كَعْبِ بْنِ مَالِكٍ أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ أَخْبَرَهُ أَنَّ عَلِيَّ بْنَ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُخَرَجَ مِنْ عِنْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي وَجَعِهِ الَّذِي تُوُفِّيَ فِيهِ فَقَالَ النَّاسُ يَا أَبَا حَسَنٍ كَيْفَ أَصْبَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَصْبَحَ بِحَمْدِ اللَّهِ بَارِئًا فَأَخَذَ بِيَدِهِ الْعَبَّاسُ فَقَالَ أَلَا تَرَاهُ أَنْتَ وَاللَّهِ بَعْدَ الثَّلَاثِ عَبْدُ الْعَصَا وَاللَّهِ إِنِّي لَأُرَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَيُتَوَفَّى فِي وَجَعِهِ وَإِنِّي لَأَعْرِفُ فِي وُجُوهِ بَنِي عَبْدِ الْمُطَّلِبِ الْمَوْتَ فَاذْهَبْ بِنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَسْأَلَهُ فِيمَنْ يَكُونُ الْأَمْرُ فَإِنْ كَانَ فِينَا عَلِمْنَا ذَلِكَ وَإِنْ كَانَ فِي غَيْرِنَا أَمَرْنَاهُ فَأَوْصَى بِنَا قَالَ عَلِيٌّ وَاللَّهِ لَئِنْ سَأَلْنَاهَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَمْنَعُنَا لَا يُعْطِينَاهَا النَّاسُ أَبَدًا وَإِنِّي لَا أَسْأَلُهَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبَدًا","id":"Telah menceritakan kepada kami [Ishaq] telah mengabarkan kepada kami [Bisyr bin Syu'aib] telah menceritakan kepadaku [Ayahku] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku [Abdullah bin Ka'b] bahwa [Abdullah bin Abbas] telah mengabarkan kepadanya, bahwa [Ali yaitu Ibnu Abu Thalib] pergi dari sisi Nabi shallallahu 'alaihi wasallam. Dan diriwayatkan dari jalur lain, telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami ['Anbasah] telah menceritakan kepada kami [Yunus] dari [Ibnu Syihab] dia berkata; telah mengabarkan kepadaku [Abdullah bin Ka'b bin Malik] bahwa [Abdullah bin Abbas] telah mengabarkan kepadanya; bahwa [Ali bin Abu Thalib] radliallahu 'anhu keluar dari sisi Nabi shallallahu 'alaihi wasallam disaat beliau sakit yang menyebabkan beliau meninggal, maka orang-orang bertanya; \"Wahai Abu Hasan, bagaimana keadaan Rasulullah shallallahu 'alaihi wasallam?\" Ia menjawab; \"Alhamdulillah beliau sudah agak baikan.\" Lalu Abbas memegang tangannya dan berkata; \"Demi Allah, tidakkah engkau lihat? Sesungguhnya aku mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam akan wafat karena sakitnya ini. Sesungguhnya aku juga mengetahui wajah bani Abdul Muththalib ketika menghadapi kematiannya. Mari kita menemui Rasulullah shallallahu 'alaihi wasallam, lalu kita tanyakan kepada siapa perkara (kepemimpinan) ini akan diserahkan? Jika kepada (orang) kita, maka kita mengetahuinya dan jika (diserahkan) kepada selain kita maka kita akan menyuruh beliau supaya mewasiatkannya pada kita.\" Lalu Ali radliallahu 'anhu berkata; \"Demi Allah, bila kita memohonnya kepada Rasulullah shallallahu 'alaihi wasallam lalu beliau menolak, maka selamanya orang-orang tidak akan memberikannya kepada kita. Karena itu, aku tidak akan pernah menanyakan kepada Rasulullah shallallahu 'alaihi wasallam selamanya.\""},"5491":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ عَنْ مُعَاذٍ قَالَأَنَا رَدِيفُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا مُعَاذُ قُلْتُ لَبَّيْكَ وَسَعْدَيْكَ ثُمَّ قَالَ مِثْلَهُ ثَلَاثًا هَلْ تَدْرِي مَا حَقُّ اللَّهِ عَلَى الْعِبَادِ قُلْتُ لَا قَالَ حَقُّ اللَّهِ عَلَى الْعِبَادِ أَنْ يَعْبُدُوهُ وَلَا يُشْرِكُوا بِهِ شَيْئًا ثُمَّ سَارَ سَاعَةً فَقَالَ يَا مُعَاذُ قُلْتُ لَبَّيْكَ وَسَعْدَيْكَ قَالَ هَلْ تَدْرِي مَا حَقُّ الْعِبَادِ عَلَى اللَّهِ إِذَا فَعَلُوا ذَلِكَ أَنْ لَا يُعَذِّبَهُمْحَدَّثَنَا هُدْبَةُ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ عَنْ مُعَاذٍ بِهَذَا","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Anas] dari [Mu'adz] dia berkata; \"Aku pernah membonceng Nabi shallallahu 'alaihi wasallam lalu beliau bersabda: \"Wahai Mu'adz!.\" Aku menjawab; \"Ya, saya memenuhi panggilan anda.\" Beliau bersabda seperti itu hingga tiga kali, lalu beliau melanjutkan: \"Apakah kamu tahu hak Allah atas hamba-Nya?\" Aku menjawab; \"Tidak.\" Beliau bersabda: \"Hak Allah atas hamba-Nya adalah hendaknya mereka beribadah kepada-Nya dan tidak menyekutukan-Nya dengan suatu apapun.\" Kemudian beliau melanjutkan perjalanannya sesaat lalu bersabda lagi: \"Wahai Mu'adz!.\" Jawabku; \"Ya, aku penuhi panggilanmu.\" Beliau bersabda: \"Apakah kamu tahu hak hamba atas Allah jika hamba tersebut melaksanakan hal itu?, yaitu Allah tidak akan menyiksa mereka.\" Telah menceritakan kepada kami [Hudbah] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] dari [Anas] dari [Mu'adz] dengan hadits ini."},"5492":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا زَيْدُ بْنُ وَهْبٍ حَدَّثَنَاوَاللَّهِ أَبُو ذَرٍّ بِالرَّبَذَةِ قَالَ كُنْتُ أَمْشِي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَرَّةِ الْمَدِينَةِ عِشَاءً اسْتَقْبَلَنَا أُحُدٌ فَقَالَ يَا أَبَا ذَرٍّ مَا أُحِبُّ أَنَّ أُحُدًا لِي ذَهَبًا يَأْتِي عَلَيَّ لَيْلَةٌ أَوْ ثَلَاثٌ عِنْدِي مِنْهُ دِينَارٌ إِلَّا أَرْصُدُهُ لِدَيْنٍ إِلَّا أَنْ أَقُولَ بِهِ فِي عِبَادِ اللَّهِ هَكَذَا وَهَكَذَا وَهَكَذَا وَأَرَانَا بِيَدِهِ ثُمَّ قَالَ يَا أَبَا ذَرٍّ قُلْتُ لَبَّيْكَ وَسَعْدَيْكَ يَا رَسُولَ اللَّهِ قَالَ الْأَكْثَرُونَ هُمْ الْأَقَلُّونَ إِلَّا مَنْ قَالَ هَكَذَا وَهَكَذَا ثُمَّ قَالَ لِي مَكَانَكَ لَا تَبْرَحْ يَا أَبَا ذَرٍّ حَتَّى أَرْجِعَ فَانْطَلَقَ حَتَّى غَابَ عَنِّي فَسَمِعْتُ صَوْتًا فَخَشِيتُ أَنْ يَكُونَ عُرِضَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَرَدْتُ أَنْ أَذْهَبَ ثُمَّ ذَكَرْتُ قَوْلَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَبْرَحْ فَمَكُثْتُ قُلْتُ يَا رَسُولَ اللَّهِ سَمِعْتُ صَوْتًا خَشِيتُ أَنْ يَكُونَ عُرِضَ لَكَ ثُمَّ ذَكَرْتُ قَوْلَكَ فَقُمْتُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاكَ جِبْرِيلُ أَتَانِي فَأَخْبَرَنِي أَنَّهُ مَنْ مَاتَ مِنْ أُمَّتِي لَا يُشْرِكُ بِاللَّهِ شَيْئًا دَخَلَ الْجَنَّةَ قُلْتُ يَا رَسُولَ اللَّهِ وَإِنْ زَنَى وَإِنْ سَرَقَ قَالَ وَإِنْ زَنَى وَإِنْ سَرَقَ قُلْتُ لِزَيْدٍ إِنَّهُ بَلَغَنِي أَنَّهُ أَبُو الدَّرْدَاءِ فَقَالَ أَشْهَدُ لَحَدَّثَنِيهِ أَبُو ذَرٍّ بِالرَّبَذَةِقَالَ الْأَعْمَشُ وَحَدَّثَنِي أَبُو صَالِحٍ عَنْ أَبِي الدَّرْدَاءِ نَحْوَهُ وَقَالَ أَبُو شِهَابٍ عَنْ الْأَعْمَشِ يَمْكُثُ عِنْدِي فَوْقَ ثَلَاثٍ","id":"Telah menceritakan kepada kami [Umar bin Hafsh] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Al A'masy] telah menceritakan kepada kami [Zaid bin Wahb] demi Allah, telah menceritakan kepada kami [Abu Dzar] ketika berada di Rabdzah, dia berkata; \"Aku pernah jalan-jalan bersama Nabi shallallahu 'alaihi wasallam di Harrah Madinah (tempat yang banyak bebatuan hitam) saat malam hari, lalu kami menghadap ke arah gunung Uhud, beliau pun bersabda: \"Wahai Abu Dzar! Aku tidak suka bila emas sebesar gunung Uhud itu menjadi milikku dan bermalam di rumahku hingga tiga malam, kemudan aku mempunyai satu dinar darinya, kecuali satu dinar tersebut akan kupersiapkan untuk membayar hutangku. Lalu aku akan mengatakannya pada hamba-hamba Allah begini, begini dan begini.\" -Beliau lantas mendemontrasikan dengan genggaman tangannya. Beliau bersabda: \"Wahai Abu Dzar, sungguh orang-orang yang berbanyak-banyak (mengumpulkan harta) akan menjadi sedikit (melarat) pada hari kiamat, kecuali orang yang berkata seperti ini, dan seperti ini!\" lalu beliau bersabda kepadaku: \"Wahai Abu Dzar, kamu tunggu di sini hingga aku datang.\" \"Setelah itu beliau pergi hingga hilang dari pandanganku, lalu aku mendengar gemuruh suara, dan aku khawatir jangan-jangan terjadi sesuatu terhadap Rasulullah shallallahu 'alaihi wasallam, serentak aku hendak pergi, namun aku segera teringat sabda Rasulullah shallallahu 'alaihi wasallam \"Tunggulah kamu di sini, \" maka aku pun segera diam di tempat, lalu aku berkata; \"Wahai Rasulullah, tadi aku mendengar suaru gemuruh, dan aku khawatir akan terjadi sesuatu kepada anda, lalu aku segera teringat pesan anda, maka aku tetap diam di tempat.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Itu adalah Jibril, ia datang dan memberitahukan kepadaku bahwa 'siapa saja yang mati dari ummatku dan tidak mensekutukan Allah dengan sesuatu pun, maka ia akan masuk ke surga'.\" Aku lalu bertanya, \"Wahai Rasulullah, walaupun ia berzina dan mencuri?\" Beliau menjawab: \"Walaupun berzina dan mencuri.\" Aku lalu berkata kepada Zaid telah sampai kepadaku bahwa dia adalah Abu Darda`, lalu Zaid mengatakan; \"Aku bersaksi bahwa yang menceritakan itu kepadaku adalah Abu Dzar ketika di Rabdzah. [A'masy] berkata; telah menceritakan kepadaku [Abu Shalih] dari [Abu Darda`] seperti hadits di atas, dan [Abu Syihab] berkata; dari [Al A'masy] bahwa dia pernah menginap di tempatku selama lebih dari tiga hari.\""},"5493":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يُقِيمُ الرَّجُلُ الرَّجُلَ مِنْ مَجْلِسِهِ ثُمَّ يَجْلِسُ فِيهِ","id":"Telah menceritakan kepada kami [Isma'il bin Abdullah] dia berkata; telah menceritakan kepadaku [Malik] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhuma dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Janganlah seseorang membangunkan orang lain dari tempat duduknya kemudian ia duduk di situ.\""},"5494":{"ar":"حَدَّثَنَا خَلَّادُ بْنُ يَحْيَى حَدَّثَنَا سُفْيَانُ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى أَنْ يُقَامَ الرَّجُلُ مِنْ مَجْلِسِهِ وَيَجْلِسَ فِيهِ آخَرُ وَلَكِنْ تَفَسَّحُوا وَتَوَسَّعُواوَكَانَ ابْنُ عُمَرَ يَكْرَهُ أَنْ يَقُومَ الرَّجُلُ مِنْ مَجْلِسِهِ ثُمَّ يَجْلِسَ مَكَانَهُ","id":"Telah menceritakan kepada kami [Khallad bin Yahya] telah menceritakan kepada kami [Sufyan] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam bahwa beliau melarang seseorang membangunkan orang lain dari tempat duduknya, lalu dia duduk di situ, akan tetapi hendaknya ia mengatakan; \"Geser dan berlapang-lapanglah.\" Dan Ibnu Umar sendiri membenci seseorang yang membangunkan orang lain dari tempat duduknya, lalu dia duduk di situ.\""},"5495":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عُمَرَ حَدَّثَنَا مُعْتَمِرٌ سَمِعْتُ أَبِي يَذْكُرُ عَنْ أَبِي مِجْلَزٍ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا تَزَوَّجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَيْنَبَ بِنْتَ جَحْشٍ دَعَا النَّاسَ طَعِمُوا ثُمَّ جَلَسُوا يَتَحَدَّثُونَ قَالَ فَأَخَذَ كَأَنَّهُ يَتَهَيَّأُ لِلْقِيَامِ فَلَمْ يَقُومُوا فَلَمَّا رَأَى ذَلِكَ قَامَ فَلَمَّا قَامَ قَامَ مَنْ قَامَ مَعَهُ مِنْ النَّاسِ وَبَقِيَ ثَلَاثَةٌ وَإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَ لِيَدْخُلَ فَإِذَا الْقَوْمُ جُلُوسٌ ثُمَّ إِنَّهُمْ قَامُوا فَانْطَلَقُوا قَالَ فَجِئْتُ فَأَخْبَرْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُمْ قَدْ انْطَلَقُوا فَجَاءَ حَتَّى دَخَلَ فَذَهَبْتُ أَدْخُلُ فَأَرْخَى الْحِجَابَ بَيْنِي وَبَيْنَهُ وَأَنْزَلَ اللَّهُ تَعَالَى{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَدْخُلُوا بُيُوتَ النَّبِيِّ إِلَّا أَنْ يُؤْذَنَ لَكُمْ إِلَى قَوْلِهِ إِنَّ ذَلِكُمْ كَانَ عِنْدَ اللَّهِ عَظِيمًا }","id":"Telah menceritakan kepada kami [Al Hasan bin Umar] telah menceritakan kepada kami [Mu'tamir] saya mendengar [Ayahku] bahwa dia menyebutkan dari [Abu Mijlaz] dari [Anas bin Malik] radliallahu 'anhu dia berkata; \"Ketika Rasulullah shallallahu 'alaihi wasallam menikah dengan Zainab binti Jahsy, beliau mengundang orang-orang untuk menikmati jamuan, kemudian mereka duduk-duduk dan berbincang-bincang.\" Anas melanjutkan ceritanya; \"Kemudian beliau merubah posisi seakan-akan hendak berdiri, namun orang-orang tidak juga berdiri, ketika beliau berdiri, maka orang-orang pun ikut berdiri bersama beliau, hingga tinggal tiga orang. Sesungguhnya Nabi shallallahu 'alaihi wasallam datang untuk masuk ke kamar, namun orang-orang masih saja duduk-duduk, selepas itu akhirnya mereka beranjak dan pergi. Tinggalah tiga orang yang masih duduk. Nabi shallallahu 'alaihi wasallam datang dan hendak masuk (ke kamar Zainab), namun tiga orang tersebut masih tetap duduk-duduk, setelah itu mereka berdiri dan beranjak pergi. Anas berkata; Lalu saya mengabarkan kepada Nabi shallallahu 'alaihi wasallam bahwa mereka sudah beranjak pergi.\" Kemudian beliau datang dan masuk, maka saya pun mengikuti beliau masuk, lantas beliau menurunkan kain tirainya antara saya dengan beliau.\" Lalu Allah Ta'ala menurunkan (ayat): Hai orang-orang yang beriman, janganlah kamu memasuki rumah- rumah nabi kecuali bila kamu diizinkan -hingga firman Allah- Sesungguhnya perbuatan itu adalah amat besar (dosanya) di sisi Allah.\" (Al Ahzab: 53)."},"5496":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي غَالِبٍ أَخْبَرَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ الْحِزَامِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ فُلَيْحٍ عَنْ أَبِيهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِفِنَاءِ الْكَعْبَةِ مُحْتَبِيًا بِيَدِهِ هَكَذَا","id":"Telah menceritakan kepada kami [Muhammad bin Abu Ghalib] telah mengabarkan kepada kami [Ibrahim bin Al Mundzir Al Khizami] telah menceritakan kepada kami [Muhammad bin Fulaih] dari [Ayahnya] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhuma dia berkata; \"Saya melihat Rasulullah shallallahu 'alaihi wasallam berada di serambi Ka'bah duduk ihtiba` dengan tangannya seperti ini.\""},"5497":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ حَدَّثَنَا الْجُرَيْرِيُّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا أُخْبِرُكُمْ بِأَكْبَرِ الْكَبَائِرِ قَالُوا بَلَى يَا رَسُولَ اللَّهِ قَالَ الْإِشْرَاكُ بِاللَّهِ وَعُقُوقُ الْوَالِدَيْنِحَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا بِشْرٌ مِثْلَهُ وَكَانَ مُتَّكِئًا فَجَلَسَ فَقَالَ أَلَا وَقَوْلُ الزُّورِ فَمَا زَالَ يُكَرِّرُهَا حَتَّى قُلْنَا لَيْتَهُ سَكَتَ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Bisyr bin Al Mufadlal] telah menceritakan kepada kami [Al Jurairi] dari [Abdurrahman bin Abu Bakrah] dari [Ayahnya] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Maukah aku beritahukan kepada kalian tentang dosa-dosa besar?\" Mereka (para sahabat) menjawab; 'Ya wahai Rasulullah.' Beliau bersabda: 'Menyekutukan Allah dan durhaka kepada kedua orang tua.' Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Bisyr] seperti hadits di atas, ketika itu beliau tengah bersandar, lalu beliau duduk dan melanjutkan sabdanya: 'Dan perkataan dusta,.' Beliau terus saja mengulanginya hingga kami mengira beliau tidak akan berhenti.\""},"5498":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ عُمَرَ بْنِ سَعِيدٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ أَنَّ عُقْبَةَ بْنَ الْحَارِثِ حَدَّثَهُ قَالَصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَصْرَ فَأَسْرَعَ ثُمَّ دَخَلَ الْبَيْتَ","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari [Umar bin Sa'id] dari [Ibnu Abu Mulaikah] bahwa [Uqbah bin Al Harits] telah menceritakan kepadanya, ia berkata; \"Nabi shallallahu 'alaihi wasallam pernah mengerjakan shalat Ashar setelah itu beliau segera masuk ke rumah.\""},"5499":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي وَسْطَ السَّرِيرِ وَأَنَا مُضْطَجِعَةٌ بَيْنَهُ وَبَيْنَ الْقِبْلَةِ تَكُونُ لِي الْحَاجَةُ فَأَكْرَهُ أَنْ أَقُومَ فَأَسْتَقْبِلَهُ فَأَنْسَلُّ انْسِلَالًا","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Adl Dluha] dari [Masruq] dari [Aisyah] radliallahu 'anha dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah mengerjakan shalat di atas kasur, sementara aku terlentang antara beliau dan Kiblat, ketika itu aku hendak buang hajat, dan aku tidak suka jika berdiri, hingga akhirnya aku menghadap beliau dan mundur secara pelan-pelan.\""},"5500":{"ar":"حَدَّثَنَا إِسْحَاقُ حَدَّثَنَا خَالِدٌ ح و حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ حَدَّثَنَا خَالِدٌ عَنْ خَالِدٍ عَنْ أَبِي قِلَابَةَ قَالَ أَخْبَرَنِي أَبُو الْمَلِيحِ قَالَدَخَلْتُ مَعَ أَبِيكَ زَيْدٍ عَلَى عَبْدِ اللَّهِ بْنِ عَمْرٍو فَحَدَّثَنَا أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذُكِرَ لَهُ صَوْمِي فَدَخَلَ عَلَيَّ فَأَلْقَيْتُ لَهُ وِسَادَةً مِنْ أَدَمٍ حَشْوُهَا لِيفٌ فَجَلَسَ عَلَى الْأَرْضِ وَصَارَتْ الْوِسَادَةُ بَيْنِي وَبَيْنَهُ فَقَالَ لِي أَمَا يَكْفِيكَ مِنْ كُلِّ شَهْرٍ ثَلَاثَةُ أَيَّامٍ قُلْتُ يَا رَسُولَ اللَّهِ قَالَ خَمْسًا قُلْتُ يَا رَسُولَ اللَّهِ قَالَ سَبْعًا قُلْتُ يَا رَسُولَ اللَّهِ قَالَ تِسْعًا قُلْتُ يَا رَسُولَ اللَّهِ قَالَ إِحْدَى عَشْرَةَ قُلْتُ يَا رَسُولَ اللَّهِ قَالَ لَا صَوْمَ فَوْقَ صَوْمِ دَاوُدَ شَطْرَ الدَّهْرِ صِيَامُ يَوْمٍ وَإِفْطَارُ يَوْمٍ","id":"Telah menceritakan kepada kami [Ishaq] telah menceritakan kepada kami [Khalid]. Dan diriwayatkan dari jalur lain, telah menceritakan kepadaku [Abdullah bin Muhammad] telah menceritakan kepada kami ['Amru bin 'Aun] telah menceritakan kepada kami [Khalid] dari [Khalid] dari [Abu Qilabah] dia berkata; telah mengabarkan kepadaku [Abu Al Malih] dia berkata; \"Aku bersama ayahmu Zaid pernah menemui [Abdullah bin 'Amru] kemudian dia menceritakan kepada kami bahwa Nabi shallallahu 'alaihi wasallam pernah mendengar kabar tentang puasaku, lalu beliau menemuiku, maka aku langsung menghamparkan bantal kulit yang dalamnya terbuat dari serabut, namun beliau duduk di atas tanah, hingga bantal tersebut berada antara aku dan beliau, beliau bersabda kepadaku: 'Tidakkah cukup bagimu (berpuasa) tiga hari setiap bulan? ' Jawabku; 'Wahai Rasulullah (aku mampu lebih dari itu -red).' Beliau bersabda: 'Kalau begitu lima hari (setiap bulan).' Jawabku; 'Wahai Rasulullah (aku masih mampu lebih dari itu -red).' Beliau bersabda: 'Kalau begitu tujuh hari (setiap bulan).' Jawabku; 'Wahai Rasulullah (aku mampu lebih dari itu -red).' Beliau bersabda: 'Kalau begitu sebelas hari (setiap bulan).' Aku berkata; 'Wahai Rasulullah, (aku mampu lebih dari itu).' Beliau bersabda: 'Tidak ada puasa lebih dari puasanya (nabi) Daud yaitu setengah masa, puasa sehari dan berbuka sehari).'"}};
